const TOEIC_QUESTIONS = {"part5":[{"id":"p5-1","part":5,"type":"word-form","question":"The company's new strategy proved highly _____ in reducing costs.","options":["effect","effective","effectively","effectiveness"],"answer":1,"explanation":"'Effective' là tính từ, dùng sau động từ 'proved' (liên kết). 'Effect' là danh từ, 'effectively' là phó từ, 'effectiveness' là danh từ."},{"id":"p5-2","part":5,"type":"word-form","question":"Applications must be submitted _____ to be considered for the position.","options":["electronic","electronics","electronically","electronica"],"answer":2,"explanation":"Phó từ 'electronically' bổ nghĩa cho động từ 'submitted'."},{"id":"p5-3","part":5,"type":"word-form","question":"The _____ of the new policy will take effect next month.","options":["implement","implemented","implementing","implementation"],"answer":3,"explanation":"Sau mạo từ 'the' cần danh từ. 'Implementation' = sự thực hiện."},{"id":"p5-4","part":5,"type":"word-form","question":"The sales team worked _____ to exceed their quarterly targets.","options":["diligent","diligently","diligence","diligently"],"answer":1,"explanation":"Phó từ 'diligently' bổ nghĩa cho động từ 'worked'."},{"id":"p5-5","part":5,"type":"word-form","question":"His _____ to detail made him an ideal candidate for the auditing role.","options":["attend","attentive","attention","attentively"],"answer":2,"explanation":"Sau sở hữu cách 'His' cần danh từ. 'Attention to detail' = sự chú ý đến chi tiết."},{"id":"p5-6","part":5,"type":"word-form","question":"The report provided a _____ analysis of consumer behavior.","options":["comprehend","comprehensive","comprehensively","comprehension"],"answer":1,"explanation":"Tính từ 'comprehensive' bổ nghĩa cho danh từ 'analysis'."},{"id":"p5-7","part":5,"type":"word-form","question":"The CEO made a _____ decision to expand into the Asian market.","options":["strategy","strategize","strategic","strategically"],"answer":2,"explanation":"Tính từ 'strategic' đứng trước danh từ 'decision'."},{"id":"p5-8","part":5,"type":"word-form","question":"Employee _____ has improved significantly since the new benefits package was introduced.","options":["satisfy","satisfied","satisfying","satisfaction"],"answer":3,"explanation":"Sau 'Employee' cần danh từ chủ ngữ. 'Satisfaction' = sự hài lòng."},{"id":"p5-9","part":5,"type":"word-form","question":"The project manager's _____ style motivated the entire team.","options":["lead","leader","leads","leadership"],"answer":3,"explanation":"'Leadership style' là cụm danh từ chuẩn (phong cách lãnh đạo). Vị trí sau sở hữu cách cần danh từ. 'Lead/leads' là động từ, 'leader' là danh từ chỉ người – không đứng trước 'style'."},{"id":"p5-10","part":5,"type":"word-form","question":"The factory is _____ expanding its production capacity.","options":["current","currency","currently","currents"],"answer":2,"explanation":"Phó từ 'currently' bổ nghĩa cho động từ 'expanding'."},{"id":"p5-11","part":5,"type":"verb-tense","question":"By the time the director arrives, the team _____ the presentation.","options":["will finish","finishes","will have finished","has finished"],"answer":2,"explanation":"'By the time + past/present' cần 'future perfect (will have + V3)' ở mệnh đề chính."},{"id":"p5-12","part":5,"type":"verb-tense","question":"The company _____ three new branches since the beginning of the year.","options":["opens","opened","has opened","had opened"],"answer":2,"explanation":"'Since the beginning of the year' → hiện tại hoàn thành 'has opened'."},{"id":"p5-13","part":5,"type":"verb-tense","question":"Sales figures _____ steadily over the past six months.","options":["increase","increased","have increased","are increasing"],"answer":2,"explanation":"'Over the past six months' → hiện tại hoàn thành 'have increased'."},{"id":"p5-14","part":5,"type":"verb-tense","question":"The training session _____ at 9 a.m. every Monday morning.","options":["begins","began","has begun","will begin"],"answer":0,"explanation":"Lịch trình cố định, thói quen → hiện tại đơn 'begins'."},{"id":"p5-15","part":5,"type":"verb-tense","question":"The previous manager _____ the company for over twenty years before retiring.","options":["leads","has led","led","will lead"],"answer":2,"explanation":"Hành động đã hoàn tất trong quá khứ (before retiring) → quá khứ đơn 'led'."},{"id":"p5-16","part":5,"type":"verb-tense","question":"The client _____ the contract by the end of this week.","options":["signed","is signing","will have signed","has signed"],"answer":2,"explanation":"'By the end of this week' → future perfect 'will have signed'."},{"id":"p5-17","part":5,"type":"preposition","question":"The report must be submitted _____ Friday at the latest.","options":["until","by","on","at"],"answer":1,"explanation":"'By' = không muộn hơn (deadline). 'Until' = cho đến tận (liên tục)."},{"id":"p5-18","part":5,"type":"preposition","question":"The new policy is _____ accordance with international safety standards.","options":["on","in","at","by"],"answer":1,"explanation":"'In accordance with' là cụm giới từ cố định = phù hợp với."},{"id":"p5-19","part":5,"type":"preposition","question":"The manager will be available _____ appointment only.","options":["by","on","in","with"],"answer":0,"explanation":"'By appointment only' = chỉ theo lịch hẹn (cụm cố định)."},{"id":"p5-20","part":5,"type":"preposition","question":"The seminar will be held _____ the conference center downtown.","options":["in","at","on","by"],"answer":1,"explanation":"'At' dùng cho địa điểm cụ thể/rõ ràng như 'the conference center'."},{"id":"p5-21","part":5,"type":"preposition","question":"She is responsible _____ overseeing the company's social media accounts.","options":["of","to","for","by"],"answer":2,"explanation":"'Be responsible for' là cụm cố định."},{"id":"p5-22","part":5,"type":"preposition","question":"The announcement was made _____ behalf of the entire board.","options":["on","in","of","at"],"answer":0,"explanation":"'On behalf of' = thay mặt (cụm cố định)."},{"id":"p5-23","part":5,"type":"conjunction","question":"_____ the project was challenging, the team completed it on time.","options":["Because","Although","Since","So"],"answer":1,"explanation":"'Although' = mặc dù (nhượng bộ). Câu có sự tương phản giữa 'challenging' và 'completed on time'."},{"id":"p5-24","part":5,"type":"conjunction","question":"Please contact us _____ you have any questions about your order.","options":["although","unless","should","whether"],"answer":2,"explanation":"'Should you have any questions' = đảo ngữ câu điều kiện loại 1 lịch sự (should + S + V)."},{"id":"p5-25","part":5,"type":"conjunction","question":"The deadline is tomorrow; _____, the team will need to work overtime.","options":["however","therefore","moreover","instead"],"answer":1,"explanation":"'Therefore' = do đó, vì vậy. Câu sau là kết quả của câu trước."},{"id":"p5-26","part":5,"type":"conjunction","question":"Staff must wear protective gear _____ entering the production area.","options":["while","during","when","throughout"],"answer":2,"explanation":"'When entering' = khi vào (when + V-ing, rút gọn mệnh đề thời gian)."},{"id":"p5-27","part":5,"type":"conjunction","question":"The factory will remain open _____ the renovation is being carried out.","options":["since","while","because","until"],"answer":1,"explanation":"'While' = trong khi (hai hành động xảy ra song song)."},{"id":"p5-28","part":5,"type":"passive","question":"The new safety guidelines _____ to all staff before the end of the month.","options":["will distribute","will be distributed","distributes","is distributing"],"answer":1,"explanation":"Chủ thể nhận tác động (guidelines được phân phát) → bị động 'will be distributed'."},{"id":"p5-29","part":5,"type":"passive","question":"The annual report _____ by the accounting team every December.","options":["prepares","is prepared","has preparing","preparing"],"answer":1,"explanation":"Hành động thường xuyên, lặp đi lặp lại → bị động hiện tại đơn 'is prepared'."},{"id":"p5-30","part":5,"type":"passive","question":"All inquiries should _____ to the customer service department.","options":["direct","directs","be directed","directing"],"answer":2,"explanation":"'Should be directed' = bị động sau động từ khuyết thiếu (should + be + V3)."},{"id":"p5-31","part":5,"type":"pronoun","question":"The marketing team presented _____ quarterly findings to the board.","options":["it's","their","they","theirs"],"answer":1,"explanation":"Sở hữu tính từ 'their' đứng trước danh từ 'findings'."},{"id":"p5-32","part":5,"type":"pronoun","question":"_____ of the candidates met all the required qualifications.","options":["Neither","Either","Each","Both"],"answer":0,"explanation":"'Neither' = không ai trong hai người (cả hai đều không đủ tiêu chuẩn, phù hợp nghĩa ở đây)."},{"id":"p5-33","part":5,"type":"article","question":"The committee reached _____ unanimous decision after hours of discussion.","options":["a","an","the","—"],"answer":0,"explanation":"'Unanimous' bắt đầu bằng âm /j/ (yoo), không phải nguyên âm → dùng 'a'."},{"id":"p5-34","part":5,"type":"pronoun","question":"Employees are encouraged to voice _____ concerns at the monthly meetings.","options":["its","their","our","one's"],"answer":1,"explanation":"'Employees' là số nhiều → 'their concerns'."},{"id":"p5-35","part":5,"type":"vocabulary","question":"The board of directors has _____ the proposed merger with the tech firm.","options":["approved","applied","appealed","appeased"],"answer":0,"explanation":"'Approved' = phê duyệt. Phù hợp ngữ cảnh 'board approving a merger'."},{"id":"p5-36","part":5,"type":"vocabulary","question":"The training program is _____ to all full-time employees.","options":["available","reliable","capable","suitable"],"answer":0,"explanation":"'Available to' = có sẵn/dành cho. Cụm cố định trong văn bản thông báo."},{"id":"p5-37","part":5,"type":"vocabulary","question":"Due to _____ demand, the new product will be restocked next week.","options":["high","large","great","wide"],"answer":0,"explanation":"'High demand' là collocation chuẩn trong tiếng Anh thương mại."},{"id":"p5-38","part":5,"type":"vocabulary","question":"The merger is _____ to be completed by the end of the fiscal year.","options":["expected","assumed","supposed","thought"],"answer":0,"explanation":"'Expected to + V' = được kỳ vọng là sẽ. Dùng phổ biến trong tin tức kinh doanh."},{"id":"p5-39","part":5,"type":"vocabulary","question":"The conference room _____ up to 50 people.","options":["contains","accommodates","fits","stores"],"answer":1,"explanation":"'Accommodates' = có sức chứa/đáp ứng, đây là collocation chuẩn khi nói về sức chứa người. 'Contains' và 'stores' dùng cho vật, không dùng cho người. 'Fits' mang nghĩa không gian vật lý, không trang trọng bằng."},{"id":"p5-40","part":5,"type":"vocabulary","question":"Mr. Park has _____ over the new project since last month.","options":["taken charge","been in charge","taken over","been responsible"],"answer":2,"explanation":"'Taken over' = đảm nhận, tiếp quản. Dùng với 'over + something'."},{"id":"p5-41","part":5,"type":"gerund-infinitive","question":"The HR manager suggested _____ the interview process to attract more applicants.","options":["to simplify","simplify","simplified","simplifying"],"answer":3,"explanation":"'Suggest + V-ing' là cú pháp cố định. Động từ 'suggest' không đi với to-infinitive."},{"id":"p5-42","part":5,"type":"gerund-infinitive","question":"The company plans _____ a new branch in Ho Chi Minh City next quarter.","options":["opening","to open","open","opened"],"answer":1,"explanation":"'Plan + to + V' là cú pháp cố định."},{"id":"p5-43","part":5,"type":"gerund-infinitive","question":"All participants are required _____ their badges at the entrance.","options":["wearing","wore","to wear","wear"],"answer":2,"explanation":"'Be required to + V' = phải làm gì."},{"id":"p5-44","part":5,"type":"relative-clause","question":"The candidate _____ application was shortlisted has ten years of experience.","options":["who","whom","whose","which"],"answer":2,"explanation":"'Whose' dùng để chỉ sở hữu (application của candidate)."},{"id":"p5-45","part":5,"type":"relative-clause","question":"The department _____ handles customer complaints is understaffed.","options":["who","whose","where","that"],"answer":3,"explanation":"'That' dùng trong mệnh đề quan hệ hạn định (defining relative clause) cho vật/tổ chức. 'Who' dùng cho người, 'whose' chỉ sở hữu, 'where' chỉ địa điểm."},{"id":"p5-46","part":5,"type":"comparison","question":"The new factory is _____ efficient than the old one.","options":["more","most","much","better"],"answer":0,"explanation":"So sánh hơn với tính từ dài: 'more + adj + than'."},{"id":"p5-47","part":5,"type":"comparison","question":"This is _____ the best deal we have received from a supplier.","options":["by far","so far","more far","near"],"answer":0,"explanation":"'By far the best' = vượt trội hoàn toàn, cách xa (nhấn mạnh so sánh nhất)."},{"id":"p5-48","part":5,"type":"vocabulary","question":"The company's _____ decision to relocate surprised many employees.","options":["sudden","gradual","tentative","significant"],"answer":0,"explanation":"'Sudden decision' = quyết định đột ngột (collocation chuẩn). 'Gradual' (dần dần) trái nghĩa hoàn toàn. 'Tentative' (tạm thời, chưa chắc) và 'significant' (đáng kể) không phù hợp ngữ cảnh 'surprise'."},{"id":"p5-49","part":5,"type":"vocabulary","question":"Please _____ the attached form and return it to reception.","options":["complete","fulfill","accomplish","achieve"],"answer":0,"explanation":"'Complete a form' = hoàn thành mẫu đơn (collocation cố định)."},{"id":"p5-50","part":5,"type":"vocabulary","question":"The firm is _____ a comprehensive review of its pricing strategy.","options":["doing","making","conducting","performing"],"answer":2,"explanation":"'Conduct a review' = tiến hành đánh giá (collocation chuẩn trong tiếng Anh thương mại)."},{"id":"n5-1","part":5,"type":"vocabulary","question":"The board of directors _____ the CEO to explore new sustainability initiatives in the Southeast Asian market.","options":["urged","insisted","demanded","notified"],"answer":0,"explanation":"✅ <b>Urged</b> (Thúc giục). <br>💡 <i>Sắc thái:</i> 'Urge someone to do something' là lời khuyên/yêu cầu lịch sự nhưng quyết đoán từ cấp trên. 'Insisted' phải đi với 'on', 'Demanded' quá gắt gao."},{"id":"n5-2","part":5,"type":"vocabulary","question":"To remain competitive, the firm must _____ its operations to better align with digital industry trends.","options":["refine","resume","recruit","replace"],"answer":0,"explanation":"✅ <b>Refine</b> (Tinh chỉnh/Cải tiến). <br>💡 <i>Sắc thái:</i> Dùng 'refine operations' khi muốn nói về việc làm cho quy trình trở nên chuyên nghiệp và hiệu quả hơn."},{"id":"n5-3","part":5,"type":"vocabulary","question":"The marketing campaign was highly _____, resulting in a significant uptick in customer engagement.","options":["productive","effective","beneficial","valuable"],"answer":1,"explanation":"✅ <b>Effective</b> (Hiệu quả). <br>💡 <i>Mẹo ETS:</i> Trong marketing, 'effective' chỉ chiến dịch đạt được mục tiêu đề ra (conversion/engagement)."},{"id":"n5-4","part":5,"type":"vocabulary","question":"The factory's recent switch to solar power has led to a _____ decrease in monthly energy costs.","options":["notable","noting","notably","noted"],"answer":0,"explanation":"✅ <b>Notable</b> (Đáng kể). <br>💡 <i>Cấu trúc:</i> 'Notable decrease/increase' là cụm từ cố định để chỉ sự thay đổi rõ rệt."},{"id":"n5-5","part":5,"type":"vocabulary","question":"Mr. Park's _____ in handling client disputes has made him an invaluable asset to the PR department.","options":["discretion","determination","disruption","diversity"],"answer":0,"explanation":"✅ <b>Discretion</b> (Sự khéo léo/Thận trọng). <br>💡 <i>Sắc thái:</i> 'Discretion' là kỹ năng xử lý các tình huống nhạy cảm hoặc tranh chấp một cách êm đẹp."},{"id":"n5-6","part":5,"type":"vocabulary","question":"The _____ of the new safety protocols is mandatory for all laboratory personnel.","options":["observation","observance","observing","observed"],"answer":1,"explanation":"✅ <b>Observance</b> (Sự tuân thủ). <br>💡 <i>Phân biệt:</i> 'Observance' (tuân thủ luật lệ) khác với 'Observation' (quan sát bằng mắt)."},{"id":"n5-7","part":5,"type":"vocabulary","question":"After a thorough _____, the research team concluded that the market was ready for the new product line.","options":["appraisal","approval","application","appearance"],"answer":0,"explanation":"✅ <b>Appraisal</b> (Thẩm định). <br>💡 <i>Từ chuyên dụng:</i> 'Thorough appraisal' chỉ việc đánh giá cực kỳ chi tiết trước khi đưa ra kết luận."},{"id":"n5-8","part":5,"type":"vocabulary","question":"The CEO requested a _____ summary of the merger's potential impact on the company's long-term growth.","options":["concise","precise","strict","minor"],"answer":0,"explanation":"✅ <b>Concise</b> (Súc tích). <br>💡 <i>Collocation:</i> 'Concise summary' là bản tóm tắt ngắn gọn nhưng đầy đủ ý."},{"id":"n5-9","part":5,"type":"vocabulary","question":"The project was _____ completed within the allotted budget and timeframe.","options":["successfully","fortunately","specifically","marginally"],"answer":0,"explanation":"✅ <b>Successfully</b> (Thành công). <br>💡 Trạng từ bổ nghĩa cho 'completed' để chỉ dự án đạt chỉ tiêu."},{"id":"n5-10","part":5,"type":"vocabulary","question":"Managers are expected to _____ any potential conflicts of interest to the HR department immediately.","options":["disclose","declare","describe","discover"],"answer":0,"explanation":"✅ <b>Disclose</b> (Tiết lộ). <br>💡 <i>Mẹo ETS:</i> Dùng 'disclose' khi nói về việc khai báo các thông tin nhạy cảm hoặc bí mật kinh doanh."},{"id":"n5-11","part":5,"type":"vocabulary","question":"The committee made several _____ recommendations to improve workplace safety.","options":["valuable","valuing","valuably","valuation"],"answer":0,"explanation":"✅ <b>Valuable</b> (Giá trị). <br>💡 Tính từ bổ nghĩa cho 'recommendations' (đề xuất có giá trị)."},{"id":"n5-12","part":5,"type":"vocabulary","question":"All documents must be reviewed for _____ before being submitted to the legal team.","options":["accuracy","accurate","accurately","accurateness"],"answer":0,"explanation":"✅ <b>Accuracy</b> (Độ chính xác). <br>💡 Vị trí danh từ sau giới từ 'for'."},{"id":"n5-13","part":5,"type":"vocabulary","question":"The new branch manager has _____ transformed the team's productivity within just two months.","options":["radically","remarkably","rarely","randomly"],"answer":0,"explanation":"✅ <b>Radically</b> (Triệt để). <br>💡 <i>Bẫy 2025:</i> 'Radically transform' là cụm từ mạnh chỉ sự thay đổi toàn diện từ gốc rễ."},{"id":"n5-14","part":5,"type":"vocabulary","question":"The _____ of the annual report requires contributions from all department heads.","options":["compilation","compile","compiler","compiled"],"answer":0,"explanation":"✅ <b>Compilation</b> (Việc biên soạn). <br>💡 Danh từ đóng vai trò chủ ngữ, chỉ quá trình tổng hợp dữ liệu."},{"id":"n5-15","part":5,"type":"vocabulary","question":"Employees who demonstrate _____ in their roles will be considered for promotion.","options":["exceptionality","exception","excellence","excel"],"answer":2,"explanation":"✅ <b>Excellence</b> (Sự xuất sắc). <br>💡 Danh từ sau verb 'demonstrate' (thể hiện sự xuất sắc)."},{"id":"n5-16","part":5,"type":"verb-tense","question":"The client _____ the proposal three times since the initial submission.","options":["revised","revises","has revised","will revise"],"answer":2,"explanation":"✅ <b>Has revised</b> (Hiện tại hoàn thành). <br>💡 <i>Dấu hiệu:</i> 'Since' + mốc thời gian -> dùng Present Perfect."},{"id":"n5-17","part":5,"type":"verb-tense","question":"Ms. Chen _____ as the lead architect on the downtown tower project for five years.","options":["served","serves","has served","will serve"],"answer":2,"explanation":"✅ <b>Has served</b>. <br>💡 'For five years' chỉ quá trình làm việc liên tục kéo dài đến hiện tại."},{"id":"n5-18","part":5,"type":"verb-tense","question":"The finance team _____ the quarterly budget when the auditors arrived unexpectedly.","options":["reviews","reviewed","was reviewing","will review"],"answer":2,"explanation":"✅ <b>Was reviewing</b>. <br>💡 <i>Cấu trúc:</i> Hành động đang diễn ra (quá khứ tiếp diễn) thì có hành động khác xen vào (arrived)."},{"id":"n5-19","part":5,"type":"verb-tense","question":"If the supply chain issues are resolved, the company _____ its production targets.","options":["meet","met","will meet","has met"],"answer":2,"explanation":"✅ <b>Will meet</b>. <br>💡 Câu điều kiện Loại 1 (Có thể xảy ra): If + Hiện tại, Tương lai."},{"id":"n5-20","part":5,"type":"verb-tense","question":"The CEO _____ all senior managers before announcing the restructuring plan.","options":["consults","will consult","consulted","has consulted"],"answer":1,"explanation":"✅ <b>Will consult</b>. <br>💡 'Before announcing' (trước khi thông báo) ám chỉ hành động sẽ xảy ra trong tương lai."},{"id":"n5-21","part":5,"type":"verb-tense","question":"By next month, the development team _____ the mobile application for two years.","options":["develops","developed","will develop","will have been developing"],"answer":3,"explanation":"✅ <b>Will have been developing</b>. <br>💡 <i>Mẹo ETS:</i> 'By + next month' + 'for [duration]' -> Tương lai hoàn thành tiếp diễn."},{"id":"n5-22","part":5,"type":"verb-tense","question":"The store _____ at 9 a.m. and closes at 9 p.m. every day of the week.","options":["opened","opens","has opened","will open"],"answer":1,"explanation":"✅ <b>Opens</b>. <br>💡 Hiện tại đơn dùng cho lịch trình hoặc thói quen lặp lại hàng ngày."},{"id":"n5-23","part":5,"type":"verb-tense","question":"The shipment that _____ two days ago has finally cleared customs.","options":["arrived","arrives","has arrived","was arrived"],"answer":0,"explanation":"✅ <b>Arrived</b>. <br>💡 <i>Dấu hiệu:</i> 'Two days ago' là mốc thời gian xác định trong quá khứ."},{"id":"n5-24","part":5,"type":"verb-tense","question":"All participants _____ a certificate upon completing the training program.","options":["receive","received","will receive","has received"],"answer":2,"explanation":"✅ <b>Will receive</b>. <br>💡 Diễn tả sự việc sẽ xảy ra sau khi hoàn thành một điều kiện (completing program)."},{"id":"n5-25","part":5,"type":"preposition","question":"The sales team is working _____ a tight deadline to finalize the client proposal.","options":["to","on","under","with"],"answer":2,"explanation":"✅ <b>Under</b>. <br>💡 <i>Cụm cố định:</i> 'Working under a deadline' (Làm việc dưới áp lực thời gian)."},{"id":"n5-26","part":5,"type":"preposition","question":"The company is committed _____ reducing its carbon footprint by 2030.","options":["for","on","to","with"],"answer":2,"explanation":"✅ <b>To</b>. <br>💡 <i>Cấu trúc:</i> 'Commit to + V-ing/Noun' (Cam kết làm gì)."},{"id":"n5-27","part":5,"type":"preposition","question":"The conference will be held _____ three days, starting Monday.","options":["in","for","over","during"],"answer":2,"explanation":"✅ <b>Over</b>. <br>💡 'Over + số ngày' dùng để chỉ sự kiện diễn ra xuyên suốt trong một khoảng thời gian."},{"id":"n5-28","part":5,"type":"preposition","question":"Please refer any technical issues _____ the IT help desk on the third floor.","options":["to","at","for","by"],"answer":0,"explanation":"✅ <b>To</b>. <br>💡 <i>Cấu trúc:</i> 'Refer something to someone' (Chuyển giao/Gửi vấn đề cho ai)."},{"id":"n5-29","part":5,"type":"preposition","question":"The memorandum was circulated _____ all branch offices last Tuesday.","options":["among","between","to","for"],"answer":2,"explanation":"✅ <b>To</b>. <br>💡 'Circulate something to...' (Lưu hành/Gửi thông báo tới các đơn vị)."},{"id":"n5-30","part":5,"type":"preposition","question":"Staff members are eligible _____ the wellness reimbursement program after 90 days of employment.","options":["of","on","for","by"],"answer":2,"explanation":"✅ <b>For</b>. <br>💡 <i>Cấu trúc:</i> 'Be eligible for something' (Đủ điều kiện được hưởng cái gì)."},{"id":"n5-31","part":5,"type":"preposition","question":"The revised contract was sent _____ email to all vendors this morning.","options":["in","with","by","on"],"answer":2,"explanation":"✅ <b>By</b>. <br>💡 'By + phương tiện liên lạc' (By email, by post, by phone)."},{"id":"n5-32","part":5,"type":"preposition","question":"The new software is compatible _____ both Windows and Mac operating systems.","options":["to","for","with","of"],"answer":2,"explanation":"✅ <b>With</b>. <br>💡 <i>Cấu trúc:</i> 'Compatible with' (Tương thích với)."},{"id":"n5-33","part":5,"type":"preposition","question":"The research team's findings are consistent _____ previous studies on consumer behavior.","options":["to","with","on","by"],"answer":1,"explanation":"✅ <b>With</b>. <br>💡 <i>Cấu trúc:</i> 'Consistent with' (Nhất quán/Phù hợp với)."},{"id":"n5-34","part":5,"type":"conjunction","question":"The new packaging was designed to be eco-friendly _____ cost-effective.","options":["yet","and","but","or"],"answer":1,"explanation":"✅ <b>And</b>. <br>💡 'And' nối hai tính từ tương đồng mang nghĩa tích cực cho sản phẩm."},{"id":"n5-35","part":5,"type":"conjunction","question":"The product launch was delayed _____ supply chain disruptions earlier this year.","options":["despite","due to","although","whereas"],"answer":1,"explanation":"✅ <b>Due to</b> (Do/Bởi vì). <br>💡 <i>Ghi nhớ:</i> 'Due to' + Noun Phrase (supply chain disruptions)."},{"id":"n5-36","part":5,"type":"conjunction","question":"_____ the report is ready, please send it directly to the board of directors.","options":["If","When","Once","Since"],"answer":2,"explanation":"✅ <b>Once</b> (Ngay khi). <br>💡 'Once' nhấn mạnh thời điểm một hành động vừa hoàn thành thì hành động sau xảy ra ngay."},{"id":"n5-37","part":5,"type":"conjunction","question":"The company will proceed with the expansion _____ the new regulation is approved.","options":["provided that","regardless of","so that","in case"],"answer":0,"explanation":"✅ <b>Provided that</b> (Miễn là/Với điều kiện là). <br>💡 Đây là cấu trúc câu điều kiện thường xuyên xuất hiện trong Part 5."},{"id":"n5-38","part":5,"type":"conjunction","question":"Mr. Yamamoto agreed to take on the additional responsibilities _____ asking for a salary increase.","options":["despite","without","unless","instead of"],"answer":1,"explanation":"✅ <b>Without</b>. <br>💡 'Without + V-ing' (mà không...). Phù hợp nghĩa: làm thêm việc mà không đòi tăng lương."},{"id":"n5-39","part":5,"type":"conjunction","question":"The renovation will take approximately six weeks; _____, all staff will be working from home.","options":["therefore","however","meanwhile","otherwise"],"answer":2,"explanation":"✅ <b>Meanwhile</b> (Trong khi đó). <br>💡 Dùng để kết nối hai sự việc xảy ra song song về mặt thời gian."},{"id":"n5-40","part":5,"type":"conjunction","question":"The survey results were positive; _____, management decided to make further improvements.","options":["even so","since then","as a result","for instance"],"answer":0,"explanation":"✅ <b>Even so</b> (Dù vậy/Mặc dù thế). <br>💡 Dùng để nối hai vế có tính chất tương phản nhẹ (kết quả tốt nhưng vẫn muốn tốt hơn)."},{"id":"n5-41","part":5,"type":"passive","question":"A formal complaint _____ by the tenant regarding the building's heating system.","options":["filed","is filing","has been filed","files"],"answer":2,"explanation":"✅ <b>Has been filed</b> (Bị động hiện tại hoàn thành). <br>💡 <i>Phân tích:</i> Complaint (lời phàn nàn) phải được 'nộp' (filed)."},{"id":"n5-42","part":5,"type":"passive","question":"The quarterly targets _____ to the sales team during last Monday's briefing.","options":["distributed","were distributed","will distribute","distributing"],"answer":1,"explanation":"✅ <b>Were distributed</b> (Bị động quá khứ). <br>💡 <i>Dấu hiệu:</i> 'Last Monday' -> Quá khứ đơn."},{"id":"n5-43","part":5,"type":"passive","question":"All employees are _____ to complete the mandatory cybersecurity training by Friday.","options":["require","required","requiring","requirement"],"answer":1,"explanation":"✅ <b>Required</b>. <br>💡 <i>Cấu trúc:</i> 'Be required to do something' (Bị bắt buộc/Được yêu cầu làm gì)."},{"id":"n5-44","part":5,"type":"passive","question":"The defective items _____ at no additional charge to all affected customers.","options":["will replace","will be replaced","are replacing","has replaced"],"answer":1,"explanation":"✅ <b>Will be replaced</b> (Bị động tương lai). <br>💡 Chủ ngữ 'defective items' (hàng lỗi) được thay thế."},{"id":"n5-45","part":5,"type":"passive","question":"New employees _____ a comprehensive orientation program during their first week.","options":["are given","give","have given","giving"],"answer":0,"explanation":"✅ <b>Are given</b>. <br>💡 Nhân viên mới 'được cấp' chương trình định hướng."},{"id":"n5-46","part":5,"type":"pronoun","question":"The board of directors will announce _____ decision regarding the merger next week.","options":["it","its","those","them"],"answer":1,"explanation":"✅ <b>Its</b>. <br>💡 <i>Mẹo ETS:</i> 'The board of directors' được coi là một tổ chức (số ít) nên dùng tính từ sở hữu 'its'."},{"id":"n5-47","part":5,"type":"pronoun","question":"The seminar participants were asked to introduce _____ at the beginning of the session.","options":["them","they","themselves","theirs"],"answer":2,"explanation":"✅ <b>Themselves</b> (Đại từ phản thân). <br>💡 Dùng khi chủ ngữ và tân ngữ cùng là một đối tượng (người tham gia tự giới thiệu mình)."},{"id":"n5-48","part":5,"type":"pronoun","question":"Each candidate must provide _____ own references from previous employers.","options":["their","them","they","theirs"],"answer":0,"explanation":"✅ <b>Their</b>. <br>💡 <i>Ghi chú:</i> 'Each' thường đi với 'their' (số nhiều trung tính) trong văn phong hiện đại hoặc 'his/her'."},{"id":"n5-49","part":5,"type":"pronoun","question":"The manager spoke highly of _____ assistant's organizational skills during the review.","options":["hers","she","her","herself"],"answer":2,"explanation":"✅ <b>Her</b>. <br>💡 Tính từ sở hữu đứng trước danh từ 'assistant'."},{"id":"n5-50","part":5,"type":"article","question":"Please refer to _____ attached document for details on the reimbursement process.","options":["a","an","the","—"],"answer":2,"explanation":"✅ <b>The</b>. <br>💡 'The attached document' (Tài liệu đính kèm) – đã xác định cụ thể tài liệu nào rồi."},{"id":"n5-51","part":5,"type":"article","question":"Ms. Rivera is _____ expert in supply chain logistics with over 15 years of experience.","options":["a","an","the","—"],"answer":1,"explanation":"✅ <b>An</b>. <br>💡 'An' đứng trước danh từ bắt đầu bằng nguyên âm (expert)."},{"id":"n5-52","part":5,"type":"article","question":"The charity event raised _____ impressive amount for local community programs.","options":["a","an","the","—"],"answer":1,"explanation":"✅ <b>An</b>. <br>💡 'An impressive amount' – 'an' trước tính từ bắt đầu bằng nguyên âm (impressive)."},{"id":"n5-53","part":5,"type":"relative-clause","question":"The candidate _____ submitted the most detailed portfolio was selected for the design position.","options":["whom","whose","which","who"],"answer":3,"explanation":"✅ <b>Who</b>. <br>💡 Đại từ quan hệ thay thế cho người (candidate) làm chủ ngữ trong mệnh đề."},{"id":"n5-54","part":5,"type":"relative-clause","question":"The conference room _____ we held the meeting is no longer available for booking.","options":["who","whose","in which","to whom"],"answer":2,"explanation":"✅ <b>In which</b> (Mà trong đó). <br>💡 'In which' = 'Where', chỉ địa điểm."},{"id":"n5-55","part":5,"type":"relative-clause","question":"The architect _____ design won the national award will speak at our annual gala.","options":["who","whom","whose","which"],"answer":2,"explanation":"✅ <b>Whose</b>. <br>💡 Chỉ sự sở hữu: 'Whose design' (Thiết kế CỦA kiến trúc sư đó)."},{"id":"n5-56","part":5,"type":"modal","question":"Employees _____ submit their expense reports within 30 days of the business trip.","options":["might","could","must","would"],"answer":2,"explanation":"✅ <b>Must</b>. <br>💡 Chỉ sự bắt buộc hoặc quy định của công ty."},{"id":"n5-57","part":5,"type":"modal","question":"You _____ contact the support team directly if you encounter any technical difficulties.","options":["may","ought","should","need"],"answer":2,"explanation":"✅ <b>Should</b>. <br>💡 Lời khuyên hoặc hướng dẫn quy trình."},{"id":"n5-58","part":5,"type":"modal","question":"The new product _____ be released earlier than planned if testing goes well.","options":["must","could","shall","ought"],"answer":1,"explanation":"✅ <b>Could</b>. <br>💡 Diễn tả khả năng có thể xảy ra nhưng không chắc chắn 100%."},{"id":"n5-59","part":5,"type":"gerund-infinitive","question":"The HR department is considering _____ flexible work schedules for all departments.","options":["implement","to implement","implementing","implemented"],"answer":2,"explanation":"✅ <b>Implementing</b>. <br>💡 <i>Cấu trúc:</i> 'Consider + V-ing' (Cân nhắc làm việc gì)."},{"id":"n5-60","part":5,"type":"gerund-infinitive","question":"The manager agreed _____ the deadline by an additional week.","options":["extending","extend","to extend","extended"],"answer":2,"explanation":"✅ <b>To extend</b>. <br>💡 <i>Cấu trúc:</i> 'Agree + to V-inf' (Đồng ý làm việc gì)."},{"id":"n5-61","part":5,"type":"gerund-infinitive","question":"Dr. Kim recommended _____ a second audit to ensure compliance.","options":["conduct","to conduct","conducting","conducted"],"answer":2,"explanation":"✅ <b>Conducting</b>. <br>💡 <i>Cấu trúc:</i> 'Recommend + V-ing' (Khuyên/Đề xuất làm việc gì)."},{"id":"n5-62","part":5,"type":"gerund-infinitive","question":"The board expects all department heads _____ monthly progress reports.","options":["submitting","submit","to submit","submission"],"answer":2,"explanation":"✅ <b>To submit</b>. <br>💡 <i>Cấu trúc:</i> 'Expect someone TO DO something'."},{"id":"n5-63","part":5,"type":"comparison","question":"The updated software runs _____ than the previous version.","options":["fast","faster","fastest","most fast"],"answer":1,"explanation":"✅ <b>Faster</b>. <br>💡 So sánh hơn của tính từ ngắn (fast -> faster)."},{"id":"n5-64","part":5,"type":"comparison","question":"This is _____ complex project the engineering team has ever undertaken.","options":["more","the most","most","the more"],"answer":1,"explanation":"✅ <b>The most</b>. <br>💡 So sánh nhất đi kèm cụm 'ever undertaken' (từng được thực hiện)."},{"id":"n5-65","part":5,"type":"comparison","question":"Renting office space downtown is _____ than operating from the suburbs.","options":["expensively","more expensive","most expensive","expense"],"answer":1,"explanation":"✅ <b>More expensive</b>. <br>💡 So sánh hơn của tính từ dài (more + adjective + than)."},{"id":"n5-66","part":5,"type":"vocabulary","question":"The board meeting was _____ from Thursday to the following Monday to accommodate board members' schedules.","options":["postponed","cancelled","promoted","recorded"],"answer":0,"explanation":"✅ <b>Postponed</b> (Trì hoãn). <br>💡 <i>Sắc thái:</i> 'Postponed' thường đi kèm với thời điểm mới (from... to...). 'Cancelled' là hủy bỏ hoàn toàn."},{"id":"n5-67","part":5,"type":"vocabulary","question":"The company will _____ a new recycling initiative to reduce waste by 40% by year-end.","options":["launch","resign","withdraw","delay"],"answer":0,"explanation":"✅ <b>Launch</b> (Khởi động/Ra mắt). <br>💡 <i>Collocation:</i> 'Launch an initiative/campaign/product' là cụm từ cực kỳ phổ biến trong TOEIC."},{"id":"n5-68","part":5,"type":"vocabulary","question":"The _____ of the client's contract was celebrated with a team dinner.","options":["cancellation","renewal","dismissal","return"],"answer":1,"explanation":"✅ <b>Renewal</b> (Gia hạn). <br>💡 <i>Logics:</i> Việc gia hạn hợp đồng (renewal) là tin mừng nên mới được tổ chức ăn mừng (celebrated)."},{"id":"n5-69","part":5,"type":"vocabulary","question":"The candidate made a very _____ impression during the interview with her industry knowledge.","options":["favorable","defective","negative","brief"],"answer":0,"explanation":"✅ <b>Favorable</b> (Tốt/Có lợi). <br>💡 <i>Collocation:</i> 'Make a favorable impression' (Tạo ấn tượng tốt)."},{"id":"n5-70","part":5,"type":"vocabulary","question":"The IT security team has put _____ measures to prevent unauthorized access to the network.","options":["into effect","in place","under review","on hold"],"answer":1,"explanation":"✅ <b>In place</b>. <br>💡 <i>Cụm cố định:</i> 'Put measures in place' (Thiết lập các biện pháp an ninh)."},{"id":"n5-71","part":5,"type":"vocabulary","question":"Please _____ any changes to the project schedule with your team leader first.","options":["confirm","discuss","impose","demand"],"answer":1,"explanation":"✅ <b>Discuss</b> (Thảo luận). <br>💡 <i>Mẹo ETS:</i> 'Discuss something with someone' là hành động phối hợp công việc chuẩn mực trong văn phòng."},{"id":"n5-72","part":5,"type":"vocabulary","question":"The company's quarterly profit _____ analyst expectations by a significant margin.","options":["exceeded","extended","expanded","exceeded"],"answer":0,"explanation":"✅ <b>Exceeded</b> (Vượt quá). <br>💡 <i>Collocation:</i> 'Exceed expectations' (Vượt quá sự mong đợi)."},{"id":"n5-73","part":5,"type":"vocabulary","question":"The hotel offers _____ rates for guests who book more than three nights in advance.","options":["discounted","increased","standard","final"],"answer":0,"explanation":"✅ <b>Discounted</b> (Đã giảm giá). <br>💡 <i>Ngữ cảnh:</i> Đặt phòng nhiều đêm thường được hưởng 'discounted rates'."},{"id":"n5-74","part":5,"type":"vocabulary","question":"The inspection team was asked to _____ the safety of all equipment before operations resumed.","options":["verify","modify","provide","register"],"answer":0,"explanation":"✅ <b>Verify</b> (Xác minh). <br>💡 'Verify safety' là hành động kiểm tra để đảm bảo mọi thứ an toàn."},{"id":"n5-75","part":5,"type":"vocabulary","question":"All travel expenses must be supported by _____ such as receipts and boarding passes.","options":["documentation","subscription","reference","revision"],"answer":0,"explanation":"✅ <b>Documentation</b> (Chứng từ/Tài liệu giấy tờ). <br>💡 <i>Ghi nhớ:</i> Receipts (hóa đơn) là một loại 'documentation'."},{"id":"n5-76","part":5,"type":"word-form","question":"The product's _____ has improved significantly following the feedback from the pilot launch.","options":["perform","performance","performing","performer"],"answer":1,"explanation":"✅ <b>Performance</b> (Hiệu suất). <br>💡 Đứng sau sở hữu cách ('s) cần một danh từ."},{"id":"n5-77","part":5,"type":"preposition","question":"The updated guidelines are _____ effect as of January 1.","options":["on","in","at","by"],"answer":1,"explanation":"✅ <b>In</b>. <br>💡 <i>Cụm cố định:</i> 'In effect' (Có hiệu lực)."},{"id":"n5-78","part":5,"type":"conjunction","question":"The company has expanded significantly _____ it was founded just five years ago.","options":["although","since","because","so"],"answer":1,"explanation":"✅ <b>Since</b> (Kể từ khi). <br>💡 Dấu hiệu của thì Hiện tại hoàn thành (has expanded)."},{"id":"n5-79","part":5,"type":"passive","question":"A new employee handbook _____ to all new hires at the beginning of their orientation.","options":["is providing","will be provided","provides","was providing"],"answer":1,"explanation":"✅ <b>Will be provided</b> (Sẽ được cung cấp). <br>💡 <i>Ngữ cảnh:</i> Thông báo về một việc sẽ diễn ra tại orientation."},{"id":"n5-80","part":5,"type":"word-form","question":"The decision to outsource customer service was made after _____ consideration of the costs and benefits.","options":["care","careful","carefully","carefulness"],"answer":1,"explanation":"✅ <b>Careful</b>. <br>💡 Vị trí tính từ đứng trước danh từ 'consideration'."},{"id":"n5-81","part":5,"type":"verb-tense","question":"The annual shareholders meeting _____ place every June at the main headquarters.","options":["took","takes","has taken","is taking"],"answer":1,"explanation":"✅ <b>Takes</b>. <br>💡 <i>Thói quen/Lịch trình:</i> Dùng Hiện tại đơn với 'every June'."},{"id":"n5-82","part":5,"type":"conjunction","question":"All employees must wear their ID badges _____ they enter or exit the building.","options":["whenever","wherever","whatever","whoever"],"answer":0,"explanation":"✅ <b>Whenever</b> (Bất cứ khi nào). <br>💡 Liên từ chỉ thời gian lặp lại."},{"id":"n5-83","part":5,"type":"preposition","question":"The software automatically generates reports _____ a weekly basis.","options":["in","on","at","by"],"answer":1,"explanation":"✅ <b>On</b>. <br>💡 <i>Cụm cố định:</i> 'On a [weekly/daily] basis' (Đều đặn hàng [tuần/ngày])."},{"id":"n5-84","part":5,"type":"word-form","question":"The team's _____ approach to problem-solving has earned them recognition company-wide.","options":["innovate","innovation","innovative","innovatively"],"answer":2,"explanation":"✅ <b>Innovative</b> (Sáng tạo). <br>💡 Tính từ bổ nghĩa cho danh từ 'approach'."},{"id":"n5-85","part":5,"type":"vocabulary","question":"The new branch will _____ its doors to customers next month on its grand opening day.","options":["open","close","lock","remove"],"answer":0,"explanation":"✅ <b>Open</b>. <br>💡 <i>Idiom kinh doanh:</i> 'Open its doors' (Bắt đầu mở cửa kinh doanh)."},{"id":"n5-86","part":5,"type":"preposition","question":"The results of the market research were _____ expectations, showing strong consumer interest.","options":["below","over","beyond","against"],"answer":2,"explanation":"✅ <b>Beyond</b>. <br>💡 <i>Cụm cố định:</i> 'Beyond expectations' (Vượt ngoài mong đợi)."},{"id":"n5-87","part":5,"type":"gerund-infinitive","question":"The manager avoided _____ any assumptions without reviewing all of the data first.","options":["make","to make","making","made"],"answer":2,"explanation":"✅ <b>Making</b>. <br>💡 <i>Cấu trúc:</i> 'Avoid + V-ing' (Tránh làm gì)."},{"id":"n5-88","part":5,"type":"modal","question":"Visitors _____ sign in at the reception desk before proceeding to any office.","options":["could","may","must","would"],"answer":2,"explanation":"✅ <b>Must</b>. <br>💡 Chỉ quy định bắt buộc (obligation)."},{"id":"n5-89","part":5,"type":"conjunction","question":"The conference has been sold out every year _____ it was first held in 2018.","options":["when","until","since","while"],"answer":2,"explanation":"✅ <b>Since</b> (Kể từ khi). <br>💡 Dùng với Hiện tại hoàn thành 'has been sold out'."},{"id":"n5-90","part":5,"type":"word-form","question":"The _____ layout of the new office space was designed to promote collaboration.","options":["open-plan","opens-plan","openly-plan","open-planning"],"answer":0,"explanation":"✅ <b>Open-plan</b>. <br>💡 <i>Từ vựng chuyên ngành:</i> 'Open-plan layout' (Bố cục không gian mở)."},{"id":"n5-91","part":5,"type":"vocabulary","question":"The manager asked the team to _____ their project timelines to reflect recent changes in scope.","options":["revise","remove","request","respond"],"answer":0,"explanation":"✅ <b>Revise</b> (Sửa đổi/Điều chỉnh). <br>💡 Dùng khi cập nhật lại kế hoạch hoặc tài liệu."},{"id":"n5-92","part":5,"type":"preposition","question":"The training session is scheduled _____ 9:00 a.m. on the second floor.","options":["on","at","in","by"],"answer":1,"explanation":"✅ <b>At</b>. <br>💡 'At' dùng cho thời gian cụ thể."},{"id":"n5-93","part":5,"type":"relative-clause","question":"The technician _____ repaired the printer also updated the firmware.","options":["which","whose","whom","who"],"answer":3,"explanation":"✅ <b>Who</b>. <br>💡 Đại từ quan hệ thay thế cho người (technician)."},{"id":"n5-94","part":5,"type":"conjunction","question":"The new software is user-friendly, _____ all staff members are expected to learn it quickly.","options":["so","yet","but","nor"],"answer":0,"explanation":"✅ <b>So</b> (Vì vậy). <br>💡 Chỉ kết quả."},{"id":"n5-95","part":5,"type":"passive","question":"The agenda for the annual general meeting _____ out to all shareholders last week.","options":["sent","was sent","sends","will send"],"answer":1,"explanation":"✅ <b>Was sent</b> (Bị động quá khứ). <br>💡 Agenda (chương trình họp) 'được gửi' đi."},{"id":"n5-96","part":5,"type":"word-form","question":"The job posting attracted over 300 _____ within the first 48 hours.","options":["apply","applicants","applied","applicable"],"answer":1,"explanation":"✅ <b>Applicants</b> (Người nộp đơn). <br>💡 'Over 300' cần một danh từ số nhiều chỉ người."},{"id":"n5-97","part":5,"type":"conjunction","question":"The proposal was rejected _____ it failed to meet the minimum budget requirements.","options":["despite","in case","because","although"],"answer":2,"explanation":"✅ <b>Because</b>. <br>💡 Giải thích lý do bị từ chối."},{"id":"n5-98","part":5,"type":"preposition","question":"Our products are available _____ both online and in-store retail locations.","options":["by","through","of","with"],"answer":1,"explanation":"✅ <b>Through</b>. <br>💡 <i>Sắc thái:</i> 'Available through' chỉ kênh phân phối hàng hóa."},{"id":"n5-99","part":5,"type":"vocabulary","question":"The director expressed her _____ for the team's outstanding work on the campaign.","options":["appreciation","application","assumption","attention"],"answer":0,"explanation":"✅ <b>Appreciation</b> (Sự trân trọng/biết ơn). <br>💡 <i>Mẹo ETS:</i> 'Express appreciation to/for' là mẫu câu khen ngợi nhân sự."},{"id":"n5-100","part":5,"type":"word-form","question":"The board of directors must ensure full _____ with the new financial reporting standards.","options":["comply","compliant","compliance","complying"],"answer":2,"explanation":"✅ <b>Compliance</b> (Sự tuân thủ). <br>💡 'Ensure full compliance with' là cụm từ chuẩn mực pháp lý doanh nghiệp."},{"id":"b5-01","part":5,"type":"vocabulary","question":"The company's _____ to digital transformation was accelerated by the recent global shifts in consumer behavior.","options":["transition","transmission","transaction","translation"],"answer":0,"explanation":"'Transition' (sự chuyển đổi) là thuật ngữ chuẩn cho digital transformation. Các từ khác tuy bắt đầu bằng 'trans' nhưng nghĩa hoàn toàn khác biệt."},{"id":"b5-02","part":5,"type":"vocabulary","question":"Team leaders must _____ the performance of their subordinates on a semi-annual basis.","options":["assess","access","assert","assist"],"answer":0,"explanation":"'Assess' (đánh giá) là sắc thái chuẩn cho việc kiểm tra năng lực. 'Access' (truy cập) là từ gây nhầm lẫn về mặt chữ viết (distractor)."},{"id":"b5-03","part":5,"type":"vocabulary","question":"The board of directors _____ the proposal for the new merger after extensive deliberation.","options":["endorsed","enforced","engaged","enlarged"],"answer":0,"explanation":"'Endorsed' (tán thành/chấp thuận) là sắc thái formal nhất trong Board meeting. 'Enforced' (ép buộc) quá mạnh."},{"id":"b5-04","part":5,"type":"vocabulary","question":"The updated safety manual provides _____ instructions on how to handle hazardous materials.","options":["explicit","exclusive","extreme","external"],"answer":0,"explanation":"'Explicit instructions' (hướng dẫn rõ ràng/chi tiết). Đây là cặp từ thường gặp trong các đề thi ETS mới."},{"id":"b5-05","part":5,"type":"vocabulary","question":"To _____ the growing demand for hybrid work, the company is renovating its downtown office space.","options":["accommodate","accumulate","accomplish","accompany"],"answer":0,"explanation":"'Accommodate demand/need' (đáp ứng nhu cầu). Collocation cực kỳ phổ biến."},{"id":"b5-06","part":5,"type":"vocabulary","question":"The marketing team's _____ of the latest market trends led to a highly successful campaign.","options":["interpretation","interaction","interference","interruption"],"answer":0,"explanation":"'Interpretation' (sự diễn giải/hiểu) các xu hướng thị trường là chìa khóa thành công."},{"id":"b5-07","part":5,"type":"vocabulary","question":"The CEO emphasized that _____ communication between departments is essential for project success.","options":["transparent","transferable","transient","translucent"],"answer":0,"explanation":"'Transparent communication' (giao tiếp minh bạch) là cụm từ 'nuance' rất hot trong ETS 2024-2025."},{"id":"b5-08","part":5,"type":"vocabulary","question":"The research findings offer _____ evidence that the proposed changes will improve overall productivity.","options":["compelling","competing","complying","completing"],"answer":0,"explanation":"'Compelling evidence' (bằng chứng thuyết phục). Distractors là các tính từ có hậu tố -ing gây nhầm lẫn."},{"id":"b5-09","part":5,"type":"vocabulary","question":"Managers are encouraged to _____ regular feedback from their team members to identify areas for improvement.","options":["solicit","solidify","solace","soldier"],"answer":0,"explanation":"'Solicit feedback' (thu thập/kêu gọi phản hồi) là thuật ngữ formal trong quản trị."},{"id":"b5-10","part":5,"type":"vocabulary","question":"The _____ of new technology has significantly streamlined our logistics operations.","options":["implementation","implication","imposter","improvisation"],"answer":0,"explanation":"'Implementation' (việc triển khai) công nghệ mới. 'Implication' (hệ quả) cũng có nghĩa nhưng không phù hợp sắc thái chủ động bằng."},{"id":"b5-11","part":5,"type":"word-form","question":"Investors were pleased with the _____ results posted by the company this quarter.","options":["exceptional","exception","exceptionally","except"],"answer":0,"explanation":"Tính từ 'exceptional' đứng trước danh từ 'results'."},{"id":"b5-12","part":5,"type":"word-form","question":"The new assistant proved to be highly _____ in managing the director's schedule.","options":["capable","capability","capably","capacitate"],"answer":0,"explanation":"Tính từ 'capable' dùng sau linking verb 'proved to be'. 'Capably' là phó từ."},{"id":"b5-13","part":5,"type":"word-form","question":"A formal _____ of the contract will be made at the signing ceremony next week.","options":["announce","announcement","announced","announcing"],"answer":1,"explanation":"Sau mạo từ 'A formal' cần danh từ. 'Announcement' = thông báo chính thức."},{"id":"b5-14","part":5,"type":"word-form","question":"The board has _____ authorized the release of funds for the new infrastructure project.","options":["formal","formality","formally","formalize"],"answer":2,"explanation":"Phó từ 'formally' bổ nghĩa cho động từ 'authorized'."},{"id":"b5-15","part":5,"type":"word-form","question":"The _____ of qualified candidates makes the hiring decision particularly difficult.","options":["scarce","scarcely","scarcity","scare"],"answer":2,"explanation":"Sau 'The' cần danh từ chủ ngữ. 'Scarcity' = sự khan hiếm."},{"id":"b5-16","part":5,"type":"verb-tense","question":"By the end of this fiscal year, the company _____ operations in twelve countries.","options":["establishes","established","will establish","will have established"],"answer":3,"explanation":"'By the end of this fiscal year' → future perfect 'will have established'."},{"id":"b5-17","part":5,"type":"verb-tense","question":"The CEO _____ the board of directors every quarter to review financial performance.","options":["briefed","briefs","has briefed","will brief"],"answer":1,"explanation":"Lịch trình định kỳ → hiện tại đơn 'briefs'."},{"id":"b5-18","part":5,"type":"verb-tense","question":"We _____ the new inventory system for six months before the technical issues emerged.","options":["use","used","had been using","will use"],"answer":2,"explanation":"Hành động diễn ra trước sự kiện quá khứ → past perfect continuous 'had been using'."},{"id":"b5-19","part":5,"type":"verb-tense","question":"The HR team _____ the updated employee handbook to all new hires since last month.","options":["distributes","distributed","has been distributing","will distribute"],"answer":2,"explanation":"'Since last month' với hành động còn tiếp diễn → present perfect continuous."},{"id":"b5-20","part":5,"type":"verb-tense","question":"The client _____ a detailed proposal before making any final decisions.","options":["requests","requested","will request","has requested"],"answer":0,"explanation":"Chính sách/yêu cầu thường xuyên → hiện tại đơn 'requests'."},{"id":"b5-21","part":5,"type":"verb-tense","question":"Several employees _____ concerns about the proposed policy changes at yesterday's town hall.","options":["raise","raised","have raised","will raise"],"answer":1,"explanation":"'Yesterday' → quá khứ đơn 'raised'."},{"id":"b5-22","part":5,"type":"verb-tense","question":"The supply chain _____ significantly since new technology was adopted two years ago.","options":["improves","improved","has improved","will improve"],"answer":2,"explanation":"'Since + past event' → present perfect 'has improved'."},{"id":"b5-23","part":5,"type":"verb-tense","question":"Dr. Patel _____ a keynote speech at the international symposium last November.","options":["delivers","will deliver","has delivered","delivered"],"answer":3,"explanation":"'Last November' → quá khứ đơn 'delivered'."},{"id":"b5-24","part":5,"type":"verb-tense","question":"Before the merger _____, both companies had operated independently for decades.","options":["occurs","occurred","will occur","has occurred"],"answer":1,"explanation":"Mệnh đề thời gian quá khứ (before + past simple) kết hợp với past perfect 'had operated'."},{"id":"b5-25","part":5,"type":"verb-tense","question":"Our customer support center _____ around the clock to assist clients worldwide.","options":["operated","operates","has operated","will have operated"],"answer":1,"explanation":"Sự thật về hoạt động hiện tại, liên tục → hiện tại đơn 'operates'."},{"id":"b5-26","part":5,"type":"preposition","question":"The new product was developed _____ response to customer demand for eco-friendly packaging.","options":["with","on","in","by"],"answer":2,"explanation":"'In response to' = để đáp lại (cụm giới từ cố định)."},{"id":"b5-27","part":5,"type":"preposition","question":"Please CC the department manager _____ any email regarding the project timeline.","options":["on","in","at","for"],"answer":0,"explanation":"'CC someone on an email' = đưa ai vào CC của email (cụm cố định)."},{"id":"b5-28","part":5,"type":"preposition","question":"The conference will take place _____ three consecutive days starting Monday.","options":["in","for","over","during"],"answer":2,"explanation":"'Over three consecutive days' = kéo dài trong ba ngày liên tiếp."},{"id":"b5-29","part":5,"type":"preposition","question":"The internship program is open _____ students who are currently enrolled in a university.","options":["for","to","of","with"],"answer":1,"explanation":"'Open to' = mở cửa cho, dành cho (cụm cố định)."},{"id":"b5-30","part":5,"type":"preposition","question":"The renovation project is expected to be completed _____ schedule this autumn.","options":["on","in","to","by"],"answer":0,"explanation":"'On schedule' = đúng tiến độ (cụm cố định)."},{"id":"b5-31","part":5,"type":"preposition","question":"All invoices must be reviewed _____ the finance team prior to final approval.","options":["to","by","of","with"],"answer":1,"explanation":"'Reviewed by' = được xem xét bởi (tác nhân trong câu bị động)."},{"id":"b5-32","part":5,"type":"preposition","question":"The new policy is _____ line with the company's long-term sustainability goals.","options":["in","on","at","by"],"answer":0,"explanation":"'In line with' = phù hợp với, nhất quán với (cụm giới từ cố định)."},{"id":"b5-33","part":5,"type":"preposition","question":"The company has been operating _____ a loss for the past two quarters.","options":["at","in","on","with"],"answer":0,"explanation":"'Operating at a loss' = hoạt động thua lỗ (collocation cố định)."},{"id":"b5-34","part":5,"type":"preposition","question":"The training program is designed to equip employees _____ the skills needed for digital transformation.","options":["by","on","with","for"],"answer":2,"explanation":"'Equip someone with skills' = trang bị cho ai kỹ năng (cụm cố định)."},{"id":"b5-35","part":5,"type":"preposition","question":"Applications submitted _____ the posted deadline will not be considered for this intake.","options":["before","after","within","during"],"answer":1,"explanation":"'After the deadline' = sau hạn chót → bị loại. Phù hợp nhất với ngữ nghĩa."},{"id":"b5-36","part":5,"type":"conjunction","question":"The team managed to complete the project _____ losing two key members mid-way through.","options":["despite","without","even though","regardless"],"answer":1,"explanation":"'Without + V-ing' = mà không. 'Without losing' = mà không mất. 'Despite' cần danh từ hay gerund phrase."},{"id":"b5-37","part":5,"type":"conjunction","question":"_____ the product received positive reviews, sales figures remained below expectations.","options":["Since","While","Although","Because"],"answer":2,"explanation":"'Although' = mặc dù. Tương phản giữa review tốt và doanh số thấp."},{"id":"b5-38","part":5,"type":"conjunction","question":"The company will expand _____ market conditions remain favorable.","options":["unless","as long as","even though","in case"],"answer":1,"explanation":"'As long as' = miễn là/chừng nào còn. Điều kiện để mở rộng."},{"id":"b5-39","part":5,"type":"conjunction","question":"Production was halted; _____, engineers worked overnight to resolve the malfunction.","options":["however","moreover","therefore","meanwhile"],"answer":3,"explanation":"'Meanwhile' = trong thời gian đó (hai việc xảy ra song song)."},{"id":"b5-40","part":5,"type":"conjunction","question":"The manager confirmed the venue _____ all participants could finalize their travel plans.","options":["so that","in order","for","because"],"answer":0,"explanation":"'So that' = để cho, nhằm mục đích. Mục đích xác nhận địa điểm."},{"id":"b5-41","part":5,"type":"conjunction","question":"_____ the training is mandatory, employees who miss it must attend a makeup session.","options":["Since","Until","Whether","While"],"answer":0,"explanation":"'Since' = vì (nguyên nhân). Vì buổi đào tạo bắt buộc → phải tham dự bù."},{"id":"b5-42","part":5,"type":"conjunction","question":"The proposal was strong; _____, the committee requested several revisions.","options":["otherwise","nonetheless","accordingly","likewise"],"answer":1,"explanation":"'Nonetheless' = tuy nhiên, dù vậy. Đề xuất mạnh NHƯNG ủy ban vẫn yêu cầu sửa đổi."},{"id":"b5-43","part":5,"type":"conjunction","question":"Employees are encouraged to submit feedback _____ they have concerns about the new workflow.","options":["whenever","wherever","however","whoever"],"answer":0,"explanation":"'Whenever' = bất cứ khi nào. Gửi phản hồi khi nào có lo ngại."},{"id":"b5-44","part":5,"type":"passive","question":"The quarterly budget report _____ to all department heads by the end of this week.","options":["will circulate","circulates","will be circulated","has circulating"],"answer":2,"explanation":"Bị động tương lai 'will be circulated'. Báo cáo được lưu hành (bởi finance team)."},{"id":"b5-45","part":5,"type":"passive","question":"All candidates who applied for the position _____ by phone within two weeks.","options":["will contact","will be contacted","are contacting","have contacted"],"answer":1,"explanation":"Bị động 'will be contacted'. Ứng viên được liên hệ (bởi HR)."},{"id":"b5-46","part":5,"type":"passive","question":"The conference room bookings _____ through the company intranet.","options":["manage","are managed","managing","have managed"],"answer":1,"explanation":"Bị động hiện tại đơn 'are managed'. Việc đặt phòng được quản lý qua intranet."},{"id":"b5-47","part":5,"type":"passive","question":"The CEO _____ with honorary membership by the Chamber of Commerce last year.","options":["presented","was presented","has presented","is presenting"],"answer":1,"explanation":"'Was presented with' = được trao tặng (quá khứ bị động). 'Last year' xác định thì."},{"id":"b5-48","part":5,"type":"passive","question":"All software updates _____ automatically unless the user disables the feature.","options":["install","are installed","installing","have installed"],"answer":1,"explanation":"Bị động hiện tại đơn 'are installed'. Cập nhật được cài đặt tự động."},{"id":"b5-49","part":5,"type":"passive","question":"The safety inspection results _____ to local authorities within 48 hours of completion.","options":["must submit","must be submitted","must submitting","must have submitted"],"answer":1,"explanation":"Modal + be + V3 (bị động). 'Must be submitted' = phải được nộp."},{"id":"b5-50","part":5,"type":"passive","question":"Customers _____ that their personal data will never be shared with third parties.","options":["assure","are assured","assuring","have assuring"],"answer":1,"explanation":"Bị động 'are assured' = được đảm bảo. Khách hàng nhận sự đảm bảo từ công ty."},{"id":"b5-51","part":5,"type":"vocabulary","question":"The board _____ a decision to freeze all new hires until the financial review is complete.","options":["made","took","did","had"],"answer":0,"explanation":"'Make a decision' = ra quyết định (collocation chuẩn nhất)."},{"id":"b5-52","part":5,"type":"vocabulary","question":"Our legal team is currently _____ the contract to ensure all clauses are compliant.","options":["reviewing","revising","rescinding","reissuing"],"answer":0,"explanation":"'Reviewing a contract' = xem xét hợp đồng (để kiểm tra tuân thủ)."},{"id":"b5-53","part":5,"type":"vocabulary","question":"The event was a tremendous _____, attracting over 3,000 visitors on opening day.","options":["triumph","success","victory","achievement"],"answer":1,"explanation":"'Success' là từ phổ biến nhất trong ngữ cảnh sự kiện thương mại. 'Triumph/victory' thiên về cạnh tranh."},{"id":"b5-54","part":5,"type":"vocabulary","question":"Employees are _____ to report any suspicious activity to the security department immediately.","options":["encouraged","urged","required","advised"],"answer":2,"explanation":"'Required' = bắt buộc. Câu dùng 'immediately' và ngữ cảnh an ninh → bắt buộc nhất."},{"id":"b5-55","part":5,"type":"vocabulary","question":"The new pricing structure will _____ effect on the first day of the next billing cycle.","options":["fall into","go into","take","put into"],"answer":2,"explanation":"'Take effect' = có hiệu lực (collocation cố định duy nhất đúng). 'Fall into effect', 'go into effect', 'put into effect' không phải cụm từ chuẩn trong ngữ cảnh này."},{"id":"b5-56","part":5,"type":"vocabulary","question":"The conference attracted a _____ audience of professionals from over 40 countries.","options":["diverse","broad","mixed","various"],"answer":0,"explanation":"'Diverse audience' = khán giả đa dạng (về quốc tịch/nền tảng). Collocation tự nhiên nhất."},{"id":"b5-57","part":5,"type":"vocabulary","question":"The CEO _____ responsibility for the accounting error and issued a public apology.","options":["accepted","admitted","acknowledged","assumed"],"answer":0,"explanation":"'Accept responsibility' = nhận trách nhiệm (collocation cố định trong TOEIC)."},{"id":"b5-58","part":5,"type":"vocabulary","question":"The new employee orientation program is _____ to help new hires integrate quickly.","options":["intended","designed","aimed","meant"],"answer":1,"explanation":"'Designed to' = được thiết kế để (phổ biến nhất khi nói về mục đích của chương trình/sản phẩm)."},{"id":"b5-59","part":5,"type":"vocabulary","question":"We _____ our sincere apologies for the inconvenience caused by the service disruption.","options":["offer","give","make","extend"],"answer":3,"explanation":"'Extend our sincere apologies' = gửi lời xin lỗi chân thành (formal collocation trong thư xin lỗi)."},{"id":"b5-60","part":5,"type":"vocabulary","question":"The sales data _____ a clear upward trend over the past three consecutive quarters.","options":["reveals","shows","indicates","demonstrates"],"answer":2,"explanation":"'Data indicates a trend' = dữ liệu cho thấy xu hướng. 'Indicate' phổ biến nhất với statistical data trong TOEIC."},{"id":"c5-01","part":5,"type":"word-form","question":"The committee expressed its _____ with the vendor's lack of transparency during the audit.","options":["disappoint","disappointed","disappointing","disappointment"],"answer":3,"explanation":"Sau possessive 'its' cần danh từ. 'Disappointment' = sự thất vọng."},{"id":"c5-02","part":5,"type":"word-form","question":"Staff are _____ reminded that personal use of company devices is strictly prohibited.","options":["frequent","frequency","frequently","frequented"],"answer":2,"explanation":"Phó từ 'frequently' bổ nghĩa cho động từ bị động 'are reminded'."},{"id":"c5-03","part":5,"type":"word-form","question":"The firm's rapid _____ into Southeast Asian markets caught many industry analysts by surprise.","options":["expand","expanding","expansive","expansion"],"answer":3,"explanation":"Sau possessive 'firm's' cần danh từ. 'Expansion' = sự mở rộng."},{"id":"c5-04","part":5,"type":"word-form","question":"The revised onboarding procedure proved far more _____ than the previous one.","options":["effect","effectively","effective","effectiveness"],"answer":2,"explanation":"Sau linking verb 'proved more' cần tính từ. 'Effective' = hiệu quả."},{"id":"c5-05","part":5,"type":"word-form","question":"All participants must sign a _____ agreement before accessing the confidential data room.","options":["confide","confidential","confidentiality","confidently"],"answer":2,"explanation":"Tính từ 'confidentiality' không phù hợp vị trí trước N. 'Confidential' là tính từ bổ nghĩa cho 'agreement'."},{"id":"c5-06","part":5,"type":"word-form","question":"The CEO praised the team for its _____ approach to resolving the supply chain disruption.","options":["innovate","innovative","innovation","innovatively"],"answer":1,"explanation":"Tính từ 'innovative' đứng trước danh từ 'approach'."},{"id":"c5-07","part":5,"type":"word-form","question":"The _____ of the new production facility is scheduled to begin next spring.","options":["construct","constructive","construction","constructing"],"answer":2,"explanation":"Sau 'The' cần danh từ chủ ngữ. 'Construction' = việc xây dựng."},{"id":"c5-08","part":5,"type":"word-form","question":"Ms. Vo's _____ performance throughout the quarter earned her a well-deserved promotion.","options":["consist","consistent","consistency","consistently"],"answer":1,"explanation":"Tính từ 'consistent' đứng trước danh từ 'performance'. 'Consistently' là phó từ."},{"id":"c5-09","part":5,"type":"verb-tense","question":"The factory _____ its new automated line for just three weeks when the first quality issue arose.","options":["operated","has operated","had been operating","was operating"],"answer":2,"explanation":"Hành động diễn ra liên tục trước một sự kiện quá khứ → past perfect continuous 'had been operating'."},{"id":"c5-10","part":5,"type":"verb-tense","question":"By the time the audit team _____ its findings, the board will have already convened an emergency session.","options":["publishes","published","will publish","will have published"],"answer":0,"explanation":"Mệnh đề 'by the time' + present simple → main clause dùng future perfect. 'publishes' đúng cho mệnh đề thời gian."},{"id":"c5-11","part":5,"type":"verb-tense","question":"The logistics coordinator _____ the shipment status when the warehouse called with an urgent update.","options":["tracks","tracked","was tracking","has tracked"],"answer":2,"explanation":"Hành động đang diễn ra bị gián đoạn → past continuous 'was tracking'."},{"id":"c5-12","part":5,"type":"verb-tense","question":"Demand for our premium subscription tier _____ steadily over the past eighteen months.","options":["grows","grew","has grown","is growing"],"answer":2,"explanation":"'Over the past eighteen months' → present perfect 'has grown'."},{"id":"c5-13","part":5,"type":"verb-tense","question":"The head of procurement _____ three vendors before selecting Apex Supplies as the preferred partner.","options":["contacts","has contacted","contacted","had contacted"],"answer":3,"explanation":"Hành động hoàn tất trước hành động quá khứ 'selecting' → past perfect 'had contacted'."},{"id":"c5-14","part":5,"type":"verb-tense","question":"The engineering team _____ the prototype every Tuesday afternoon to monitor its performance.","options":["tests","tested","has tested","will have tested"],"answer":0,"explanation":"Lịch định kỳ 'every Tuesday afternoon' → hiện tại đơn 'tests'."},{"id":"c5-15","part":5,"type":"verb-tense","question":"Unless the client _____ the revised quotation by Thursday, the project timeline will need to be adjusted.","options":["approves","will approve","approved","has approved"],"answer":0,"explanation":"Mệnh đề 'unless' (= điều kiện) KHÔNG dùng will → hiện tại đơn 'approves'."},{"id":"c5-16","part":5,"type":"preposition","question":"The merger was completed _____ schedule, two months ahead of the original target date.","options":["on","ahead of","before","in"],"answer":1,"explanation":"'Completed ahead of schedule' = hoàn thành sớm hơn dự kiến. Vì phần sau ghi 'two months ahead' nên 'ahead of' là lựa chọn chính xác."},{"id":"c5-17","part":5,"type":"preposition","question":"The final decision rests _____ the steering committee, not the department heads.","options":["with","on","in","for"],"answer":0,"explanation":"'The decision rests with' = quyết định thuộc về (ai đó có thẩm quyền)."},{"id":"c5-18","part":5,"type":"preposition","question":"Employees are encouraged to voice concerns _____ going through the anonymous feedback portal.","options":["by","with","from","about"],"answer":0,"explanation":"'By + V-ing' = bằng cách. 'By going through the portal' = bằng cách sử dụng cổng phản hồi."},{"id":"c5-19","part":5,"type":"conjunction","question":"The new safety training is mandatory; _____, online completion is now accepted as an alternative to classroom attendance.","options":["however","therefore","nevertheless","moreover"],"answer":3,"explanation":"'Moreover' = hơn nữa, bổ sung thêm. Thêm thông tin về sự linh hoạt của chương trình bắt buộc."},{"id":"c5-20","part":5,"type":"conjunction","question":"_____ experienced in project management, Mr. Reeves found the new software system challenging to navigate.","options":["Despite being","Even though","Although","While"],"answer":0,"explanation":"'Despite being + adj' = dù dày dạn kinh nghiệm (despite + gerund phrase). Các đáp án còn lại cần mệnh đề (S+V)."},{"id":"c5-21","part":5,"type":"preposition","question":"The product recall was carried out _____ precaution after a small number of units showed defects.","options":["as a","for a","with a","by a"],"answer":0,"explanation":"'As a precaution' = như một biện pháp phòng ngừa (cụm giới từ cố định)."},{"id":"c5-22","part":5,"type":"conjunction","question":"The engineering team worked through the weekend _____ the prototype could be ready in time for the client demo.","options":["so that","because","although","unless"],"answer":0,"explanation":"'So that' = để cho (mục đích). Mục đích làm thêm cuối tuần."},{"id":"c5-23","part":5,"type":"preposition","question":"The revised guidelines will take effect _____ January 1 of the upcoming fiscal year.","options":["on","as of","by","until"],"answer":1,"explanation":"'As of January 1' = kể từ ngày 1 tháng 1 (thời điểm bắt đầu hiệu lực). 'On' chỉ đúng thời điểm cụ thể, 'as of' nhấn mạnh khởi đầu hiệu lực."},{"id":"c5-24","part":5,"type":"passive","question":"New staff members _____ a comprehensive orientation session during their first week.","options":["give","are given","giving","have giving"],"answer":1,"explanation":"Bị động hiện tại đơn 'are given'. Nhân viên được cấp phát/tham dự (orientation = tân ngữ gián tiếp)."},{"id":"c5-25","part":5,"type":"passive","question":"All meeting minutes _____ and distributed to participants within 24 hours of the session.","options":["will compile","will be compiled","are compiling","have compiled"],"answer":1,"explanation":"Bị động tương lai 'will be compiled'. Biên bản được tổng hợp và phân phát."},{"id":"c5-26","part":5,"type":"vocabulary","question":"The finance director asked staff to _____ unnecessary expenses in light of the budget shortfall.","options":["reduce","eliminate","minimize","curtail"],"answer":3,"explanation":"'Curtail unnecessary expenses' = cắt giảm chi phí không cần thiết (formal, phổ biến trong TOEIC financial context)."},{"id":"c5-27","part":5,"type":"vocabulary","question":"The partnership agreement was _____ after both parties failed to reach a compromise.","options":["terminated","cancelled","finished","stopped"],"answer":0,"explanation":"'Terminated' = chấm dứt hợp đồng/thỏa thuận một cách chính thức. Thuật ngữ chuẩn trong văn bản pháp lý."},{"id":"c5-28","part":5,"type":"vocabulary","question":"All candidates are _____ to bring two forms of identification to the interview.","options":["told","reminded","requested","asked"],"answer":2,"explanation":"'Requested to bring' = được yêu cầu mang theo (formal, phổ biến trong thông báo tuyển dụng)."},{"id":"c5-29","part":5,"type":"vocabulary","question":"The engineering team _____ several alternative designs before settling on the final prototype.","options":["assessed","evaluated","considered","reviewed"],"answer":1,"explanation":"'Evaluated alternative designs' = đánh giá các phương án thay thế (kỹ thuật). 'Evaluate' = phân tích có hệ thống."},{"id":"c5-30","part":5,"type":"vocabulary","question":"The spokesperson _____ that the company remains committed to its zero-emission targets.","options":["said","told","confirmed","mentioned"],"answer":2,"explanation":"'Confirmed that' = xác nhận rằng. Nhấn mạnh sự cam kết, chính thức hơn 'said'. 'Told' cần tân ngữ người."},{"id":"g5-01","part":5,"type":"word-form","question":"The _____ of the new software platform has been praised for its clean, intuitive interface.","options":["design","designer","designate","designedly"],"answer":0,"explanation":"'The design of the platform' = thiết kế. Danh từ làm chủ ngữ sau 'The'."},{"id":"g5-02","part":5,"type":"word-form","question":"All participants are _____ reminded to register at the welcome desk upon arrival.","options":["kind","kindness","kindly","kinder"],"answer":2,"explanation":"Phó từ 'kindly' dùng trong yêu cầu lịch sự ('kindly reminded' = kính nhờ). Bổ nghĩa cho 'are reminded'."},{"id":"g5-03","part":5,"type":"word-form","question":"The committee found the auditor's report _____ thorough and above reproach.","options":["exception","except","exceptionally","exceptional"],"answer":2,"explanation":"Phó từ 'exceptionally' bổ nghĩa cho tính từ 'thorough'."},{"id":"g5-04","part":5,"type":"word-form","question":"A _____ review of the supplier contracts revealed several clauses that required updating.","options":["comprehend","comprehensive","comprehension","comprehensively"],"answer":1,"explanation":"Tính từ 'comprehensive' (toàn diện) đứng trước danh từ 'review'."},{"id":"g5-05","part":5,"type":"word-form","question":"The board expressed its full _____ for the CEO's restructuring plan at last week's meeting.","options":["supported","supporting","supportive","support"],"answer":3,"explanation":"'Its full support' = sự ủng hộ hoàn toàn. Danh từ sau sở hữu 'its full'."},{"id":"g5-06","part":5,"type":"word-form","question":"The _____ of the warehouse makes it ideal for companies requiring large-scale cold storage.","options":["spatially","spacious","spaciousness","space"],"answer":2,"explanation":"Danh từ trừu tượng 'spaciousness' = tính rộng lớn, phù hợp sau 'The'."},{"id":"g5-07","part":5,"type":"word-form","question":"Our product packaging is _____ to ensure that it meets the highest environmental standards.","options":["certificate","certified","certification","certify"],"answer":1,"explanation":"Tính từ bị động 'certified' = được chứng nhận. Bổ nghĩa qua 'is certified'."},{"id":"g5-08","part":5,"type":"word-form","question":"Staff are encouraged to act _____ when they notice potential safety hazards in the workplace.","options":["proactive","proactively","proactiveness","proactivate"],"answer":1,"explanation":"Phó từ 'proactively' bổ nghĩa cho động từ 'act'."},{"id":"g5-09","part":5,"type":"verb-tense","question":"The company _____ its new headquarters in Singapore when the pandemic disrupted the timeline.","options":["built","has built","was building","had built"],"answer":2,"explanation":"Hành động đang diễn ra khi bị gián đoạn → past continuous 'was building'."},{"id":"g5-10","part":5,"type":"verb-tense","question":"By next March, Ms. Wong _____ the accounting department for a full decade.","options":["leads","led","has led","will have led"],"answer":3,"explanation":"'By next March' + khoảng thời gian → future perfect 'will have led'."},{"id":"g5-11","part":5,"type":"verb-tense","question":"The finance team _____ quarterly projections every Monday since the new CFO joined.","options":["reviewed","reviews","has been reviewing","had reviewed"],"answer":2,"explanation":"'Since + past event' với hành động còn tiếp diễn → present perfect continuous."},{"id":"g5-12","part":5,"type":"verb-tense","question":"Once the contract _____, the engineering team can begin the preliminary site assessment.","options":["signs","is signed","will be signed","signed"],"answer":1,"explanation":"Mệnh đề 'once' chỉ thời gian tương lai → không dùng 'will'. Bị động 'is signed' = hợp đồng được ký."},{"id":"g5-13","part":5,"type":"verb-tense","question":"The delegates _____ the convention center for over an hour before the keynote speaker arrived.","options":["waited","have waited","had been waiting","are waiting"],"answer":2,"explanation":"Hành động diễn ra liên tục trước một sự kiện quá khứ → past perfect continuous."},{"id":"g5-14","part":5,"type":"verb-tense","question":"The new overtime policy _____ effect next Monday, so all managers should inform their teams.","options":["takes","took","has taken","will take"],"answer":3,"explanation":"'Next Monday' chỉ tương lai → 'will take effect'."},{"id":"g5-15","part":5,"type":"verb-tense","question":"We _____ to the same catering supplier for all corporate events for the past eight years.","options":["turned","have turned","had turned","turn"],"answer":1,"explanation":"'For the past eight years' → present perfect 'have turned'."},{"id":"g5-16","part":5,"type":"preposition","question":"The final report must be submitted _____ the close of business on Friday without exception.","options":["until","by","before","at"],"answer":1,"explanation":"'By Friday' = trước hoặc vào thứ Sáu (deadline). 'Until' chỉ hành động kéo dài đến một thời điểm."},{"id":"g5-17","part":5,"type":"preposition","question":"Sales figures for the third quarter were _____ par with the same period last year.","options":["on","at","in","by"],"answer":0,"explanation":"'On par with' = ngang bằng với (cụm cố định)."},{"id":"g5-18","part":5,"type":"preposition","question":"The initiative was launched _____ collaboration with three leading universities.","options":["by","in","with","through"],"answer":1,"explanation":"'In collaboration with' = hợp tác cùng (cụm giới từ cố định)."},{"id":"g5-19","part":5,"type":"preposition","question":"The HR director reminded employees that grievance procedures are outlined _____ detail in the handbook.","options":["at","by","in","with"],"answer":2,"explanation":"'In detail' = một cách chi tiết (cụm giới từ cố định)."},{"id":"g5-20","part":5,"type":"preposition","question":"Requests for time off during peak season are subject _____ manager approval.","options":["for","of","to","by"],"answer":2,"explanation":"'Subject to' = phụ thuộc vào, chịu sự (cụm giới từ cố định)."},{"id":"g5-21","part":5,"type":"preposition","question":"The two firms agreed to put their differences aside and work _____ a common goal.","options":["to","toward","for","onto"],"answer":1,"explanation":"'Work toward a goal' = nỗ lực hướng đến mục tiêu (toward = hướng tới)."},{"id":"g5-22","part":5,"type":"conjunction","question":"_____ the quarterly results were disappointing, the board chose not to revise the annual forecast.","options":["Even though","Despite","Whereas","Due to"],"answer":0,"explanation":"'Even though' + mệnh đề (S+V) = mặc dù. 'Despite' cần danh từ/gerund phía sau."},{"id":"g5-23","part":5,"type":"conjunction","question":"The venue has been booked; _____, the catering arrangements still need to be finalized.","options":["nonetheless","as a result","moreover","besides"],"answer":2,"explanation":"'Moreover' = hơn nữa, thêm vào đó. Bổ sung thông tin còn thiếu (catering chưa xong)."},{"id":"g5-24","part":5,"type":"conjunction","question":"Employees may work from home on Fridays _____ their productivity targets are consistently met.","options":["unless","provided that","even if","in case"],"answer":1,"explanation":"'Provided that' = miễn là, với điều kiện là. Điều kiện để được làm việc tại nhà."},{"id":"g5-25","part":5,"type":"conjunction","question":"The marketing team revised the campaign _____ the initial data showed lower-than-expected click rates.","options":["so that","after","although","since"],"answer":3,"explanation":"'Since' = vì (nguyên nhân). Dữ liệu thấp → lý do để sửa chiến dịch."},{"id":"g5-26","part":5,"type":"conjunction","question":"The presentation was delayed _____ the projector malfunctioned just before the session began.","options":["because of","although","when","due to"],"answer":2,"explanation":"'When' = khi (chỉ thời điểm hành động xảy ra). Máy chiếu hỏng vào đúng lúc buổi sắp bắt đầu."},{"id":"g5-27","part":5,"type":"vocabulary","question":"The company has decided to _____ its unprofitable regional branches to cut costs.","options":["consolidate","advertise","motivate","decorate"],"answer":0,"explanation":"'Consolidate branches' = sáp nhập chi nhánh để tiết kiệm. Các động từ khác không liên quan đến việc cắt giảm chi phí."},{"id":"g5-28","part":5,"type":"vocabulary","question":"The training program was _____ to address the specific technical skill gaps identified in the performance review.","options":["tailored","rejected","borrowed","exported"],"answer":0,"explanation":"'Tailored to' = được thiết kế riêng cho. Phù hợp nhất khi nói về chương trình đào tạo giải quyết hổng kỹ năng."},{"id":"g5-29","part":5,"type":"vocabulary","question":"The committee will _____ proposals from all departments before making its final recommendation.","options":["solicit","postpone","compete","celebrate"],"answer":0,"explanation":"'Solicit proposals' = kêu gọi đề xuất. 'Postpone' hay 'Celebrate' không đi với 'proposals' trong ngữ cảnh này."},{"id":"g5-30","part":5,"type":"vocabulary","question":"To _____ compliance with the new data regulations, all departments must submit an updated privacy policy by month-end.","options":["ensure","assure","secure","guarantee"],"answer":0,"explanation":"'Ensure compliance' = đảm bảo tuân thủ. 'Ensure' dùng với hành động/trạng thái, không cần tân ngữ người."},{"id":"h5-01","part":5,"type":"word-form","question":"The _____ of the merger agreement is expected to take several more months due to regulatory reviews.","options":["finalize","finalization","finally","finalizing"],"answer":1,"explanation":"Sau 'The' cần danh từ chủ ngữ. 'Finalization' = sự hoàn thiện/ký kết cuối cùng."},{"id":"h5-02","part":5,"type":"word-form","question":"The director spoke _____ about the company's performance at the shareholder meeting.","options":["candid","candidly","candidness","candidacy"],"answer":1,"explanation":"Phó từ 'candidly' (một cách thẳng thắn) bổ nghĩa cho động từ 'spoke'."},{"id":"h5-03","part":5,"type":"word-form","question":"All visitors must wear _____ safety equipment when entering the construction zone.","options":["appropriate","appropriately","appropriateness","appropriated"],"answer":0,"explanation":"Tính từ 'appropriate' (phù hợp) đứng trước danh từ 'safety equipment'."},{"id":"h5-04","part":5,"type":"word-form","question":"The sales team showed great _____ in closing three major deals within a single quarter.","options":["persist","persistent","persistence","persistently"],"answer":2,"explanation":"Sau 'great' cần danh từ tân ngữ. 'Persistence' = sự kiên trì."},{"id":"h5-05","part":5,"type":"word-form","question":"The seminar was _____ attended, with over 400 professionals registering in advance.","options":["well","good","better","best"],"answer":0,"explanation":"'Well-attended' = có đông người tham dự. Phó từ 'well' kết hợp với participle 'attended'."},{"id":"h5-06","part":5,"type":"word-form","question":"Ms. Kim was _____ selected as the keynote speaker for the annual leadership summit.","options":["unanimity","unanimous","unanimously","unanimousness"],"answer":2,"explanation":"Phó từ 'unanimously' (được chọn nhất trí) bổ nghĩa cho 'was selected'."},{"id":"h5-07","part":5,"type":"word-form","question":"The _____ of the safety audit revealed several areas requiring immediate attention.","options":["find","findings","found","finder"],"answer":1,"explanation":"'The findings of the audit' = kết quả/phát hiện của cuộc kiểm tra. Danh từ số nhiều làm chủ ngữ."},{"id":"h5-08","part":5,"type":"word-form","question":"Customers who are _____ with their purchase may return the item within 30 days for a full refund.","options":["satisfy","satisfaction","satisfactorily","dissatisfied"],"answer":3,"explanation":"Tính từ 'dissatisfied' (không hài lòng) phù hợp ngữ cảnh câu — khách hàng không hài lòng thì trả hàng."},{"id":"h5-09","part":5,"type":"verb-tense","question":"The branch office in Toronto _____ operations for over twenty years when it finally closed.","options":["conducted","has conducted","had been conducting","is conducting"],"answer":2,"explanation":"Hành động diễn ra liên tục trước một sự kiện quá khứ → past perfect continuous 'had been conducting'."},{"id":"h5-10","part":5,"type":"verb-tense","question":"Sales projections indicate that the new product line _____ strong demand throughout the holiday season.","options":["attracts","attracted","will attract","has attracted"],"answer":2,"explanation":"Dự báo tương lai (projections indicate) → 'will attract'."},{"id":"h5-11","part":5,"type":"verb-tense","question":"The HR manager _____ all applications before the interview panel meets next Monday.","options":["reviews","reviewed","will have reviewed","has reviewed"],"answer":2,"explanation":"'Before the interview panel meets' = trước khi hội đồng họp vào thứ Hai → future perfect 'will have reviewed'."},{"id":"h5-12","part":5,"type":"verb-tense","question":"The procurement team _____ with three suppliers simultaneously when the budget freeze was announced.","options":["negotiates","negotiated","had negotiated","was negotiating"],"answer":3,"explanation":"Hành động đang diễn ra bị gián đoạn bởi 'was announced' → past continuous 'was negotiating'."},{"id":"h5-13","part":5,"type":"verb-tense","question":"The company _____ its social media engagement significantly since hiring a dedicated content strategist.","options":["improves","improved","has improved","will improve"],"answer":2,"explanation":"'Since + past event' và kết quả còn ảnh hưởng đến hiện tại → present perfect 'has improved'."},{"id":"h5-14","part":5,"type":"verb-tense","question":"Provided the client _____ the revised specifications by Friday, production can start on Monday.","options":["approves","will approve","approved","has approved"],"answer":0,"explanation":"Mệnh đề 'Provided' (điều kiện) không dùng 'will' → hiện tại đơn 'approves'."},{"id":"h5-15","part":5,"type":"preposition","question":"The proposal was put forward _____ behalf of the entire research committee.","options":["in","on","at","for"],"answer":1,"explanation":"'On behalf of' = thay mặt cho (cụm giới từ cố định)."},{"id":"h5-16","part":5,"type":"preposition","question":"The new safety procedures are _____ accordance with the updated ISO standards.","options":["on","by","in","for"],"answer":2,"explanation":"'In accordance with' = phù hợp với, theo đúng (cụm giới từ cố định)."},{"id":"h5-17","part":5,"type":"preposition","question":"Applications submitted _____ time will be reviewed in the order they are received.","options":["on","in","at","by"],"answer":0,"explanation":"'On time' = đúng hạn (cụm giới từ cố định). Không nhầm với 'in time' = kịp giờ."},{"id":"h5-18","part":5,"type":"preposition","question":"The research team worked _____ the clock to meet the publication deadline.","options":["by","around","on","with"],"answer":1,"explanation":"'Work around the clock' = làm việc suốt ngày đêm (cụm cố định)."},{"id":"h5-19","part":5,"type":"preposition","question":"The two departments collaborate closely _____ a daily basis to streamline workflows.","options":["in","at","on","by"],"answer":2,"explanation":"'On a daily basis' = hàng ngày, theo cơ sở hàng ngày (cụm giới từ cố định)."},{"id":"h5-20","part":5,"type":"conjunction","question":"The marketing campaign received positive feedback; _____, actual conversion rates remained below target.","options":["therefore","moreover","nonetheless","similarly"],"answer":2,"explanation":"'Nonetheless' = tuy nhiên, dù vậy. Tương phản giữa feedback tốt nhưng kết quả chuyển đổi thấp."},{"id":"h5-21","part":5,"type":"conjunction","question":"_____ the shipment arrives before noon, the warehouse team can process it the same day.","options":["Even though","As long as","Unless","Whereas"],"answer":1,"explanation":"'As long as' = miễn là. Điều kiện để warehouse team xử lý cùng ngày."},{"id":"h5-22","part":5,"type":"conjunction","question":"The new branch will be profitable within two years _____ market conditions remain stable.","options":["assuming","despite","although","in spite of"],"answer":0,"explanation":"'Assuming (that)' = giả sử rằng, với điều kiện là. Điều kiện tương lai."},{"id":"h5-23","part":5,"type":"conjunction","question":"Management introduced the flexible hours policy _____ reduce commuting stress for staff.","options":["in order to","so that","because","for"],"answer":0,"explanation":"'In order to + V' = để, nhằm mục đích. Đứng trước động từ nguyên thể."},{"id":"h5-24","part":5,"type":"conjunction","question":"The board approved the expansion plan; _____, certain conditions must be met before funds are released.","options":["as a result","however","furthermore","otherwise"],"answer":1,"explanation":"'However' = tuy nhiên. Bổ sung điều kiện mặc dù kế hoạch đã được phê duyệt."},{"id":"h5-25","part":5,"type":"passive","question":"The confidential documents _____ access to only during scheduled audit sessions.","options":["grant","are granted","have granted","were granting"],"answer":1,"explanation":"Bị động 'are granted access to' = được phép truy cập. Tài liệu nhận tác động từ người quản lý."},{"id":"h5-26","part":5,"type":"passive","question":"All incoming parcels _____ by the security team before being distributed to recipients.","options":["screening","are screened","screen","have screening"],"answer":1,"explanation":"Bị động hiện tại đơn 'are screened' = được kiểm tra (quy trình thường xuyên)."},{"id":"h5-27","part":5,"type":"passive","question":"The annual performance awards ceremony _____ at the Grand Pavilion Hotel next month.","options":["will hold","will be held","is holding","has been holding"],"answer":1,"explanation":"Bị động tương lai 'will be held' = sẽ được tổ chức. Buổi lễ nhận tác động."},{"id":"h5-28","part":5,"type":"vocabulary","question":"The firm decided to _____ the launch of its flagship product until supply chain issues were resolved.","options":["postpone","abandon","retrieve","install"],"answer":0,"explanation":"'Postpone the launch' = hoãn ngày ra mắt. 'Abandon' (từ bỏ) hay 'Install' (cài đặt) không phù hợp với trạng thái 'until resolved'."},{"id":"h5-29","part":5,"type":"vocabulary","question":"The CFO presented a _____ plan showing how the company could return to profitability within 18 months.","options":["feasible","expensive","temporary","confidential"],"answer":0,"explanation":"'Feasible plan' = kế hoạch khả thi. Các từ còn lại không đi kèm với 'plan' để tạo nghĩa phù hợp trong báo cáo CFO."},{"id":"h5-30","part":5,"type":"vocabulary","question":"The company is committed to _____ its carbon footprint by 50% before the end of the decade.","options":["reducing","expanding","ignoring","recalling"],"answer":0,"explanation":"'Reducing carbon footprint' là cụm cố định. 'Expanding' (mở rộng) hay 'Ignoring' (phớt lờ) sai hướng cam kết môi trường."},{"id":"e5-1","part":5,"type":"word-form","question":"The _____ of the contract requires both parties to sign before January.","options":["finalize","finalization","finalizing","finalized"],"answer":1,"explanation":"Sau mạo từ 'The' cần danh từ. 'Finalization' = sự hoàn tất."},{"id":"e5-2","part":5,"type":"word-form","question":"Customer feedback was _____ positive about the new service.","options":["overwhelm","overwhelming","overwhelmingly","overwhelmed"],"answer":2,"explanation":"Phó từ 'overwhelmingly' bổ nghĩa cho tính từ 'positive'."},{"id":"e5-3","part":5,"type":"word-form","question":"The company's _____ growth exceeded all expectations last quarter.","options":["remark","remarkable","remarkably","remarked"],"answer":1,"explanation":"Tính từ 'remarkable' đứng trước danh từ 'growth'."},{"id":"e5-4","part":5,"type":"word-form","question":"All applicants must provide _____ of their educational qualifications.","options":["prove","proof","proven","provable"],"answer":1,"explanation":"Sau 'provide' cần tân ngữ (danh từ). 'Proof' = bằng chứng."},{"id":"e5-5","part":5,"type":"word-form","question":"The marketing director gave a very _____ presentation at the annual meeting.","options":["persuade","persuasion","persuasive","persuasively"],"answer":2,"explanation":"Tính từ 'persuasive' đứng trước danh từ 'presentation'."},{"id":"e5-6","part":5,"type":"word-form","question":"The _____ between the two departments has improved communication significantly.","options":["collaborate","collaboration","collaborative","collaboratively"],"answer":1,"explanation":"Sau mạo từ 'The' cần danh từ. 'Collaboration' = sự hợp tác."},{"id":"e5-7","part":5,"type":"word-form","question":"Participants are _____ encouraged to submit their registration before the deadline.","options":["strong","strength","strongly","strengthen"],"answer":2,"explanation":"Phó từ 'strongly' bổ nghĩa cho động từ 'encouraged'."},{"id":"e5-8","part":5,"type":"word-form","question":"The new regulation aims to ensure _____ working conditions for all employees.","options":["safe","safely","safety","safeguard"],"answer":0,"explanation":"Tính từ 'safe' đứng trước danh từ 'working conditions'."},{"id":"e5-9","part":5,"type":"word-form","question":"The company has made _____ investments in renewable energy this year.","options":["substance","substantial","substantially","substantiate"],"answer":1,"explanation":"Tính từ 'substantial' đứng trước danh từ 'investments'."},{"id":"e5-10","part":5,"type":"word-form","question":"The executive board reviewed the _____ report before making a decision.","options":["finance","financial","financially","financing"],"answer":1,"explanation":"Tính từ 'financial' đứng trước danh từ 'report'."},{"id":"e5-11","part":5,"type":"verb-tense","question":"The project team _____ on the proposal since early January.","options":["works","worked","has been working","will work"],"answer":2,"explanation":"'Since early January' → hiện tại hoàn thành tiếp diễn 'has been working'."},{"id":"e5-12","part":5,"type":"verb-tense","question":"Before the meeting started, the director already _____ the agenda.","options":["reviews","reviewed","has reviewed","had reviewed"],"answer":3,"explanation":"Hành động xảy ra trước một hành động quá khứ khác → quá khứ hoàn thành 'had reviewed'."},{"id":"e5-13","part":5,"type":"verb-tense","question":"The workshop _____ every Wednesday at 2:00 p.m. in Conference Room B.","options":["is held","holds","was held","will hold"],"answer":0,"explanation":"Lịch trình cố định, lặp lại → bị động hiện tại đơn 'is held'."},{"id":"e5-14","part":5,"type":"verb-tense","question":"Ms. Tanaka _____ the Tokyo office before she was transferred to Seoul.","options":["manages","managed","has managed","had managed"],"answer":3,"explanation":"Hành động trước 'was transferred' → quá khứ hoàn thành 'had managed'."},{"id":"e5-15","part":5,"type":"verb-tense","question":"The construction crew _____ the building by the time tenants move in.","options":["will complete","completes","will have completed","has completed"],"answer":2,"explanation":"'By the time + present' → future perfect 'will have completed'."},{"id":"e5-16","part":5,"type":"verb-tense","question":"Revenue _____ by 15 percent if the marketing plan is approved.","options":["increases","increased","will increase","has increased"],"answer":2,"explanation":"Câu điều kiện loại 1: if + present → will + V. 'Will increase'."},{"id":"e5-17","part":5,"type":"verb-tense","question":"Mr. Lee _____ as a consultant for our firm for the past decade.","options":["serves","served","has served","will serve"],"answer":2,"explanation":"'For the past decade' → hiện tại hoàn thành 'has served'."},{"id":"e5-18","part":5,"type":"verb-tense","question":"The shipment _____ yesterday afternoon according to the tracking system.","options":["arrives","arrived","has arrived","will arrive"],"answer":1,"explanation":"'Yesterday afternoon' → quá khứ đơn 'arrived'."},{"id":"e5-19","part":5,"type":"preposition","question":"The company specializes _____ developing software for the healthcare industry.","options":["at","on","in","with"],"answer":2,"explanation":"'Specialize in' = chuyên về (cụm cố định)."},{"id":"e5-20","part":5,"type":"preposition","question":"All complaints should be addressed _____ the department supervisor.","options":["for","to","at","by"],"answer":1,"explanation":"'Be addressed to' = gửi đến (cụm cố định)."},{"id":"e5-21","part":5,"type":"preposition","question":"The event was postponed _____ next Thursday due to the storm.","options":["on","at","until","by"],"answer":2,"explanation":"'Postpone until' = hoãn cho đến. 'Until' chỉ thời điểm tương lai."},{"id":"e5-22","part":5,"type":"preposition","question":"The intern reports directly _____ the marketing manager.","options":["for","to","at","with"],"answer":1,"explanation":"'Report to someone' = báo cáo với ai (cụm cố định)."},{"id":"e5-23","part":5,"type":"preposition","question":"Our new product line is aimed _____ young professionals aged 25-35.","options":["for","to","at","on"],"answer":2,"explanation":"'Aimed at' = nhắm vào (cụm cố định). 'Aimed at young professionals'."},{"id":"e5-24","part":5,"type":"preposition","question":"The contract must be signed _____ advance of the project start date.","options":["on","in","at","by"],"answer":1,"explanation":"'In advance of' = trước (cụm cố định)."},{"id":"e5-25","part":5,"type":"conjunction","question":"_____ the budget was limited, the team managed to deliver an impressive result.","options":["Even though","Because","Since","So that"],"answer":0,"explanation":"'Even though' = mặc dù. Câu tương phản: budget limited nhưng kết quả tốt."},{"id":"e5-26","part":5,"type":"conjunction","question":"The new policy will take effect _____ all employees have been notified.","options":["once","unless","although","while"],"answer":0,"explanation":"'Once' = một khi, ngay khi. Chính sách có hiệu lực khi tất cả được thông báo."},{"id":"e5-27","part":5,"type":"conjunction","question":"_____ the weather conditions improve, the outdoor event will be held indoors.","options":["If","Unless","Although","Because"],"answer":1,"explanation":"'Unless' = trừ khi. Nếu thời tiết không cải thiện → tổ chức trong nhà."},{"id":"e5-28","part":5,"type":"conjunction","question":"Mr. Cho accepted the position _____ the salary was lower than expected.","options":["so that","in order to","even though","as a result"],"answer":2,"explanation":"'Even though' = mặc dù. Nhận việc dù lương thấp hơn kỳ vọng."},{"id":"e5-29","part":5,"type":"conjunction","question":"The factory will remain operational _____ the safety inspection is completed.","options":["until","while","so","since"],"answer":0,"explanation":"'Until' = cho đến khi. Nhà máy hoạt động cho đến khi kiểm tra xong."},{"id":"e5-30","part":5,"type":"conjunction","question":"We need to increase production; _____, we must hire additional workers.","options":["however","furthermore","consequently","otherwise"],"answer":2,"explanation":"'Consequently' = do đó. Câu sau là hệ quả logic của câu trước."},{"id":"e5-31","part":5,"type":"passive","question":"The annual conference _____ in Singapore this year.","options":["has held","is being held","holding","have held"],"answer":1,"explanation":"Bị động hiện tại tiếp diễn 'is being held' = đang được tổ chức."},{"id":"e5-32","part":5,"type":"passive","question":"The invoice _____ to your email address within three business days.","options":["will send","will be sent","sends","is sending"],"answer":1,"explanation":"Bị động tương lai 'will be sent'. Hóa đơn được gửi (nhận tác động)."},{"id":"e5-33","part":5,"type":"passive","question":"Employees who violate the dress code _____ a formal warning.","options":["will give","will be given","are giving","have giving"],"answer":1,"explanation":"Bị động 'will be given'. Nhân viên được đưa cảnh cáo chính thức."},{"id":"e5-34","part":5,"type":"passive","question":"The damaged goods _____ and refunded within 14 days of return.","options":["will inspect","will be inspected","inspecting","have inspect"],"answer":1,"explanation":"Bị động tương lai 'will be inspected'. Hàng hóa được kiểm tra."},{"id":"e5-35","part":5,"type":"pronoun","question":"_____ attending the seminar should register at the front desk upon arrival.","options":["Those","These","They","Their"],"answer":0,"explanation":"'Those attending' = những ai tham dự (đại từ chỉ định + phân từ)."},{"id":"e5-36","part":5,"type":"pronoun","question":"The supervisor asked the team members to introduce _____.","options":["them","themselves","they","their"],"answer":1,"explanation":"Đại từ phản thân 'themselves'. Chủ ngữ và tân ngữ trùng nhau."},{"id":"e5-37","part":5,"type":"pronoun","question":"_____ of the proposals submitted met the selection criteria.","options":["None","No","Not","Neither"],"answer":0,"explanation":"'None of the proposals' = không có đề xuất nào. 'None of + danh từ'."},{"id":"e5-38","part":5,"type":"pronoun","question":"The two applicants both have relevant experience, but _____ has the required certification.","options":["both","either","neither","each"],"answer":2,"explanation":"'Neither' = cả hai đều không. Cả hai có kinh nghiệm nhưng không ai có chứng chỉ."},{"id":"e5-39","part":5,"type":"vocabulary","question":"The company will _____ a press conference to announce the merger.","options":["have","hold","make","do"],"answer":1,"explanation":"'Hold a press conference' = tổ chức họp báo (collocation cố định)."},{"id":"e5-40","part":5,"type":"vocabulary","question":"The manager asked staff to _____ to the new working hours.","options":["adhere","stick","follow","obey"],"answer":0,"explanation":"'Adhere to' = tuân thủ (trang trọng, phổ biến trong văn bản TOEIC)."},{"id":"e5-41","part":5,"type":"vocabulary","question":"The warranty _____ parts and labor for a period of two years.","options":["includes","covers","contains","holds"],"answer":1,"explanation":"'Covers parts and labor' = bao gồm phụ tùng và nhân công (collocation bảo hành)."},{"id":"e5-42","part":5,"type":"vocabulary","question":"Due to unforeseen circumstances, the event has been _____ indefinitely.","options":["delayed","postponed","canceled","rescheduled"],"answer":1,"explanation":"'Postponed indefinitely' = hoãn vô thời hạn (collocation chuẩn)."},{"id":"e5-43","part":5,"type":"vocabulary","question":"The board has decided to _____ additional funds for the research project.","options":["allocate","distribute","assign","appoint"],"answer":0,"explanation":"'Allocate funds' = phân bổ ngân sách (collocation cố định trong kinh doanh)."},{"id":"e5-44","part":5,"type":"vocabulary","question":"Employees must _____ with the company's code of conduct at all times.","options":["comply","agree","follow","accept"],"answer":0,"explanation":"'Comply with' = tuân thủ (cụm cố định trong quy định công ty)."},{"id":"e5-45","part":5,"type":"vocabulary","question":"The negotiation _____ in a mutually beneficial agreement.","options":["ended","resulted","concluded","led"],"answer":1,"explanation":"'Resulted in' = dẫn đến kết quả (cụm cố định)."},{"id":"e5-46","part":5,"type":"vocabulary","question":"The manager will _____ the final decision after consulting with all stakeholders.","options":["do","make","take","get"],"answer":1,"explanation":"'Make a decision' = ra quyết định (collocation cố định)."},{"id":"e5-47","part":5,"type":"vocabulary","question":"Ms. Rivera was promoted in _____ of her outstanding contributions.","options":["view","light","recognition","response"],"answer":2,"explanation":"'In recognition of' = để ghi nhận, tôn vinh (cụm cố định)."},{"id":"e5-48","part":5,"type":"vocabulary","question":"The company _____ a substantial profit despite the economic downturn.","options":["earned","gained","won","obtained"],"answer":0,"explanation":"'Earn a profit' = kiếm được lợi nhuận (collocation cố định)."},{"id":"e5-49","part":5,"type":"vocabulary","question":"The new factory is _____ to begin production in the third quarter.","options":["planned","scheduled","arranged","organized"],"answer":1,"explanation":"'Scheduled to' = được lên lịch để (dùng cho kế hoạch cụ thể)."},{"id":"e5-50","part":5,"type":"vocabulary","question":"Please _____ to the enclosed brochure for a complete list of services.","options":["look","refer","see","check"],"answer":1,"explanation":"'Refer to' = tham khảo (cụm cố định trong thư tín thương mại)."},{"id":"t8-01","part":5,"type":"word-form","question":"The committee's _____ of the merger terms took nearly three months of intensive negotiation.","options":["finalise","finalised","finalisation","finally"],"answer":2,"explanation":"'The committee's + noun' → cần danh từ làm chủ ngữ. 'Finalisation' (sự hoàn tất) là danh từ duy nhất. 'Finally' là phó từ."},{"id":"t8-02","part":5,"type":"word-form","question":"Ms. Park gave a _____ account of how the project had evolved from concept to completion.","options":["detail","detailed","detailing","detailedly"],"answer":1,"explanation":"Tính từ 'detailed' (chi tiết, kỹ lưỡng) đứng trước danh từ 'account'. 'Detail' là danh từ/động từ; 'detailedly' không phải từ chuẩn."},{"id":"t8-03","part":5,"type":"word-form","question":"The new payroll software has significantly _____ the time required to process monthly salaries.","options":["reduce","reduction","reducing","reduced"],"answer":3,"explanation":"Sau 'has significantly' cần quá khứ phân từ (V3) trong thì hiện tại hoàn thành → 'reduced'. 'Reducing' là V-ing không dùng được sau 'has'."},{"id":"t8-04","part":5,"type":"word-form","question":"Parkfield Consulting is known for its _____ approach to client relationships, often staying with clients for decades.","options":["persevere","perseverance","persevering","perseverant"],"answer":2,"explanation":"Tính từ 'persevering' (kiên trì, bền bỉ) bổ nghĩa trực tiếp cho 'approach'. 'Perseverance' là danh từ, không thể đứng trước danh từ khác làm tính từ."},{"id":"t8-05","part":5,"type":"word-form","question":"The annual gala was organised _____ and received unanimous praise from all 300 guests.","options":["flawless","flawlessly","flaw","flawed"],"answer":1,"explanation":"Phó từ 'flawlessly' bổ nghĩa cho động từ 'was organised'. 'Flawless' là tính từ (cần đứng trước danh từ hoặc sau be)."},{"id":"t8-06","part":5,"type":"verb-tense","question":"The new data centre _____ at full capacity since it was commissioned in the spring.","options":["operates","operated","has been operating","will operate"],"answer":2,"explanation":"'Since it was commissioned' → hiện tại hoàn thành tiếp diễn 'has been operating'. Hành động bắt đầu từ quá khứ và vẫn tiếp tục đến nay."},{"id":"t8-07","part":5,"type":"verb-tense","question":"All participants _____ a welcome package upon arrival at the registration desk tomorrow morning.","options":["received","receive","will receive","had received"],"answer":2,"explanation":"'Tomorrow morning' chỉ tương lai → 'will receive'. Ngữ cảnh là chính sách/lịch trình sự kiện sắp tới."},{"id":"t8-08","part":5,"type":"preposition","question":"Please be aware that your subscription will renew automatically _____ the end of the billing cycle.","options":["during","until","at","by"],"answer":2,"explanation":"'At the end of' = vào lúc kết thúc (điểm thời gian cụ thể). 'Until' = tiếp tục cho đến; 'by' = trước thời điểm đó."},{"id":"t8-09","part":5,"type":"preposition","question":"The financial analyst's projections proved to be _____ with actual performance figures for the quarter.","options":["consistent","consistent with","inconsistent","consistently"],"answer":1,"explanation":"'Consistent with' = phù hợp với, nhất quán với (cụm tính từ + giới từ cố định). Câu đang test xem 'with' có bị thiếu không – đây là bẫy điển hình trong ETS."},{"id":"t8-10","part":5,"type":"conjunction","question":"The training session will be recorded _____ employees who are unable to attend may watch it at a later time.","options":["so that","now that","in case","even though"],"answer":0,"explanation":"'So that' = để (chỉ mục đích). Buổi được quay với mục đích rõ ràng là để nhân viên xem lại. 'In case' = phòng khi (dùng khi sự việc được coi là không chắc xảy ra), không phù hợp vì đây là mục đích chủ động. 'Now that' = bây giờ khi, 'even though' = mặc dù – sai nghĩa."},{"id":"t8-11","part":5,"type":"conjunction","question":"_____ the renovation was disruptive, most staff agreed the refurbished office was well worth it.","options":["Despite","Although","Because of","However"],"answer":1,"explanation":"'Although' = mặc dù (liên từ phụ thuộc nối hai mệnh đề). 'Despite' cần danh từ/V-ing (despite the disruption). 'However' là trạng từ liên kết, không thể ở đầu một mệnh đề phụ như thế này."},{"id":"t8-12","part":5,"type":"passive","question":"Suppliers who fail to meet the quality specifications _____ from the approved vendor list.","options":["remove","are removed","removing","to be removed"],"answer":1,"explanation":"Chủ ngữ 'Suppliers' nhận hành động (bị loại khỏi danh sách) → bị động hiện tại đơn 'are removed'. Đây là quy định lặp lại → hiện tại đơn."},{"id":"t8-13","part":5,"type":"vocabulary","question":"The director of communications was tasked with _____ the company's response to the media inquiry.","options":["drafting","launching","expanding","installing"],"answer":0,"explanation":"'Drafting a response' = soạn thảo câu trả lời (collocation chuẩn trong PR/corporate communications). 'Launch' = khởi động chiến dịch/sản phẩm; 'install' dùng cho phần mềm/thiết bị."},{"id":"t8-14","part":5,"type":"vocabulary","question":"The logistics team worked around the clock to _____ that all orders were dispatched before the holiday freeze.","options":["ensure","result","cause","indicate"],"answer":0,"explanation":"'Ensure that' = đảm bảo rằng (cụm động từ chuẩn). Phân biệt: 'ensure that' (đảm bảo) vs 'result in' (dẫn đến kết quả) vs 'indicate that' (chỉ ra rằng)."},{"id":"t8-15","part":5,"type":"pronoun","question":"The new compensation guidelines apply to _____ who joined the organisation on or after January 1.","options":["whichever","those","them","each"],"answer":1,"explanation":"'Those who' = những người mà (cấu trúc chuẩn trong văn bản chính sách). 'Whichever' dùng cho vật/lựa chọn, không dùng cho người. 'Them who' sai ngữ pháp. 'Each' cần đứng với danh từ đơn."},{"id":"ex5-1","part":5,"type":"verb-tense","question":"The management team _____ the budget proposal several times before final approval was granted.","options":["reviews","is reviewing","had reviewed","will review"],"answer":2,"explanation":"✅ <b>Had reviewed</b> (Quá khứ hoàn thành). <br>💡 <i>Cấu trúc:</i> Hành động xảy ra trước một hành động khác trong quá khứ (granted) -> dùng Past Perfect."},{"id":"ex5-2","part":5,"type":"verb-tense","question":"By the time the new regulations take effect, the company _____ its compliance software for six months.","options":["tests","has tested","will have been testing","is testing"],"answer":2,"explanation":"✅ <b>Will have been testing</b> (Tương lai hoàn thành tiếp diễn). <br>💡 <i>Mẹo ETS:</i> 'By the time + Hiện tại' + 'for [khoảng thời gian]' -> Tương lai hoàn thành tiếp diễn."},{"id":"ex5-3","part":5,"type":"vocabulary","question":"Establishing a strong _____ in the local market is the first priority for the new branch.","options":["presence","participation","presentation","precedence"],"answer":0,"explanation":"✅ <b>Presence</b> (Sự hiện diện). <br>💡 'Market presence' là cụm từ cố định (collocation) phổ biến trong TOEIC."},{"id":"ex5-4","part":5,"type":"passive","question":"All sensitive documents _____ to the secure shredding facility every Friday afternoon.","options":["transport","are transported","are transporting","have transported"],"answer":1,"explanation":"✅ <b>Are transported</b> (Bị động hiện tại đơn). <br>💡 Chủ ngữ 'documents' bị tác động (được vận chuyển) + 'every Friday' (thói quen)."},{"id":"ex5-5","part":5,"type":"passive","question":"Employees _____ of any changes to the health insurance policy at least one month in advance.","options":["notify","will notify","will be notified","notifying"],"answer":2,"explanation":"✅ <b>Will be notified</b> (Bị động tương lai). <br>💡 Cấu trúc 'notify someone of something'. Ở đây nhân viên ĐƯỢC thông báo."},{"id":"ex5-6","part":5,"type":"conditionals","question":"If the candidate _____ the interview successfully, he will be offered the position immediately.","options":["pass","passes","passed","will pass"],"answer":1,"explanation":"✅ <b>Passes</b> (Câu điều kiện Loại 1). <br>💡 Diễn tả sự việc có thể xảy ra: If + S + V(hiện tại), S + will + V."},{"id":"ex5-7","part":5,"type":"conditionals","question":"Had the directors known about the potential risks, they _____ the merger.","options":["won't approve","wouldn't approve","wouldn't have approved","didn't approve"],"answer":2,"explanation":"✅ <b>Wouldn't have approved</b> (Đảo ngữ loại 3). <br>💡 Had + S + V3 (loại 3), S + would have + V3. Diễn tả sự việc trái ngược với quá khứ."},{"id":"ex5-8","part":5,"type":"word-form","question":"The marketing director emphasized the need for _____ branding across all social media platforms.","options":["consistent","consistency","consistently","consist"],"answer":0,"explanation":"✅ <b>Consistent</b> (Tính từ). <br>💡 Vị trí đứng trước danh từ 'branding' để bổ nghĩa. Trạng từ 'consistently' chỉ bổ nghĩa cho tính từ hoặc động từ."},{"id":"ex5-9","part":5,"type":"word-form","question":"The _____ of the new product line exceeded all previous sales records.","options":["successful","success","successfully","succeed"],"answer":1,"explanation":"✅ <b>Success</b> (Danh từ). <br>💡 Vị trí sau 'The' và trước giới từ 'of' luôn là một danh từ đóng vai trò chủ ngữ."},{"id":"ex5-10","part":5,"type":"preposition","question":"The finance department is responsible _____ monitoring all international transactions.","options":["to","for","with","at"],"answer":1,"explanation":"✅ <b>For</b>. <br>💡 Cấu trúc tính từ: <i>to be responsible for something/V-ing</i> (chịu trách nhiệm cho việc gì)."},{"id":"ex5-11","part":5,"type":"preposition","question":"According _____ the latest financial report, the company's revenue has increased by 15%.","options":["to","with","on","for"],"answer":0,"explanation":"✅ <b>To</b>. <br>💡 Cụm từ cố định: 'According to' (Theo như) mang tính dẫn dắt thông tin."},{"id":"ex5-12","part":5,"type":"conjunction","question":"The new software is highly intuitive; _____, some employees may still require initial training.","options":["therefore","however","meanwhile","consequently"],"answer":1,"explanation":"✅ <b>However</b> (Tuy nhiên). <br>💡 Trạng từ liên kết chỉ sự tương phản giữa hai ý (dễ dùng vs vẫn cần đào tạo)."},{"id":"ex5-13","part":5,"type":"conjunction","question":"_____ the system upgrade is complete, users will be able to access the new features.","options":["Although","Unless","Once","While"],"answer":2,"explanation":"✅ <b>Once</b> (Ngay khi). <br>💡 Chỉ điều kiện về thời gian: sự việc 1 kết thúc thì sự việc 2 bắt đầu."},{"id":"ex5-14","part":5,"type":"relative-clause","question":"The machinery, _____ was installed last month, has significantly improved production speed.","options":["who","which","whom","whose"],"answer":1,"explanation":"✅ <b>Which</b> (Đại từ quan hệ). <br>💡 Thay thế cho vật (machinery) trong mệnh đề không hạn định (sau dấu phẩy)."},{"id":"ex5-15","part":5,"type":"relative-clause","question":"The technician _____ we hired last week has already identified several assembly line issues.","options":["who","whose","which","whom"],"answer":3,"explanation":"✅ <b>Whom</b>. <br>💡 Đại từ quan hệ làm tân ngữ (we hired <i>him</i> → whom). Trong văn bản TOEIC trang trọng, 'whom' là đáp án chuẩn duy nhất khi đại từ đóng vai trò tân ngữ. 'Who' chỉ dùng khi là chủ ngữ."},{"id":"ex5-16","part":5,"type":"pronoun","question":"Travelers are reminded to keep _____ boarding passes and identification ready for inspection.","options":["them","their","they","themselves"],"answer":1,"explanation":"✅ <b>Their</b> (Tính từ sở hữu). <br>💡 Cần một tính từ sở hữu đứng trước cụm danh từ 'boarding passes' của các hành khách."},{"id":"ex5-17","part":5,"type":"pronoun","question":"The hotel manager personally welcomed the guests and offered _____ a complimentary dinner.","options":["they","their","them","themselves"],"answer":2,"explanation":"✅ <b>Them</b> (Đại từ tân ngữ). <br>💡 Vị trí tân ngữ sau động từ 'offered'. Tránh nhầm với 'themselves' (phản thân)."},{"id":"ex5-18","part":5,"type":"modal","question":"All attendees _____ register at the front desk before entering the main hall.","options":["might","would","must","could"],"answer":2,"explanation":"✅ <b>Must</b> (Động từ khuyết thiếu). <br>💡 Diễn tả sự bắt buộc hoặc quy định chung trong sự kiện."},{"id":"ex5-19","part":5,"type":"modal","question":"If the weather improves, the outdoor reception _____ be held as originally planned.","options":["must","should","might","ought"],"answer":2,"explanation":"✅ <b>Might</b>. <br>💡 Diễn tả khả năng có thể xảy ra nhưng không chắc chắn 100% trong tương lai."},{"id":"ex5-20","part":5,"type":"comparison","question":"Using a third-party logistics provider proved to be _____ than managing the warehouse internally.","options":["efficient","more efficient","most efficient","efficiently"],"answer":1,"explanation":"✅ <b>More efficient</b> (So sánh hơn). <br>💡 Có 'than' và tính từ dài 'efficient' -> dùng 'more + adj'."},{"id":"ex5-21","part":5,"type":"comparison","question":"Shipping by sea is often the _____ option for large-scale international orders.","options":["economical","more economical","most economical","economically"],"answer":2,"explanation":"✅ <b>Most economical</b> (So sánh nhất). <br>💡 Có 'the' + so sánh giữa nhiều lựa chọn -> dùng 'the most + adj'."},{"id":"ex5-22","part":5,"type":"subject-verb","question":"The manager, along with his assistants, _____ attending the investment seminar today.","options":["is","are","being","been"],"answer":0,"explanation":"✅ <b>Is</b> (Hòa hợp chủ vị). <br>💡 <i>Mẹo ETS:</i> Cấu trúc 'S1, along with S2,' thì động từ chia theo S1 (The manager) -> số ít."},{"id":"ex5-23","part":5,"type":"subject-verb","question":"Neither the bank nor the clients _____ happy with the sudden change in interest rates.","options":["is","are","was","has been"],"answer":1,"explanation":"✅ <b>Are</b>. <br>💡 Cấu trúc 'Neither S1 nor S2' -> động từ chia theo S2 (the clients) -> số nhiều."},{"id":"ex5-24","part":5,"type":"subject-verb","question":"Investing in diversified portfolios _____ a proven strategy for long-term wealth accumulation.","options":["is","are","being","been"],"answer":0,"explanation":"✅ <b>Is</b>. <br>💡 Danh động từ (V-ing) làm chủ ngữ luôn được coi là số ít."},{"id":"ex5-25","part":5,"type":"subject-verb","question":"The number of bank account holders _____ steadily increasing since the introduction of the digital app.","options":["has been","have been","is","are"],"answer":0,"explanation":"✅ <b>Has been</b>. <br>💡 <i>Mẹo ETS:</i> 'The number of' + Danh từ số nhiều + Động từ số ít."},{"id":"ex5-26","part":5,"type":"vocabulary","question":"The investment bank decided to _____ its assets to reduce exposure to the volatile energy market.","options":["diversify","calculate","withdraw","deposit"],"answer":0,"explanation":"✅ <b>Diversify</b> (Đa dạng hóa). <br>💡 'Diversify assets' (đa dạng hóa tài sản) là thuật ngữ tài chính để giảm rủi ro."},{"id":"ex5-27","part":5,"type":"vocabulary","question":"A significant _____ in the stock price was observed after the company announced its merger.","options":["fluctuation","foundation","formation","function"],"answer":0,"explanation":"✅ <b>Fluctuation</b> (Sự biến động). <br>💡 Chỉ sự lên xuống không ổn định của giá cả hoặc số liệu."},{"id":"ex5-28","part":5,"type":"vocabulary","question":"The central bank raised interest rates to _____ rising inflation in the second quarter.","options":["combat","conduct","connect","convert"],"answer":0,"explanation":"✅ <b>Combat</b> (Chống lại). <br>💡 'Combat inflation' là collocation phổ biến chỉ việc ngăn chặn lạm phát."},{"id":"ex5-29","part":5,"type":"vocabulary","question":"Investors are looking for high-yield bonds that offer a _____ return on investment.","options":["stable","static","sterile","sturdy"],"answer":0,"explanation":"✅ <b>Stable</b> (Ổn định). <br>💡 'Stable return' (lợi nhuận ổn định) là tính từ bổ nghĩa cho lợi nhuận đầu tư."},{"id":"ex5-30","part":5,"type":"verb-tense","question":"Since the new CEO took over, the company _____ its international market share by 20%.","options":["expanded","expands","has expanded","is expanding"],"answer":2,"explanation":"✅ <b>Has expanded</b>. <br>💡 'Since + Quá khứ' -> mệnh đề chính dùng Hiện tại hoàn thành."},{"id":"ex5-31","part":5,"type":"verb-tense","question":"Next year, Horizon Group _____ its 10th anniversary with a series of community events.","options":["celebrates","celebrated","will celebrate","has celebrated"],"answer":2,"explanation":"✅ <b>Will celebrate</b>. <br>💡 'Next year' là mốc thời gian trong tương lai -> dùng Future Simple."},{"id":"ex5-32","part":5,"type":"verb-tense","question":"The marketing team _____ the spring campaign for three months before it was launched.","options":["prepared","prepares","had been preparing","is preparing"],"answer":2,"explanation":"✅ <b>Had been preparing</b> (Quá khứ hoàn thành tiếp diễn). <br>💡 Nhấn mạnh tính liên tục của hành động xảy ra trước một thời điểm khác trong quá khứ."},{"id":"ex5-33","part":5,"type":"passive","question":"The annual performance reviews _____ by the department heads next week.","options":["conduct","are conducted","will be conducted","conducting"],"answer":2,"explanation":"✅ <b>Will be conducted</b>. <br>💡 Bị động tương lai đơn: will be + PII."},{"id":"ex5-34","part":5,"type":"passive","question":"New safety protocols _____ following the recent audit of the manufacturing facility.","options":["implemented","were implemented","is implementing","has implemented"],"answer":1,"explanation":"✅ <b>Were implemented</b>. <br>💡 Bị động quá khứ đơn (safety protocols được thực thi)."},{"id":"ex5-35","part":5,"type":"conditionals","question":"If the shipment _____ by tomorrow, we will have to suspend production.","options":["doesn't arrive","didn't arrive","won't arrive","hadn't arrived"],"answer":0,"explanation":"✅ <b>Doesn't arrive</b>. <br>💡 Câu điều kiện loại 1: If + Hiện tại, Tương lai."},{"id":"ex5-36","part":5,"type":"conditionals","question":"Unless the terms are renegotiated, the contract _____ at the end of the month.","options":["expires","will expire","expired","would expire"],"answer":1,"explanation":"✅ <b>Will expire</b>. <br>💡 Unless = If not. Dùng tương đương câu điều kiện loại 1."},{"id":"ex5-37","part":5,"type":"relative-clause","question":"The quality control manager, _____ expertise is unmatched, oversees the entire production line.","options":["who","whom","whose","which"],"answer":2,"explanation":"✅ <b>Whose</b>. <br>💡 Đại từ quan hệ sở hữu cho 'expertise' (chuyên môn CỦA người quản lý)."},{"id":"ex5-38","part":5,"type":"vocabulary","question":"Any _____ items found during inspection are immediately removed from the assembly line.","options":["defective","effective","protective","selective"],"answer":0,"explanation":"✅ <b>Defective</b> (Lỗi/hỏng). <br>💡 Thuật ngữ chuyên ngành trong sản xuất (Quality Control)."},{"id":"ex5-39","part":5,"type":"vocabulary","question":"The factory has achieved _____ production levels since the introduction of automation.","options":["precedent","preceded","unprecedented","preceding"],"answer":2,"explanation":"✅ <b>Unprecedented</b> (Chưa từng có). <br>💡 Thường dùng để mô tả sự phát triển vượt bậc hoặc kỷ lục mới."},{"id":"ex5-40","part":5,"type":"vocabulary","question":"The tourism board is launching a campaign to _____ the city's historical landmarks.","options":["promote","produce","provide","protect"],"answer":0,"explanation":"✅ <b>Promote</b> (Quảng bá). <br>💡 Collocation: 'promote tourism/landmarks' (thúc đẩy du lịch)."},{"id":"ex5-41","part":5,"type":"vocabulary","question":"International travelers are advised to check the _____ of their passports 6 months before departure.","options":["validity","utility","facility","ability"],"answer":0,"explanation":"✅ <b>Validity</b> (Thời hạn hiệu lực). <br>💡 Thuật ngữ thường gặp trong du lịch và thủ tục giấy tờ."},{"id":"ex5-42","part":5,"type":"vocabulary","question":"The annual gala is a prestigious _____ that brings together leaders from across the industry.","options":["encounter","event","episode","exchange"],"answer":1,"explanation":"✅ <b>Event</b> (Sự kiện). <br>💡 Ngữ cảnh về một buổi tiệc thường niên quan trọng."},{"id":"ex5-43","part":5,"type":"vocabulary","question":"We need to hire a professional _____ to manage the catering for the international conference.","options":["vendor","investor","monitor","applicant"],"answer":0,"explanation":"✅ <b>Vendor</b> (Nhà cung cấp). <br>💡 Trong kinh doanh, 'vendor' chỉ các đơn vị cung cấp dịch vụ bên ngoài."},{"id":"ex5-44","part":5,"type":"relative-clause","question":"The manufacturing plant, _____ began operations in 1995, is undergoing a major renovation.","options":["that","which","where","who"],"answer":1,"explanation":"✅ <b>Which</b>. <br>💡 Dùng cho vật (plant) trong mệnh đề quan hệ không hạn định."},{"id":"ex5-45","part":5,"type":"relative-clause","question":"The engineer _____ designed the new assembly line has just received a company award.","options":["who","whose","which","whom"],"answer":0,"explanation":"✅ <b>Who</b>. <br>💡 Đại từ quan hệ làm chủ ngữ trong mệnh đề ('who designed' – kỹ sư đó thiết kế). 'Whom' chỉ dùng khi làm tân ngữ; 'which' dùng cho vật; 'whose' chỉ sở hữu."},{"id":"ex5-46","part":5,"type":"vocabulary","question":"The production line was halted to _____ a minor technical error in the sorting machine.","options":["rectify","record","release","replace"],"answer":0,"explanation":"✅ <b>Rectify</b> (Khắc phục/Sửa chữa). <br>💡 Collocation: 'rectify an error/problem'."},{"id":"ex5-47","part":5,"type":"vocabulary","question":"Stringent quality _____ are applied to every batch of products before shipment.","options":["standards","stations","strategies","statutes"],"answer":0,"explanation":"✅ <b>Standards</b> (Tiêu chuẩn). <br>💡 'Quality standards' là bộ tiêu chuẩn chất lượng sản phẩm."},{"id":"ex5-48","part":5,"type":"vocabulary","question":"The factory's _____ output has doubled since the new equipment was installed.","options":["daily","finally","rarely","nearly"],"answer":0,"explanation":"✅ <b>Daily</b> (Hàng ngày). <br>💡 Tính từ bổ nghĩa cho sản lượng (output)."},{"id":"ex5-49","part":5,"type":"vocabulary","question":"The resort offers a variety of _____ activities, including guided mountain tours.","options":["recreational","mechanical","educational","industrial"],"answer":0,"explanation":"✅ <b>Recreational</b> (Giải trí). <br>💡 'Recreational activities' là các hoạt động vui chơi giải trí."},{"id":"ex5-50","part":5,"type":"vocabulary","question":"Travelers are advised to _____ their flight status 24 hours before departure.","options":["confirm","conform","confine","confront"],"answer":0,"explanation":"✅ <b>Confirm</b> (Xác nhận). <br>💡 Thủ tục kiểm tra lại trước khi bay."},{"id":"ex5-51","part":5,"type":"vocabulary","question":"The historical district is a popular _____ for both domestic and international tourists.","options":["destination","distribution","description","demonstration"],"answer":0,"explanation":"✅ <b>Destination</b> (Điểm đến). <br>💡 Nơi khách du lịch lựa chọn hành trình."},{"id":"ex5-52","part":5,"type":"modal","question":"Conference participants _____ wear their identification badges at all times.","options":["should","would","might","could"],"answer":0,"explanation":"✅ <b>Should</b> (Nên). <br>💡 Lời khuyên/hướng dẫn lịch sự trong sự kiện hội nghị."},{"id":"ex5-53","part":5,"type":"modal","question":"The keynote speaker _____ arrive early to test the audiovisual equipment.","options":["might","must","could","would"],"answer":1,"explanation":"✅ <b>Must</b> (Bắt buộc/Cần thiết). <br>💡 Nhấn mạnh tính quan trọng của việc kiểm tra thiết bị."},{"id":"ex5-54","part":5,"type":"vocabulary","question":"The organizing committee is looking for a _____ with a seating capacity of at least 500.","options":["venue","vessel","venture","vehicle"],"answer":0,"explanation":"✅ <b>Venue</b> (Địa điểm tổ chức). <br>💡 Từ chuyên dụng cho nơi diễn ra sự kiện/tiệc/hội thảo."},{"id":"ex5-55","part":5,"type":"vocabulary","question":"A formal _____ will be sent to all distinguished guests by the end of the week.","options":["invitation","invention","intention","instruction"],"answer":0,"explanation":"✅ <b>Invitation</b> (Thư mời). <br>💡 Thủ tục gửi thư mời cho các khách mời quan trọng."},{"id":"ex5-56","part":5,"type":"vocabulary","question":"The banquet hall was _____ decorated for the company's silver jubilee celebration.","options":["elegantly","urgently","randomly","silently"],"answer":0,"explanation":"✅ <b>Elegantly</b> (Trang nhã). <br>💡 Trạng từ phù hợp để mô tả không gian tiệc sang trọng."},{"id":"ex5-57","part":5,"type":"vocabulary","question":"We need to hire an _____ to provide simultaneous translation for the delegates.","options":["interpreter","inspector","instructor","investor"],"answer":0,"explanation":"✅ <b>Interpreter</b> (Phiên dịch viên trực tiếp). <br>💡 Khác với translator (dịch viết)."},{"id":"ex5-58","part":5,"type":"subject-verb","question":"Neither of the proposed investment plans _____ viable in the current economic climate.","options":["is","are","being","been"],"answer":0,"explanation":"✅ <b>Is</b>. <br>💡 <i>Mẹo ETS:</i> 'Neither of + N số nhiều' vẫn chia động từ ở số ít."},{"id":"ex5-59","part":5,"type":"vocabulary","question":"The bank's new mobile app allows customers to _____ funds between accounts instantly.","options":["transfer","translate","transform","transcribe"],"answer":0,"explanation":"✅ <b>Transfer</b> (Chuyển khoản). <br>💡 Thuật ngữ chuyển tiền trong ngân hàng."},{"id":"b9-5-1","part":5,"type":"noun-clauses","question":"The real estate agent explained _____ the property taxes are calculated for commercial buildings.","options":["that","how","what","which"],"answer":1,"explanation":"✅ <b>How</b> (Mệnh đề danh từ). <br>💡 Giải thích 'cách thức' (how) mà cái gì đó vận hành."},{"id":"b9-5-2","part":5,"type":"noun-clauses","question":"Whether the board approves the zoning changes _____ yet to be officially announced.","options":["is","are","have","has"],"answer":0,"explanation":"✅ <b>Is</b>. <br>💡 Cả một mệnh đề danh từ 'Whether S + V' làm chủ ngữ luôn chia động từ số ít."},{"id":"b9-5-3","part":5,"type":"adverb-time","question":"The news anchor reported that the summit had concluded _____ the final statement was released.","options":["shortly before","just as","until","since"],"answer":0,"explanation":"✅ <b>Shortly before</b> (Ngay trước khi). <br>💡 Cụm trạng từ thời gian chỉ sự kiện xảy ra liền kề."},{"id":"b9-5-4","part":5,"type":"vocabulary-context","question":"The retail chain decided to _____ its inventory management system to reduce seasonal waste.","options":["overhaul","overlook","overlap","overtake"],"answer":0,"explanation":"✅ <b>Overhaul</b> (Kiểm tra và sửa chữa toàn bộ/cải tổ). <br>💡 Ngữ cảnh nâng cấp hệ thống quản lý."},{"id":"b9-5-5","part":5,"type":"inversion","question":"Only after the signature is verified _____ the funds be released to the seller.","options":["the bank will","will the bank","has the bank","the bank has"],"answer":1,"explanation":"✅ <b>Will the bank</b> (Đảo ngữ). <br>💡 Cấu trúc 'Only after + N/V-ing/Clause + Trợ động từ + S + V'."},{"id":"b9-5-6","part":5,"type":"inversion","question":"Under no circumstances _____ employees share their login credentials with third parties.","options":["should","employees should","do","must"],"answer":0,"explanation":"✅ <b>Should</b> (Đảo ngữ). <br>💡 'Under no circumstances + Trợ động từ + S + V' (Quy định bắt buộc/Không được phép)."},{"id":"b9-5-7","part":5,"type":"quantifiers","question":"There is _____ evidence to suggest that the new solar panels are 30% more efficient than the previous model.","options":["many","ample","very","few"],"answer":1,"explanation":"✅ <b>Ample</b> (Phong phú/Dư dả). <br>💡 'Ample evidence' là collocation thường dùng trong báo cáo khoa học/kỹ thuật."},{"id":"b9-5-8","part":5,"type":"subjunctive","question":"The company handbook mandates that every employee _____ the safety workshop annually.","options":["attend","attends","attended","attending"],"answer":0,"explanation":"✅ <b>Attend</b> (Giá định cách). <br>💡 Cấu trúc 'Mandate/Require/Suggest + that + S + V-inf'."},{"id":"b9-5-9","part":5,"type":"subjunctive","question":"It is essential that the legal department _____ all contracts before they are signed by the CEO.","options":["reviews","review","reviewed","is reviewing"],"answer":1,"explanation":"✅ <b>Review</b> (Giá định cách). <br>💡 It is essential/important/vital + that + S + V-inf."},{"id":"b9-5-10","part":5,"type":"prep-structures","question":"Contrary _____ popular belief, the increase in automation has actually created more specialized jobs.","options":["with","to","at","on"],"answer":1,"explanation":"✅ <b>To</b>. <br>💡 Cụm cố định: 'Contrary to...' (Trái ngược với...)."},{"id":"b9-5-11","part":5,"type":"word-form","question":"The _____ of the building was completed ahead of schedule despite the heavy rains.","options":["construct","construction","constructive","constructed"],"answer":1,"explanation":"✅ <b>Construction</b> (Danh từ)."},{"id":"b9-5-12","part":5,"type":"vocabulary","question":"The new CEO has a _____ for identifying untapped market opportunities.","options":["knack","track","lack","sack"],"answer":0,"explanation":"✅ <b>Knack</b> (Năng khiếu/Sở trường). <br>💡 'Have a knack for V-ing' là một collocation hay."},{"id":"b9-5-13","part":5,"type":"preposition","question":"The merger is contingent _____ the approval of the regulatory commission.","options":["to","on","with","for"],"answer":1,"explanation":"✅ <b>On</b>. <br>💡 'Contingent on' = tùy thuộc vào."},{"id":"b9-5-14","part":5,"type":"conjunction","question":"_____ the high cost of raw materials, the company managed to maintain its profit margins.","options":["Because","Although","Despite","Unless"],"answer":2,"explanation":"✅ <b>Despite</b> + Cụm danh từ."},{"id":"b9-5-15","part":5,"type":"verb-tense","question":"Our team _____ on this project for six months by the time it launches next August.","options":["will work","will have been working","has been working","works"],"answer":1,"explanation":"✅ <b>Will have been working</b>."},{"id":"b9-5-16","part":5,"type":"passive","question":"The faulty components _____ by the quality control team during the initial inspection.","options":["discovered","were discovered","discover","were discovering"],"answer":1,"explanation":"✅ <b>Were discovered</b>."},{"id":"b9-5-17","part":5,"type":"conditionals","question":"If the interest rates _____ further, many small businesses would struggle to repay their loans.","options":["rise","rose","had risen","risen"],"answer":1,"explanation":"✅ <b>Rose</b> (Điều kiện loại 2)."},{"id":"b9-5-18","part":5,"type":"word-form","question":"The manager was highly _____ of the new marketing proposal.","options":["support","supportive","supportively","supported"],"answer":1,"explanation":"✅ <b>Supportive</b> (Tính từ)."},{"id":"b9-5-19","part":5,"type":"quantifiers","question":"Only _____ people attended the seminar due to the unexpected snowstorm.","options":["a few","a little","many","few"],"answer":0,"explanation":"✅ <b>A few</b> (Một vài - số ít)."},{"id":"b9-5-20","part":5,"type":"pronoun","question":"The directors organized the gala _____ without any help from outside event planners.","options":["them","their","themselves","they"],"answer":2,"explanation":"✅ <b>Themselves</b> (Chính họ)."},{"id":"b9-5-21","part":5,"type":"modal","question":"You _____ submit your expense reports by the end of each month to avoid delays in reimbursement.","options":["could","should","might","would"],"answer":1,"explanation":"✅ <b>Should</b> (Khuyên bảo)."},{"id":"b9-5-22","part":5,"type":"gerund-infinitive","question":"The company considers _____ its operations to South America next year.","options":["expand","to expand","expanding","expanded"],"answer":2,"explanation":"✅ <b>Expanding</b> (Consider + V-ing)."},{"id":"b9-5-23","part":5,"type":"comparison","question":"The new processor is significantly _____ than the one used in the previous model.","options":["fast","faster","fastest","fastly"],"answer":1,"explanation":"✅ <b>Faster</b>."},{"id":"b9-5-24","part":5,"type":"participles","question":"_____ by the success of the pilot program, the board decided to implement it nationwide.","options":["Encourage","Encouraging","Encouraged","Encourages"],"answer":2,"explanation":"✅ <b>Encouraged</b> (Phân từ hoàn thành bị động)."},{"id":"b9-5-25","part":5,"type":"subject-verb","question":"Each of the new employees _____ a mentor during the first month of training.","options":["is assigned","are assigned","assign","assigns"],"answer":0,"explanation":"✅ <b>Is assigned</b> (Each of + N số nhiều + V số ít)."},{"id":"b9-5-26","part":5,"type":"vocabulary","question":"The legal team is working to _____ the terms of the settlement before the court hearing.","options":["finalize","finalize","final","finally"],"answer":0,"explanation":"✅ <b>Finalize</b> (Hoàn thiện)."},{"id":"b9-5-27","part":5,"type":"preposition","question":"The office is conveniently located _____ walking distance of the subway station.","options":["at","in","within","by"],"answer":2,"explanation":"✅ <b>Within</b> walking distance."},{"id":"b9-5-28","part":5,"type":"conjunction","question":"The system is currently offline _____ maintenance work is being performed.","options":["so","because","but","while"],"answer":3,"explanation":"✅ <b>While</b>."},{"id":"b9-5-29","part":5,"type":"verb-tense","question":"The researcher _____ her findings at the international conference next week.","options":["presented","presents","will present","has presented"],"answer":2,"explanation":"✅ <b>Will present</b>."},{"id":"b9-5-30","part":5,"type":"adverb-time","question":"The merger will be finalized _____ the shareholders give their approval.","options":["once","meanwhile","during","since"],"answer":0,"explanation":"✅ <b>Once</b> (Ngay khi)."},{"id":"b9-5-31","part":5,"type":"vocabulary-context","question":"To stay competitive, the firm must _____ new technologies into its production process.","options":["integrate","implicate","indicate","instigated"],"answer":0,"explanation":"✅ <b>Integrate</b> (Tích hợp)."},{"id":"b9-5-32","part":5,"type":"prep-structures","question":"Employees are selected based _____ their experience and technical skills.","options":["on","with","at","for"],"answer":0,"explanation":"✅ <b>Based on</b>."},{"id":"b9-5-33","part":5,"type":"inversion","question":"Rarely _____ seen such a high level of dedication in a junior employee.","options":["the manager has","has the manager","did the manager","the manager did"],"answer":1,"explanation":"✅ <b>Has the manager</b>."},{"id":"b9-5-34","part":5,"type":"quantifiers","question":"_____ information regarding the new benefits package is available on the internal portal.","options":["Many","Further","A few","Long"],"answer":1,"explanation":"✅ <b>Further</b> (Thêm thông tin)."},{"id":"b9-5-35","part":5,"type":"business-english","question":"Attached is the _____ for tomorrow's executive board meeting.","options":["agenda","address","affidavit","agency"],"answer":0,"explanation":"✅ <b>Agenda</b> (Chương trình nghị sự)."},{"id":"b9-5-36","part":5,"type":"subjunctive","question":"It is vital that the safety protocols _____ followed strictly at all times.","options":["are","be","being","to be"],"answer":1,"explanation":"✅ <b>Be</b>."},{"id":"b9-5-37","part":5,"type":"word-form","question":"The CEO was impressed by the _____ shown by the research team.","options":["creative","creativity","creatively","created"],"answer":1,"explanation":"✅ <b>Creativity</b> (Danh từ)."},{"id":"b9-5-38","part":5,"type":"vocabulary","question":"The warehouse operates at full _____ during the holiday shopping season.","options":["capacity","capture","capital","caption"],"answer":0,"explanation":"✅ <b>Capacity</b>."},{"id":"b9-5-39","part":5,"type":"preposition","question":"Please refrain _____ making personal phone calls during office hours.","options":["to","with","from","at"],"answer":2,"explanation":"✅ <b>Refrain from</b>."},{"id":"b9-5-40","part":5,"type":"conjunction","question":"_____ the weather was poor, the flight departed on schedule.","options":["Because","Although","Despite","Unless"],"answer":1,"explanation":"✅ <b>Although</b>."}],"part6":[{"passage":"To: All Staff\nFrom: HR Department\nSubject: Annual Performance Reviews\n\nDear Team,\n\nThis is a reminder that annual performance reviews will (1)_____ next month. All managers should (2)_____ their team members in advance to discuss goals and overall performance for the year. Evaluation forms are (3)_____ on the company intranet. Please complete them prior to your scheduled meeting. If you have any questions, (4)_____ contact the HR department at extension 204.","passageTitle":null,"type":"single","questions":[{"id":"p6-1a","part":6,"qNum":1,"question":"Blank (1):","options":["take place","take over","take off","take up"],"answer":0,"explanation":"'Take place' = xảy ra, diễn ra. Đây là cụm cố định dùng cho sự kiện."},{"id":"p6-1b","part":6,"qNum":2,"question":"Blank (2):","options":["contact","contacted","contacting","to contact"],"answer":0,"explanation":"'Should + V (nguyên mẫu)'. Câu mệnh lệnh lịch sự với 'should'."},{"id":"p6-1c","part":6,"qNum":3,"question":"Blank (3):","options":["available","avail","availability","availably"],"answer":0,"explanation":"'Available' (tính từ) = có sẵn. Sau động từ 'are' cần tính từ."},{"id":"p6-1d","part":6,"qNum":4,"question":"(4) The correct sentence connector:","options":["please","however","although","because"],"answer":0,"explanation":"Câu mời/yêu cầu lịch sự bắt đầu câu mới → 'please'."}]},{"passage":"Dear Mr. Johnson,\n\nThank you for your inquiry (1)_____ our catering services. We (2)_____ in the industry for over fifteen years and pride ourselves on delivering high-quality food and service for corporate events of all sizes.\n\nWe (3)_____ be delighted to discuss your upcoming conference. Our event coordinator, Ms. Kim, will contact you (4)_____ the end of this week to arrange a consultation.\n\nSincerely,\nBlue Horizon Catering","passageTitle":null,"type":"single","questions":[{"id":"p6-2a","part":6,"qNum":1,"question":"Blank (1):","options":["beside","on","regarding","for"],"answer":2,"explanation":"'Regarding' = liên quan đến (giới từ trang trọng dùng trong email kinh doanh). 'Beside' = bên cạnh (sai nghĩa). 'On' và 'for' không dùng với 'inquiry' trong ngữ cảnh này."},{"id":"p6-2b","part":6,"qNum":2,"question":"(2) Correct verb form:","options":["are","have been","had been","were"],"answer":1,"explanation":"'For over fifteen years' kết hợp với 'have been' → hiện tại hoàn thành."},{"id":"p6-2c","part":6,"qNum":3,"question":"(3) Correct modal:","options":["must","can","would","shall"],"answer":2,"explanation":"'Would be delighted' = lịch sự, trang trọng. Phù hợp ngữ cảnh email kinh doanh."},{"id":"p6-2d","part":6,"qNum":4,"question":"(4) Correct preposition:","options":["until","by","in","on"],"answer":1,"explanation":"'By the end of this week' = trước cuối tuần này (deadline). 'By' dùng cho thời hạn."}]},{"passage":"Notice: Office Renovation\n\nPlease be (1)_____ that the third-floor office spaces will undergo renovation starting Monday, March 10th. During this period, those staff members (2)_____ on this floor will be temporarily relocated to the fifth floor. Access to the third floor will be (3)_____.\n\nWe apologize for any inconvenience this may cause. The renovation is (4)_____ to be completed by April 5th. Thank you for your patience.","passageTitle":null,"type":"single","questions":[{"id":"p6-3a","part":6,"qNum":1,"question":"Blank (1):","options":["known","aware","informed","advised"],"answer":3,"explanation":"'Please be advised that' = xin thông báo rằng. Cụm cố định trong thông báo chính thức."},{"id":"p6-3b","part":6,"qNum":2,"question":"(2) Correct relative structure:","options":["who work","that worked","whose work","working"],"answer":0,"explanation":"'Staff members who work on this floor' = nhân viên làm việc ở tầng này."},{"id":"p6-3c","part":6,"qNum":3,"question":"(3) Correct adjective:","options":["closed","restricted","limited","reduced"],"answer":1,"explanation":"'Access will be restricted' = quyền truy cập sẽ bị hạn chế (cụm phổ biến trong thông báo)."},{"id":"p6-3d","part":6,"qNum":4,"question":"(4) Correct verb/adjective:","options":["expected","planned","scheduled","supposed"],"answer":2,"explanation":"'Scheduled to be completed' = được lên lịch hoàn tất (chính xác nhất trong ngữ cảnh kế hoạch cụ thể)."}]},{"passage":"To: All Department Managers\nFrom: Human Resources\nSubject: Updated Performance Review Process\n\nDear Managers,\n\nWe are writing to inform you of changes to the annual performance review process that will take effect beginning this cycle.\n\nFirst, all employees ____(1)____ receive a self-assessment form one week before their scheduled review. Second, managers are required to document ____(2)____ specific examples of each employee's contributions. This change is intended to make reviews more objective and fair. Finally, all completed review forms ____(3)____ to HR no later than November 30.\n\nWe believe these changes will help create a more transparent and ____(4)____ evaluation process. Please contact the HR team if you have any questions.\n\nBest regards,\nHuman Resources Department","passageTitle":null,"type":"single","questions":[{"id":"n6-1a","part":6,"question":"Choose the correct answer for blank (1):","options":["will","would","should have","had"],"answer":0,"explanation":"✅ <b>Will</b>. <br>💡 <i>Ngữ cảnh:</i> Thông báo về quy trình mới sắp áp dụng (take effect) nên dùng Tương lai đơn."},{"id":"n6-1b","part":6,"question":"Choose the correct answer for blank (2):","options":["at least two","almost never","rarely any","few or no"],"answer":0,"explanation":"✅ <b>At least two</b>. <br>💡 <i>Logics:</i> Yêu cầu manager ghi lại ví dụ cụ thể thì phải là số lượng 'ít nhất 2' mới hợp lý cho một bản review."},{"id":"n6-1c","part":6,"question":"Choose the correct answer for blank (3):","options":["must submit","must be submitted","should submit","are submitting"],"answer":1,"explanation":"✅ <b>Must be submitted</b> (Bị động). <br>💡 <i>Phân tích:</i> Forms (mẫu đơn) 'phải được nộp' trước hạn chót."},{"id":"n6-1d","part":6,"question":"Choose the correct answer for blank (4):","options":["consequence","consistent","consistently","consequential"],"answer":1,"explanation":"'Consistent' (tính từ) = nhất quán. Cấu trúc song song: 'transparent AND consistent' — hai tính từ. 'Consequence' và 'consequential' sai nghĩa; 'consistently' là phó từ, không đứng trước danh từ."}]},{"passage":"Dear Valued Customer,\n\nThank you for your continued patronage of BrightClean Laundry Services. We are pleased to announce that we will be ____(1)____ our service offerings beginning March 1.\n\nIn addition to our standard dry cleaning and garment care, we will now offer same-day express service for items dropped off before 10:00 a.m. ____(2)____, our new pickup and delivery option will be available to customers within a 10-kilometer radius of any of our three locations.\n\nTo celebrate these additions, all customers who register for our loyalty card this month will receive a 20% discount ____(3)____ their first five orders. We hope these enhancements demonstrate our ongoing commitment to providing you with ____(4)____ service.\n\nWarm regards,\nThe BrightClean Team","passageTitle":null,"type":"single","questions":[{"id":"n6-2a","part":6,"question":"Choose the correct answer for blank (1):","options":["expanding","reducing","suspending","reviewing"],"answer":0,"explanation":"✅ <b>Expanding</b> (Mở rộng). <br>💡 Câu sau liệt kê dịch vụ mới (express service, pickup) → đang mở rộng quy mô."},{"id":"n6-2b","part":6,"question":"Choose the correct answer for blank (2):","options":["In contrast","Furthermore","Nevertheless","Instead"],"answer":1,"explanation":"✅ <b>Furthermore</b> (Hơn nữa). <br>💡 Dùng để bổ sung thêm một tin vui/thông tin tích cực khác cùng chiều."},{"id":"n6-2c","part":6,"question":"Choose the correct answer for blank (3):","options":["off","on","at","for"],"answer":0,"explanation":"✅ <b>Off</b>. <br>💡 <i>Cụm cố định:</i> 'A discount off something' (Giảm giá bao nhiêu phần trăm trên giá gốc)."},{"id":"n6-2d","part":6,"question":"Choose the correct answer for blank (4):","options":["inconvenient","exceptional","average","infrequent"],"answer":1,"explanation":"✅ <b>Exceptional</b> (Xuất sắc/Đặc biệt). <br>💡 Lời hứa về dịch vụ của doanh nghiệp luôn dùng các từ mang nghĩa cực kỳ tốt."}]},{"passage":"NOTICE TO ALL TENANTS\n\nRe: Building Maintenance Schedule – Elevator Servicing\n\nDear Residents of Harborview Towers,\n\nThis notice is to inform you that the elevators in Building A will undergo ____(1)____ maintenance from Saturday, April 12 to Sunday, April 13. During this period, the elevators will be completely out of service.\n\n____(2)____, residents requiring assistance with moving heavy items between floors should contact building management at least 24 hours in advance so that we can make arrangements.\n\nWe apologize for any inconvenience this may cause and appreciate your patience. The maintenance is ____(3)____ to prevent more serious problems in the future and to ensure the safety of all residents. For urgent matters, please contact the front desk, which will be ____(4)____ 24 hours a day during the maintenance period.\n\nSincerely,\nHarborview Towers Management","passageTitle":null,"type":"single","questions":[{"id":"n6-3a","part":6,"question":"Choose the correct answer for blank (1):","options":["scheduled","surprising","optional","brief"],"answer":0,"explanation":"✅ <b>Scheduled</b> (Theo lịch). <br>💡 'Scheduled maintenance' là cụm từ chuẩn cho các thông báo bảo trì tòa nhà."},{"id":"n6-3b","part":6,"question":"Choose the correct answer for blank (2):","options":["As a result","In addition","Consequently","Therefore"],"answer":1,"explanation":"✅ <b>In addition</b> (Ngoài ra). <br>💡 Bổ sung thêm hướng dẫn cho cư dân khi thang máy hỏng."},{"id":"n6-3c","part":6,"question":"Choose the correct answer for blank (3):","options":["required","unnecessary","recommended","intended"],"answer":3,"explanation":"✅ <b>Intended</b>. <br>💡 <i>Cấu trúc:</i> 'Be intended to do something' (Nhằm mục đích làm gì)."},{"id":"n6-3d","part":6,"question":"Choose the correct answer for blank (4):","options":["staffed","closed","renovated","relocated"],"answer":0,"explanation":"✅ <b>Staffed</b> (Có nhân viên trực). <br>💡 Thông báo quầy lễ tân sẽ 'có người trực' 24/24 để hỗ trợ khách."}]},{"passage":"From: Oliver Grant <o.grant@paxtongroup.com>\nTo: All Staff\nSubject: Introduction of New Expense Reporting System\n\nDear Colleagues,\n\nAs of April 1, Paxton Group will transition from paper-based expense forms to a new digital expense reporting platform, ExpenseLink Pro. This change is ____(1)____ to streamline the approval process and reduce processing times.\n\nAll employees will be required to attend a 45-minute training session to familiarize ____(2)____ with the new system. Sessions will be held twice daily from March 20 through March 28.\n\n____(3)____, paper forms will no longer be accepted after March 31. Any expenses submitted on paper after this date will not be processed and will need to be resubmitted digitally.\n\nPlease do not hesitate to contact the Finance Department if you have any questions or concerns. We look forward to a ____(4)____ transition.\n\nBest regards,\nOliver Grant\nChief Financial Officer","passageTitle":null,"type":"single","questions":[{"id":"n6-4a","part":6,"question":"Choose the correct answer for blank (1):","options":["designed","refused","hesitated","delayed"],"answer":0,"explanation":"✅ <b>Designed</b>. <br>💡 <i>Collocation:</i> 'Be designed to do something' (Được thiết kế nhằm...). Dùng cho phần mềm/hệ thống."},{"id":"n6-4b","part":6,"question":"Choose the correct answer for blank (2):","options":["them","themselves","their","they"],"answer":1,"explanation":"✅ <b>Themselves</b>. <br>💡 <i>Cụm cố định:</i> 'Familiarize themselves with' (Làm quen với cái gì)."},{"id":"n6-4c","part":6,"question":"Choose the correct answer for blank (3):","options":["In the meantime","On the other hand","Please note that","Despite this"],"answer":2,"explanation":"✅ <b>Please note that</b> (Xin lưu ý rằng). <br>💡 Dẫn dắt vào một quy định quan trọng bắt buộc phải tuân theo."},{"id":"n6-4d","part":6,"question":"Choose the correct answer for blank (4):","options":["difficult","smooth","sudden","lengthy"],"answer":1,"explanation":"✅ <b>Smooth</b> (Suôn sẻ). <br>💡 'A smooth transition' là mong muốn chung khi thay đổi hệ thống."}]},{"passage":"GREENFIELD COMMUNITY CENTER\nNewsletters – Spring Edition\n\nSpring Programs Now Open for Registration!\n\nGreenfield Community Center is delighted to announce its spring program lineup, which ____(1)____ fitness, arts, and youth development. Registration is now open for all community members aged 5 and above.\n\nHighlights this season include a new Photography for Beginners course, a ten-week yoga series for seniors, and a weekend robotics camp for children aged 8–14. All programs are ____(2)____ by qualified instructors with extensive backgrounds in their fields.\n\n____(3)____, members who register before March 10 will receive a 15% early-bird discount. Membership is not required to enroll in programs, but members enjoy priority registration and reduced fees throughout the year.\n\nFor a complete program guide and registration details, please ____(4)____ our website at www.greenfieldcc.org or visit the center during regular hours.\n\nWe look forward to seeing you this spring!","passageTitle":null,"type":"single","questions":[{"id":"n6-5a","part":6,"question":"Choose the correct answer for blank (1):","options":["concludes","spans","lacks","avoids"],"answer":1,"explanation":"✅ <b>Spans</b> (Trải rộng/Bao trùm). <br>💡 Chỉ chương trình bao gồm nhiều lĩnh vực khác nhau."},{"id":"n6-5b","part":6,"question":"Choose the correct answer for blank (2):","options":["led","refused","declined","cancelled"],"answer":0,"explanation":"✅ <b>Led</b> (Dẫn dắt). <br>💡 <i>Bị động:</i> 'Led by instructors' (Được phụ trách bởi các giảng viên)."},{"id":"n6-5c","part":6,"question":"Choose the correct answer for blank (3):","options":["However","As a reminder","Consequently","Nevertheless"],"answer":1,"explanation":"✅ <b>As a reminder</b> (Nhắc nhở nhẹ). <br>💡 Dẫn dắt thông tin về ưu đãi khuyến mại cần ghi nhớ."},{"id":"n6-5d","part":6,"question":"Choose the correct answer for blank (4):","options":["avoid","visit","deactivate","contact"],"answer":1,"explanation":"✅ <b>Visit</b>. <br>💡 'Visit our website' là lời kêu gọi hành động (CTA) phổ biến."}]},{"passage":"Memo\n\nTo: Research & Development Team\nFrom: Dr. Sarah Okonkwo, Director of Innovation\nDate: September 4\nRe: Phase 2 Project Timelines\n\nDear Team,\n\nFollowing last week's project review meeting, I would like to ____(1)____ the key milestones for Phase 2 of the Helios Project.\n\nAs discussed, the prototype must be completed and ready for internal testing by October 15. The testing phase is ____(2)____ to run for approximately four weeks, after which a full report must be submitted to the executive board by November 30.\n\nI am aware that these timelines are demanding. ____(3)____, I am confident in each of your abilities and I am committed to providing whatever resources are necessary to support your work.\n\nPlease review the updated project schedule attached to this memo and confirm your availability for the first testing review, ____(4)____ for October 18.\n\nThank you for your continued dedication.\n\nDr. Sarah Okonkwo","passageTitle":null,"type":"single","questions":[{"id":"n6-6a","part":6,"question":"Choose the correct answer for blank (1):","options":["confirm","ignore","extend","remove"],"answer":0,"explanation":"✅ <b>Confirm</b> (Xác nhận). <br>💡 <i>Mục đích:</i> Email chốt lại các mốc thời gian đã thảo luận."},{"id":"n6-6b","part":6,"question":"Choose the correct answer for blank (2):","options":["scheduled","cancelled","avoided","dismissed"],"answer":0,"explanation":"✅ <b>Scheduled</b>. <br>💡 <i>Collocation:</i> 'Scheduled to run for...' (Dự kiến kéo dài trong...). "},{"id":"n6-6c","part":6,"question":"Choose the correct answer for blank (3):","options":["As a result","For instance","That said","In conclusion"],"answer":2,"explanation":"✅ <b>That said</b> (Dù vậy/Tuy nhiên). <br>💡 Dùng để chuyển hướng sau khi thừa nhận deadline căng thẳng nhưng vẫn tin tưởng team."},{"id":"n6-6d","part":6,"question":"Choose the correct answer for blank (4):","options":["tentatively scheduled","already cancelled","recently approved","currently ongoing"],"answer":0,"explanation":"✅ <b>Tentatively scheduled</b> (Dự kiến tạm thời). <br>💡 <i>Từ khóa 2025:</i> 'Tentatively' ám chỉ lịch trình có thể thay đổi tùy tình hình."}]},{"passage":"ANNOUNCEMENT\n\nTo: All Staff\nFrom: CEO's Office\nSubject: Workplace Flexibility Policy Update\n\nWe are pleased to announce a significant update to our workplace flexibility policy, effective the first Monday of next month.\n\nEmployees in eligible roles will now be ____(1)____ to choose between three working arrangements: fully on-site, hybrid (three days in office), or fully remote. Managers will review each request and confirm arrangements within five ____(2)____ days.\n\nWe believe this change reflects our commitment to employee well-being ____(3)____ maintaining the high standards of collaboration and performance our clients expect. Detailed guidelines will be shared via the company intranet.\n\n____(4)____, if you have any questions, please contact your HR business partner directly.","passageTitle":null,"type":"single","questions":[{"id":"b6-1a","part":6,"question":"Blank (1):","options":["allowed","permitting","let","enable"],"answer":0,"explanation":"'Be allowed to' = được phép (bị động với modal sense)."},{"id":"b6-1b","part":6,"question":"Blank (2):","options":["business","working","calendar","office"],"answer":0,"explanation":"'Five business days' = 5 ngày làm việc (cụm cố định trong văn bản công ty)."},{"id":"b6-1c","part":6,"question":"Blank (3):","options":["despite","while","however","whereas"],"answer":1,"explanation":"'While maintaining' = trong khi vẫn duy trì. 'While' chỉ sự đồng thời không mâu thuẫn."},{"id":"b6-1d","part":6,"question":"Blank (4):","options":["In the meantime","As a reminder","In conclusion","That said"],"answer":1,"explanation":"'As a reminder' = nhắc lại. Câu cuối nhắc cách liên hệ HR."}]},{"passage":"From: David Okafor <d.okafor@nexuspartners.com>\nTo: Customer Support <support@primelogistics.com>\nDate: February 14\n\nDear Prime Logistics Support Team,\n\nI am writing to follow up on shipment #PL-7782, which was ____(1)____ to arrive at our warehouse on February 10. As of today, the tracking portal shows the package is still in transit with no estimated delivery date.\n\nThis delay is causing significant disruption to our operations, as the goods contained in this shipment are urgently ____(2)____ for a production run scheduled for February 20.\n\nCould you please provide an ____(3)____ explanation of the delay and a confirmed delivery date? If delivery cannot be guaranteed before February 18, we may need to ____(4)____ alternative sourcing arrangements.\n\nThank you for your prompt attention to this matter.\n\nDavid Okafor","passageTitle":null,"type":"single","questions":[{"id":"b6-2a","part":6,"question":"Blank (1):","options":["scheduled","supposed","estimated","assumed"],"answer":0,"explanation":"'Scheduled to arrive' = được lên lịch giao vào ngày cụ thể (shipment booking). 'Supposed/estimated/assumed' đều chỉ phỏng đoán không chính thức, không dùng cho tracking shipment."},{"id":"b6-2b","part":6,"question":"Blank (2):","options":["needed","requested","required","demanded"],"answer":2,"explanation":"'Required for a production run' = cần thiết cho một đợt sản xuất. 'Required' mạnh nhất và phù hợp ngữ cảnh khẩn cấp."},{"id":"b6-2c","part":6,"question":"Blank (3):","options":["immediate","urgent","updated","detailed"],"answer":2,"explanation":"'Updated explanation' = giải thích cập nhật về tình trạng hiện tại. Phù hợp ngữ cảnh theo dõi đơn hàng."},{"id":"b6-2d","part":6,"question":"Blank (4):","options":["explore","consider","seek","pursue"],"answer":1,"explanation":"'Consider alternative sourcing' = cân nhắc nguồn cung thay thế. Lịch sự nhất trong ngữ cảnh này."}]},{"passage":"MEMORANDUM\n\nTo: All Research Staff\nFrom: Dr. Linda Marsh, Head of R&D\nDate: October 7\nRe: Updated Lab Access Protocols\n\nFollowing last month's safety review, the following updated protocols are now ____(1)____ for all laboratory access:\n\n1. All staff must obtain a new access badge from Security before October 15.\n2. Entry after 8:00 p.m. requires supervisor ____(2)____.\n3. Personal protective equipment (PPE) is ____(3)____ at all times in Lab Areas B and C.\n\nThese measures are ____(4)____ to prevent a recurrence of the minor incidents documented in the recent safety audit. Full compliance is expected by all personnel.\n\nPlease direct any questions to the Safety Officer, Mr. James Choo, at extension 4422.","passageTitle":null,"type":"single","questions":[{"id":"b6-3a","part":6,"question":"Blank (1):","options":["required","recommended","optional","requested"],"answer":0,"explanation":"'Now required for all laboratory access' = bắt buộc. Ngữ cảnh sau safety review."},{"id":"b6-3b","part":6,"question":"Blank (2):","options":["permission","approval","consent","authorization"],"answer":1,"explanation":"'Supervisor approval' = phê duyệt của cấp trên. 'Approval' phổ biến nhất trong văn bản nội bộ."},{"id":"b6-3c","part":6,"question":"Blank (3):","options":["optional","recommended","required","suggested"],"answer":2,"explanation":"'Required' = được quy định bắt buộc (ngôn ngữ chính sách). 'Optional' (tùy chọn) và 'suggested' (được đề xuất) trái nghĩa; 'recommended' (khuyến nghị) không đủ mạnh cho quy định bắt buộc."},{"id":"b6-3d","part":6,"question":"Blank (4):","options":["designed","intended","arranged","scheduled"],"answer":1,"explanation":"'Intended to prevent' = nhằm mục đích ngăn chặn (biện pháp/quy trình). 'Designed' dùng cho vật thể kỹ thuật; 'arranged' = được sắp xếp/tổ chức; 'scheduled' = được lên lịch."}]},{"passage":"NOVA FITNESS APP – PRODUCT UPDATE\nNewsletter | November Edition\n\nHello Nova Members,\n\nThis month's update brings exciting new ____(1)____ to the Nova Fitness App based on your valuable feedback.\n\nFirst, we have introduced a customizable dashboard that allows you to ____(2)____ the metrics most important to your personal fitness goals. Second, a new sleep tracking feature has been added to provide a ____(3)____ view of your overall health and recovery.\n\nThese updates are available now for both iOS and Android devices. To access them, ensure your app is updated to version 4.2 or ____(4)____.\n\nWe hope you enjoy these improvements. As always, we welcome your feedback through the in-app survey feature.","passageTitle":null,"type":"single","questions":[{"id":"b6-4a","part":6,"question":"Blank (1):","options":["features","functions","improvements","updates"],"answer":0,"explanation":"'New features' = tính năng mới. Từ phổ biến nhất khi nói về cập nhật phần mềm."},{"id":"b6-4b","part":6,"question":"Blank (2):","options":["prioritize","select","choose","track"],"answer":0,"explanation":"'Prioritize the metrics' = ưu tiên các chỉ số. Phù hợp ngữ cảnh tùy chỉnh dashboard."},{"id":"b6-4c","part":6,"question":"Blank (3):","options":["holistic","complete","overall","total"],"answer":0,"explanation":"'Holistic view of health' = cái nhìn toàn diện về sức khỏe. 'Holistic' là từ chuyên dùng trong wellness/fitness."},{"id":"b6-4d","part":6,"question":"Blank (4):","options":["above","higher","later","newer"],"answer":0,"explanation":"'Version 4.2 or above' = phiên bản 4.2 hoặc cao hơn. 'Or above/higher' cả hai đúng nhưng 'above' chuẩn nhất."}]},{"passage":"NOTICE TO ALL TENANTS\nSilverstone Business Park – Building C\n\nThis notice is to advise all tenants of upcoming ____(1)____ to the parking facility located adjacent to Building C.\n\nBeginning Monday, September 9, parking spaces 1 through 50 will be temporarily unavailable for a period of three weeks. During this time, tenants may use the overflow parking lot ____(2)____ across Ferndale Road.\n\nWe regret any inconvenience this may cause. ____(3)____, we wish to reassure all tenants that the renovation will significantly improve the overall capacity and safety of the facility.\n\nFor any urgent inquiries, please contact the Building Management Office on the ground floor or call 555-0198. We appreciate your ____(4)____ during this period.","passageTitle":null,"type":"single","questions":[{"id":"b6-5a","part":6,"question":"Blank (1):","options":["renovations","constructions","repairs","installations"],"answer":0,"explanation":"'Upcoming renovations' = sắp tiến hành cải tạo. Phổ biến nhất cho facility improvement."},{"id":"b6-5b","part":6,"question":"Blank (2):","options":["located","situated","placed","found"],"answer":0,"explanation":"'Located across' = nằm ở phía bên kia. 'Located' là participle phổ biến nhất."},{"id":"b6-5c","part":6,"question":"Blank (3):","options":["However","Therefore","Moreover","Nonetheless"],"answer":3,"explanation":"'Nonetheless' = tuy nhiên. Mặc dù bất tiện → nhưng muốn trấn an (tương phản nhẹ)."},{"id":"b6-5d","part":6,"question":"Blank (4):","options":["patience","understanding","cooperation","support"],"answer":1,"explanation":"'Appreciate your understanding' = trân trọng sự thông cảm. Cụm kết thúc thông báo chuẩn nhất."}]},{"passage":"From: Priya Nair <p.nair@globaledge.org>\nTo: All Registered Delegates\nDate: June 3\n\nDear Delegates,\n\nWe are delighted to confirm your registration for the Global Edge Leadership Forum, ____(1)____ on June 25–27 at the Elara Convention Centre.\n\nYour delegate package includes full access to all keynote sessions, workshops, and networking events. Lunch and refreshments will be ____(2)____ on all three days. Please note that dinner on June 25 is not included and is at your own ____(3)____.\n\nA detailed program schedule and venue map will be emailed to you one week before the event. We kindly ask all delegates to carry their confirmation email or printed badge at all times for ____(4)____ purposes.\n\nWe look forward to welcoming you at the Forum.\n\nWarm regards,\nPriya Nair\nEvents Coordinator, Global Edge","passageTitle":null,"type":"single","questions":[{"id":"b6-6a","part":6,"question":"Blank (1):","options":["scheduled","taking place","held","occurring"],"answer":0,"explanation":"'Scheduled on June 25–27' = được lên lịch vào ngày... (participle modifier)."},{"id":"b6-6b","part":6,"question":"Blank (2):","options":["provided","charged","sold","cooked"],"answer":0,"explanation":"'Provided' = được cung cấp (bị động chuẩn cho dịch vụ ăn uống tại sự kiện). 'Charged' = bị tính phí (nghĩa ngược lại); 'sold' và 'cooked' không phù hợp văn phong thông báo sự kiện."},{"id":"b6-6c","part":6,"question":"Blank (3):","options":["expense","cost","charge","bill"],"answer":0,"explanation":"'At your own expense' = tự chi trả (cụm cố định). Không thể thay thế bằng các từ khác."},{"id":"b6-6d","part":6,"question":"Blank (4):","options":["identification","security","verification","authentication"],"answer":0,"explanation":"'For identification purposes' = cho mục đích nhận dạng/kiểm tra danh tính (cụm cố định chuẩn)."}]},{"passage":"Crestwood Financial Services\n875 Bay Avenue, Suite 200\nVancouver, BC\n\nApril 15\n\nDear Ms. Fujimoto,\n\nOn behalf of Crestwood Financial Services, I am pleased to ____(1)____ you a formal offer of employment for the position of Senior Risk Analyst.\n\nYour starting annual salary will be CAD 98,000, with eligibility for a performance bonus of up to 15% ____(2)____ on your year-end review. You will also receive a comprehensive benefits package, including health, dental, and vision coverage, as well as five weeks of ____(3)____ leave per year.\n\nYour anticipated start date is May 1. Please ____(4)____ your acceptance of this offer by April 22 by signing and returning the enclosed contract.\n\nWe are excited about the prospect of you joining our team.\n\nSincerely,\nRobert Hall\nHead of Human Resources","passageTitle":null,"type":"single","questions":[{"id":"b6-7a","part":6,"question":"Blank (1):","options":["extend","give","provide","offer"],"answer":0,"explanation":"'Extend a formal offer' = gửi lời mời chính thức (formal collocation trong offer letter)."},{"id":"b6-7b","part":6,"question":"Blank (2):","options":["based","depending","subject","contingent"],"answer":0,"explanation":"'Based on your year-end review' = dựa trên đánh giá cuối năm (collocation chuẩn)."},{"id":"b6-7c","part":6,"question":"Blank (3):","options":["annual","paid","compensated","earned"],"answer":1,"explanation":"'Paid leave' = nghỉ có lương (cụm cố định trong HR)."},{"id":"b6-7d","part":6,"question":"Blank (4):","options":["confirm","acknowledge","sign","indicate"],"answer":0,"explanation":"'Confirm your acceptance' = xác nhận chấp nhận (cụm cố định trong offer letter)."}]},{"passage":"From: Customer Relations <support@oriontech.com>\nTo: Samuel Wu <s.wu@email.com>\nDate: March 18\n\nDear Mr. Wu,\n\nThank you for ____(1)____ out to us regarding your recent experience with our OrionCloud subscription service.\n\nWe sincerely apologize for the technical difficulties you ____(2)____ during the billing process. After reviewing your account, we can confirm that you were incorrectly charged twice for your February subscription. A full refund of USD 49.99 has been ____(3)____ to your original payment method and should appear within 3–5 business days.\n\nWe have also applied a one-month complimentary subscription to your account as a gesture of goodwill. We hope this ____(4)____ for the inconvenience caused.\n\nPlease do not hesitate to contact us if you require any further assistance.\n\nBest regards,\nOrion Technologies Customer Relations","passageTitle":null,"type":"single","questions":[{"id":"b6-8a","part":6,"question":"Blank (1):","options":["reaching","getting","contacting","writing"],"answer":0,"explanation":"'Thank you for reaching out to us' = cảm ơn đã liên hệ (cụm cố định trong customer service)."},{"id":"b6-8b","part":6,"question":"Blank (2):","options":["experienced","encountered","suffered","faced"],"answer":1,"explanation":"'Encountered difficulties' = gặp phải khó khăn. 'Encountered' phổ biến nhất với 'difficulties/issues'."},{"id":"b6-8c","part":6,"question":"Blank (3):","options":["issued","returned","processed","credited"],"answer":0,"explanation":"'Refund has been issued' = hoàn tiền đã được xử lý/phát hành. 'Issued' chuẩn nhất cho refund."},{"id":"b6-8d","part":6,"question":"Blank (4):","options":["compensates","makes up","accounts","corrects"],"answer":0,"explanation":"'Compensates for the inconvenience' = bù đắp sự bất tiện (collocation cố định)."}]},{"passage":"From: Operations Director\nTo: All Store Managers\nDate: November 12\nSubject: Updated Returns and Exchanges Policy\n\nDear Team,\n\nI am writing to inform you of changes to our retail returns and exchange policy, ____(1)____ on December 1.\n\nKey changes include: extended return window from 14 to 30 days for all full-priced items; exchanges ____(2)____ without a receipt for items purchased using a loyalty card, as purchases can be verified in our system; and a new tiered refund structure for sale items depending on the discount level applied at the time of purchase.\n\nFull details and updated training materials will be available on the staff portal by November 22. All store managers are ____(3)____ to brief their teams before the policy takes effect.\n\n____(4)____ let us know if you foresee any operational challenges in implementing these changes at your location.\n\nBest regards,\nLinda Frost\nOperations Director","passageTitle":null,"type":"single","questions":[{"id":"c6-1a","part":6,"question":"Blank (1):","options":["effective","effecting","effectively","effected"],"answer":0,"explanation":"'Effective on December 1' = có hiệu lực vào ngày 1/12. 'Effective' dùng như tính từ/giới từ để chỉ ngày có hiệu lực."},{"id":"c6-1b","part":6,"question":"Blank (2):","options":["will allow","are allowed","allowing","allowed"],"answer":1,"explanation":"'Exchanges are allowed without a receipt' = đổi hàng không cần biên lai (bị động hiện tại). Phù hợp ngữ cảnh chính sách."},{"id":"c6-1c","part":6,"question":"Blank (3):","options":["expected","suggested","invited","welcomed"],"answer":0,"explanation":"'Are expected to brief their teams' = được kỳ vọng/yêu cầu thông báo cho nhóm. 'Expected' có tính bắt buộc phù hợp với chính sách mới."},{"id":"c6-1d","part":6,"question":"Blank (4):","options":["However","Therefore","Please","Despite"],"answer":2,"explanation":"'Please let us know' = xin hãy cho chúng tôi biết. Câu kêu gọi phản hồi từ store managers."}]},{"passage":"IMPORTANT NOTICE TO ALL SUPPLIERS\nTerraForm Manufacturing – Procurement Department\nDate: March 4\n\nDear Valued Supplier,\n\nAs part of our ongoing commitment to operational excellence, TerraForm Manufacturing is ____(1)____ a new Supplier Portal, launching April 1.\n\nStarting April 1, all invoices, delivery confirmations, and compliance documents must be submitted ____(2)____ through the portal. The current email-based submission process will be discontinued on that date.\n\nTo register for portal access, please visit suppliers.terraform-mfg.com and complete the online registration form. You will receive login credentials within three ____(3)____ days of submitting your registration.\n\n____(4)____, if you experience any difficulties registering, our Procurement Support team is available at procurement@terraform-mfg.com or +1 800 400 7700.\n\nWe appreciate your continued partnership and cooperation.\n\nTerraForm Procurement Team","passageTitle":null,"type":"single","questions":[{"id":"c6-2a","part":6,"question":"Blank (1):","options":["introducing","launching","opening","creating"],"answer":0,"explanation":"'Introducing a new Supplier Portal' = giới thiệu/triển khai cổng nhà cung cấp mới. Phổ biến nhất trong announcement về hệ thống mới."},{"id":"c6-2b","part":6,"question":"Blank (2):","options":["exclusively","solely","only","primarily"],"answer":0,"explanation":"'Submitted exclusively through the portal' = phải nộp riêng qua cổng (không còn cách nào khác). 'Exclusively' mạnh và rõ ràng nhất."},{"id":"c6-2c","part":6,"question":"Blank (3):","options":["business","working","operating","weekday"],"answer":0,"explanation":"'Three business days' = 3 ngày làm việc. Cụm cố định phổ biến nhất trong văn bản thương mại."},{"id":"c6-2d","part":6,"question":"Blank (4):","options":["In the event","As a reminder","Meanwhile","On the other hand"],"answer":0,"explanation":"'In the event (that you experience difficulties)' = trong trường hợp gặp khó khăn. Phù hợp nhất với nội dung hỗ trợ kỹ thuật."}]},{"passage":"From: Isabel Ferreira <i.ferreira@grandviewhotels.com>\nTo: Reservations Team\nDate: August 9\n\nTeam,\n\nI would like to update you on a situation involving one of our long-standing guests, Mr. Robert Chu, who ____(1)____ with us every quarter for the past three years.\n\nMr. Chu contacted our front desk this morning to express his disappointment about a billing discrepancy he noticed on his most recent invoice. Specifically, he was charged for the premium breakfast package on two mornings when he had, in fact, ____(2)____ at 6:30 a.m. and would not have had time to use the service.\n\n____(3)____\n\nI would like someone from billing to contact Mr. Chu directly today to issue a full refund for the two incorrect charges and to apply a complimentary upgrade to his next reservation as a goodwill gesture. We must ensure that loyal guests like Mr. Chu ____(4)____ that their satisfaction is our top priority.\n\nIsabel Ferreira\nGuest Relations Manager","passageTitle":null,"type":"single","questions":[{"id":"c6-3a","part":6,"question":"Blank (1):","options":["is staying","has stayed","stayed","was staying"],"answer":1,"explanation":"'Has stayed with us every quarter for the past three years' = present perfect vì thói quen kéo dài đến hiện tại. 'For the past three years' là dấu hiệu."},{"id":"c6-3b","part":6,"question":"Blank (2):","options":["checked out","departed","left","exited"],"answer":0,"explanation":"'Checked out' = trả phòng (collocation chuẩn của khách sạn). Các từ còn lại kém chuyên nghiệp hơn."},{"id":"c6-3c","part":6,"question":"Blank (3) – Choose the best sentence:","options":["The hotel breakfast menu will be updated next season.","I have reviewed Mr. Chu's account and confirmed that the charges were made in error.","Mr. Chu is scheduled to arrive again on September 15.","Breakfast packages are available to all guests at an additional fee."],"answer":1,"explanation":"Câu trước mô tả vấn đề; câu tiếp theo nên xác nhận kết quả điều tra để dẫn vào hành động giải quyết. Chỉ đáp án B phù hợp logic."},{"id":"c6-3d","part":6,"question":"Blank (4):","options":["know","understand","feel","sense"],"answer":2,"explanation":"'Feel that their satisfaction is our top priority' = cảm thấy được ưu tiên. 'Feel' phù hợp nhất khi nói về trải nghiệm cảm xúc của khách hàng."}]},{"passage":"MEMO\nTo: All Employees\nFrom: Chief People Officer\nDate: June 18\n\nRe: Revisions to the Annual Leave Policy\n\nFollowing feedback gathered during our most recent employee engagement survey, we are pleased to announce revisions to the annual leave policy, effective July 1.\n\nThe most significant change is an increase in the standard annual leave ____(1)____ from 15 to 18 days for all employees who have completed one year of service. Employees with three or more years of service will be ____(2)____ to 22 days annually.\n\nIn addition, we are introducing one additional day of paid leave, to be ____(3)____ on an employee's birthday. This day must be taken within the same calendar month as the employee's birthday and cannot be carried over.\n\n____(4)____, we will be extending the deadline for submitting leave applications from two weeks' notice to one week, offering greater flexibility for short-notice personal requests.\n\nFull policy documentation will be circulated via the HR portal by June 25. Please direct any questions to hr@company.com.\n\nOffice of the Chief People Officer","passageTitle":null,"type":"single","questions":[{"id":"c6-4a","part":6,"question":"Blank (1):","options":["entitlement","allowance","provision","allocation"],"answer":0,"explanation":"'Annual leave entitlement' = quyền nghỉ phép theo quy định pháp lý. 'Allowance' = khoản trợ cấp tài chính (sai loại); 'provision' = điều khoản hợp đồng; 'allocation' = phân bổ nguồn lực."},{"id":"c6-4b","part":6,"question":"Blank (2):","options":["entitled","allowed","permitted","given"],"answer":0,"explanation":"'Entitled to 22 days' = có quyền được hưởng 22 ngày. 'Entitled to' là cụm cố định trong văn bản quyền lợi nhân viên."},{"id":"c6-4c","part":6,"question":"Blank (3):","options":["used","taken","spent","applied"],"answer":1,"explanation":"'A day to be taken on an employee's birthday' = một ngày được nghỉ vào ngày sinh nhật. 'Taken' là collocation chuẩn với 'leave/day off'."},{"id":"c6-4d","part":6,"question":"Blank (4):","options":["Furthermore","However","Therefore","As a result"],"answer":0,"explanation":"'Furthermore' = hơn nữa. Bổ sung thêm thay đổi thứ ba vào danh sách. Không có sự tương phản hay kết quả → 'However/Therefore' sai."}]},{"passage":"MEMO\nTo:   All Staff\nFrom: Finance Department\nDate: April 22\nRe:   Revised Expense Reimbursement Procedure\n\nPlease be ____(1)____ that the expense reimbursement process has been updated, effective May 1.\n\nGoing forward, all expense claims must be submitted through the new ExpenseHub portal at expensehub.company.com. Paper claim forms will no longer be ____(2)____ after April 30.\n\nClaims must be accompanied by original receipts or digital scans. Requests submitted without supporting documentation will be automatically ____(3)____ and will need to be resubmitted.\n\n____(4)____, the reimbursement processing time has been reduced from ten business days to five, provided that all required documentation is complete at the time of submission.\n\nIf you have any questions about the new process, please attend one of the drop-in sessions hosted by the Finance team every Tuesday in Room 2B.","passageTitle":null,"type":"single","questions":[{"id":"g6-1a","part":6,"question":"Blank (1):","options":["noted","reminded","advised","aware"],"answer":2,"explanation":"'Please be advised that' = kính thông báo rằng (cụm mở đầu thông báo chính thức, cố định). 'Reminded' dùng khi nhắc lại điều đã biết; 'noted' là V3 không phù hợp; 'aware' là tính từ, cần cấu trúc khác."},{"id":"g6-1b","part":6,"question":"Blank (2):","options":["allowed","accepted","valid","available"],"answer":1,"explanation":"'Will no longer be accepted' = sẽ không còn được chấp nhận. 'Accepted' dùng cho quy trình/tài liệu."},{"id":"g6-1c","part":6,"question":"Blank (3):","options":["denied","returned","rejected","declined"],"answer":2,"explanation":"'Automatically rejected' = tự động bị từ chối. 'Rejected' là thuật ngữ chuẩn cho yêu cầu không hợp lệ trong hệ thống."},{"id":"g6-1d","part":6,"question":"Blank (4):","options":["In addition","However","Therefore","As a result"],"answer":0,"explanation":"'In addition' = ngoài ra, thêm vào đó. Bổ sung thông tin tích cực (thời gian xử lý nhanh hơn)."}]},{"passage":"From: Customer Experience Team <support@arcadiahome.com>\nTo: [Customer Name]\nSubject: Important Update Regarding Your Order #AH-88712\n\nDear Valued Customer,\n\nWe are writing to ____(1)____ you that your order (#AH-88712) is experiencing an unexpected delay due to supply chain disruptions affecting several of our product lines.\n\nYour estimated delivery date has been revised from April 18 to April 28. We sincerely apologize for any inconvenience this may ____(2)____.\n\nAs a token of our appreciation for your patience, we have applied a USD 15 store credit to your account. This credit will be automatically ____(3)____ at checkout during your next purchase and requires no coupon code.\n\nShould you prefer to cancel your order instead, a full refund will be ____(4)____ to your original payment method within three to five business days. To cancel, please reply to this email or visit your account at arcadiahome.com/orders.\n\nWe value your trust and look forward to serving you.\n\nWarm regards,\nArcadia Home – Customer Experience","passageTitle":null,"type":"single","questions":[{"id":"g6-2a","part":6,"question":"Blank (1):","options":["inform","notify","advise","tell"],"answer":1,"explanation":"'Notify you that' = thông báo cho bạn về. 'Notify' là động từ chuẩn nhất trong email thông báo chậm giao hàng."},{"id":"g6-2b","part":6,"question":"Blank (2):","options":["bring","create","cause","make"],"answer":2,"explanation":"'Cause inconvenience' = gây bất tiện (collocation cố định, chuẩn nhất trong văn bản xin lỗi)."},{"id":"g6-2c","part":6,"question":"Blank (3):","options":["deducted","applied","redeemed","used"],"answer":0,"explanation":"'Automatically deducted at checkout' = tự động khấu trừ khi thanh toán. Đây là cụm kỹ thuật chuẩn trong e-commerce."},{"id":"g6-2d","part":6,"question":"Blank (4):","options":["sent","returned","processed","issued"],"answer":3,"explanation":"'Refund will be issued to your payment method' = hoàn tiền sẽ được phát hành về phương thức thanh toán. 'Issued' là từ kỹ thuật chuẩn cho refund."}]},{"passage":"STERLING ASSOCIATES QUARTERLY NEWSLETTER – Q2\n\nWe are delighted to ____(1)____ our Q2 newsletter, packed with updates on our recent projects, new team members, and upcoming industry events.\n\nThis quarter, Sterling Associates was recognised as one of the Top 50 Consulting Firms in Asia-Pacific by Business Insights Magazine — an ____(2)____ that reflects the dedication and expertise of every member of our team.","passageTitle":null,"type":"single","questions":[{"id":"g6-3a","part":6,"question":"Blank (1):","options":["release","present","share","introduce"],"answer":2,"explanation":"'Share our Q2 newsletter' = chia sẻ bản tin. 'Share' là lựa chọn tự nhiên nhất trong ngữ cảnh newsletter nội bộ/khách hàng."},{"id":"g6-3b","part":6,"question":"Blank (2):","options":["award","acknowledgment","honor","achievement"],"answer":3,"explanation":"'An achievement that reflects' = một thành tích phản ánh. 'Achievement' phù hợp nhất vì nó là kết quả của nỗ lực tập thể, không phải giải thưởng cụ thể."}]},{"passage":"PULSE – INTERNAL NEWSLETTER\nTerraGreen Energy | Monthly Edition\n\nENHANCED EMPLOYEE BENEFITS PACKAGE – LAUNCHING JULY 1\n\nWe are pleased to ____(1)____ that TerraGreen Energy will introduce an enhanced benefits package for all permanent employees, effective July 1.\n\nThe upgraded package includes an increase in the annual wellness allowance from USD 500 to USD 800, extended parental leave for both primary and secondary caregivers, and a new employee assistance programme ____(2)____ mental health support and financial counselling.\n\nIn addition, employees will be ____(3)____ access to the new TerraGreen Learning Hub — an online platform featuring over 2,000 courses in leadership, technology, and professional skills.\n\n____(4)____ about the new benefits package will be circulated to all employees via the HR portal by June 15. An information session will also be hosted on June 20 for those who have questions.","passageTitle":null,"type":"single","questions":[{"id":"h6-1a","part":6,"question":"Blank (1):","options":["confirm","declare","announce","notify"],"answer":2,"explanation":"'Pleased to announce' = vui mừng thông báo. Cụm mở đầu chuẩn trong thông báo tích cực nội bộ."},{"id":"h6-1b","part":6,"question":"Blank (2):","options":["providing","covering","offering","including"],"answer":3,"explanation":"'Programme including mental health support' = chương trình bao gồm hỗ trợ sức khỏe tâm thần. 'Including' là participle tự nhiên nhất để liệt kê nội dung chương trình."},{"id":"h6-1c","part":6,"question":"Blank (3):","options":["granted","permitted","given","offered"],"answer":0,"explanation":"'Granted access to' = được cấp quyền truy cập (cụm cố định trong văn bản IT/HR). 'Be granted access' là collocaton chuẩn nhất."},{"id":"h6-1d","part":6,"question":"Blank (4):","options":["Complete details","Full information","Comprehensive guidance","All documents"],"answer":0,"explanation":"'Complete details will be circulated' = thông tin đầy đủ sẽ được gửi đến. 'Complete details' là cụm tự nhiên nhất trong văn bản thông báo."}]},{"passage":"Pemberton Legal Associates\nSuite 1100, One Pacific Tower\nVancouver, BC V6E 4A2\nSeptember 5\n\nMr. Daniel Chow\nChief Procurement Officer\nBridgewater Manufacturing Ltd.\n300 Industrial Way, Burnaby, BC\n\nDear Mr. Chow,\n\nI am writing with ____(1)____ to the service agreement between Pemberton Legal Associates and Bridgewater Manufacturing Ltd., which is due for renewal on October 31.\n\nWe are pleased to confirm our continued interest in ____(2)____ the agreement for a further two-year term under the same service scope. However, we would like to propose a modest adjustment to the annual retainer — an increase of 4%, in line with the current consumer price index — effective from the renewal date.\n\nShould you wish to ____(3)____ the proposed terms, please do not hesitate to contact me directly. We would welcome the opportunity to meet in person to review the details before the renewal deadline.\n\nWe value our long-standing relationship with Bridgewater Manufacturing and look forward to your ____(4)____.\n\nYours sincerely,\nHelen Pemberton\nSenior Partner, Pemberton Legal Associates","passageTitle":null,"type":"single","questions":[{"id":"h6-2a","part":6,"question":"Blank (1):","options":["reference","regard","respect","relation"],"answer":1,"explanation":"'With regard to' = liên quan đến, về vấn đề (cụm giới từ cố định trong thư tín trang trọng)."},{"id":"h6-2b","part":6,"question":"Blank (2):","options":["extending","renewing","continuing","maintaining"],"answer":1,"explanation":"'Renewing the agreement' = gia hạn thỏa thuận. 'Renew a contract/agreement' là collocation chuẩn nhất."},{"id":"h6-2c","part":6,"question":"Blank (3):","options":["review","discuss","negotiate","consider"],"answer":2,"explanation":"'Discuss the proposed terms' = thảo luận về các điều khoản đề xuất. 'Discuss' phù hợp nhất trong ngữ cảnh mời gặp gỡ để làm rõ."},{"id":"h6-2d","part":6,"question":"Blank (4):","options":["reply","answer","response","feedback"],"answer":2,"explanation":"'Look forward to your response' = mong nhận được phản hồi của bạn. 'Response' là cụm kết thúc thư trang trọng chuẩn nhất."}]},{"passage":"VELOTECH ANNOUNCES NEXT-GENERATION SMARTWATCH — THE VELOWATCH X2\n\nVeloTech Corporation today ____(1)____ the launch of its most advanced wearable device to date, the VeloWatch X2, which features continuous health monitoring, a five-day battery life, and seamless integration with all major smartphone platforms.\n\nThe VeloWatch X2 will be ____(2)____ exclusively through VeloTech's official website and authorised retail partners beginning November 15, with global availability expected by year-end.","passageTitle":null,"type":"single","questions":[{"id":"h6-3a","part":6,"question":"Blank (1):","options":["released","unveiled","declared","proclaimed"],"answer":1,"explanation":"'Unveiled the launch' = công bố ra mắt. 'Unveiled' là từ mạnh nhất và chuyên biệt nhất khi nói về việc tiết lộ sản phẩm mới lần đầu."},{"id":"h6-3b","part":6,"question":"Blank (2):","options":["sold","distributed","available","released"],"answer":0,"explanation":"'Will be sold exclusively through' = sẽ được bán độc quyền qua. 'Sold through channels' là cụm phân phối chuẩn nhất."}]},{"passage":"Dear Valued Customer,\n\nThank you for choosing Skyline Airlines. We are writing to (1)_____ you of an upcoming change to our frequent flyer program. Effective March 1st, members will earn double miles on all international flights.\n\nAdditionally, we are (2)_____ a new tier called \"Platinum Elite\" for customers who fly more than 100,000 miles per year. Platinum Elite members will enjoy (3)_____ benefits including priority boarding, complimentary lounge access, and free seat upgrades.\n\nFor more details, (4)_____ visit our website at www.skylineair.com/rewards.\n\nBest regards,\nSkyline Airlines Customer Relations","passageTitle":null,"type":"single","questions":[{"id":"e6-1a","part":6,"qNum":1,"question":"Blank (1):","options":["inform","tell","say","speak"],"answer":0,"explanation":"'Inform you of' = thông báo cho bạn về (trang trọng, phù hợp email công ty)."},{"id":"e6-1b","part":6,"qNum":2,"question":"Blank (2):","options":["presenting","introducing","offering","starting"],"answer":1,"explanation":"'Introducing a new tier' = giới thiệu hạng mới (dùng khi ra mắt sản phẩm/dịch vụ mới)."},{"id":"e6-1c","part":6,"qNum":3,"question":"Blank (3):","options":["exclusive","expensive","excessive","extensive"],"answer":0,"explanation":"'Exclusive benefits' = quyền lợi độc quyền (collocation phổ biến trong chương trình khách hàng thân thiết)."},{"id":"e6-1d","part":6,"qNum":4,"question":"Blank (4):","options":["please","however","therefore","although"],"answer":0,"explanation":"'Please visit' = xin hãy truy cập. Câu mời lịch sự."}]},{"passage":"MEMO\nTo: All Department Heads\nFrom: Operations Manager\nDate: April 5\nRe: Energy Conservation Initiative\n\nAs part of our commitment to (1)_____ our environmental impact, we are launching a company-wide energy conservation program. Starting next Monday, the following measures will be (2)_____:\n\n• All lights in unoccupied offices must be turned off.\n• Thermostats should be set no lower than 24°C during summer.\n• Employees are encouraged to use public transportation (3)_____ driving to work.\n\nWe believe these small changes can make a (4)_____ difference in our energy consumption. Thank you for your cooperation.","passageTitle":null,"type":"single","questions":[{"id":"e6-2a","part":6,"qNum":1,"question":"Blank (1):","options":["increasing","reducing","expanding","maintaining"],"answer":1,"explanation":"'Reducing our environmental impact' = giảm tác động môi trường. Phù hợp ngữ cảnh tiết kiệm năng lượng."},{"id":"e6-2b","part":6,"qNum":2,"question":"Blank (2):","options":["imposed","implemented","imported","improved"],"answer":1,"explanation":"'Measures will be implemented' = các biện pháp sẽ được thực hiện (collocation chuẩn)."},{"id":"e6-2c","part":6,"qNum":3,"question":"Blank (3):","options":["despite","instead of","in addition to","regardless of"],"answer":1,"explanation":"'Instead of driving' = thay vì lái xe. Khuyến khích phương tiện công cộng thay vì xe cá nhân."},{"id":"e6-2d","part":6,"qNum":4,"question":"Blank (4):","options":["significant","slight","minor","marginal"],"answer":0,"explanation":"'Significant difference' = sự khác biệt đáng kể (collocation phổ biến, tích cực)."}]},{"passage":"Dear Ms. Park,\n\nI am pleased to confirm your (1)_____ at the Grand Meridian Hotel from June 12 to June 15. Your booking includes a Deluxe Suite with an ocean view.\n\nPlease note that check-in time is 3:00 p.m. and check-out is at 11:00 a.m. Should you need to arrive (2)_____, early check-in can be arranged for an additional fee of $50.\n\nComplimentary breakfast is (3)_____ daily from 7:00 a.m. to 10:00 a.m. in the Garden Restaurant on the ground floor.\n\nWe look forward to (4)_____ you at the Grand Meridian Hotel.\n\nSincerely,\nReservations Department","passageTitle":null,"type":"single","questions":[{"id":"e6-3a","part":6,"qNum":1,"question":"Blank (1):","options":["reservation","appointment","arrangement","subscription"],"answer":0,"explanation":"'Reservation' = đặt phòng. Đúng ngữ cảnh khách sạn."},{"id":"e6-3b","part":6,"qNum":2,"question":"Blank (2):","options":["late","soon","earlier","lately"],"answer":2,"explanation":"'Arrive earlier' = đến sớm hơn. 'Early check-in' = nhận phòng sớm."},{"id":"e6-3c","part":6,"qNum":3,"question":"Blank (3):","options":["served","provided","delivered","offered"],"answer":0,"explanation":"'Breakfast is served' = bữa sáng được phục vụ (collocation chuẩn khách sạn)."},{"id":"e6-3d","part":6,"qNum":4,"question":"Blank (4):","options":["greeting","welcoming","receiving","meeting"],"answer":1,"explanation":"'We look forward to welcoming you' = chúng tôi mong được chào đón bạn (cụm cố định trong hospitality)."}]},{"passage":"NOTICE\n\nEffective immediately, all employees are required to use the new digital time-tracking system, ClockSmart, to record their working hours. The previous paper-based system will be (1)_____ as of May 1.\n\nTraining sessions on how to use ClockSmart will be (2)_____ next week. Sessions are available on Tuesday and Thursday from 10:00 to 11:00 a.m. in Training Room A. Attendance is (3)_____.\n\nIf you experience any technical difficulties, please contact the IT Help Desk at extension 5501. We (4)_____ your patience during this transition.\n\nHuman Resources Department","passageTitle":null,"type":"single","questions":[{"id":"e6-4a","part":6,"qNum":1,"question":"Blank (1):","options":["discontinued","disconnected","discounted","discouraged"],"answer":0,"explanation":"'Discontinued' = ngừng sử dụng. Hệ thống cũ sẽ bị ngừng hoạt động."},{"id":"e6-4b","part":6,"qNum":2,"question":"Blank (2):","options":["conducted","directed","managed","operated"],"answer":0,"explanation":"'Training sessions will be conducted' = buổi tập huấn sẽ được tiến hành (collocation chuẩn)."},{"id":"e6-4c","part":6,"qNum":3,"question":"Blank (3):","options":["voluntary","mandatory","optional","recommended"],"answer":1,"explanation":"'Attendance is mandatory' = bắt buộc tham dự. Phù hợp ngữ cảnh 'required'."},{"id":"e6-4d","part":6,"qNum":4,"question":"Blank (4):","options":["appreciate","accept","acknowledge","admit"],"answer":0,"explanation":"'We appreciate your patience' = cảm ơn sự kiên nhẫn (cụm cố định trong thông báo)."}]},{"passage":"From:    Procurement Team <procurement@halversongroup.com>\nTo:      Oliver Chen <o.chen@deltapackaging.com>\nDate:    Tuesday, 4 November\nSubject: Contract Renewal – Packaging Supply Agreement\n\nDear Mr. Chen,\n\nI am writing on behalf of Halverson Group to express our continued interest in _____(1)_____ our supply agreement with Delta Packaging for another 12 months, commencing January 1.\n\nOver the past year, Delta Packaging has consistently delivered high-quality materials on schedule, and we have been extremely _____(2)_____ with the service and support provided by your account team. _____(3)_____\n\nFor the renewal, we would like to discuss the possibility of a modest volume discount, given that we expect to increase our order quantities by approximately 20 percent in the coming year. We believe a revised pricing structure would benefit both organisations.\n\nCould you please _____(4)_____ a convenient time for a call this week or early next week to discuss the terms? I look forward to hearing from you.\n\nYours sincerely,\nHelena Marsh\nSenior Procurement Manager, Halverson Group","passageTitle":null,"type":"single","questions":[{"id":"t8-p6-1a","part":6,"question":"... our continued interest in _____(1)_____ our supply agreement with Delta Packaging.","options":["renew","renewed","renewing","to be renewed"],"answer":2,"explanation":"'Interest in + V-ing' = cụm cố định (giới từ 'in' đòi hỏi danh động từ). 'Renewing' là danh động từ duy nhất phù hợp."},{"id":"t8-p6-1b","part":6,"question":"... we have been extremely _____(2)_____ with the service and support provided.","options":["satisfying","satisfaction","satisfactory","satisfied"],"answer":3,"explanation":"'Been satisfied with' = hài lòng với (tính từ bị động 'satisfied', dùng với chủ thể cảm nhận). 'Satisfying' dùng cho vật/sự việc gây ra cảm giác. 'Been satisfied with' là cấu trúc chuẩn sau 'have been extremely'."},{"id":"t8-p6-1c","part":6,"question":"_____(3)_____","options":["In particular, the expedited delivery during our peak season in August was greatly appreciated.","However, there were several quality issues reported during the third quarter.","We would also like to inform you that we are currently seeking alternative suppliers.","Please note that our procurement policy requires a minimum of three competitive bids."],"answer":0,"explanation":"Đoạn trước khen ngợi Delta Packaging về chất lượng và đúng lịch → câu thêm vào phải là ví dụ cụ thể minh họa cho sự khen ngợi đó. Option A (giao hàng nhanh trong mùa cao điểm) là bằng chứng tự nhiên nhất."},{"id":"t8-p6-1d","part":6,"question":"Could you please _____(4)_____ a convenient time for a call?","options":["propose","impose","expose","compose"],"answer":0,"explanation":"'Propose a time' = đề xuất một thời điểm (collocation chuẩn). 'Impose' = áp đặt; 'expose' = phơi bày; 'compose' = soạn thảo/sáng tác."}]},{"passage":"ANNOUNCEMENT\nTo:   All Employees\nFrom: People & Culture Department\nRe:   Introduction of Flexible Benefits Programme\nDate: November 10\n\nWe are pleased to announce the launch of Arcturus Holdings' new Flexible Benefits Programme, _____(1)_____ will take effect from 1 December.\n\nUnder the new programme, each employee will receive an annual benefits allowance of AUD 2,000. This allowance may be _____(2)_____ across a range of options, including additional annual leave, gym memberships, professional development courses, and private health insurance top-ups.\n\nEmployees are encouraged to log in to the HR portal to review the full list of available benefits and submit their selections by 20 November. _____(3)_____\n\nPlease note that unused allowances cannot be carried over to the following year. _____(4)_____, employees who do not make a selection by the deadline will have their allowance automatically directed to the default option: private health insurance.\n\nIf you have any questions about the programme, please contact the People & Culture team at people@arcturus.com.au.","passageTitle":null,"type":"single","questions":[{"id":"t8-p6-2a","part":6,"question":"... Arcturus Holdings' new Flexible Benefits Programme, _____(1)_____ will take effect from 1 December.","options":["that","what","which","it"],"answer":2,"explanation":"Mệnh đề quan hệ phi hạn định (non-defining relative clause) bổ sung thông tin cho danh từ 'Programme' → dùng 'which'. 'That' không dùng được trong mệnh đề phi hạn định có dấu phẩy."},{"id":"t8-p6-2b","part":6,"question":"This allowance may be _____(2)_____ across a range of options.","options":["allocated","collected","submitted","measured"],"answer":0,"explanation":"'Allowance allocated across options' = khoản trợ cấp được phân bổ vào các lựa chọn. 'Allocate' là thuật ngữ tài chính/HR chuẩn. 'Submitted' dùng cho tài liệu/đơn."},{"id":"t8-p6-2c","part":6,"question":"_____(3)_____","options":["Selections made after this date may not be processed in time for the December rollout.","The HR portal will be unavailable for maintenance on 18 and 19 November.","Employees who joined after October 1 are not eligible for the programme this year.","Professional development courses must be pre-approved by your line manager."],"answer":0,"explanation":"Sau deadline 20 November → câu tiếp theo hợp lý nhất là hệ quả nếu nộp trễ. Option A cảnh báo về nguy cơ không kịp xử lý cho đợt triển khai tháng 12."},{"id":"t8-p6-2d","part":6,"question":"_____(4)_____, employees who do not make a selection by the deadline will have their allowance automatically directed to the default option.","options":["In addition","Furthermore","Additionally","In this regard"],"answer":3,"explanation":"'In this regard' = về vấn đề này (liên kết với nội dung vừa đề cập – unused allowances). Các option A/B/C đều mang nghĩa 'thêm vào đó', nhưng 'In this regard' kết nối tốt nhất với câu liền trước về carry-over."}]},{"passage":"PINNACLE INSURANCE GROUP\nPolicy Renewal Notice\n\nDear Ms. Aldridge,\n\nYour commercial property insurance policy (No. CP-774812) is due for renewal on 1 December. We are pleased to confirm that your current _____(1)_____ of AUD 3,240 per annum remains unchanged for the coming year.\n\nYour policy provides comprehensive _____(2)_____ for the building structure, business contents, and public liability up to AUD 5 million. Please note that the standard excess — the amount you are required to pay when making a claim — is AUD 750 per incident.\n\n_____(3)_____ We recommend reviewing the policy schedule to ensure the insured values continue to reflect the current replacement cost of your assets.\n\nTo renew your policy, simply sign and return the enclosed form by 20 November, or log in to your account at pinnacleinsurance.com.au. _____(4)_____ one of our advisers will be happy to assist you.\n\nYours sincerely,\nMarcus Holt\nClient Relations, Pinnacle Insurance Group","passageTitle":null,"type":"single","questions":[{"id":"t9-p6-1a","part":6,"question":"... your current _____(1)_____ of AUD 3,240 per annum remains unchanged.","options":["premium","coverage","deductible","claim"],"answer":0,"explanation":"'Premium' = phí bảo hiểm hàng năm (annual premium). Đây là số tiền khách hàng đóng cho công ty bảo hiểm. 'Coverage' = phạm vi bảo hiểm; 'deductible' = mức khấu trừ."},{"id":"t9-p6-1b","part":6,"question":"Your policy provides comprehensive _____(2)_____ for the building structure.","options":["compliance","coverage","contingency","conversion"],"answer":1,"explanation":"'Coverage' = phạm vi bảo hiểm — những gì được bảo hiểm chi trả. Cụm 'comprehensive coverage' là collocation chuẩn trong ngành bảo hiểm ETS."},{"id":"t9-p6-1c","part":6,"question":"_____(3)_____","options":["Any changes to the property should be reported to us promptly to avoid gaps in coverage.","Your policy will be automatically cancelled if the renewal is not completed by the deadline.","Please note that flood damage is excluded from all standard commercial property policies.","A new claims form is available for download on our website."],"answer":0,"explanation":"Đoạn trước đề cập đến giá trị tài sản được bảo hiểm → câu tiếp theo hợp lý nhất là khuyến cáo báo cáo thay đổi tài sản. Option A nối tiếp logic về việc duy trì 'coverage' chính xác."},{"id":"t9-p6-1d","part":6,"question":"_____(4)_____ one of our advisers will be happy to assist you.","options":["Should you have any questions about your policy,","In the event that your claim is denied,","Once the premium has been paid in full,","Although the renewal process is straightforward,"],"answer":0,"explanation":"Câu kết hướng đến hỗ trợ khách hàng → mệnh đề điều kiện lịch sự 'Should you have any questions' là chuẩn nhất. Đây là cấu trúc đảo ngữ 'if you have' rất phổ biến trong ETS Part 6."}]},{"passage":"CORFIELD & ASSOCIATES — Staff Development Bulletin\n\nMANDATORY TRAINING: DATA PRIVACY AND INFORMATION SECURITY\n\nAll employees are _____(1)_____ to complete the updated Data Privacy and Information Security training module by 30 November. This requirement applies to permanent and contract staff across all departments.\n\nThe training is delivered entirely online and _____(2)_____ approximately 90 minutes to complete. Participants will be assessed at the end of the module, and a minimum score of 80 percent is required to receive a certificate of completion.\n\n_____(3)_____ Employees who do not meet the required score on their first attempt may retake the assessment up to two additional times.\n\nTo access the module, log in to the Learning Management System at lms.corfield.com using your employee credentials. _____(4)_____ completing the module, please forward your certificate to your line manager and the HR department.\n\nQuestions regarding the training should be directed to training@corfield.com.","passageTitle":null,"type":"single","questions":[{"id":"t9-p6-2a","part":6,"question":"All employees are _____(1)_____ to complete the updated training module by 30 November.","options":["required","advised","invited","encouraged"],"answer":0,"explanation":"'Required to' = bắt buộc phải. Phù hợp với 'mandatory training' trong tiêu đề. 'Advised/invited/encouraged' đều có nghĩa khuyến khích, không đủ mạnh cho ngữ cảnh bắt buộc."},{"id":"t9-p6-2b","part":6,"question":"The training is delivered entirely online and _____(2)_____ approximately 90 minutes to complete.","options":["takes","is taken","taking","has taken"],"answer":0,"explanation":"Chủ ngữ 'The training' + động từ chủ động hiện tại đơn → 'takes'. Cấu trúc 'it takes [time] to do' là cố định trong tiếng Anh."},{"id":"t9-p6-2c","part":6,"question":"_____(3)_____","options":["This certificate will be required for your annual performance review.","The module covers topics such as password security, phishing awareness, and data handling.","IT support is available Monday to Friday if you experience technical difficulties.","Employees who completed the previous version do not need to retake the training."],"answer":1,"explanation":"Câu trước nói về bài đánh giá cuối module → câu tiếp theo hợp lý nhất là mô tả nội dung học. Option B cung cấp thông tin cụ thể về chủ đề trong module."},{"id":"t9-p6-2d","part":6,"question":"_____(4)_____ completing the module, please forward your certificate to your line manager.","options":["Upon","Despite","While","Unless"],"answer":0,"explanation":"'Upon completing' = ngay sau khi hoàn thành (giới từ chỉ thời gian tức thì, văn phong trang trọng). Cấu trúc 'upon + V-ing' rất phổ biến trong ETS Part 6 formal announcements."}]},{"passage":"From: Facilities Management\nTo: All Building Tenants\nDate: May 12\nSubject: Scheduled Water Main Maintenance\n\nPlease be advised that the water supply to Building B will be ____(1)____ suspended on Saturday, May 15, from 8:00 a.m. to 4:00 p.m. This is necessary to facilitate critical repairs to the main water line.\n\n____(2)____, all restrooms and kitchen facilities on floors 1 through 10 will be unavailable during this time. We recommend that tenants who normally work on Saturdays make alternative arrangements ____(3)____ working from Building A or working remotely.\n\nWe apologize for any inconvenience this essential maintenance may cause. Normal water service is ____(4)____ to resume by 5:00 p.m. on Saturday.\n\nThank you for your cooperation.","passageTitle":null,"type":"single","questions":[{"id":"ex6-1a","part":6,"question":"Blank (1):","options":["permanently","temporarily","randomly","silently"],"answer":1,"explanation":"'Temporarily suspended' = tạm đình chỉ. Phù hợp với bảo trì theo lịch."},{"id":"ex6-1b","part":6,"question":"Blank (2):","options":["Consequently","However","In contrast","Nevertheless"],"answer":0,"explanation":"'Consequently' = Hậu quả là/Kết quả là. Chỉ hệ quả của việc ngắt nước."},{"id":"ex6-1c","part":6,"question":"Blank (3):","options":["such as","instead of","despite","regardless of"],"answer":0,"explanation":"'Such as' = như là (liệt kê các phương án thay thế)."},{"id":"ex6-1d","part":6,"question":"Blank (4):","options":["expected","denied","refused","cancelled"],"answer":0,"explanation":"'Expected to resume' = dự kiến tiếp tục lại."}]},{"passage":"To: All Sales Staff\nFrom: Marketing Director\nDate: June 15\nSubject: Third Quarter Strategy\n\nAs we approach the third quarter, it is imperative that we ____(1)____ our efforts to increase market share in the regional territories. Our recent survey shows that customer brand awareness is ____(2)____ than we initially projected.\n\n____(3)____, we will be launching a series of promotional events across major cities starting next month. All staff are required to attend a briefing session on Monday to discuss their specific roles. If you cannot attend, please ____(4)____ your manager as soon as possible.","passageTitle":null,"type":"single","questions":[{"id":"b9-6-1a","part":6,"question":"Blank (1):","options":["double","redouble","reduce","relax"],"answer":1,"explanation":"'Redouble efforts' = tăng cường nỗ lực (collocation)."},{"id":"b9-6-1b","part":6,"question":"Blank (2):","options":["lowly","lower","lowest","low"],"answer":1,"explanation":"So sánh hơn 'lower than'."},{"id":"b9-6-1c","part":6,"question":"Blank (3):","options":["However","Therefore","Moreover","Instead"],"answer":1,"explanation":"'Therefore' = Vì vậy (Kết quả của việc nhận diện thương hiệu thấp)."},{"id":"b9-6-1d","part":6,"question":"Blank (4):","options":["notify","notification","notifying","notified"],"answer":0,"explanation":"Động từ 'notify someone'."}]},{"passage":"Lumina Energy Solutions\nCustomer Satisfaction Survey\n\nDear Value Customer,\n\nAt Lumina Energy, we strive to provide the most ____(1)____ service in the industry. Your feedback is vital to our continuous improvement process. Please take a few minutes to complete the attached survey regarding your recent ____(2)____ of our home solar panel kit.\n\nAs a token of our appreciation, ____(3)____ who complete the survey by July 31 will be entered into a drawing for a $100 gift card. Thank you for your continued ____(4)____.\n\nSincerely,\nLumina Customer Relations","passageTitle":null,"type":"single","questions":[{"id":"b9-6-2a","part":6,"question":"Blank (1):","options":["reliable","reliability","reliably","relied"],"answer":0,"explanation":"Tính từ 'reliable' bổ nghĩa cho 'service'."},{"id":"b9-6-2b","part":6,"question":"Blank (2):","options":["bought","buying","purchase","purchased"],"answer":2,"explanation":"Danh từ 'purchase' (việc mua hàng)."},{"id":"b9-6-2c","part":6,"question":"Blank (3):","options":["this","that","those","these"],"answer":2,"explanation":"'Those who...' = Những người mà..."},{"id":"b9-6-2d","part":6,"question":"Blank (4):","options":["support","supportive","supporting","supportively"],"answer":0,"explanation":"Danh từ 'support'."}]},{"passage":"SYSTEM MAINTENANCE NOTIFICATION\nFrom: IT Infrastructure Team\nTo: All Staff\n\nPlease be advised that the company's core IT systems will be _____(1)_____ for scheduled maintenance on Sunday, March 9, from 11:00 p.m. to 3:00 a.m.\n\nDuring this period, access to email, the internal portal, and all cloud-based applications will be _____(2)_____. We strongly recommend that all employees save and close any open files before the maintenance window begins.\n\n_____(3)_____\n\nWe apologize for any inconvenience. Normal service will _____(4)_____ immediately after maintenance is completed.\nIT Infrastructure Team","passageTitle":null,"type":"single","questions":[{"id":"xp6-01a","part":6,"question":"Blank (1):","options":["offline","unavailable","suspended","inactive"],"answer":0,"explanation":"'Taken offline' = đưa ra khỏi trạng thái hoạt động để bảo trì. 'Unavailable' mô tả trạng thái; 'suspended' dùng cho tài khoản/dịch vụ; 'inactive' mô tả trạng thái thụ động."},{"id":"xp6-01b","part":6,"question":"Blank (2):","options":["accessible","unavailable","restricted","active"],"answer":1,"explanation":"'Access will be unavailable' = không thể truy cập trong thời gian bảo trì. 'Unavailable' chính xác nhất cho dịch vụ bị gián đoạn."},{"id":"xp6-01c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["The IT team will be monitoring systems throughout the maintenance window to ensure a smooth process.","All employees are required to attend an IT briefing session next Friday.","The new system will include additional security features and improved performance.","Please contact HR if you experience any personal data concerns."],"answer":0,"explanation":"Câu tiếp theo trấn an người dùng rằng đội IT sẽ giám sát trong suốt quá trình bảo trì — logic nhất sau thông báo gián đoạn."},{"id":"xp6-01d","part":6,"question":"Blank (4):","options":["restore","resume","recover","return"],"answer":1,"explanation":"'Service will resume' = dịch vụ sẽ tiếp tục hoạt động (collocation chuẩn). 'Restore' cần tân ngữ; 'recover' dùng cho dữ liệu; 'return' không đi với 'service'."}]},{"passage":"Apex Consulting Group\n15 Commerce Street, Auckland\n\nDear Ms. Tanaka,\n\nOn behalf of Apex Consulting Group, I am delighted to _____(1)_____ you a formal offer of employment as Senior Business Analyst, effective April 14.\n\nYour annual base salary will be NZD 95,000, _____(2)_____ on a monthly basis. You will also be eligible for the company's performance bonus scheme, with a target award of 12% of base salary based on individual and company results.\n\nWe would be grateful if you could confirm your _____(3)_____ of this offer by March 28 by signing and returning the enclosed contract.\n\n_____(4)_____ We look forward to you joining the team.\n\nYours sincerely,\nDavid Lin, Head of People & Culture","passageTitle":null,"type":"single","questions":[{"id":"xp6-02a","part":6,"question":"Blank (1):","options":["extend","provide","give","present"],"answer":0,"explanation":"'Extend an offer' = đưa ra lời đề nghị (formal collocation cố định trong offer letters). 'Provide/give/present an offer' không phải collocations chuẩn – 'provide' thường đi với 'provide someone WITH something'; 'give' quá thông thường; 'present' đi với 'present something TO someone'."},{"id":"xp6-02b","part":6,"question":"Blank (2):","options":["payable","paid","paying","payment"],"answer":0,"explanation":"'Payable on a monthly basis' = có thể thanh toán/được trả theo tháng. Đây là tính từ bổ sung cho danh từ 'salary' (danh từ được thanh toán như thế nào). 'Paid' là quá khứ phân từ không phù hợp ở vị trí này; 'paying' và 'payment' sai từ loại."},{"id":"xp6-02c","part":6,"question":"Blank (3):","options":["acceptance","agreement","acknowledgment","approval"],"answer":0,"explanation":"'Confirm your acceptance of this offer' = xác nhận chấp thuận (collocation cố định trong offer letters). 'Agreement' dùng cho thỏa thuận song phương; 'acknowledgment' = xác nhận đã nhận."},{"id":"xp6-02d","part":6,"question":"Blank (4) — Choose the best sentence:","options":["Should you have any questions about the terms, please do not hesitate to contact me directly.","The company's holiday schedule will be sent separately.","Your start date may be subject to a background check.","Please ensure you bring two forms of ID on your first day."],"answer":0,"explanation":"Câu kết offer letter — hợp lý nhất là mời ứng viên liên hệ nếu có thắc mắc về điều khoản."}]},{"passage":"CUSTOMER NOTICE\n\nDear Valued Customers,\n\nWith effect from June 1, Horizon Homewares will be _____(1)_____ its returns policy.\n\nKey changes include: the return window for all full-priced merchandise will be _____(2)_____ from 30 days to 45 days; items purchased during promotional events will remain eligible for exchange only. Proof of purchase is required in all cases.\n\n_____(3)_____\n\nWe appreciate your continued _____(4)_____ and look forward to serving you.\n\nHorizon Homewares Customer Team","passageTitle":null,"type":"single","questions":[{"id":"xp6-03a","part":6,"question":"Blank (1):","options":["updating","revising","amending","expanding"],"answer":0,"explanation":"'Updating its returns policy' = cập nhật chính sách. 'Updating' tự nhiên nhất trong thông báo khách hàng."},{"id":"xp6-03b","part":6,"question":"Blank (2):","options":["extended","expanded","increased","widened"],"answer":0,"explanation":"'Return window extended from 30 to 45 days' = kéo dài thời hạn (collocation chuẩn). 'Extended period/window' là cụm cố định."},{"id":"xp6-03c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["For full details on the updated policy, please visit our website or speak with a team member in store.","Our store hours will remain unchanged throughout the holiday period.","We are also pleased to introduce a new loyalty rewards programme launching next month.","Customers who have existing returns should process them before May 31."],"answer":0,"explanation":"Sau khi nêu thay đổi chính sách → hướng dẫn khách tìm thêm thông tin là logic nhất."},{"id":"xp6-03d","part":6,"question":"Blank (4):","options":["patronage","loyalty","support","custom"],"answer":0,"explanation":"'Your continued patronage' = sự ghé thăm/mua sắm liên tục (collocation trang trọng trong thư gửi khách hàng)."}]},{"passage":"MEMORANDUM\nTo:    All Department Heads\nFrom:  Finance Director\nDate:  February 3\nRe:    Annual Budget Submission — Deadline Reminder\n\nThis memo serves as a reminder that all departmental budget submissions for the upcoming fiscal year are _____(1)_____ February 28.\n\nPlease ensure that all requests are supported by a detailed _____(2)_____ of projected expenditures, including headcount costs, capital purchases, and operational expenses. Submissions received without full documentation will not be processed.\n\n_____(3)_____\n\nAny department that anticipates difficulty meeting this deadline should contact the Finance team immediately to discuss _____(4)_____ arrangements.\n\nThank you for your cooperation.","passageTitle":null,"type":"single","questions":[{"id":"xp6-04a","part":6,"question":"Blank (1):","options":["due by","due on","due at","due for"],"answer":0,"explanation":"'Due by February 28' = phải nộp trước ngày 28/2 (deadline). 'Due by' chỉ hạn chót không muộn hơn."},{"id":"xp6-04b","part":6,"question":"Blank (2):","options":["breakdown","summary","overview","outline"],"answer":0,"explanation":"'Detailed breakdown of expenditures' = phân tích chi tiết từng khoản (collocation tài chính chuẩn). 'Summary/overview' nghĩa tổng quát, ngược với 'detailed'."},{"id":"xp6-04c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["Budget templates and submission guidelines are available on the Finance portal under 'FY Budget Resources'.","All capital purchases above USD 10,000 require board approval regardless of budget allocation.","The Finance team will be hosting a webinar on budget forecasting next Thursday at 2:00 p.m.","Departments that overspend their approved budget will face a review in Q3."],"answer":0,"explanation":"Sau hướng dẫn nộp ngân sách → cung cấp tài nguyên/công cụ là logic nhất."},{"id":"xp6-04d","part":6,"question":"Blank (4):","options":["alternative","extended","revised","flexible"],"answer":0,"explanation":"'Alternative arrangements' = sắp xếp thay thế khi không đáp ứng deadline. Collocation tự nhiên nhất."}]},{"passage":"From: People Operations <hr@stellartech.com>\nTo: New Starters — May Cohort\nDate: April 28\nSubject: Your First Week at StellarTech\n\nWe are excited to welcome you to StellarTech! To help you _____(1)_____ smoothly into your new role, we have prepared a structured onboarding programme for your first week.\n\nYour first day will begin with a welcome session at 9:00 a.m. in the Main Boardroom. You will then meet your _____(2)_____ manager, who will guide you through your department's processes and introduce you to your colleagues.\n\n_____(3)_____\n\nPlease ensure you bring valid identification and your signed employment contract on your first day. If you have any questions before then, do not _____(4)_____ to reach out to your designated HR contact.\n\nWe look forward to seeing you soon!\nPeople Operations Team","passageTitle":null,"type":"single","questions":[{"id":"xp6-05a","part":6,"question":"Blank (1):","options":["settle","transition","integrate","adapt"],"answer":2,"explanation":"'Integrate smoothly into your new role' = hòa nhập suôn sẻ (HR collocation chuẩn). 'Integrate into' phổ biến nhất trong văn bản onboarding."},{"id":"xp6-05b","part":6,"question":"Blank (2):","options":["line","direct","immediate","assigned"],"answer":0,"explanation":"'Line manager' = quản lý trực tiếp (thuật ngữ HR chuẩn). Phổ biến nhất trong văn bản công ty ETS."},{"id":"xp6-05c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["A full onboarding schedule, including IT setup and system access times, has been emailed to you separately.","The canteen is located on the ground floor and serves hot meals from 12:00 to 2:00 p.m.","Please note that parking is available in the basement from 7:00 a.m.","Your employment contract outlines all terms and conditions of your engagement."],"answer":0,"explanation":"Mô tả onboarding ngày đầu → lịch trình chi tiết hơn là thực dụng nhất cho nhân viên mới."},{"id":"xp6-05d","part":6,"question":"Blank (4):","options":["hesitate","fail","forget","delay"],"answer":0,"explanation":"'Do not hesitate to reach out' = đừng ngại liên hệ (cụm lịch sự cố định trong email HR)."}]},{"passage":"NOTICE OF CONTRACT RENEWAL\nPrepared by: Legal & Compliance\nTo: Procurement Department\n\nThis notice is to inform you that the Master Services Agreement with Pinnacle Logistics will _____(1)_____ on September 30.\n\nIn accordance with Section 12.3 of the agreement, either party must provide at least 60 days' written notice of _____(2)_____ to renew. Failure to provide this notice within the required timeframe will result in the contract being automatically renewed for a further 12-month period.\n\n_____(3)_____\n\nIf you wish to proceed with renegotiating the terms of the agreement, please contact the Legal team _____(4)_____ your soonest convenience.\n\nLegal & Compliance Division","passageTitle":null,"type":"single","questions":[{"id":"xp6-06a","part":6,"question":"Blank (1):","options":["expire","conclude","terminate","end"],"answer":0,"explanation":"'Contract will expire' = hết hạn (thuật ngữ pháp lý chuẩn). 'Terminate' = chấm dứt sớm do vi phạm; 'conclude/end' không đặc thù cho hợp đồng."},{"id":"xp6-06b","part":6,"question":"Blank (2):","options":["intention","decision","preference","desire"],"answer":0,"explanation":"'Notice of intention not to renew' = thông báo có ý định không gia hạn (ngôn ngữ pháp lý chuẩn)."},{"id":"xp6-06c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["Given the upcoming expiration date, we recommend initiating a review of the current terms by August 1 at the latest.","The procurement team should consult with the finance department regarding budget implications.","All future supplier agreements must be approved by the board prior to signing.","Please be aware that late renewals may incur a 5% administrative surcharge."],"answer":0,"explanation":"Sau thông báo hết hạn → khuyến nghị hành động cụ thể với deadline là logic nhất."},{"id":"xp6-06d","part":6,"question":"Blank (4):","options":["at","on","in","by"],"answer":0,"explanation":"'At your soonest convenience' = vào thời điểm sớm nhất thuận tiện (cụm cố định trong văn bản trang trọng)."}]},{"passage":"From: Reservations <reservations@grandpacific.com>\nTo: Mr. David Park\nDate: October 12\nSubject: Booking Confirmation — Ref: GP-44921\n\nDear Mr. Park,\n\nThank you for choosing Grand Pacific Hotel. We are pleased to confirm your reservation for a Superior King Room from November 8 to November 11 (3 nights).\n\nAs requested, early check-in at 11:00 a.m. has been _____(1)_____, subject to room availability on the day of arrival. Standard check-out time is 12:00 noon; a late check-out _____(2)_____ be arranged for an additional charge if required.\n\n_____(3)_____\n\nShould you need to modify or cancel your booking, please note that cancellations made less than 48 hours before arrival will _____(4)_____ a one-night charge.\n\nWe look forward to welcoming you.\nGrand Pacific Reservations Team","passageTitle":null,"type":"single","questions":[{"id":"xp6-07a","part":6,"question":"Blank (1):","options":["arranged","confirmed","reserved","noted"],"answer":0,"explanation":"'Early check-in has been arranged' = đã được thu xếp (collocation khách sạn chuẩn cho special requests)."},{"id":"xp6-07b","part":6,"question":"Blank (2):","options":["can","may","will","should"],"answer":1,"explanation":"'Late check-out may be arranged' = có thể được sắp xếp (khả năng). 'May' lịch sự nhất; 'will' quá khẳng định."},{"id":"xp6-07c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["A complimentary breakfast for two is included in your room rate and is served in the Garden Restaurant from 7:00 to 10:30 a.m.","Please note that parking is not available at the hotel; the nearest public car park is 200 metres away.","Our spa facilities are open daily from 8:00 a.m. to 9:00 p.m. and can be booked in advance.","Room service is available 24 hours and the menu can be found in your room."],"answer":0,"explanation":"Email xác nhận đặt phòng → bữa sáng miễn phí (included amenity) là thông tin quan trọng và phổ biến nhất trong ETS sentence-insertion."},{"id":"xp6-07d","part":6,"question":"Blank (4):","options":["incur","attract","result in","carry"],"answer":0,"explanation":"'Will incur a charge' = sẽ phải chịu khoản phí (collocation tài chính/pháp lý chuẩn ETS)."}]},{"passage":"From: Product Team <product@velosoft.com>\nTo: Enterprise Clients\nDate: May 19\nSubject: VeloDesk 4.0 — Now Available\n\nWe are pleased to announce that VeloDesk 4.0 is now _____(1)_____ for download.\n\nThis major update introduces a redesigned dashboard, improved API integrations, and enhanced security protocols in _____(2)_____ with the latest ISO 27001 standards.\n\n_____(3)_____\n\nTo upgrade, simply log into your admin portal and navigate to Settings > System Updates. Your existing data and configurations will be _____(4)_____ during the upgrade process.\n\nPlease reach out to your account manager if you require assistance.\nThe VeloSoft Product Team","passageTitle":null,"type":"single","questions":[{"id":"xp6-08a","part":6,"question":"Blank (1):","options":["available","accessible","released","ready"],"answer":0,"explanation":"'Now available for download' = hiện có thể tải xuống (collocation chuẩn cho software release)."},{"id":"xp6-08b","part":6,"question":"Blank (2):","options":["compliance","accordance","line","alignment"],"answer":1,"explanation":"'In accordance with ISO standards' = phù hợp với tiêu chuẩn (cụm giới từ cố định). Phổ biến nhất trong văn bản kỹ thuật ETS."},{"id":"xp6-08c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["All enterprise clients on annual plans will receive the update at no additional cost.","The new dashboard design was developed based on feedback from over 2,000 users in our beta programme.","VeloDesk 4.0 is compatible with Windows 10 and above, and macOS 12 or later.","A full list of changes and known issues is documented in the release notes."],"answer":0,"explanation":"Email thông báo cập nhật cho enterprise clients → thông tin về giá/phí là quan trọng nhất và trả lời câu hỏi thực tế nhất."},{"id":"xp6-08d","part":6,"question":"Blank (4):","options":["preserved","retained","maintained","kept"],"answer":0,"explanation":"'Data will be preserved during upgrade' = dữ liệu được giữ nguyên (IT collocation chuẩn nhấn mạnh tính toàn vẹn)."}]},{"passage":"From: Customer Care <care@rapidfreight.com>\nTo: Elena Sousa\nDate: March 6\nSubject: Shipment Update — Order #RF-20214\n\nDear Ms. Sousa,\n\nWe are writing to advise you of an _____(1)_____ delay affecting your shipment (#RF-20214), originally scheduled for delivery on March 7.\n\nDue to severe weather conditions in the transit region, your consignment has been _____(2)_____ at our Brisbane depot until conditions improve. We currently estimate delivery will take place within 3–5 business days.\n\n_____(3)_____\n\nWe sincerely apologize for the inconvenience. If you would like to discuss alternative _____(4)_____ options, our customer care team is available 24/7.\n\nRapidFreight Customer Care","passageTitle":null,"type":"single","questions":[{"id":"xp6-09a","part":6,"question":"Blank (1):","options":["unforeseen","unexpected","unplanned","sudden"],"answer":0,"explanation":"'Unforeseen delay' = sự chậm trễ không lường trước (logistics collocation chuẩn)."},{"id":"xp6-09b","part":6,"question":"Blank (2):","options":["held","stored","kept","placed"],"answer":0,"explanation":"'Consignment has been held at the depot' = lô hàng bị giữ lại (thuật ngữ logistics chuẩn)."},{"id":"xp6-09c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["You can track your shipment in real time using your tracking number at rapidfreight.com/track.","Our depot operates Monday to Friday from 8:00 a.m. to 6:00 p.m.","We recommend that you contact your local customs office if the delay exceeds 10 days.","RapidFreight handles over 50,000 deliveries per week across Australia."],"answer":0,"explanation":"Email thông báo chậm giao hàng → hướng dẫn theo dõi trạng thái là thực dụng nhất cho khách hàng."},{"id":"xp6-09d","part":6,"question":"Blank (4):","options":["delivery","shipping","dispatch","forwarding"],"answer":0,"explanation":"'Alternative delivery options' = phương án giao hàng thay thế (collocation chuẩn trong customer service)."}]},{"passage":"NOTICE OF ANNUAL GENERAL MEETING\nArcadia Holdings Limited\n\nNotice is hereby _____(1)_____ that the Annual General Meeting (AGM) of Arcadia Holdings Limited will be held at the Riverside Conference Centre, Level 4, on Thursday, June 19, commencing at 10:00 a.m.\n\nThe AGM agenda will include: (i) review of the annual financial statements; (ii) re-election of board directors; (iii) appointment of external auditors for the _____(2)_____ financial year; and (iv) any other business as approved by the Chairman.\n\n_____(3)_____\n\nShareholders who are unable to attend in person may _____(4)_____ a proxy to vote on their behalf by submitting the enclosed proxy form no later than June 12.\n\nBy order of the Board\nGenevieve Park, Company Secretary","passageTitle":null,"type":"single","questions":[{"id":"xp6-10a","part":6,"question":"Blank (1):","options":["given","stated","provided","issued"],"answer":0,"explanation":"'Notice is hereby given' = xin thông báo rằng (cụm pháp lý cố định, bắt buộc trong AGM notices)."},{"id":"xp6-10b","part":6,"question":"Blank (2):","options":["upcoming","forthcoming","ensuing","next"],"answer":1,"explanation":"'For the forthcoming financial year' = cho năm tài chính sắp tới (từ trang trọng chuẩn trong văn bản AGM)."},{"id":"xp6-10c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["Shareholders are entitled to attend, speak, and vote at the AGM, and may also submit written questions in advance.","Light refreshments will be served prior to the commencement of the meeting.","The Board recommends voting in favour of all resolutions presented.","Annual reports and proxy forms have been mailed to all registered shareholders."],"answer":0,"explanation":"AGM notice → giải thích quyền của cổ đông là logic nhất trong cấu trúc văn bản pháp lý."},{"id":"xp6-10d","part":6,"question":"Blank (4):","options":["appoint","assign","designate","nominate"],"answer":0,"explanation":"'Appoint a proxy' = ủy quyền đại diện biểu quyết (thuật ngữ pháp lý cố định)."}]},{"passage":"SUSTAINABILITY UPDATE — Q3\nGreenCore Manufacturing\n\nGreenCore Manufacturing is pleased to report _____(1)_____ progress toward its 2030 sustainability goals.\n\nThis quarter, the company reduced its total carbon emissions by 18% compared to the same period last year, _____(2)_____ the early deployment of solar panels across three production facilities.\n\nIn addition, 94% of packaging materials now _____(3)_____ from certified sustainable sources. GreenCore aims to achieve 100% sustainable sourcing by the end of next year.\n\n_____(4)_____\n\nFull details are available in the quarterly sustainability report on our website.","passageTitle":null,"type":"single","questions":[{"id":"xp6-11a","part":6,"question":"Blank (1):","options":["significant","substantial","considerable","notable"],"answer":3,"explanation":"'Report notable progress' = tiến triển đáng chú ý. 'Notable' phổ biến nhất trong sustainability reporting."},{"id":"xp6-11b","part":6,"question":"Blank (2):","options":["following","owing to","due to","thanks to"],"answer":1,"explanation":"'Owing to the deployment' = nhờ vào việc triển khai (chỉ nguyên nhân tích cực, trang trọng). 'Owing to' có sắc thái tích cực phù hợp báo cáo."},{"id":"xp6-11c","part":6,"question":"Blank (3):","options":["originate","are sourced","come","derive"],"answer":1,"explanation":"'Materials are sourced from sustainable sources' = được lấy từ nguồn bền vững (passive collocation chuẩn)."},{"id":"xp6-11d","part":6,"question":"Blank (4) — Choose the best sentence:","options":["These achievements have been independently verified by EcoAudit International, a third-party sustainability certification body.","The company has also pledged to eliminate single-use plastics from all office locations by year-end.","Employees are encouraged to participate in GreenCore's annual sustainability survey.","GreenCore's sustainability strategy was launched in 2021 following a review by the board."],"answer":0,"explanation":"Sau báo cáo tiến triển → xác nhận bên thứ ba (third-party verification) là điểm mạnh nhất trong sustainability reporting."}]},{"passage":"From: Trust & Safety <safety@shopwave.com>\nTo: Account: SunriseCraft (seller ID: SC-88421)\nDate: August 14\nSubject: Important Notice Regarding Your Account\n\nDear SunriseCraft Team,\n\nWe are writing to notify you that your ShopWave seller account has been _____(1)_____ following a review of recent activity.\n\nOur systems identified that three orders were fulfilled with items that did not _____(2)_____ the descriptions listed on your product pages. This is a violation of ShopWave's Seller Accuracy Policy.\n\n_____(3)_____\n\nTo have your account _____(4)_____, please submit a written explanation and corrective action plan to trust@shopwave.com within seven business days. Failure to respond within this timeframe may result in permanent account closure.\n\nTrust & Safety Team, ShopWave","passageTitle":null,"type":"single","questions":[{"id":"xp6-12a","part":6,"question":"Blank (1):","options":["suspended","restricted","deactivated","frozen"],"answer":0,"explanation":"'Account has been suspended' = tài khoản bị tạm đình chỉ (collocation chuẩn trong platform enforcement)."},{"id":"xp6-12b","part":6,"question":"Blank (2):","options":["match","correspond to","align with","reflect"],"answer":0,"explanation":"'Items did not match the descriptions' = không khớp mô tả (e-commerce collocation chuẩn)."},{"id":"xp6-12c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["While your account is suspended, you will not be able to list new products or process orders.","ShopWave has over 5 million active buyers across 40 countries.","We value your contribution to the ShopWave marketplace and hope to resolve this matter quickly.","Our seller support team is available Monday to Friday from 9:00 a.m. to 6:00 p.m."],"answer":0,"explanation":"Sau thông báo đình chỉ → giải thích tác động cụ thể là logic nhất cho người bán."},{"id":"xp6-12d","part":6,"question":"Blank (4):","options":["reinstated","restored","reactivated","reopened"],"answer":0,"explanation":"'Account reinstated' = tài khoản được phục hồi (collocation chuẩn sau suspension trong platform policy)."}]},{"passage":"PREMIER MEMBERSHIP — ANNUAL BENEFITS RENEWAL\nFitLife Wellness Centres\n\nDear Ms. Callahan,\n\nThank you for being a valued Premier member. Your membership is due for _____(1)_____ on September 1, and we would like to take this opportunity to highlight some exciting updates to your benefits.\n\nThis year, your Premier membership will include _____(2)_____ access to all 12 FitLife locations nationwide, an increase from the previous 8. In addition, Premier members will now receive a complimentary personal training session each _____(3)_____.\n\n_____(4)_____ To take advantage of this offer, simply present your membership card or the FitLife app at any location.\n\nWe look forward to continuing to support your wellness journey.\nFitLife Member Services","passageTitle":null,"type":"single","questions":[{"id":"xp6-13a","part":6,"question":"Blank (1):","options":["renewal","extension","expiry","review"],"answer":0,"explanation":"'Membership due for renewal' = thành viên cần gia hạn (collocation cố định). 'Renewal' là thuật ngữ chuẩn."},{"id":"xp6-13b","part":6,"question":"Blank (2):","options":["unlimited","unrestricted","full","complete"],"answer":0,"explanation":"'Unlimited access to all locations' = truy cập không giới hạn (membership collocation chuẩn)."},{"id":"xp6-13c","part":6,"question":"Blank (3):","options":["quarter","month","year","visit"],"answer":1,"explanation":"'A complimentary session each month' = buổi miễn phí mỗi tháng — tần suất tự nhiên nhất cho recurring benefit."},{"id":"xp6-13d","part":6,"question":"Blank (4) — Choose the best sentence:","options":["Your new membership card, valid through August 31 of next year, will be mailed to your registered address within five business days.","Personal training sessions must be booked at least 24 hours in advance through the FitLife app.","FitLife has been voted the number one wellness brand in Australia for three consecutive years.","Our group fitness timetable has been updated for the new season and is available on the website."],"answer":0,"explanation":"Sau thông báo gia hạn → thông tin về thẻ thành viên mới là thực dụng và liên quan trực tiếp nhất."}]},{"passage":"POLICY UPDATE: FLEXIBLE WORKING ARRANGEMENTS\nTo: All Permanent Staff\nFrom: Director of Human Resources\nEffective: Monday, October 6\n\nFollowing a comprehensive review, the company is pleased to introduce an _____(1)_____ remote working policy, effective October 6.\n\nEligible employees may work remotely for up to three days per week, _____(2)_____ that they maintain full availability during core business hours (9:00 a.m. – 4:00 p.m.) and attend all scheduled in-person team meetings.\n\n_____(3)_____\n\nManagers will review remote working arrangements on a quarterly basis and retain the _____(4)_____ to modify or withdraw the arrangement if business needs require.\n\nFull policy guidelines are available on the HR portal.\nDirector of Human Resources","passageTitle":null,"type":"single","questions":[{"id":"xp6-14a","part":6,"question":"Blank (1):","options":["updated","enhanced","expanded","revised"],"answer":2,"explanation":"'Expanded remote working policy' = chính sách được mở rộng (phù hợp ngữ cảnh tăng số ngày WFH). 'Expanded' chỉ sự mở rộng phạm vi."},{"id":"xp6-14b","part":6,"question":"Blank (2):","options":["provided","given","assuming","considering"],"answer":0,"explanation":"'Provided that they maintain availability' = với điều kiện là (cụm điều kiện cố định, trang trọng nhất)."},{"id":"xp6-14c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["Requests to work remotely must be submitted to your line manager at least one week in advance and are subject to approval.","Staff are reminded that all company data accessed remotely must be handled in accordance with the IT Security Policy.","Hot-desking stations have been set up on Floors 3 and 4 for staff who choose to work on-site less frequently.","The company will provide a one-time home office equipment allowance of AUD 400 for eligible employees."],"answer":1,"explanation":"Sau điều khoản WFH → bảo mật dữ liệu khi làm việc từ xa là yêu cầu tuân thủ quan trọng nhất cần bổ sung."},{"id":"xp6-14d","part":6,"question":"Blank (4):","options":["right","authority","discretion","option"],"answer":2,"explanation":"'Managers retain the discretion to modify arrangements' = giữ quyền quyết định theo từng tình huống (HR policy collocation chuẩn)."}]},{"passage":"From: Organising Committee <events@nexussummit.org>\nTo: All Registered Delegates\nDate: November 22\nSubject: Thank You — Nexus Innovation Summit 2024\n\nDear Delegate,\n\nOn behalf of the Nexus Innovation Summit Organising Committee, we would like to _____(1)_____ our sincere gratitude for your participation in this year's event.\n\nWe were delighted to welcome over 1,200 delegates from 35 countries, making this the most _____(2)_____ attended edition of the Summit to date.\n\n_____(3)_____\n\nAll keynote recordings and presentation slides will be made _____(4)_____ to registered delegates via the Summit portal within the next 10 business days. You will receive a separate email with your access link.\n\nWe look forward to seeing you at Nexus 2025.\nNexus Organising Committee","passageTitle":null,"type":"single","questions":[{"id":"xp6-15a","part":6,"question":"Blank (1):","options":["express","extend","convey","offer"],"answer":0,"explanation":"'Express our sincere gratitude' = bày tỏ lòng biết ơn (collocation chuẩn nhất)."},{"id":"xp6-15b","part":6,"question":"Blank (2):","options":["widely","well","highly","broadly"],"answer":1,"explanation":"'Most well-attended edition' = phiên bản có đông người tham dự nhất ('well-attended' là tính từ ghép tiêu chuẩn)."},{"id":"xp6-15c","part":6,"question":"Blank (3) — Choose the best sentence:","options":["We are currently reviewing delegate feedback and will incorporate your suggestions into the planning of Nexus 2025.","The venue, the Grand Hyatt Convention Centre, has been confirmed for next year's event as well.","Our sponsorship packages for Nexus 2025 will be available from January.","A highlight reel of the Summit is now available on our YouTube channel."],"answer":0,"explanation":"Email cảm ơn sau sự kiện → cho thấy phản hồi được lắng nghe là quan trọng nhất để xây dựng mối quan hệ với delegate."},{"id":"xp6-15d","part":6,"question":"Blank (4):","options":["available","accessible","open","free"],"answer":0,"explanation":"'Will be made available to delegates' = sẽ được cung cấp ('made available' là collocation cố định cho quyền truy cập tài liệu)."}]}],"part7":[{"passage":"From: Sarah Chen <s.chen@globaltrade.com>\nTo: Marcus Webb <m.webb@globaltrade.com>\nDate: September 14\nSubject: Q3 Sales Report\n\nHi Marcus,\n\nI've just finished compiling the Q3 sales report, and the results look very promising. Overall, sales increased by 18% compared to the same period last year. The Asia-Pacific region performed particularly well, with a 34% growth, largely driven by new partnerships in South Korea and Singapore.\n\nHowever, our North America division saw a slight decline of about 3%, primarily due to supply chain disruptions in Q2 that carried over into Q3. I've included a detailed breakdown in the attached spreadsheet.\n\nI recommend we schedule a meeting with the regional managers to discuss strategies for North America and how to sustain growth in Asia-Pacific. Are you available for a call this Thursday or Friday?\n\nBest regards,\nSarah","passageTitle":null,"type":"single","questions":[{"id":"p7-1a","part":7,"question":"What is the main purpose of this email?","options":["To request a budget approval","To share a quarterly sales report","To introduce a new business partner","To schedule a training session"],"answer":1,"explanation":"Chủ đề email là chia sẻ kết quả Q3 sales report với đồng nghiệp."},{"id":"p7-1b","part":7,"question":"Which region showed the strongest growth?","options":["North America","Europe","Asia-Pacific","South America"],"answer":2,"explanation":"'The Asia-Pacific region performed particularly well, with a 34% growth.'"},{"id":"p7-1c","part":7,"question":"What caused the decline in North America?","options":["Increased competition","Low product demand","Supply chain disruptions","Staffing shortages"],"answer":2,"explanation":"'primarily due to supply chain disruptions in Q2 that carried over into Q3'"},{"id":"p7-1d","part":7,"question":"What does Sarah suggest doing?","options":["Hiring new regional managers","Canceling the North America operations","Meeting with regional managers","Revising the company's product line"],"answer":2,"explanation":"'I recommend we schedule a meeting with the regional managers'"}]},{"passage":"PRESS RELEASE\nFor Immediate Release\n\nNovaBright Technologies Announces Launch of SmartDesk Pro\n\nSAN FRANCISCO, October 3 – NovaBright Technologies today unveiled SmartDesk Pro, its latest productivity software designed for remote and hybrid work environments. The platform integrates task management, video conferencing, and document collaboration into a single interface.\n\n\"SmartDesk Pro was built in response to direct feedback from over 5,000 beta users,\" said CEO Linda Park. \"We listened carefully and created a tool that genuinely addresses the challenges of modern work.\"\n\nThe software will be available starting October 15 and will be offered in three pricing tiers: Basic ($9.99/month), Professional ($24.99/month), and Enterprise (custom pricing). A 30-day free trial is available for all plans.\n\nFor more information, visit www.novabrighttech.com or contact media@novabrighttech.com.","passageTitle":null,"type":"single","questions":[{"id":"p7-2a","part":7,"question":"What type of document is this?","options":["A product brochure","A press release","An internal memo","A user manual"],"answer":1,"explanation":"Dòng đầu ghi 'PRESS RELEASE' – thông cáo báo chí."},{"id":"p7-2b","part":7,"question":"When will SmartDesk Pro be available for purchase?","options":["October 3","October 10","October 15","November 1"],"answer":2,"explanation":"'The software will be available starting October 15'"},{"id":"p7-2c","part":7,"question":"What was used to develop the product?","options":["A market research report","Feedback from beta users","A competitor analysis","Government funding"],"answer":1,"explanation":"'built in response to direct feedback from over 5,000 beta users'"},{"id":"p7-2d","part":7,"question":"What is offered for all pricing plans?","options":["A discount for annual subscriptions","24/7 customer support","A 30-day free trial","Free upgrades for one year"],"answer":2,"explanation":"'A 30-day free trial is available for all plans.'"}]},{"passage":"[Document 1 – Job Advertisement]\nMarketing Manager – GreenLeaf Organics\nLocation: New York, NY | Full-Time\n\nGreenLeaf Organics is seeking an experienced Marketing Manager to lead our brand development initiatives. Ideal candidates will have at least 5 years of experience in consumer goods marketing, strong analytical skills, and a passion for sustainable products.\n\nKey Responsibilities:\n• Develop and execute multi-channel marketing campaigns\n• Manage a team of 6 marketing professionals\n• Analyze campaign performance and present findings to management\n• Collaborate with product developers on new launches\n\nSalary: $85,000 – $100,000 annually. Application deadline: November 30.\nTo apply, send your resume and cover letter to careers@greenleaf.com.\n\n[Document 2 – Application Email]\nFrom: James Doyle <jdoyle@email.com>\nTo: careers@greenleaf.com\nDate: November 15\n\nDear Hiring Team,\n\nI am writing to apply for the Marketing Manager position advertised on your website. I have seven years of experience in marketing within the food and beverage sector and have managed teams of up to eight people. In my current role at FreshFarm Co., I led campaigns that resulted in a 22% increase in brand awareness.\n\nI am particularly drawn to GreenLeaf Organics because of your commitment to sustainability, a value I share deeply. I have attached my resume and a detailed cover letter for your review.\n\nI look forward to hearing from you.\nSincerely,\nJames Doyle","passageTitle":"Email + Job Listing","type":"double","questions":[{"id":"p7-3a","part":7,"question":"According to the job posting, what is the maximum salary offered?","options":["$75,000","$85,000","$95,000","$100,000"],"answer":3,"explanation":"Mức lương trong bài đăng là '$85,000 – $100,000 annually' → tối đa $100,000."},{"id":"p7-3b","part":7,"question":"What experience does James Doyle have that matches the job requirements?","options":["He has a degree in marketing","He has led teams of 6+ people","He specializes in technology marketing","He has worked at GreenLeaf Organics before"],"answer":1,"explanation":"Yêu cầu: 'Manage a team of 6'. James đã 'managed teams of up to eight people'. ✓"},{"id":"p7-3c","part":7,"question":"Why is James Doyle interested in GreenLeaf Organics specifically?","options":["The high salary","The company's green values","The team size","The job location"],"answer":1,"explanation":"'particularly drawn to GreenLeaf Organics because of your commitment to sustainability'"},{"id":"p7-3d","part":7,"question":"What did James Doyle accomplish in his current role?","options":["Launched a new organic product line","Increased company revenue by 22%","Raised brand awareness by 22%","Reduced marketing costs by 22%"],"answer":2,"explanation":"'campaigns that resulted in a 22% increase in brand awareness'"}]},{"passage":"INTERNAL ANNOUNCEMENT\n\nTo: All Employees\nFrom: Office of the CEO\nDate: June 15\nSubject: Employee of the Quarter – Q2 Recognition\n\nWe are delighted to announce that this quarter's Employee of the Quarter award goes to Ms. Priya Sharma from the Customer Experience Department.\n\nMs. Sharma joined Horizon Consulting three years ago as a junior support specialist and has since demonstrated exceptional dedication and initiative. This quarter, she independently designed and implemented a new client onboarding process that reduced average onboarding time from 14 days to 6 days — a 57% improvement. Her approach has since been adopted company-wide.\n\nIn recognition of her achievement, Ms. Sharma will receive a certificate of excellence, a bonus equivalent to one week's salary, and a reserved parking spot for the next three months.\n\nNominations for Q3 are now open. Employees are encouraged to nominate colleagues who have made a meaningful impact on clients, the team, or our company culture. Submission forms are available on the company intranet.\n\nCongratulations, Priya!","passageTitle":null,"type":"single","questions":[{"id":"n7-1a","part":7,"question":"What is the purpose of this announcement?","options":["To introduce a new employee program","To recognize an employee's achievement","To announce a company-wide process change","To invite staff to a company celebration"],"answer":1,"explanation":"✅ <b>To recognize an employee's achievement</b>. <br>💡 <i>Dẫn chứng:</i> 'this quarter's Employee of the Quarter award goes to Ms. Priya Sharma'."},{"id":"n7-1b","part":7,"question":"How long has Ms. Sharma worked at Horizon Consulting?","options":["One year","Two years","Three years","Five years"],"answer":2,"explanation":"✅ <b>Three years</b>. <br>💡 <i>Dẫn chứng:</i> 'Ms. Sharma joined Horizon Consulting three years ago'."},{"id":"n7-1c","part":7,"question":"What improvement did Ms. Sharma make to the onboarding process?","options":["She cut costs by 57%","She reduced onboarding time by 57%","She trained 57 new staff members","She increased client satisfaction by 57%"],"answer":1,"explanation":"✅ <b>She reduced onboarding time by 57%</b>. <br>💡 <i>Dẫn chứng:</i> 'reduced average onboarding time from 14 days to 6 days — a 57% improvement'."},{"id":"n7-1d","part":7,"question":"What is NOT mentioned as part of Ms. Sharma's reward?","options":["A certificate of excellence","A salary bonus","A company trip","A reserved parking spot"],"answer":2,"explanation":"✅ <b>A company trip</b>. <br>💡 <i>Loại trừ:</i> Bài viết nhắc đến certificate, bonus, và parking spot. Không có 'trip'."}]},{"passage":"NOTICE OF SERVICE DISRUPTION\n\nPlatform: CloudSuite Business Solutions\nDate of Notice: Wednesday, March 12\n\nDear CloudSuite Users,\n\nWe are writing to inform you that CloudSuite Business Solutions will undergo essential system maintenance on Saturday, March 15, between the hours of 11:00 p.m. and 3:00 a.m. (Eastern Standard Time).\n\nDuring this maintenance window, access to all CloudSuite modules — including file storage, project management tools, and the reporting dashboard — will be temporarily unavailable. Scheduled automated reports that would normally run during this time will be delayed and will be processed automatically once maintenance is complete.\n\nTo minimize the impact on your workflow, we recommend the following:\n• Download or export any critical files or reports before 10:00 p.m. on March 15.\n• Reschedule any time-sensitive tasks that depend on real-time data access.\n• Notify your team members of the expected downtime.\n\nWe sincerely apologize for any inconvenience this may cause. Our team has scheduled this work during off-peak hours to minimize disruption. If you have any questions or concerns, please contact our support center at support@cloudsuite.com.\n\nThank you for your understanding.\nThe CloudSuite Technical Team","passageTitle":null,"type":"single","questions":[{"id":"n7-2a","part":7,"question":"What is the main purpose of this notice?","options":["To introduce a new feature","To announce a price increase","To inform users about scheduled maintenance","To respond to a service complaint"],"answer":2,"explanation":"✅ <b>To inform users about scheduled maintenance</b>. <br>💡 <i>Tiêu đề:</i> 'NOTICE OF SERVICE DISRUPTION' và nội dung về 'system maintenance'."},{"id":"n7-2b","part":7,"question":"Which of the following will NOT be affected during maintenance?","options":["File storage","Project management tools","Reporting dashboard","Email inbox"],"answer":3,"explanation":"✅ <b>Email inbox</b>. <br>💡 <i>Loại trừ:</i> Văn bản liệt kê file storage, project management tools, dashboard. Không nhắc đến email."},{"id":"n7-2c","part":7,"question":"What is recommended for scheduled automated reports?","options":["Cancel them permanently","Run them before 10:00 p.m.","They will be processed automatically after maintenance","Submit them manually to the support team"],"answer":2,"explanation":"✅ <b>Processed automatically once maintenance is complete</b>. <br>💡 <i>Dẫn chứng:</i> 'will be processed automatically once maintenance is complete'."},{"id":"n7-2d","part":7,"question":"Why was this maintenance time chosen?","options":["It was requested by users","It falls during off-peak hours","It is the only available window","It avoids weekend disruptions"],"answer":1,"explanation":"✅ <b>Off-peak hours</b>. <br>💡 <i>Dẫn chứng:</i> 'Our team has scheduled this work during off-peak hours'."}]},{"passage":"TRAVEL ADVISORY\nInternational Business Travel Division\nHorizon Financial Group\n\nDestination: Ho Chi Minh City, Vietnam\nIssued: September 2025\n\nGENERAL OVERVIEW\nHo Chi Minh City (HCMC) is Vietnam's largest commercial hub and a growing destination for international business. Travelers will find a dynamic, fast-paced city with a well-developed infrastructure for business visitors.\n\nVISA REQUIREMENTS\nMost business travelers will require a visa. Citizens of certain countries may be eligible for visa-free entry or e-visa arrangements. Employees are advised to check visa requirements at least 4 weeks prior to departure and submit applications through the official Vietnam Immigration Department portal.\n\nHEALTH & SAFETY\nConsult your physician at least 4 weeks prior to travel regarding recommended vaccinations. Travel insurance that covers medical evacuation is strongly recommended. HCMC has reputable international hospitals; however, medical costs can be high without appropriate coverage.\n\nBUSINESS CULTURE\nBusiness meetings in HCMC typically begin on time. Bring printed business cards and present them with both hands as a sign of respect. Formal attire is expected in most business settings.\n\nEXPENSE REPORTING\nAll travel expenses must be submitted within 14 days of returning to the home office using the standard expense form on the company intranet. Original receipts are required for any single expense over USD 50.\n\nFor assistance, contact the International Travel Desk at travel@horizonfg.com.","passageTitle":null,"type":"single","questions":[{"id":"n7-3a","part":7,"question":"What is this document?","options":["A tourist guidebook","A visa application form","A company travel advisory","A health and safety policy"],"answer":2,"explanation":"✅ <b>Company travel advisory</b>. <br>💡 <i>Tiêu đề:</i> 'TRAVEL ADVISORY' từ Horizon Financial Group."},{"id":"n7-3b","part":7,"question":"How far in advance should employees check visa requirements?","options":["1 week","2 weeks","4 weeks","8 weeks"],"answer":2,"explanation":"✅ <b>4 weeks</b>. <br>💡 <i>Dẫn chứng:</i> 'check visa requirements at least 4 weeks prior to departure'."},{"id":"n7-3c","part":7,"question":"What should employees do with business cards when meeting Vietnamese counterparts?","options":["Keep them in their wallet","Present them with one hand","Present them with both hands","Decline to offer them in the first meeting"],"answer":2,"explanation":"✅ <b>Present them with both hands</b>. <br>💡 <i>Dẫn chứng:</i> 'present them with both hands as a sign of respect'."},{"id":"n7-3d","part":7,"question":"When must expense reports be submitted?","options":["Before the trip begins","On the day of return","Within 14 days of returning","Within 30 days of returning"],"answer":2,"explanation":"✅ <b>Within 14 days of returning</b>. <br>💡 <i>Dẫn chứng:</i> 'must be submitted within 14 days of returning'."}]},{"passage":"[Document 1 – Job Advertisement]\n\nVACANCY: Senior Financial Analyst\nCompany: Meridian Capital Partners\nLocation: Singapore (Hybrid – 3 days on-site)\nSalary: SGD 90,000 – 115,000 annually + performance bonus\n\nMeridian Capital Partners is a leading investment advisory firm with offices across Asia-Pacific. We are seeking a Senior Financial Analyst to join our Singapore team.\n\nKey Requirements:\n• Bachelor's degree in Finance, Accounting, or related field (MBA or CFA preferred)\n• Minimum 5 years of financial analysis experience\n• Proficiency in Excel, Bloomberg Terminal, and Python\n• Strong communication skills in English; Mandarin is an advantage\n\nResponsibilities include: conducting company valuations, preparing investment research reports, presenting findings to senior management, and monitoring portfolio performance.\n\nApplication deadline: October 20. Send your CV and cover letter to: careers@meridiancapital.sg\n\n[Document 2 – Cover Letter]\n\nFrom: Angela Yu <a.yu@email.com>\nTo: careers@meridiancapital.sg\nDate: October 14\n\nDear Hiring Manager,\n\nI am writing to apply for the Senior Financial Analyst role at Meridian Capital Partners. I hold an MBA from the National University of Singapore and have over six years of experience in equity research and portfolio analysis at DBS Bank.\n\nIn my current role, I regularly use Excel and Bloomberg Terminal, and I recently completed an online Python course to further strengthen my analytical toolkit. I am also fluent in both English and Mandarin, which I believe will be a valuable asset in your regional operations.\n\nI am particularly excited about Meridian's focus on Asia-Pacific markets, an area I have followed closely throughout my career. I would welcome the opportunity to contribute my expertise to your team.\n\nI look forward to hearing from you.\nSincerely,\nAngela Yu","passageTitle":"Job Advertisement + Cover Letter","type":"double","questions":[{"id":"n7-4a","part":7,"question":"What is the maximum salary offered for the position?","options":["SGD 90,000","SGD 100,000","SGD 115,000","SGD 120,000"],"answer":2,"explanation":"✅ <b>SGD 115,000</b>. <br>💡 <i>Dẫn chứng:</i> 'Salary: SGD 90,000 – 115,000 annually'."},{"id":"n7-4b","part":7,"question":"Which qualification listed as preferred does Angela Yu possess?","options":["CFA certification","MBA degree","Bachelor's in Accounting","CPA designation"],"answer":1,"explanation":"✅ <b>MBA degree</b>. <br>💡 <i>Kết nối:</i> JD yêu cầu 'MBA or CFA preferred', Angela Yu có 'MBA from the National University of Singapore'."},{"id":"n7-4c","part":7,"question":"How does Angela Yu's Python proficiency compare to the job requirements?","options":["She exceeds the requirement with a formal degree","She meets it with years of experience","She recently obtained the skill through a course","She does not mention Python"],"answer":2,"explanation":"✅ <b>Recently obtained via a course</b>. <br>💡 <i>Dẫn chứng:</i> 'I recently completed an online Python course'."},{"id":"n7-4d","part":7,"question":"What additional advantage does Angela Yu mention she has?","options":["Knowledge of financial regulations","Fluency in Mandarin","Prior experience at Meridian","A network of regional clients"],"answer":1,"explanation":"✅ <b>Fluency in Mandarin</b>. <br>💡 <i>Kết nối:</i> JD nói 'Mandarin is an advantage', Angela nói 'I am also fluent in both English and Mandarin'."}]},{"passage":"[Document 1 – Email]\n\nFrom: Diana Cho <d.cho@nordicretail.com>\nTo: Marcus Webb <m.webb@nordicretail.com>\nDate: April 25\nSubject: Customer Satisfaction Survey – Q1 Results\n\nHi Marcus,\n\nPlease find attached the Q1 customer satisfaction survey results. Overall, the numbers look promising, though I wanted to draw your attention to a few key findings.\n\nFirst, our average satisfaction score has risen to 4.2 out of 5, up from 3.8 last quarter. However, product variety received the lowest rating, scoring just 3.4. Several customers also commented that wait times during peak hours are too long.\n\nI recommend we discuss these findings at next week's operations meeting. I'll prepare a more detailed breakdown by category beforehand. In the meantime, could you look into whether the checkout staffing levels are adequate during peak periods?\n\nThanks,\nDiana\n\n[Document 2 – Survey Summary]\n\nNordic Retail – Customer Satisfaction Survey Q1\nTotal Respondents: 412\nSurvey Period: January 1 – March 31\n\nCategory Scores (out of 5):\n• Staff Friendliness: 4.7\n• Store Cleanliness: 4.5\n• Checkout Speed: 3.6\n• Product Variety: 3.4\n• Overall Experience: 4.2\n\nTop Customer Comments:\n• \"Staff are always helpful and welcoming.\"\n• \"I wish there were more options for plant-based products.\"\n• \"Lines at checkout are too long on Saturday mornings.\"\n\nNote: Compared to Q4 of last year, overall satisfaction has increased by 0.4 points.","passageTitle":"Email + Survey Results","type":"double","questions":[{"id":"n7-5a","part":7,"question":"What was the overall satisfaction score in Q4 of the previous year?","options":["3.4","3.6","3.8","4.2"],"answer":2,"explanation":"✅ <b>3.8</b>. <br>💡 <i>Tính toán:</i> Hiện tại 4.2, tăng 0.4 so với quý trước → 4.2 - 0.4 = 3.8."},{"id":"n7-5b","part":7,"question":"What does Diana ask Marcus to look into?","options":["Expanding product variety","Improving store cleanliness","Reviewing staffing during peak periods","Updating the survey format"],"answer":2,"explanation":"✅ <b>Reviewing staffing</b>. <br>💡 <i>Dẫn chứng:</i> 'could you look into whether the checkout staffing levels are adequate during peak periods?'."},{"id":"n7-5c","part":7,"question":"Based on the survey, what received the highest rating?","options":["Overall Experience","Checkout Speed","Staff Friendliness","Product Variety"],"answer":2,"explanation":"✅ <b>Staff Friendliness</b> (4.7). <br>💡 <i>So sánh:</i> Trong bảng điểm, Staff Friendliness đạt 4.7, cao nhất."},{"id":"n7-5d","part":7,"question":"What do customer comments suggest about Saturday mornings?","options":["The store is particularly clean","Staff are less friendly on weekends","Checkout lines are too long","Product variety improves on weekends"],"answer":2,"explanation":"✅ <b>Checkout lines are too long</b>. <br>💡 <i>Dẫn chứng:</i> 'Lines at checkout are too long on Saturday mornings'."}]},{"passage":"[Document 1 – Job Posting]\n\nPOSITION: Events Coordinator\nCompany: Apex Event Solutions\nLocation: Toronto, ON\nEmployment: Full-time, Permanent\nSalary: CAD 55,000 – 65,000\n\nApex Event Solutions is a full-service event management company specializing in corporate conferences, product launches, and charity galas. We are looking for an organized, energetic Events Coordinator to join our team.\n\nRequirements:\n• Diploma or degree in Event Management, Hospitality, or related field\n• Minimum 2 years of event coordination experience\n• Proficiency in event management software (e.g., Cvent, Eventbrite)\n• Valid driver's license\n• Ability to work evenings and weekends as needed\n\nApplication Instructions:\nSend CV and cover letter to hr@apexevents.ca by August 15.\n\n[Document 2 – Application Email]\n\nFrom: Tyler Brooks <t.brooks@email.com>\nTo: hr@apexevents.ca\nDate: August 10\n\nDear HR Team,\n\nI am applying for the Events Coordinator position at Apex Event Solutions. I hold a diploma in Hospitality Management from Centennial College and have three years of experience coordinating events for a nonprofit organization in Toronto.\n\nI am highly proficient in Eventbrite and have recently begun training in Cvent. I hold a valid driver's license and am comfortable with weekend and evening work.\n\nI would be excited to bring my passion for event planning to Apex Event Solutions. Please find my CV attached.\n\nWarm regards,\nTyler Brooks\n\n[Document 3 – Interview Schedule]\n\nFrom: Sandra Lim <s.lim@apexevents.ca>\nTo: Tyler Brooks <t.brooks@email.com>\nDate: August 22\n\nDear Mr. Brooks,\n\nThank you for your application. We are pleased to invite you to an interview on Tuesday, September 3, at 10:00 a.m. at our office (200 Bay Street, Suite 1500, Toronto).\n\nThe interview will be conducted by our Events Director, Ms. Patricia Allen, and will last approximately one hour. You will be asked to complete a brief practical exercise related to event planning as part of the interview process.\n\nPlease confirm your availability by replying to this email by August 28.\n\nKind regards,\nSandra Lim\nHR Coordinator","passageTitle":"Job Posting + Application Email + Interview Schedule","type":"triple","questions":[{"id":"n7-6a","part":7,"question":"What is the minimum salary for the Events Coordinator position?","options":["CAD 45,000","CAD 55,000","CAD 65,000","CAD 75,000"],"answer":1,"explanation":"✅ <b>CAD 55,000</b>. <br>💡 <i>Dẫn chứng:</i> 'Salary: CAD 55,000 – 65,000'."},{"id":"n7-6b","part":7,"question":"How does Tyler Brooks' experience compare to the job requirements?","options":["He lacks the required qualification","He meets the minimum experience requirement","He has more experience than required","He does not have a valid driver's license"],"answer":2,"explanation":"✅ <b>More experience than required</b>. <br>💡 <i>So sánh:</i> JD yêu cầu 2 năm, Tyler có 3 năm kinh nghiệm."},{"id":"n7-6c","part":7,"question":"What does Tyler Brooks mention about Cvent?","options":["He has been using it for three years","He is an expert in it","He is currently being trained in it","He does not know the software"],"answer":2,"explanation":"✅ <b>Currently being trained</b>. <br>💡 <i>Dẫn chứng:</i> 'have recently begun training in Cvent'."},{"id":"n7-6d","part":7,"question":"What will Tyler Brooks be required to do during the interview?","options":["Give a 30-minute presentation","Complete a written grammar test","Participate in a practical event planning exercise","Meet with three different managers"],"answer":2,"explanation":"✅ <b>Practical event planning exercise</b>. <br>💡 <i>Dẫn chứng:</i> 'complete a brief practical exercise related to event planning'."},{"id":"n7-6e","part":7,"question":"By what date must Tyler Brooks confirm his availability?","options":["August 10","August 15","August 22","August 28"],"answer":3,"explanation":"✅ <b>August 28</b>. <br>💡 <i>Dẫn chứng:</i> 'confirm your availability by replying to this email by August 28'."}]},{"passage":"[Document 1 – Website Notice]\n\nSTAR FITNESS APP – SERVICE UPDATE\nPosted: October 1\n\nDear Star Fitness Members,\n\nWe are excited to announce that Star Fitness will be launching its redesigned mobile application on October 15. The new app includes a personalized workout planner, nutrition tracker, and live class booking feature.\n\nExisting subscribers will be migrated to the new platform automatically. Please note that your existing workout history and preferences will be transferred to the new app. The legacy app will remain accessible until November 30, after which it will be retired.\n\nAll current memberships will continue under their existing terms. New annual subscriptions will be priced at $89/year (previously $79/year).\n\n[Document 2 – Member Email]\n\nFrom: Rachel Stone <r.stone@email.com>\nTo: support@starfitness.com\nDate: October 8\n\nHello,\n\nI recently saw the update on your website regarding the new app. I am an existing annual subscriber — my renewal is coming up in November.\n\nI have two questions:\n1. Will my November renewal be charged at the old rate ($79) or the new rate ($89)?\n2. My workout history goes back about two years — will all of it transfer?\n\nThank you for your assistance.\nRachel Stone\n\n[Document 3 – Support Response]\n\nFrom: Star Fitness Support <support@starfitness.com>\nTo: Rachel Stone <r.stone@email.com>\nDate: October 10\n\nDear Ms. Stone,\n\nThank you for reaching out.\n\nRegarding your renewal: since your subscription was active before October 15, your November renewal will be honored at the existing rate of $79. The new pricing applies only to subscriptions initiated after the launch date.\n\nAs for your workout history, we are pleased to confirm that all historical data — including sessions logged up to two years prior — will be transferred to the new app automatically. Any data older than two years may need to be manually imported; instructions will be included in the app's help section.\n\nPlease don't hesitate to contact us if you have any further questions.\n\nBest regards,\nStar Fitness Support Team","passageTitle":"Notice + Customer Email + Company Response","type":"triple","questions":[{"id":"n7-7a","part":7,"question":"What is the price of a new annual Star Fitness subscription after October 15?","options":["$69/year","$79/year","$89/year","$99/year"],"answer":2,"explanation":"✅ <b>$89/year</b>. <br>💡 <i>Dẫn chứng:</i> 'New annual subscriptions will be priced at $89/year'."},{"id":"n7-7b","part":7,"question":"What is Rachel Stone concerned about?","options":["The quality of the new app's design","Her subscription renewal price and workout data","The retirement of the old app","The new nutrition tracking feature"],"answer":1,"explanation":"✅ <b>Renewal price and workout data</b>. <br>💡 <i>Phân tích:</i> Email của Rachel hỏi về giá gia hạn và lịch sử tập luyện."},{"id":"n7-7c","part":7,"question":"How much will Rachel Stone pay for her November renewal?","options":["$69","$79","$89","$99"],"answer":1,"explanation":"✅ <b>$79</b>. <br>💡 <i>Dẫn chứng:</i> 'your November renewal will be honored at the existing rate of $79'."},{"id":"n7-7d","part":7,"question":"What does the support response say about Rachel's two-year workout history?","options":["It will be lost during migration","It can only be accessed on the old app","It will be transferred automatically","It must be exported by Rachel manually"],"answer":2,"explanation":"✅ <b>Transferred automatically</b>. <br>💡 <i>Dẫn chứng:</i> 'sessions logged up to two years prior — will be transferred to the new app automatically'."},{"id":"n7-7e","part":7,"question":"What will happen to data older than two years?","options":["It will be deleted permanently","It will transfer automatically like recent data","It will require manual import with instructions provided","It will be emailed to the user"],"answer":2,"explanation":"✅ <b>Manual import with instructions</b>. <br>💡 <i>Dẫn chứng:</i> 'Any data older than two years may need to be manually imported'."}]},{"passage":"[Document 1 – Product Brochure Excerpt]\n\nINTRODUCING THE LUMINO DESK LAMP – Model L300\nManufacturer: Solara Home Products\n\nThe Lumino L300 is our most advanced desk lamp, designed for home office and professional use.\n\nKey Features:\n• Three adjustable color temperature modes: Cool White, Neutral, Warm\n• 5-level brightness control\n• USB-A charging port on base\n• Touch control panel\n• Energy-efficient LED — 50,000-hour lifespan\n• 2-year manufacturer's warranty\n\nRetail Price: $79.99\n\nFor warranty claims and support, visit www.solarahome.com/support or call 1-800-765-4321.\n\n[Document 2 – Online Customer Review]\n\nReviewer: T. Harrison | Rating: 3 out of 5 stars\nPosted: February 20\n\nI purchased the Lumino L300 about six months ago and overall it performs well for reading and working. The color temperature options are genuinely useful and the brightness range is excellent.\n\nHowever, I was disappointed to find that the USB charging port stopped working after only three months. I checked the product listing and it clearly states a 2-year warranty, but when I contacted customer service, I was initially told the USB port wasn't covered. I pushed back, and they eventually agreed to send a replacement unit, but the process took three weeks.\n\nThe product itself is good, but customer service needs improvement.\n\n[Document 3 – Company Response]\n\nPosted by Solara Home Products – February 25\n\nDear T. Harrison,\n\nThank you for your feedback. We sincerely apologize for the confusion regarding warranty coverage. To clarify, all components of the Lumino L300, including the USB charging port, are covered under the 2-year manufacturer's warranty. We are sorry that this was not communicated clearly during your initial contact with our team.\n\nWe have taken note of your experience and are retraining our customer support team to ensure consistent and accurate warranty information is provided from the outset.\n\nWe hope the replacement unit is serving you well. Should you experience any further issues, please do not hesitate to reach out to us directly.\n\nWarm regards,\nSolara Home Products Customer Relations","passageTitle":"Product Brochure + Customer Review + Company Reply","type":"triple","questions":[{"id":"n7-8a","part":7,"question":"How many brightness levels does the Lumino L300 offer?","options":["3","4","5","6"],"answer":2,"explanation":"✅ <b>5</b>. <br>💡 <i>Dẫn chứng:</i> '5-level brightness control'."},{"id":"n7-8b","part":7,"question":"What issue did T. Harrison experience with the product?","options":["The touch panel stopped working","The color temperature stopped changing","The USB charging port failed","The LED burned out early"],"answer":2,"explanation":"✅ <b>USB charging port failed</b>. <br>💡 <i>Dẫn chứng:</i> 'the USB charging port stopped working after only three months'."},{"id":"n7-8c","part":7,"question":"What was T. Harrison initially told by customer service?","options":["The lamp was out of warranty","The USB port was not covered by warranty","A replacement would be sent immediately","The product was discontinued"],"answer":1,"explanation":"✅ <b>Not covered by warranty</b>. <br>💡 <i>Dẫn chứng:</i> 'I was initially told the USB port wasn't covered'."},{"id":"n7-8d","part":7,"question":"According to Solara's response, what action are they taking following this complaint?","options":["Redesigning the USB port","Offering refunds to all customers","Retraining their customer support team","Extending the warranty to 3 years"],"answer":2,"explanation":"✅ <b>Retraining customer support</b>. <br>💡 <i>Dẫn chứng:</i> 'we are retraining our customer support team'."},{"id":"n7-8e","part":7,"question":"What can be inferred about the USB port's warranty coverage?","options":["It was excluded from the original warranty","It is covered under the 2-year warranty per company policy","It requires a separate warranty purchase","It is only covered if registered online"],"answer":1,"explanation":"✅ <b>Covered under 2-year warranty</b>. <br>💡 <i>Dẫn chứng:</i> Solara khẳng định 'all components... are covered under the 2-year manufacturer's warranty'."}]},{"passage":"JOB OPPORTUNITY\n\nPosition: Digital Marketing Specialist\nCompany: BrightPath Media Group\nLocation: Ho Chi Minh City, Vietnam (On-site)\nSalary: VND 25,000,000 – 35,000,000/month\nEmployment Type: Full-Time, Permanent\n\nBrightPath Media Group is a leading digital marketing agency specializing in content strategy, social media management, and performance advertising. We are seeking a talented and results-driven Digital Marketing Specialist to join our growing team.\n\nKey Responsibilities:\n• Develop and execute multi-channel digital marketing campaigns\n• Manage paid advertising campaigns (Google Ads, Meta Ads)\n• Analyze campaign performance using Google Analytics and prepare weekly reports\n• Collaborate with the creative team on content development\n\nRequirements:\n• Minimum 2 years of experience in digital marketing\n• Google Ads certification preferred\n• Strong analytical skills and proficiency in Excel\n• Excellent written and verbal communication skills in English and Vietnamese\n\nBenefits: 13th month salary, health insurance, annual performance review, and 15 days of paid leave.\n\nTo apply, send your CV and portfolio to careers@brightpathmedia.vn by August 30.\nOnly shortlisted candidates will be notified.","passageTitle":null,"type":"single","questions":[{"id":"b7-s1a","part":7,"question":"What type of company is BrightPath Media Group?","options":["A technology startup","A digital marketing agency","A television production house","A financial consulting firm"],"answer":1,"explanation":"'BrightPath Media Group is a leading digital marketing agency'."},{"id":"b7-s1b","part":7,"question":"Which skill is listed as preferred but not required?","options":["Proficiency in Excel","Communication skills in Vietnamese","Google Ads certification","Experience in content development"],"answer":2,"explanation":"'Google Ads certification preferred' = ưu tiên nhưng không bắt buộc."},{"id":"b7-s1c","part":7,"question":"How many days of paid leave are offered?","options":["10 days","12 days","13 days","15 days"],"answer":3,"explanation":"'15 days of paid leave' nêu trong phần Benefits."},{"id":"b7-s1d","part":7,"question":"What must applicants include when applying?","options":["A cover letter and references","A CV and portfolio","A CV and transcript","A portfolio only"],"answer":1,"explanation":"'Send your CV and portfolio to careers@brightpathmedia.vn'."}]},{"passage":"From: Rachel Moore <r.moore@cedarwoodshops.com>\nTo: Kevin Tanaka <k.tanaka@email.com>\nDate: September 16\nSubject: RE: Order #CW-44821 – Delayed Delivery\n\nDear Mr. Tanaka,\n\nThank you for bringing this matter to our attention. I sincerely apologize for the delay in delivering your order, which was originally estimated to arrive on September 10.\n\nAfter conducting a thorough investigation, we have determined that the delay was caused by an unexpected inventory error at our distribution center in Melbourne, which resulted in your items being held for an additional five business days.\n\nI am pleased to inform you that your order has now been dispatched and is currently in transit. Based on the updated tracking information, delivery is expected by September 19.\n\nAs an apology for the inconvenience, we have added a store credit of AUD 25 to your account, which can be applied to any future purchase. Additionally, shipping fees for this order have been fully waived.\n\nWe value your patronage and appreciate your patience. Should you have any further concerns, please do not hesitate to contact our support team.\n\nWarm regards,\nRachel Moore\nCustomer Relations Manager, Cedarwood Shops","passageTitle":null,"type":"single","questions":[{"id":"b7-s2a","part":7,"question":"Why was Mr. Tanaka's order delayed?","options":["A courier service problem","An inventory error at the distribution center","A delay in payment processing","A public holiday in Melbourne"],"answer":1,"explanation":"'delay was caused by an unexpected inventory error at our distribution center in Melbourne'."},{"id":"b7-s2b","part":7,"question":"When is the order now expected to arrive?","options":["September 10","September 14","September 16","September 19"],"answer":3,"explanation":"'delivery is expected by September 19'."},{"id":"b7-s2c","part":7,"question":"What compensation did the company offer?","options":["A full refund","A replacement item and a discount","Store credit and free shipping","A gift card and priority delivery"],"answer":2,"explanation":"'store credit of AUD 25' và 'shipping fees for this order have been fully waived'."},{"id":"b7-s2d","part":7,"question":"What can be inferred about Cedarwood Shops?","options":["It only sells products online","It has a distribution center outside Australia","It is based in Melbourne","It has store credit programs for customers"],"answer":3,"explanation":"Công ty đã cộng store credit vào tài khoản → có chương trình store credit."}]},{"passage":"FOR IMMEDIATE RELEASE\n\nVertexLink Acquires CloudNest Analytics to Strengthen Data Intelligence Capabilities\n\nSAN JOSE, October 22 – VertexLink Corporation (NASDAQ: VTLK) today announced the acquisition of CloudNest Analytics, a leading provider of real-time business intelligence solutions, for approximately USD 420 million in cash and stock.\n\nCloudNest Analytics serves more than 800 enterprise clients across North America and Europe, including five Fortune 500 companies. Its flagship product, DataPulse, provides organizations with real-time dashboards and predictive analytics capabilities.\n\n\"This acquisition accelerates our vision of delivering end-to-end data intelligence solutions to our global enterprise customers,\" said Marcus Chen, CEO of VertexLink. \"CloudNest's technology and talent are a perfect strategic fit.\"\n\nThe transaction is subject to regulatory approvals and is expected to close in the first quarter of the coming year. CloudNest Analytics will continue to operate under its own brand until integration is complete.\n\nAbout VertexLink Corporation: VertexLink is a global technology company headquartered in San Jose, California, providing enterprise software solutions to over 3,500 clients in 40 countries.\n\nMedia Contact: press@vertexlink.com","passageTitle":null,"type":"single","questions":[{"id":"b7-s3a","part":7,"question":"What is the purpose of this press release?","options":["To announce a new product launch","To report quarterly earnings results","To announce the acquisition of a company","To introduce a new CEO"],"answer":2,"explanation":"Press release thông báo VertexLink mua lại CloudNest Analytics."},{"id":"b7-s3b","part":7,"question":"What is DataPulse?","options":["A new VertexLink product","CloudNest's flagship product","A Fortune 500 company client","A financial analytics platform"],"answer":1,"explanation":"'Its flagship product, DataPulse, provides...' – 'Its' refers to CloudNest Analytics."},{"id":"b7-s3c","part":7,"question":"When is the transaction expected to be finalized?","options":["By the end of October","In the first quarter of next year","After regulatory approvals in six months","Immediately following the announcement"],"answer":1,"explanation":"'expected to close in the first quarter of the coming year'."},{"id":"b7-s3d","part":7,"question":"What does the press release say about CloudNest's brand?","options":["It will be rebranded as VertexLink","It will be discontinued after integration","It will operate under its own name during integration","It will merge with DataPulse"],"answer":2,"explanation":"'CloudNest Analytics will continue to operate under its own brand until integration is complete'."}]},{"passage":"NOTICE\n\nLibrary Services – Temporary Closure of Reference Section\n\nThe Reference Section of the Westgate City Library will be closed for refurbishment from Monday, April 7 through Friday, April 18. All other areas of the library, including the general lending floors, the digital resource room, and the children's section, will remain open during normal hours.\n\nDuring the closure, patrons requiring access to reference materials may use the Eastdale Branch Library, located at 1245 Eastdale Drive, which is open Monday through Saturday, 9:00 a.m. to 7:00 p.m.\n\nOnline access to e-books, academic journals, and digital databases will continue without interruption and is available 24 hours a day at library.westgatecity.org.\n\nAll items currently on loan from the Reference Section are due to be returned by April 5. Late returns will not incur fines during the closure period.\n\nWe apologize for any inconvenience this may cause and look forward to welcoming you to an improved Reference Section when it reopens on April 21.\n\nWestgate City Library Management","passageTitle":null,"type":"single","questions":[{"id":"b7-s4a","part":7,"question":"Which part of the library will be temporarily closed?","options":["The children's section","The digital resource room","The general lending floors","The Reference Section"],"answer":3,"explanation":"'The Reference Section of the Westgate City Library will be closed for refurbishment'."},{"id":"b7-s4b","part":7,"question":"Where can patrons go for reference materials during the closure?","options":["The Westgate City Library digital portal","The Eastdale Branch Library","The downtown community center","An affiliated university library"],"answer":1,"explanation":"'patrons requiring access to reference materials may use the Eastdale Branch Library'."},{"id":"b7-s4c","part":7,"question":"What happens to late returns during the closure period?","options":["Fines are doubled","Fines are charged at the standard rate","No fines will be charged","Items must be returned before the closure begins"],"answer":2,"explanation":"'Late returns will not incur fines during the closure period'."},{"id":"b7-s4d","part":7,"question":"When does the Reference Section reopen?","options":["April 5","April 7","April 18","April 21"],"answer":3,"explanation":"'welcoming you to an improved Reference Section when it reopens on April 21'."}]},{"passage":"EMPLOYEE WELLNESS SURVEY – SUMMARY REPORT\nIsland Pacific Group | Prepared by: People & Culture Team\nSurvey Period: August 1–15 | Total Respondents: 287 (out of 312 staff)\n\nKEY FINDINGS\n\nOverall Job Satisfaction: 74% of respondents reported feeling satisfied or very satisfied with their roles, a 6-point increase compared to last year's survey.\n\nWork-Life Balance: 61% of employees reported that their current workload allows for adequate personal time. However, 38% indicated they regularly work beyond their contracted hours, with this figure highest among staff in the Finance and Operations departments.\n\nProfessional Development: 82% expressed a desire for more structured training and career development opportunities. The top requested programs were leadership development (48%), technical skills training (35%), and language learning (17%).\n\nWorkplace Environment: The canteen facilities and the open-plan office layout were rated as the top two areas for improvement. Conversely, team collaboration and management support received the highest satisfaction scores.\n\nRECOMMENDATIONS\nBased on these results, the People & Culture Team recommends: (1) introducing a capped overtime policy for Finance and Operations staff; (2) launching a structured development program with quarterly workshops; and (3) initiating a canteen upgrade in Q1 next year.","passageTitle":null,"type":"single","questions":[{"id":"b7-s5a","part":7,"question":"What percentage of staff responded to the survey?","options":["61%","74%","82%","The majority of the 312 staff"],"answer":3,"explanation":"287 out of 312 responded. 287/312 ≈ 92% → 'the majority'. Không có con số 92% nào trong đáp án → chọn 'The majority'."},{"id":"b7-s5b","part":7,"question":"Which departments had the highest rate of overtime work?","options":["Marketing and Sales","HR and Legal","Finance and Operations","IT and Communications"],"answer":2,"explanation":"'this figure highest among staff in the Finance and Operations departments'."},{"id":"b7-s5c","part":7,"question":"What was the most requested type of professional development?","options":["Technical skills training","Language learning","Leadership development","Project management"],"answer":2,"explanation":"'leadership development (48%)' = tỉ lệ cao nhất trong ba lựa chọn."},{"id":"b7-s5d","part":7,"question":"What is one area the People & Culture Team recommends improving?","options":["Team collaboration programs","Management support training","Canteen facilities","Open-plan office layout"],"answer":2,"explanation":"'initiating a canteen upgrade in Q1 next year' = một trong ba khuyến nghị."}]},{"passage":"DISCOVER SONOVA ISLAND\nA Premier Luxury Eco-Resort Experience\n\nNestled among the pristine coral reefs of the Andaman Sea, Sonova Island Resort offers an unrivaled escape for discerning travelers who seek both luxury and environmental responsibility.\n\nOur 42 overwater villas and beachfront suites are designed with locally sourced materials and feature panoramic ocean views, private infinity pools, and 24-hour butler service. Each villa is powered entirely by solar energy.\n\nGUEST EXPERIENCES:\n• Guided snorkeling and scuba diving excursions led by certified marine biologists\n• Farm-to-table dining at our award-winning Coral Table restaurant\n• Daily yoga and wellness retreats with resident instructors\n• Cultural tours of the neighboring fishing villages\n\nSUSTAINABILITY PLEDGE:\nSonova Island is proud to hold the Global Eco-Certification Platinum designation, the highest rating available. We employ over 80% of our staff from local communities and donate 5% of all revenue to coral reef restoration programs.\n\nRATES & AVAILABILITY:\nRates start from USD 850 per night. A minimum stay of three nights is required during peak season (December–February). Early booking discounts of 15% are available for reservations made more than 90 days in advance.\n\nBook now: www.sonovaisland.com | +66 76 521 9900","passageTitle":null,"type":"single","questions":[{"id":"b7-s6a","part":7,"question":"What is unique about the energy source for the villas?","options":["They use wind turbines","They are powered by solar energy","They rely on the local power grid","They use hydroelectric power"],"answer":1,"explanation":"'Each villa is powered entirely by solar energy'."},{"id":"b7-s6b","part":7,"question":"What certification does Sonova Island hold?","options":["ISO 14001 Environmental Management","Green Globe Standard","Global Eco-Certification Platinum","UNESCO World Heritage Eco-Status"],"answer":2,"explanation":"'Sonova Island is proud to hold the Global Eco-Certification Platinum designation'."},{"id":"b7-s6c","part":7,"question":"During which months is a minimum three-night stay required?","options":["June through August","September through November","December through February","March through May"],"answer":2,"explanation":"'minimum stay of three nights is required during peak season (December–February)'."},{"id":"b7-s6d","part":7,"question":"How can guests receive a 15% discount?","options":["By booking during off-peak season","By staying more than five nights","By booking more than 90 days in advance","By joining the resort's loyalty program"],"answer":2,"explanation":"'Early booking discounts of 15% are available for reservations made more than 90 days in advance'."}]},{"passage":"EMPLOYEE BENEFITS GUIDE\nKaleidoscope Consulting Group\nEffective January 1, Current Year\n\nHEALTH & WELLNESS\nAll full-time employees are enrolled in the company's Premier Health Plan from their first day of employment. This plan covers 100% of inpatient hospital costs and 80% of outpatient services, including specialist consultations. Dental and vision coverage is optional and can be added during the annual enrollment window (November 1–15) or within 30 days of a qualifying life event.\n\nRETIREMENT SAVINGS\nKaleidoscope offers a matching contribution to the company's registered pension scheme. The company matches employee contributions up to 5% of gross annual salary. Employees become fully vested after 36 months of continuous employment.\n\nPROFESSIONAL DEVELOPMENT\nEach employee receives an annual learning allowance of USD 1,500 for approved courses, certifications, or conferences. Unused allowances cannot be carried over to the following year. Requests for learning activities must be submitted at least 30 days before the event.\n\nPARENTAL LEAVE\nPrimary caregivers are entitled to 18 weeks of fully paid parental leave. Secondary caregivers receive 4 weeks of paid leave. Leave may be taken at any point within the first 12 months following the birth or adoption of a child.\n\nFor full policy details, visit the HR portal at hr.kaleidoscopecg.com.","passageTitle":null,"type":"single","questions":[{"id":"b7-s7a","part":7,"question":"What percentage of outpatient services is covered by the Premier Health Plan?","options":["50%","80%","100%","It depends on the service type"],"answer":1,"explanation":"'80% of outpatient services, including specialist consultations'."},{"id":"b7-s7b","part":7,"question":"When can employees add dental and vision coverage?","options":["Only during their first week of employment","Only during the annual enrollment window","During the annual enrollment window or within 30 days of a life event","At any time of year"],"answer":2,"explanation":"'can be added during the annual enrollment window (November 1–15) or within 30 days of a qualifying life event'."},{"id":"b7-s7c","part":7,"question":"What happens to unused learning allowances at year-end?","options":["They roll over to the following year","They are added to the employee's salary","They cannot be carried over","They can be donated to a colleague"],"answer":2,"explanation":"'Unused allowances cannot be carried over to the following year'."},{"id":"b7-s7d","part":7,"question":"How long is a secondary caregiver entitled to paid parental leave?","options":["2 weeks","4 weeks","12 weeks","18 weeks"],"answer":1,"explanation":"'Secondary caregivers receive 4 weeks of paid leave'."}]},{"passage":"PROFESSIONAL CERTIFICATION PROGRAM\nProject Management for Business Leaders\nOffered by: Harmon Institute of Business Excellence\n\nProgram Overview:\nThis intensive six-week online program is designed for mid-to-senior level managers seeking to formalize their project management expertise and earn internationally recognized certification.\n\nProgram Structure:\nThe course consists of four modules, each running for ten days. Participants will learn to apply agile and traditional project management frameworks, manage cross-functional teams, and use industry-standard tools including MS Project and Trello.\n\nAdmission Requirements:\n• Minimum 3 years of managerial experience\n• Bachelor's degree in any field\n• Submission of a 500-word professional statement\n\nSchedule & Fees:\nCohorts begin on the first Monday of each month. Program fee: USD 2,400, which includes all learning materials and the final certification exam. A payment plan option is available upon request.\n\nUpon successful completion, participants receive the Harmon Certified Project Manager (HCPM) designation, recognized in over 65 countries.\n\nApplication deadline: Applications must be submitted at least two weeks before the cohort start date.\n\nFor more information: admissions@harmonibe.org | +1 212 884 0031","passageTitle":null,"type":"single","questions":[{"id":"b7-s8a","part":7,"question":"Who is this program primarily designed for?","options":["Recent university graduates","Entry-level employees","Mid-to-senior level managers","IT project coordinators only"],"answer":2,"explanation":"'designed for mid-to-senior level managers seeking to formalize their project management expertise'."},{"id":"b7-s8b","part":7,"question":"How many modules does the course contain?","options":["3","4","5","6"],"answer":1,"explanation":"'The course consists of four modules, each running for ten days'."},{"id":"b7-s8c","part":7,"question":"What does the program fee include?","options":["Accommodation and meals","Learning materials and the certification exam","One-on-one mentoring sessions","MS Project software license"],"answer":1,"explanation":"'Program fee: USD 2,400, which includes all learning materials and the final certification exam'."},{"id":"b7-s8d","part":7,"question":"What must applicants submit along with the other requirements?","options":["Two letters of recommendation","A 500-word professional statement","A portfolio of past projects","A language proficiency test score"],"answer":1,"explanation":"'Submission of a 500-word professional statement' trong phần Admission Requirements."}]},{"passage":"[Document 1 – Internal Memo]\n\nTo: Sales Department\nFrom: Marcus Webb, Regional Sales Director\nDate: March 5\n\nEffective April 1, our team's sales performance will be evaluated using a new Key Performance Indicator (KPI) framework. Under this system, each sales representative will be assessed across three dimensions: monthly revenue generation, client retention rate, and new business acquisition.\n\nThe minimum acceptable score for each dimension is 70 out of 100. Representatives who score below 70 in any dimension for two consecutive months will be placed on a Performance Improvement Plan (PIP).\n\nI will hold individual briefing sessions with each of you during the week of March 20 to explain the full details. Please come prepared with any questions you may have.\n\nMarcus Webb\nRegional Sales Director\n\n[Document 2 – Reply Email]\n\nFrom: Nina Park <n.park@company.com>\nTo: Marcus Webb <m.webb@company.com>\nDate: March 8\n\nDear Marcus,\n\nThank you for the advance notice regarding the new KPI framework. I appreciate the transparency.\n\nI do have a few preliminary questions that I hope we can discuss during our individual session. My main concern relates to the new business acquisition dimension, as our territory has seen limited inbound leads over the past quarter due to the economic slowdown. I want to ensure that contextual factors like this are taken into account during evaluations.\n\nAdditionally, I would like to understand whether the 70-point minimum threshold will apply uniformly across all regions, or whether regional adjustments will be made.\n\nLooking forward to our meeting during the week of March 20.\n\nBest regards,\nNina Park\nSenior Sales Representative","passageTitle":"Internal Memo + Reply Email","type":"double","questions":[{"id":"b7-d1a","part":7,"question":"How many dimensions will sales representatives be evaluated on?","options":["Two","Three","Four","Five"],"answer":1,"explanation":"'three dimensions: monthly revenue generation, client retention rate, and new business acquisition'."},{"id":"b7-d1b","part":7,"question":"What triggers a Performance Improvement Plan?","options":["Missing one monthly target by more than 20%","Scoring below 70 in all dimensions","Scoring below 70 in any dimension for two consecutive months","Failing to attend the individual briefing session"],"answer":2,"explanation":"'Representatives who score below 70 in any dimension for two consecutive months will be placed on a PIP'."},{"id":"b7-d1c","part":7,"question":"What is Nina Park's primary concern about the new framework?","options":["The timing of the implementation","Whether client retention will be weighted fairly","That external market conditions might not be considered","The frequency of performance evaluations"],"answer":2,"explanation":"'I want to ensure that contextual factors like this are taken into account' – referring to limited leads due to economic slowdown."},{"id":"b7-d1d","part":7,"question":"What does Nina Park ask about the 70-point threshold?","options":["Whether it applies only to senior representatives","Whether it will change next quarter","Whether it will be adjusted by region","Whether it counts across all months"],"answer":2,"explanation":"'whether the 70-point minimum threshold will apply uniformly across all regions, or whether regional adjustments will be made'."},{"id":"b7-d1e","part":7,"question":"When are the individual briefing sessions scheduled?","options":["During the week of March 5","During the week of March 8","During the week of March 20","On April 1"],"answer":2,"explanation":"'I will hold individual briefing sessions...during the week of March 20'."}]},{"passage":"[Document 1 – Workshop Announcement]\n\nFINANCIAL LITERACY FOR ENTREPRENEURS\nA Half-Day Workshop\n\nDate: Saturday, November 9\nTime: 9:00 a.m. – 1:00 p.m.\nVenue: The Business Hub, Level 3, 320 Collins Street, Melbourne\nFacilitator: Ms. Diane Pearce, CPA – Senior Financial Advisor, Clearview Group\n\nWho Should Attend: Small business owners and entrepreneurs who want to strengthen their understanding of financial statements, cash flow management, and tax planning strategies.\n\nSession Outline:\n• 9:00 – 9:30: Financial Statements Demystified\n• 9:30 – 10:30: Cash Flow Management in Practice\n• 10:30 – 10:45: Break\n• 10:45 – 12:00: Tax Planning for Business Owners\n• 12:00 – 1:00: Networking Lunch\n\nRegistration Fee: AUD 95 per person (includes workbook and lunch)\nEarly Bird Rate: AUD 75 (register before October 25)\n\nPlaces are limited to 30 participants. Register at: www.thebusinesshub.com.au/events\n\n[Document 2 – Registration Email]\n\nFrom: Jamie Reyes <j.reyes@email.com>\nTo: events@thebusinesshub.com.au\nDate: October 20\n\nHello,\n\nI would like to register for the Financial Literacy for Entrepreneurs workshop on November 9. I am a sole trader who recently started a café business and I am particularly keen to attend the session on cash flow management.\n\nCould you please confirm whether the early bird rate is still available for registrations submitted today? I would also like to know whether the workbook can be accessed digitally, as I prefer to read on my tablet.\n\nFinally, are there any dietary options available at the networking lunch? I follow a vegetarian diet.\n\nThank you for your assistance.\n\nJamie Reyes","passageTitle":"Workshop Flyer + Registration Email","type":"double","questions":[{"id":"b7-d2a","part":7,"question":"Who is the facilitator of the workshop?","options":["A tax lawyer from Clearview Group","A senior financial advisor with a CPA qualification","A small business consultant","An entrepreneur and business owner"],"answer":1,"explanation":"'Ms. Diane Pearce, CPA – Senior Financial Advisor, Clearview Group'."},{"id":"b7-d2b","part":7,"question":"Which session is Jamie Reyes most interested in attending?","options":["Tax Planning for Business Owners","Financial Statements Demystified","Cash Flow Management in Practice","The Networking Lunch"],"answer":2,"explanation":"'I am particularly keen to attend the session on cash flow management'."},{"id":"b7-d2c","part":7,"question":"If Jamie Reyes qualifies for the early bird rate, how much will the registration cost?","options":["AUD 75","AUD 95","AUD 85","AUD 65"],"answer":0,"explanation":"'Early Bird Rate: AUD 75 (register before October 25)'. Jamie sent the email on October 20 → qualifies."},{"id":"b7-d2d","part":7,"question":"What is included in the registration fee?","options":["A parking pass and workbook","Lunch and a workbook","Lunch and follow-up consultation","A workbook and access to online materials"],"answer":1,"explanation":"'AUD 95 per person (includes workbook and lunch)'."},{"id":"b7-d2e","part":7,"question":"What additional information does Jamie Reyes request?","options":["The facilitator's contact information","Whether the event will be recorded","Dietary accommodations at lunch and digital workbook access","The exact room number at the venue"],"answer":2,"explanation":"Jamie hỏi hai điều: digital workbook và vegetarian options at the networking lunch."}]},{"passage":"[Document 1 – Corporate Travel Policy Update]\n\nHorizon Dynamics – UPDATED CORPORATE TRAVEL POLICY\nEffective Date: February 1\n\nThe following changes have been made to the corporate travel policy:\n\n1. Airline Bookings: All domestic flights must be booked at least 14 days in advance unless approved as an emergency by a Vice President or above. International flights require 21 days advance booking.\n\n2. Hotel Accommodation: The standard allowance for hotel accommodation is USD 180 per night for domestic travel and USD 250 per night for international travel. Any hotel exceeding these limits requires pre-approval via the travel request portal.\n\n3. Meals and Incidentals: The daily per diem rate is USD 60 for domestic and USD 90 for international travel. Receipts are required for any single expense over USD 25.\n\n4. Expense Reports: All expense reports must be submitted within 10 business days of return from travel. Late submissions will require a written explanation to the Finance Director.\n\n[Document 2 – Employee Email]\n\nFrom: Carlos Mendoza <c.mendoza@horizondynamics.com>\nTo: Finance Department <finance@horizondynamics.com>\nDate: February 17\n\nHi,\n\nI returned from the Toronto client visit on February 14 and wanted to clarify a few points before submitting my expense report.\n\nDuring my stay, I was unable to find a hotel within the USD 180 domestic limit in the downtown area near the client's office. I ended up staying at a hotel for USD 215 per night for three nights. I believe I did obtain pre-approval from the VP of Sales before booking – can you confirm this was processed?\n\nAlso, I had a client dinner on February 12 that came to USD 148. Does this fall under the per diem, or is it classified separately as a client entertainment expense?\n\nFinally, I want to make sure my expense report submission deadline is correct. I believe it should be submitted by February 28 – is that accurate?\n\nThank you.\nCarlos Mendoza","passageTitle":"Travel Policy Update + Employee Inquiry","type":"double","questions":[{"id":"b7-d3a","part":7,"question":"How far in advance must domestic flights typically be booked?","options":["7 days","10 days","14 days","21 days"],"answer":2,"explanation":"'All domestic flights must be booked at least 14 days in advance'."},{"id":"b7-d3b","part":7,"question":"Did Carlos Mendoza comply with hotel policy for his Toronto trip?","options":["Yes, because the hotel was within the allowance","Yes, because he obtained VP pre-approval before booking","No, because he did not submit a pre-approval request","No, because the hotel rate exceeded the international allowance"],"answer":1,"explanation":"Carlos stayed at a hotel exceeding the USD 180 limit but says 'I believe I did obtain pre-approval from the VP of Sales before booking' – which satisfies the policy requirement."},{"id":"b7-d3c","part":7,"question":"What is the daily domestic per diem rate?","options":["USD 25","USD 60","USD 90","USD 180"],"answer":1,"explanation":"'The daily per diem rate is USD 60 for domestic'."},{"id":"b7-d3d","part":7,"question":"Is Carlos Mendoza's estimated expense report deadline correct?","options":["Yes, February 28 is within the 10 business day requirement","No, the deadline should be February 24","No, the deadline passed on February 24","Cannot be determined from the information given"],"answer":0,"explanation":"Carlos returned February 14. 10 business days later (excluding weekends) ≈ late February/Feb 28 → correct."},{"id":"b7-d3e","part":7,"question":"What question does Carlos Mendoza ask about the client dinner expense?","options":["Whether it needs to be approved by a VP","Whether receipts are required for it","Whether it is covered under per diem or classified separately","Whether it can be split across multiple days"],"answer":2,"explanation":"'Does this fall under the per diem, or is it classified separately as a client entertainment expense?'"}]},{"passage":"[Document 1 – Product Advertisement]\n\nINTRODUCING THE ZEPHYR PRO STANDING DESK\nby ErgoWorks™\n\nTransform your workspace with the Zephyr Pro – the premium height-adjustable standing desk built for professionals who demand performance and style.\n\nFEATURES:\n• Smooth, whisper-quiet electric height adjustment (60 cm – 125 cm)\n• Solid oak desktop with anti-scratch surface coating\n• Triple memory presets to save your preferred heights\n• Built-in cable management tray\n• Maximum weight capacity: 100 kg\n• Available in three finishes: Natural Oak, Dark Walnut, and White Ash\n\nWHY ERGOWORKS™?\nClinically proven to reduce back pain by up to 54% with regular alternating sitting and standing. Backed by a 5-year manufacturer's warranty on all components.\n\nRetail Price: USD 749 | Assembly required (estimated 45 minutes)\nOrder at: www.ergoworks.com | Free shipping on orders over USD 500\n\n[Document 2 – Online Review]\n\nRated: 4 out of 5 stars\nReviewer: T. Nguyen | Verified Purchase | Posted: July 12\n\nI purchased the Zephyr Pro in Dark Walnut three weeks ago and overall I'm very satisfied. The height adjustment mechanism is genuinely whisper-quiet – you barely notice it changing. Assembly took me closer to 75 minutes, not the 45 advertised, but the instructions were clear enough.\n\nThe desk is sturdy and the surface looks premium. I use all three memory presets daily and they work flawlessly. My one complaint is the cable management tray – it is too small for my four-monitor setup and the cables still end up looking messy.\n\nThe free shipping was a welcome bonus given the desk's weight. I haven't needed to contact customer service, so I can't comment on the warranty experience.\n\nWould recommend to professionals setting up a home office, especially those with a simpler cable setup.","passageTitle":"Product Advertisement + Online Review","type":"double","questions":[{"id":"b7-d4a","part":7,"question":"What height range does the Zephyr Pro adjust to?","options":["50 cm – 110 cm","60 cm – 125 cm","70 cm – 130 cm","55 cm – 120 cm"],"answer":1,"explanation":"'Smooth, whisper-quiet electric height adjustment (60 cm – 125 cm)'."},{"id":"b7-d4b","part":7,"question":"Which color finish did the reviewer purchase?","options":["Natural Oak","White Ash","Dark Walnut","Black Carbon"],"answer":2,"explanation":"'I purchased the Zephyr Pro in Dark Walnut three weeks ago'."},{"id":"b7-d4c","part":7,"question":"How does the reviewer's assembly experience compare to the advertisement?","options":["It took less time than advertised","It matched the 45-minute estimate exactly","It took 30 minutes longer than estimated","The instructions were difficult to follow"],"answer":2,"explanation":"'Assembly took me closer to 75 minutes, not the 45 advertised' → 30 minutes longer."},{"id":"b7-d4d","part":7,"question":"What does the reviewer criticize about the desk?","options":["The height adjustment noise","The surface scratch resistance","The cable management tray size","The number of memory presets"],"answer":2,"explanation":"'My one complaint is the cable management tray – it is too small for my four-monitor setup'."},{"id":"b7-d4e","part":7,"question":"Why did the reviewer NOT comment on the warranty service?","options":["The warranty had not yet started","The reviewer returned the product","The reviewer has not needed to contact customer service","The warranty is only valid after registration"],"answer":2,"explanation":"'I haven't needed to contact customer service, so I can't comment on the warranty experience'."}]},{"passage":"[Document 1 – Annual Report Excerpt]\n\nPALMSTONE RETAIL GROUP\nAnnual Report – Financial Highlights (Year Ending December 31)\n\nTotal Revenue: USD 2.14 billion (up 8.3% year-over-year)\nNet Profit: USD 187 million (up 12.1% year-over-year)\nOnline Sales: USD 640 million (30% of total revenue; up from 22% in the prior year)\nNew Store Openings: 14 locations (bringing the global total to 218 stores)\n\nCEO Statement (excerpt): \"This year marked a turning point for Palmstone. Our digital transformation initiative, launched 18 months ago, has accelerated e-commerce growth well beyond our initial projections. We remain committed to expanding our omnichannel presence while maintaining the in-store experience our customers value.\"\n\nOutlook: The company projects total revenue growth of 6–9% for the coming year, with online sales expected to account for 35% of total revenue.\n\n[Document 2 – News Article]\n\nPalmstone Retail Announces Two New Flagship Stores in Southeast Asia\nRetail Weekly | February 4\n\nPalmstone Retail Group, the global lifestyle and apparel brand, has confirmed plans to open two flagship stores in Southeast Asia later this year – one in Singapore and one in Ho Chi Minh City. The announcement follows the company's record-breaking annual results and signals a significant push into the region.\n\nIndustry analysts have noted that Palmstone's strong online growth in Southeast Asia – particularly in Vietnam and Indonesia – makes physical store expansion a logical step to strengthen brand presence.\n\nThe Singapore store is expected to open in Q3, while the Ho Chi Minh City location is targeted for Q4. Both stores will feature the company's new \"connected retail\" concept, which integrates digital tools such as virtual fitting rooms and QR-linked product information into the physical shopping experience.","passageTitle":"Annual Report Excerpt + News Article","type":"double","questions":[{"id":"b7-d5a","part":7,"question":"By what percentage did online sales grow as a share of total revenue?","options":["From 8% to 12%","From 22% to 30%","From 30% to 35%","From 25% to 30%"],"answer":1,"explanation":"'Online Sales: 30% of total revenue; up from 22% in the prior year'."},{"id":"b7-d5b","part":7,"question":"According to the CEO, what was the primary driver of e-commerce growth?","options":["A new mobile app launch","Reduced shipping costs","A digital transformation initiative launched 18 months ago","An expansion of the product range"],"answer":2,"explanation":"'Our digital transformation initiative, launched 18 months ago, has accelerated e-commerce growth'."},{"id":"b7-d5c","part":7,"question":"How many stores does Palmstone now operate globally?","options":["14","204","218","232"],"answer":2,"explanation":"'New Store Openings: 14 locations (bringing the global total to 218 stores)'."},{"id":"b7-d5d","part":7,"question":"Where is the new Ho Chi Minh City store scheduled to open?","options":["Q1","Q2","Q3","Q4"],"answer":3,"explanation":"'the Ho Chi Minh City location is targeted for Q4'."},{"id":"b7-d5e","part":7,"question":"What feature will both new Southeast Asian flagship stores include?","options":["A café and co-working space","Virtual fitting rooms and QR-linked product information","A dedicated children's play area","Same-day delivery service hubs"],"answer":1,"explanation":"'Both stores will feature...virtual fitting rooms and QR-linked product information into the physical shopping experience'."}]},{"passage":"[Document 1 – Job Advertisement]\n\nSENIOR ACCOUNTANT – PINNACLE HOLDINGS\nLocation: Auckland, New Zealand | Full-Time\nSalary: NZD 90,000 – 105,000 per annum\n\nPinnacle Holdings is a diversified investment group managing assets across real estate, private equity, and infrastructure. We seek a Senior Accountant to join our Finance team.\n\nRequirements:\n• Chartered Accountant (CA) or CPA qualification – REQUIRED\n• Minimum 5 years of experience in financial reporting or audit\n• Proficiency in SAP or equivalent ERP systems\n• Strong command of IFRS standards\n\nDeadline: Applications close July 15. Send CV to recruitment@pinnacleholdings.co.nz\n\n[Document 2 – Application Email]\n\nFrom: Oliver Huang <o.huang@email.com>\nTo: recruitment@pinnacleholdings.co.nz\nDate: July 10\n\nDear Recruitment Team,\n\nI am applying for the Senior Accountant role. I hold a Bachelor of Commerce degree and have six years of experience in financial reporting at a Big Four accounting firm. I am highly proficient in SAP and have worked extensively with IFRS standards.\n\nI am currently completing the final stage of my CA qualification, which I expect to receive in September. In the meantime, I hold a CPA designation obtained in 2020.\n\nI am confident my skills and experience make me a strong match. Please find my CV attached.\n\nBest regards,\nOliver Huang\n\n[Document 3 – Response Letter]\n\nFrom: Sandra Miles, HR Manager <s.miles@pinnacleholdings.co.nz>\nTo: Oliver Huang <o.huang@email.com>\nDate: July 22\n\nDear Mr. Huang,\n\nThank you for your application for the Senior Accountant position at Pinnacle Holdings.\n\nAfter careful review of all applications received, we are unable to proceed with your candidacy at this time. While your experience and SAP proficiency are impressive, we require candidates to hold a fully completed CA qualification at the time of application. We note that you expect to complete your CA in September.\n\nWe encourage you to reapply once your CA qualification is finalized, as your background would be a strong fit for future openings.\n\nThank you for your interest in Pinnacle Holdings.\n\nSincerely,\nSandra Miles\nHR Manager","passageTitle":"Job Advertisement + Application + Response Letter","type":"triple","questions":[{"id":"b7-t1a","part":7,"question":"Why was Oliver Huang's application not successful?","options":["He lacks experience in financial reporting","He does not have proficiency in SAP","His CA qualification is not yet completed","He applied after the deadline"],"answer":2,"explanation":"'we require candidates to hold a fully completed CA qualification at the time of application. We note that you expect to complete your CA in September'."},{"id":"b7-t1b","part":7,"question":"How many years of experience does Oliver Huang have?","options":["4 years","5 years","6 years","7 years"],"answer":2,"explanation":"'I have six years of experience in financial reporting'."},{"id":"b7-t1c","part":7,"question":"Which qualification does Oliver Huang currently hold?","options":["CA only","CPA and CA","CPA only","Neither CA nor CPA"],"answer":2,"explanation":"Oliver's CA is not yet complete but 'I hold a CPA designation obtained in 2020'."},{"id":"b7-t1d","part":7,"question":"What does the company suggest Oliver Huang do?","options":["Apply to a different department","Reapply after completing his CA","Contact the Finance Director directly","Attend an upcoming recruitment event"],"answer":1,"explanation":"'We encourage you to reapply once your CA qualification is finalized'."},{"id":"b7-t1e","part":7,"question":"Which requirement in the job advertisement did Oliver Huang NOT fully satisfy at the time of application?","options":["SAP proficiency","IFRS knowledge","Minimum years of experience","CA qualification"],"answer":3,"explanation":"Yêu cầu 'CA or CPA qualification – REQUIRED'. Oliver có CPA nhưng CA chưa hoàn thành → không đáp ứng đầy đủ."}]},{"passage":"[Document 1 – Catering Menu & Policy]\n\nFEAST & CO. CORPORATE CATERING\nMenu Selections & Ordering Policy\n\nAvailable Packages:\n• Standard Package: Cold buffet, soft drinks – USD 28 per person (min. 10 persons)\n• Premium Package: Hot buffet, soft drinks, dessert station – USD 48 per person (min. 10 persons)\n• Executive Package: 3-course plated meal, wine service – USD 95 per person (min. 20 persons)\n\nOrdering Policy:\n• Orders must be placed at least 5 business days before the event date\n• Cancellations made less than 48 hours before the event are non-refundable\n• Dietary requirements must be submitted with the order (no changes within 24 hours of event)\n\n[Document 2 – Order Confirmation]\n\nFrom: orders@feastandco.com\nTo: t.bradley@helixcorp.com\nDate: May 6\n\nDear Ms. Bradley,\n\nThank you for your order. This confirms your booking for:\n\nPackage: Premium Package\nEvent Date: May 14 (Wednesday)\nAttendees: 35 persons\nTotal: USD 1,680\n\nDietary Notes Received: 3 vegetarian, 1 nut allergy\n\nDelivery is scheduled for 11:30 a.m. on May 14. Please ensure someone is available to receive the delivery.\n\nIf you need to make any changes to your order, please contact us no later than May 12.\n\n[Document 3 – Complaint Email]\n\nFrom: Tara Bradley <t.bradley@helixcorp.com>\nTo: orders@feastandco.com\nDate: May 15\n\nHello,\n\nI am writing to report several issues with our catering order from yesterday's event.\n\nFirst, although we confirmed three vegetarian meals, only two were provided. A colleague who does not eat meat had to go without. Second, the food arrived approximately 40 minutes late, which disrupted the meeting schedule. We had informed your team that the event started at 12:00 p.m.\n\nAdditionally, the hot dishes were lukewarm upon arrival, likely due to the delivery delay.\n\nI would appreciate a partial refund or credit toward a future order. This was our first experience with Feast & Co. and unfortunately it was disappointing.\n\nRegards,\nTara Bradley\nOffice Manager, Helix Corp","passageTitle":"Catering Order Notice + Confirmation + Complaint","type":"triple","questions":[{"id":"b7-t2a","part":7,"question":"How much did Helix Corp pay for the catering order?","options":["USD 960","USD 1,200","USD 1,680","USD 3,325"],"answer":2,"explanation":"35 persons × USD 48 (Premium Package) = USD 1,680."},{"id":"b7-t2b","part":7,"question":"According to the catering policy, by what date should any order changes have been made?","options":["May 6","May 9","May 12","May 13"],"answer":2,"explanation":"'please contact us no later than May 12' from the confirmation email."},{"id":"b7-t2c","part":7,"question":"What was the first problem Tara Bradley reported?","options":["The food arrived cold","A nut allergy meal was not prepared","Only two vegetarian meals were provided instead of three","The wrong package was delivered"],"answer":2,"explanation":"'although we confirmed three vegetarian meals, only two were provided'."},{"id":"b7-t2d","part":7,"question":"What time was the food delivered based on the complaint?","options":["11:30 a.m.","12:00 p.m.","Approximately 12:10 p.m.","Approximately 12:40 p.m."],"answer":2,"explanation":"'food arrived approximately 40 minutes late' from the scheduled 11:30 a.m. → 11:30 + 40 = 12:10 p.m."},{"id":"b7-t2e","part":7,"question":"What resolution does Tara Bradley request?","options":["A full refund","A replacement order","A partial refund or credit toward a future order","A written apology from the catering manager"],"answer":2,"explanation":"'I would appreciate a partial refund or credit toward a future order'."}]},{"passage":"[Document 1 – Internal Memo]\n\nTo: All Sales & Marketing Staff\nFrom: Dr. Helena Cross, Chief Product Officer\nDate: January 8\n\nI am excited to announce that our new product, the NutriFlow Smart Water Bottle, will officially launch on February 1.\n\nThe NutriFlow tracks daily water intake, syncs with our mobile app, and reminds users to hydrate via customizable alerts. It is available in two sizes (500ml and 750ml) and three colors.\n\nRRP is USD 69.99. An introductory 20% launch discount will be offered through our website and partner retailers for the first 30 days.\n\nOur marketing campaign will begin January 22 across social media and fitness influencer partnerships. Sales targets for Q1 are set at 20,000 units.\n\n[Document 2 – Online News Article]\n\nNutriFlow Sells Out in 72 Hours\nHealthTech Review | February 4\n\nCedarTech's newly launched NutriFlow Smart Water Bottle has sold out of its initial stock of 10,000 units within 72 hours of its February 1 launch, the company confirmed.\n\nThe rapid sell-out was attributed to the product's competitive pricing with the launch discount applied, as well as a viral social media campaign featuring fitness influencers. CedarTech has indicated that additional stock is expected within three weeks.\n\nAnalysts noted that while the sell-out was impressive, the 10,000-unit initial stock represented only half of the Q1 sales target. CedarTech will need to fulfill the remaining 10,000 units to meet its goal.\n\n[Document 3 – Customer Review]\n\nRating: 5 out of 5\nReviewer: Marcus T. | Verified Purchase | Posted: February 3\n\nI bought the NutriFlow 750ml in navy blue on launch day and I love it. Syncing with the app was seamless and the hydration reminders have genuinely changed my habits. The bottle feels premium and the insulation is excellent – my water stayed cold for over 8 hours.\n\nI did pay full price as I wasn't aware of the discount at the time of purchase. A bit disappointing in hindsight, but the quality more than justifies the cost.\n\nHighly recommend to anyone focused on improving their health.","passageTitle":"Product Launch Memo + Media Article + Customer Feedback","type":"triple","questions":[{"id":"b7-t3a","part":7,"question":"What is the standard retail price of the NutriFlow?","options":["USD 49.99","USD 55.99","USD 69.99","USD 83.99"],"answer":2,"explanation":"'RRP is USD 69.99'."},{"id":"b7-t3b","part":7,"question":"How many units were in the initial stock at launch?","options":["5,000","10,000","20,000","30,000"],"answer":1,"explanation":"'sold out of its initial stock of 10,000 units within 72 hours'."},{"id":"b7-t3c","part":7,"question":"According to the news article, what was the Q1 sales target?","options":["10,000 units","15,000 units","20,000 units","30,000 units"],"answer":2,"explanation":"'the 10,000-unit initial stock represented only half of the Q1 sales target' → Q1 target = 20,000 units."},{"id":"b7-t3d","part":7,"question":"What issue does the reviewer mention about their purchase experience?","options":["The app did not sync correctly","They received the wrong color","They paid full price and missed the launch discount","Delivery took longer than expected"],"answer":2,"explanation":"'I did pay full price as I wasn't aware of the discount at the time of purchase'."},{"id":"b7-t3e","part":7,"question":"What can be inferred about when the reviewer purchased the NutriFlow?","options":["Before the official launch date","On the launch day, February 1","After the discount period ended","During the second stock release"],"answer":1,"explanation":"Reviewer says 'I bought...on launch day' → February 1. The discount was active (first 30 days) but reviewer was unaware of it."}]},{"passage":"NOTICE\nHarbourside Office Complex – Tower B\n\nROOFTOP GARDEN ACCESS POLICY UPDATE\n\nThe rooftop garden on Level 22 of Tower B has been re-opened following its three-month closure for landscaping and safety upgrades.\n\nEffective immediately, the following access rules apply:\n\n• The rooftop garden is available to all Tower B tenants during weekday business hours (7:00 a.m. – 8:00 p.m.) and on weekends from 9:00 a.m. to 6:00 p.m.\n• Access is via the elevator to Level 22 only. Use of the fire escape stairwell for routine access is prohibited.\n• A maximum of 40 persons may be on the rooftop at any one time. If this limit is reached, building security will manage a queue at the elevator.\n• Food and beverages are permitted, but glass containers are not allowed.\n• Corporate events or group bookings of more than 15 persons require prior approval from the Building Management Office at least 5 business days in advance.\n\nTenants are reminded that CCTV monitoring is active in all common areas. Any damage to the garden facilities will be the financial responsibility of the tenant involved.\n\nFor event booking inquiries: management@harboursidecomplex.com","passageTitle":null,"type":"single","questions":[{"id":"c7-s1a","part":7,"question":"What recently happened to the rooftop garden?","options":["It was permanently closed due to safety concerns.","It was renovated and has now reopened.","It was converted into a private meeting space.","It was opened for the first time."],"answer":1,"explanation":"'has been re-opened following its three-month closure for landscaping and safety upgrades'."},{"id":"c7-s1b","part":7,"question":"What is NOT permitted in the rooftop garden?","options":["Food and snacks","Beverages in plastic cups","Glass bottles and jars","Corporate events with prior approval"],"answer":2,"explanation":"'glass containers are not allowed' — 'glass containers' = chai/hộp thủy tinh."},{"id":"c7-s1c","part":7,"question":"How far in advance must group bookings be arranged?","options":["1 business day","3 business days","5 business days","1 week"],"answer":2,"explanation":"'require prior approval from the Building Management Office at least 5 business days in advance'."},{"id":"c7-s1d","part":7,"question":"What will happen if 40 people are already on the rooftop?","options":["The garden will be closed for the day.","Tenants will be turned away permanently.","Security will manage a queue at the elevator.","An announcement will be made over the PA system."],"answer":2,"explanation":"'building security will manage a queue at the elevator'."}]},{"passage":"TRAVEL ITINERARY\nPrepared for: Ms. Amara Osei, VP of Business Development\nDestination: Singapore\nTravel Dates: May 19 – May 23\n\nMONDAY, MAY 19\n09:00  Depart Ho Chi Minh City (SGN) — SQ 185 — Arrive Singapore (SIN) 11:55\n12:30  Hotel check-in: The Fullerton Hotel, 1 Fullerton Square\n14:00  Briefing with regional sales team at Marina Bay office\n19:00  Welcome dinner hosted by DeltaTrade Singapore, 1-Altitude Restaurant\n\nTUESDAY, MAY 20\n09:00  Board meeting — DeltaTrade Singapore HQ, Level 35\n12:30  Working lunch — internal strategy review\n15:00  Client presentation — Quantum Logistics, Clarke Quay office\n18:00  Free time\n\nWEDNESDAY, MAY 21\n10:00  Site tour — DeltaTrade Tuas Distribution Centre\n14:30  Debrief meeting with regional director, Mr. Ian Fong\n19:30  Corporate dinner — Waku Ghin, Marina Bay Sands\n\nTHURSDAY, MAY 22\n09:00  Open session — stakeholder Q&A\n11:30  Depart hotel for airport\n14:25  Depart Singapore (SIN) — SQ 184 — Arrive Ho Chi Minh City 15:30\n\nNOTES:\n• All ground transport in Singapore is arranged by DeltaTrade's local coordinator.\n• Hotel costs and flight are covered by the company. Incidentals are at Ms. Osei's own expense.\n• Please keep all receipts for reimbursement requests.","passageTitle":null,"type":"single","questions":[{"id":"c7-s2a","part":7,"question":"What is the purpose of Ms. Osei's trip to Singapore?","options":["To attend a regional conference","For business meetings, a site tour, and client presentations","To conduct employee performance reviews","To negotiate a new hotel contract"],"answer":1,"explanation":"Itinerary bao gồm board meeting, client presentation, site tour, và stakeholder Q&A."},{"id":"c7-s2b","part":7,"question":"On which day does Ms. Osei visit a distribution facility?","options":["Monday, May 19","Tuesday, May 20","Wednesday, May 21","Thursday, May 22"],"answer":2,"explanation":"'Wednesday, May 21 — Site tour — DeltaTrade Tuas Distribution Centre'."},{"id":"c7-s2c","part":7,"question":"Which expenses will Ms. Osei personally need to cover?","options":["Hotel costs","Flight tickets","Ground transportation in Singapore","Incidental expenses"],"answer":3,"explanation":"'Incidentals are at Ms. Osei's own expense'."},{"id":"c7-s2d","part":7,"question":"Who is hosting the welcome dinner on Monday evening?","options":["The regional sales team","DeltaTrade Singapore","Quantum Logistics","The Fullerton Hotel"],"answer":1,"explanation":"'Welcome dinner hosted by DeltaTrade Singapore'."}]},{"passage":"THE RISE OF THE FOUR-DAY WORKWEEK\nBusiness Horizons Magazine | October Issue\n\nOnce considered a radical concept reserved for progressive startups, the four-day workweek is quietly entering the mainstream. A landmark 2023 trial conducted across 61 companies in the United Kingdom — one of the largest of its kind — found that 92% of participating firms had no intention of returning to a five-day model after experiencing the results firsthand.\n\nParticipating companies reported significant benefits: productivity held steady or improved in 95% of cases, employee sick days fell by an average of 65%, and staff turnover dropped by 57%. Revenue also increased by an average of 1.4% during the trial period.\n\nCritics, however, argue that the model is far from universally applicable. Industries dependent on continuous operations — manufacturing, healthcare, logistics — face structural barriers to implementation. Small businesses and client-facing service companies also raise concerns about maintaining service coverage across four days.\n\nDespite these challenges, momentum is building. Iceland has run successful large-scale trials, Microsoft Japan reported a 40% productivity boost after a brief four-day pilot, and a growing number of governments are exploring legislation to make compressed workweeks a legal option for employees.\n\nWhether or not the four-day week becomes the global standard, it has forced a long-overdue conversation about what productivity truly means — and whether hours spent at a desk is really the right metric for measuring it.","passageTitle":null,"type":"single","questions":[{"id":"c7-s3a","part":7,"question":"What percentage of companies in the UK trial did NOT want to return to a five-day workweek?","options":["57%","65%","92%","95%"],"answer":2,"explanation":"'92% of participating firms had no intention of returning to a five-day model'."},{"id":"c7-s3b","part":7,"question":"According to the article, which result was observed regarding employee health during the trial?","options":["Productivity fell by 65%","Sick days decreased by 65%","Staff turnover increased by 57%","Revenue fell by 1.4%"],"answer":1,"explanation":"'employee sick days fell by an average of 65%'."},{"id":"c7-s3c","part":7,"question":"Which industry is specifically mentioned as having difficulty adopting the four-day model?","options":["Financial services","Education","Retail","Healthcare"],"answer":3,"explanation":"'Industries dependent on continuous operations — manufacturing, healthcare, logistics — face structural barriers'."},{"id":"c7-s3d","part":7,"question":"What does Microsoft Japan's four-day pilot suggest?","options":["The model is only suitable for large tech companies.","Productivity can increase significantly in a shorter workweek.","The government should legislate compressed workweeks.","Employees prefer more pay over fewer working hours."],"answer":1,"explanation":"'Microsoft Japan reported a 40% productivity boost after a brief four-day pilot' → shorter workweek can boost productivity."}]},{"passage":"From: Gabrielle Lamont <g.lamont@apexevents.com>\nTo: All Event Staff\nDate: December 9\nSubject: Post-Event Summary – Apex Annual Gala\n\nDear Team,\n\nI want to take a moment to share a brief recap of last Friday's Annual Gala and to personally thank each of you for your outstanding contributions.\n\nThe event welcomed 320 guests — exceeding our target of 300 — and ran smoothly from the cocktail reception at 7:00 p.m. through the final curtain at midnight. All audio-visual elements performed without a single technical failure, a significant improvement over last year's event.\n\nA few specific highlights:\n• The live auction raised USD 48,000 for our partner charity, surpassing the USD 35,000 goal by 37%.\n• Guest satisfaction surveys collected at the exit indicated an average rating of 4.7 out of 5.\n• Three new corporate sponsorships were confirmed on the night, collectively valued at USD 120,000 for next year's program.\n\nThat said, we did encounter a catering delay during the second course that led to a roughly 25-minute interruption to the evening program. I will be meeting with the catering manager next week to review what occurred and to put safeguards in place for future events.\n\nFinal reports and budget reconciliation will be distributed by December 15.\n\nThank you once again. Your professionalism made all the difference.\n\nGabrielle Lamont\nHead of Events, Apex","passageTitle":null,"type":"single","questions":[{"id":"c7-s4a","part":7,"question":"How many guests attended the Annual Gala?","options":["300","310","320","350"],"answer":2,"explanation":"'The event welcomed 320 guests — exceeding our target of 300'."},{"id":"c7-s4b","part":7,"question":"By how much did the live auction exceed its fundraising goal?","options":["USD 10,000","USD 13,000","USD 35,000","USD 48,000"],"answer":1,"explanation":"USD 48,000 raised – USD 35,000 goal = USD 13,000 surplus."},{"id":"c7-s4c","part":7,"question":"What issue occurred during the event?","options":["A technical failure with the audio-visual equipment","A delay in the catering during the second course","A guest capacity issue at the entrance","Sponsorship commitments fell short of target"],"answer":1,"explanation":"'we did encounter a catering delay during the second course that led to a roughly 25-minute interruption'."},{"id":"c7-s4d","part":7,"question":"What will Gabrielle Lamont do regarding the catering issue?","options":["Issue a formal complaint to the catering company","Hire a new catering vendor for future events","Meet with the catering manager to review and improve processes","Include a penalty clause in the next catering contract"],"answer":2,"explanation":"'I will be meeting with the catering manager next week to review what occurred and to put safeguards in place'."}]},{"passage":"URGENT PRODUCT RECALL NOTICE\nIsued by: SafeHome Appliances Ltd.\nProduct: OptiBreeze Portable Air Purifier – Model AP-330\nDate of Notice: July 14\n\nSafeHome Appliances Ltd. is voluntarily recalling all units of the OptiBreeze Portable Air Purifier, Model AP-330, manufactured between January and April of this year. This recall has been issued after internal testing identified a potential overheating risk in the device's power circuit under certain operating conditions.\n\nNo injuries have been reported to date; however, out of an abundance of caution, customers who own this model are strongly urged to:\n\n1. IMMEDIATELY stop using the product and unplug it from the power source.\n2. Do NOT attempt to repair the device yourself.\n3. Contact SafeHome customer service at 1-800-SAFEHOME or recall@safehomeappliances.com to register your unit for a full refund or a free replacement.\n\nCustomers who purchased the AP-330 from an authorized retailer may also return it directly to the store for a full refund, regardless of the original purchase date.\n\nProof of purchase is recommended but not required to receive a refund or replacement.\n\nWe sincerely apologize for any inconvenience this may cause. SafeHome Appliances is committed to the safety and satisfaction of all our customers.\n\nFor more information, visit: www.safehomeappliances.com/recall-ap330","passageTitle":null,"type":"single","questions":[{"id":"c7-s5a","part":7,"question":"Why is the AP-330 being recalled?","options":["It was found to emit harmful gases","A potential overheating risk was identified in its power circuit","The device does not meet air quality standards","Customer complaints about noise levels were filed"],"answer":1,"explanation":"'identified a potential overheating risk in the device's power circuit under certain operating conditions'."},{"id":"c7-s5b","part":7,"question":"What should customers do immediately upon reading this notice?","options":["Return the product to the store right away","Call their insurance provider","Unplug the device and stop using it","Wait for a replacement to be delivered before stopping use"],"answer":2,"explanation":"'IMMEDIATELY stop using the product and unplug it from the power source'."},{"id":"c7-s5c","part":7,"question":"What options are available to affected customers?","options":["Only a free replacement","Only a full refund","A full refund or a free replacement","A partial refund or a discount on a new model"],"answer":2,"explanation":"'register your unit for a full refund or a free replacement'."},{"id":"c7-s5d","part":7,"question":"What does the notice say about proof of purchase?","options":["It is required for a refund but not for a replacement.","It is required for both options.","It is strongly encouraged but not mandatory.","It is not mentioned in the notice."],"answer":2,"explanation":"'Proof of purchase is recommended but not required to receive a refund or replacement'."}]},{"passage":"LEARNBRIDGE PLATFORM UPDATE\nAnnounced: September 1\n\nDear LearnBridge Members,\n\nWe are excited to announce the launch of LearnBridge Pro — our new premium subscription tier designed for professionals who want to take their skills to the next level.\n\nLearnBridge Pro offers:\n• Unlimited access to over 4,500 courses across technology, business, design, and leadership\n• New monthly additions of 50+ expert-led courses\n• Offline download for up to 30 courses at a time\n• AI-powered learning path recommendations personalized to your career goals\n• Access to live monthly Q&A sessions with industry experts\n• A verified digital certificate upon course completion, recognized by over 200 employer partners\n\nPRICING:\nMonthly: USD 29/month | Annual: USD 249/year (save 28%)\n\nExisting free members who upgrade before September 30 will receive an additional 20% discount on the first year of their annual plan, bringing the effective rate to USD 199.20.\n\nYour current free account will remain fully functional. LearnBridge Pro is entirely optional and offers additional features for those who want them.\n\nTo upgrade or learn more, visit your account dashboard at learnbridge.io/pro.\n\nHappy learning,\nThe LearnBridge Team","passageTitle":null,"type":"single","questions":[{"id":"c7-s6a","part":7,"question":"What is the main purpose of this announcement?","options":["To notify users of a price increase for existing accounts","To introduce a new premium subscription tier","To announce the closure of the free membership plan","To promote a limited-time sale on existing courses"],"answer":1,"explanation":"'We are excited to announce the launch of LearnBridge Pro — our new premium subscription tier'."},{"id":"c7-s6b","part":7,"question":"What advantage does the annual plan offer over the monthly plan?","options":["Access to more courses","A 20% early-bird discount","Savings of 28% compared to paying monthly","Free access to live Q&A sessions"],"answer":2,"explanation":"'Annual: USD 249/year (save 28%)'."},{"id":"c7-s6c","part":7,"question":"How much would a free member pay for the first year of Pro if they upgrade before September 30?","options":["USD 199.20","USD 249.00","USD 29.00 per month","USD 199.00"],"answer":0,"explanation":"Annual plan USD 249 × 80% (20% discount) = USD 199.20."},{"id":"c7-s6d","part":7,"question":"What happens to existing free accounts after the Pro launch?","options":["They will be automatically upgraded to Pro.","Free features will be reduced to encourage upgrades.","They will remain fully functional as before.","Free accounts will expire after 30 days."],"answer":2,"explanation":"'Your current free account will remain fully functional'."}]},{"passage":"[Document 1 – Service Contract Terms Excerpt]\n\nVELOCITY IT SOLUTIONS – MANAGED SERVICES AGREEMENT\nClient: Stonegate Financial Partners\n\nService Level & Billing Terms (excerpt):\n\n3.1 Monthly Managed Service Fee: USD 4,200, billed on the first of each month.\n\n3.2 On-Site Support: Included for up to 10 hours per month. Additional on-site hours are billed at USD 120 per hour.\n\n3.3 Remote Support: Unlimited. Included in the monthly fee at no additional charge.\n\n3.4 Emergency After-Hours Callout: USD 250 flat fee per callout, applicable between 8:00 p.m. and 7:00 a.m. on weekdays, and all day on weekends and public holidays.\n\n3.5 Hardware Procurement: Charged at cost plus a 12% procurement fee.\n\n[Document 2 – Client Email]\n\nFrom: James Whitfield <j.whitfield@stonegatefi.com>\nTo: billing@velocityit.com\nDate: February 7\n\nDear Velocity IT Billing Team,\n\nI am writing regarding our January invoice (Invoice #VIT-0881), which totals USD 5,148. After reviewing it against our service agreement, I believe two charges may be incorrect.\n\nFirst, the invoice includes a charge of USD 360 for three hours of on-site support listed as \"additional.\" However, our records indicate we used only 8 hours of on-site support in January, which should be within the 10-hour monthly inclusion.\n\nSecond, an emergency callout fee of USD 250 is listed for January 15, which was a Wednesday. Our engineer's report shows the callout took place at 6:30 p.m. — before the 8:00 p.m. after-hours threshold stated in section 3.4 of our agreement.\n\nIf these two charges are reversed, the corrected total should be USD 4,538. Please review and confirm.\n\nRegards,\nJames Whitfield\nOperations Manager, Stonegate Financial Partners","passageTitle":"Service Contract Terms + Invoice Dispute Email","type":"double","questions":[{"id":"c7-d1a","part":7,"question":"What is the standard monthly fee for Stonegate Financial Partners?","options":["USD 4,200","USD 4,538","USD 5,148","USD 5,400"],"answer":0,"explanation":"'Monthly Managed Service Fee: USD 4,200, billed on the first of each month'."},{"id":"c7-d1b","part":7,"question":"According to James Whitfield, why should the on-site support charge be reversed?","options":["The work was done remotely, not on-site.","Only 8 hours were used, which is within the 10-hour monthly inclusion.","The engineer's invoice was submitted after the billing deadline.","The contract does not include on-site support charges."],"answer":1,"explanation":"'our records indicate we used only 8 hours of on-site support in January, which should be within the 10-hour monthly inclusion'."},{"id":"c7-d1c","part":7,"question":"Why does James Whitfield dispute the emergency callout fee?","options":["The callout occurred on a weekend, not a weekday.","The callout took place before the 8:00 p.m. after-hours threshold.","The engineer did not complete the callout task.","Callout fees are not included in the contract."],"answer":1,"explanation":"'the callout took place at 6:30 p.m. — before the 8:00 p.m. after-hours threshold stated in section 3.4'."},{"id":"c7-d1d","part":7,"question":"If Velocity IT agrees with James Whitfield's dispute, what would the corrected invoice total be?","options":["USD 4,200","USD 4,538","USD 4,788","USD 5,148"],"answer":1,"explanation":"'the corrected total should be USD 4,538' per James Whitfield's calculation."},{"id":"c7-d1e","part":7,"question":"Based on the contract, what type of support is included at no extra charge regardless of hours used?","options":["On-site support","Emergency callouts","Remote support","Hardware procurement"],"answer":2,"explanation":"'Remote Support: Unlimited. Included in the monthly fee at no additional charge'."}]},{"passage":"[Document 1 – Job Posting]\n\nOPENING: SUSTAINABILITY MANAGER\nHorizon Consumer Goods | Kuala Lumpur, Malaysia\nDepartment: Corporate Affairs\nContract: Permanent, Full-Time\n\nHorizon Consumer Goods is seeking an experienced Sustainability Manager to lead our environmental and social responsibility programs across our Southeast Asian operations.\n\nKey Responsibilities:\n• Develop and implement the company's sustainability strategy in line with global targets\n• Manage ESG reporting and liaise with third-party auditors\n• Lead a team of three sustainability coordinators\n• Engage with government bodies, NGOs, and community stakeholders\n• Present quarterly updates to the board of directors\n\nRequirements:\n• Minimum 7 years of experience in sustainability, ESG, or corporate affairs\n• Experience managing cross-functional or regional teams\n• Strong written and verbal communication skills\n• Master's degree in Environmental Science, Business, or a related field preferred\n\nSalary: MYR 18,000 – 22,000/month + performance bonus\nApplication deadline: April 10\nEmail: careers@horizoncg.com\n\n[Document 2 – Reference Letter]\n\nApril 3\n\nTo Whom It May Concern,\n\nI am pleased to provide this reference for Ms. Yuna Park, who served as Senior Sustainability Analyst at GreenBridge Consulting for four years under my direct supervision.\n\nDuring her tenure, Ms. Park led the development of sustainability roadmaps for three multinational clients and managed a small team of two junior analysts. Her work on ESG disclosure frameworks was widely recognized within the industry and contributed to two of our clients receiving national sustainability awards.\n\nMs. Park holds a Master of Science in Environmental Management from the National University of Singapore. Her analytical skills, stakeholder communication, and leadership potential are all of the highest standard.\n\nI have no hesitation in recommending her for a senior leadership role in sustainability.\n\nSincerely,\nDr. Aaron Lim\nPrincipal Consultant, GreenBridge Consulting","passageTitle":"Job Posting + Reference Letter","type":"double","questions":[{"id":"c7-d2a","part":7,"question":"How many sustainability coordinators will the Sustainability Manager be responsible for leading?","options":["2","3","4","5"],"answer":1,"explanation":"'Lead a team of three sustainability coordinators'."},{"id":"c7-d2b","part":7,"question":"Does Yuna Park meet the minimum experience requirement for the position?","options":["Yes, she has exactly 7 years of experience.","No, she only has 4 years of experience.","Yes, because her experience exceeds the requirement.","It cannot be determined from the reference letter."],"answer":1,"explanation":"'served as Senior Sustainability Analyst...for four years' — requirement is minimum 7 years. She falls short."},{"id":"c7-d2c","part":7,"question":"What notable achievement does Dr. Lim mention about Ms. Park's work?","options":["She reduced her clients' carbon emissions by 30%.","Her ESG work helped clients win national sustainability awards.","She secured government funding for two sustainability projects.","She was promoted to principal consultant."],"answer":1,"explanation":"'contributed to two of our clients receiving national sustainability awards'."},{"id":"c7-d2d","part":7,"question":"What is stated about Yuna Park's educational background?","options":["She holds a Bachelor's degree in Environmental Science.","She has a Master's in Environmental Management from NUS.","She completed a PhD in Corporate Affairs.","Her educational background is not mentioned."],"answer":1,"explanation":"'Ms. Park holds a Master of Science in Environmental Management from the National University of Singapore'."},{"id":"c7-d2e","part":7,"question":"What qualification is listed as preferred but not required in the job posting?","options":["7 years of ESG experience","Experience managing regional teams","A Master's degree in a related field","ESG reporting experience"],"answer":2,"explanation":"'Master's degree in Environmental Science, Business, or a related field preferred'."}]},{"passage":"[Document 1 – IT Security Policy Update]\n\nMEMO\nTo: All Staff\nFrom: IT Security Team\nDate: October 1\n\nAs part of our response to an increase in phishing attempts targeting our industry, we are implementing an enhanced IT security framework effective November 1.\n\nKey requirements for all employees:\n1. Passwords must be updated every 60 days and must meet the new complexity requirements (minimum 12 characters, including at least one symbol).\n2. Multi-factor authentication (MFA) is now mandatory for all company applications.\n3. All staff must complete a cybersecurity awareness training module before October 31.\n4. Employees who handle sensitive client data must additionally complete an advanced data protection course by November 15.\n\nNon-compliance with items 1–3 by October 31 will result in account access being temporarily suspended until the requirements are met.\n\n[Document 2 – Training Course Schedule]\n\nCYBERSECURITY AWARENESS TRAINING – OCTOBER SESSION\nProvider: ShieldIQ Learning Platform\n\nCourse 1: Cybersecurity Awareness (All Staff) – MANDATORY\nDuration: 90 minutes | Format: Online, self-paced\nAvailability: October 1–31 | Access via: hr.company.com/training\n\nCourse 2: Advanced Data Protection (Client-Facing Staff Only)\nDuration: 3 hours | Format: Online with a live Q&A session\nScheduled Q&A Sessions: October 22 (2:00 p.m.) and November 8 (10:00 a.m.)\nDeadline: November 15\n\nAll completions are automatically recorded. Certificates will be emailed within 24 hours of finishing.\n\n[Document 3 – Employee Email]\n\nFrom: Kevin Ho <k.ho@company.com>\nTo: IT Help Desk <helpdesk@company.com>\nDate: October 14\n\nHi,\n\nI have a few questions about the new security requirements.\n\nI completed Course 1 yesterday but haven't received my certificate yet. Is this normal? It's been about 20 hours.\n\nAlso, I'm a client relationship manager, so I assume I need to complete Course 2 as well. I noticed there are two Q&A sessions — one in October and one in November. Is attendance at one of these sessions required to pass the course, or are they optional?\n\nFinally, I'm concerned about the password requirement. My current password is 10 characters with no symbols. Do I need to update this before October 31 or is there a grace period?\n\nThank you,\nKevin Ho","passageTitle":"IT Security Policy + Training Schedule + Employee Email","type":"triple","questions":[{"id":"c7-t1a","part":7,"question":"By what date must ALL employees complete the mandatory cybersecurity training?","options":["October 14","October 22","October 31","November 15"],"answer":2,"explanation":"Policy item 3: 'All staff must complete a cybersecurity awareness training module before October 31'."},{"id":"c7-t1b","part":7,"question":"Why has Kevin Ho not yet received his certificate after completing Course 1?","options":["He did not pass the final assessment.","He must attend a live Q&A session first.","Certificates are issued within 24 hours, and 20 hours have passed.","His completion was not recorded by the system."],"answer":2,"explanation":"'Certificates will be emailed within 24 hours of finishing.' Kevin completed it 20 hours ago → still within the 24-hour window."},{"id":"c7-t1c","part":7,"question":"Does Kevin Ho need to complete Course 2?","options":["No, Course 2 is only for IT staff.","Yes, because he is a client relationship manager and handles client data.","No, Course 2 is optional for all employees.","It cannot be determined from the information provided."],"answer":1,"explanation":"Policy: 'Employees who handle sensitive client data must additionally complete an advanced data protection course'. Kevin is a 'client relationship manager' — he handles client data."},{"id":"c7-t1d","part":7,"question":"What will happen to Kevin Ho's account if he does not update his password by October 31?","options":["He will receive a final warning email.","His account access will be temporarily suspended.","His account will be permanently deleted.","He will be required to meet with the IT Security Team."],"answer":1,"explanation":"'Non-compliance with items 1–3 by October 31 will result in account access being temporarily suspended'."},{"id":"c7-t1e","part":7,"question":"If Kevin Ho attends the October Q&A session for Course 2, what is the latest possible date for him to complete the course?","options":["October 22","October 31","November 8","November 15"],"answer":3,"explanation":"'Advanced Data Protection...Deadline: November 15'. Attending the October Q&A does not change the overall course deadline."},{"id":"c7-t1f","part":7,"question":"What is a requirement that Kevin Ho's current password does NOT meet?","options":["It is not unique enough.","It lacks a minimum number of characters and has no symbol.","It was not changed within the last 60 days.","It uses a common dictionary word."],"answer":1,"explanation":"Current password: 10 characters, no symbols. Requirement: minimum 12 characters + at least one symbol → fails on both counts."}]},{"passage":"[Document 1 – Product Specification Sheet]\n\nMAGNOLIA OFFICE SYSTEMS – FURNITURE CATALOG\n\nItem: Executive Standing Desk – Model ESD-700\nDimensions: 160cm (W) × 80cm (D) × 65–130cm (H)\nSurface: Scratch-resistant laminate in Walnut, Maple, or White\nFrame: Powder-coated steel; available in Black or Silver\nHeight Adjustment: Electric motor; 3 memory presets\nWeight Capacity: 120 kg\nWarranty: 3 years on parts; 1 year on electrical components\nLead Time: 10–14 business days from order confirmation\nPrice: USD 980 per unit\nBulk Discount: 5% on orders of 10–19 units; 10% on orders of 20+\n\n[Document 2 – Purchase Order]\n\nPURCHASE ORDER – #PO-4492\nBuyer: Nexus Coworking Hub\nDate: March 5\nSupplier: Magnolia Office Systems\n\nItem                  Qty   Unit Price   Total\nESD-700 (Maple/Black)  22   USD 980      USD 21,560\n\nApplied Discount: 10% (order of 20+ units)\nDiscounted Total: USD 19,404\n\nRequested Delivery Date: March 26\nDelivery Address: 12 Greenway Boulevard, Suite 400, Austin, TX\n\nAuthorized by: Dana Kim, Procurement Manager\n\n[Document 3 – Delivery Confirmation]\n\nFrom: dispatch@magnoliaofficesystems.com\nTo: d.kim@nexuscoworking.com\nDate: March 7\n\nDear Ms. Kim,\n\nThank you for your order (PO-4492). We are pleased to confirm that your order of 22 ESD-700 desks has been processed and is scheduled for dispatch on March 19.\n\nExpected delivery: March 22–24.\n\nPlease note that the Maple surface finish in combination with the Black frame is currently on a 3-day extended lead time due to high demand. This has been factored into the dispatch schedule above.\n\nA tracking number will be provided on the day of dispatch. For assembly, we recommend a professional installation team for orders exceeding 10 units. Our certified installer network can be reached at install@magnoliaofficesystems.com.\n\nThank you for choosing Magnolia Office Systems.\n\nBest regards,\nDispatch Team, Magnolia Office Systems","passageTitle":"Product Spec Sheet + Purchase Order + Delivery Confirmation","type":"triple","questions":[{"id":"c7-t2a","part":7,"question":"What discount rate applies to Nexus Coworking Hub's order?","options":["No discount","5%","10%","15%"],"answer":2,"explanation":"Order of 22 units → '10% on orders of 20+'. Confirmed in PO: 'Applied Discount: 10%'."},{"id":"c7-t2b","part":7,"question":"What is the total amount Nexus Coworking Hub will pay?","options":["USD 21,560","USD 19,404","USD 20,482","USD 18,324"],"answer":1,"explanation":"'Discounted Total: USD 19,404' in the Purchase Order."},{"id":"c7-t2c","part":7,"question":"What color combination did Nexus Coworking Hub order?","options":["Walnut surface with Silver frame","White surface with Black frame","Maple surface with Black frame","Maple surface with Silver frame"],"answer":2,"explanation":"'ESD-700 (Maple/Black)' in the Purchase Order."},{"id":"c7-t2d","part":7,"question":"Why is the delivery arriving later than the originally requested date?","options":["The payment was processed late.","The order quantity exceeded the warehouse stock.","The Maple/Black combination has an extended lead time due to high demand.","The delivery address was incorrect in the original order."],"answer":2,"explanation":"'the Maple surface finish in combination with the Black frame is currently on a 3-day extended lead time due to high demand'."},{"id":"c7-t2e","part":7,"question":"What recommendation does Magnolia make regarding assembly?","options":["Customers should self-assemble using the included instructions.","Assembly is included for free in all orders over 10 units.","A professional installation team is recommended for orders exceeding 10 units.","Assembly must be scheduled at least 5 days in advance."],"answer":2,"explanation":"'we recommend a professional installation team for orders exceeding 10 units'."},{"id":"c7-t2f","part":7,"question":"How long is the warranty on the electrical components of the ESD-700?","options":["6 months","1 year","2 years","3 years"],"answer":1,"explanation":"'Warranty: 3 years on parts; 1 year on electrical components'."}]},{"passage":"NOTICE TO ALL STAFF\nMeridian Consulting Group – Building 3, Floors 4 & 5\n\nOFFICE RENOVATION – TEMPORARY WORKSPACE ARRANGEMENTS\n\nAs previously communicated, the renovation of Floors 4 and 5 of Building 3 is scheduled to begin Monday, March 10 and is expected to last six weeks.\n\nDuring this period:\n• Staff currently located on Floors 4 and 5 (approximately 85 employees) will be relocated to the co-working facility at Meridian Centre, 230 King Street, Level 2.\n• All staff will be issued new temporary access badges starting March 7. Your current badge will remain valid for Building 3 common areas and the parking garage.\n• IT will complete the setup of all workstations at the co-working space by end of day March 7.\n• Mail and courier deliveries will continue to be directed to Building 3 and forwarded daily to King Street.\n\nThe café on Ground Floor of Building 3 will remain open throughout the renovation period. Parking allocations are unchanged.\n\nIf you have specific workstation requirements (e.g., dual monitors, ergonomic chairs), please submit a request to facilities@meridiancg.com no later than March 5.\n\nWe appreciate your flexibility during this period.\n\nBuilding Operations Team\nMeridian Consulting Group","passageTitle":null,"type":"single","questions":[{"id":"g7-s1a","part":7,"question":"Where will affected staff work during the renovation?","options":["In the conference rooms of Building 3","At the co-working facility on King Street","At a partner company's office","From home full-time"],"answer":1,"explanation":"'Staff...will be relocated to the co-working facility at Meridian Centre, 230 King Street'."},{"id":"g7-s1b","part":7,"question":"By what date must special workstation requests be submitted?","options":["March 5","March 7","March 10","March 14"],"answer":0,"explanation":"'please submit a request to facilities@meridiancg.com no later than March 5'."},{"id":"g7-s1c","part":7,"question":"What will remain unchanged during the renovation period?","options":["Mail delivery location","Floor access badges","Parking allocations","IT workstation setup"],"answer":2,"explanation":"'Parking allocations are unchanged'."},{"id":"g7-s1d","part":7,"question":"What can be inferred about employees NOT on Floors 4 and 5?","options":["They will also be relocated to King Street","They will work from home during the renovation","They will continue working in Building 3 as usual","They must also submit workstation preference requests"],"answer":2,"explanation":"Only the 85 staff on Floors 4 and 5 are mentioned as being relocated → others remain in Building 3."}]},{"passage":"AUTOMATED WAREHOUSES: THE NEXT FRONTIER IN LAST-MILE DELIVERY\nSupply Chain Today | April Edition\n\nThe rapid growth of e-commerce has placed unprecedented pressure on logistics companies to fulfil orders faster, more accurately, and at lower cost. In response, a growing number of major retailers and third-party logistics (3PL) providers are turning to warehouse automation as a strategic solution.\n\nAt the heart of this shift are autonomous mobile robots (AMRs) — devices that navigate warehouse floors independently, retrieving and transporting goods to packing stations. Unlike older conveyor-belt systems, AMRs are flexible, scalable, and can be deployed without major structural changes to an existing facility.\n\nGreenPort Logistics, one of Southeast Asia's largest 3PL operators, recently completed a phased rollout of 320 AMRs across its three flagship warehouses in Singapore, Malaysia, and Vietnam. The results have been compelling: order processing speed improved by 47%, picking accuracy reached 99.8%, and the company reported a 22% reduction in labour costs per unit.\n\nHowever, industry observers caution that automation is not without challenges. The upfront capital investment can be substantial — GreenPort's rollout reportedly cost in excess of USD 14 million. Additionally, integrating AMR systems with existing warehouse management software (WMS) requires significant technical expertise, and staff must be retrained to work alongside robotic systems rather than replacing manual processes entirely.\n\nDespite these hurdles, analysts predict that by 2030, more than 60% of large fulfilment centres globally will incorporate some form of robotic automation, up from roughly 20% today.","passageTitle":null,"type":"single","questions":[{"id":"g7-s2a","part":7,"question":"What advantage do AMRs have over older conveyor-belt systems?","options":["They are significantly cheaper to purchase","They can be used without modifying existing facilities","They do not require any staff training","They eliminate the need for warehouse management software"],"answer":1,"explanation":"'AMRs are flexible, scalable, and can be deployed without major structural changes to an existing facility'."},{"id":"g7-s2b","part":7,"question":"What was one outcome of GreenPort Logistics' AMR rollout?","options":["Labour costs increased by 22%","Order accuracy reached 94%","Picking accuracy reached 99.8%","Processing speed improved by 22%"],"answer":2,"explanation":"'picking accuracy reached 99.8%' — confirmed in GreenPort's results."},{"id":"g7-s2c","part":7,"question":"According to the article, what is one challenge associated with warehouse automation?","options":["AMRs are incompatible with existing warehouse floors","The technology requires replacing all manual staff","Significant upfront capital investment is required","Automation slows down order fulfilment speed"],"answer":2,"explanation":"'The upfront capital investment can be substantial — GreenPort's rollout reportedly cost in excess of USD 14 million'."},{"id":"g7-s2d","part":7,"question":"What do analysts predict about large fulfilment centres by 2030?","options":["More than 60% will use full automation with no human staff","Over 60% will incorporate some form of robotic automation","AMR technology will be replaced by newer systems","Only 20% of centres will adopt automation due to costs"],"answer":1,"explanation":"'by 2030, more than 60% of large fulfilment centres globally will incorporate some form of robotic automation'."}]},{"passage":"[Document 1 – Training Invitation Email]\n\nFrom: Learning & Development Team <ld@stellargroup.com>\nTo: All Middle Managers\nDate: May 6\nSubject: Invitation – Leadership Accelerator Workshop (May 28)\n\nDear Managers,\n\nYou are invited to attend our upcoming half-day Leadership Accelerator Workshop, designed exclusively for middle managers at Stellar Group.\n\nDate:    Wednesday, May 28\nTime:    9:00 a.m. – 1:00 p.m.\nVenue:   The Boardroom, Level 12, HQ Tower\nFacilitator: Ms. Elena Voss, Executive Coach and former VP of Talent at Fortune Dynamics\n\nThe workshop will focus on three areas: influencing without authority, managing upward effectively, and building high-performing cross-functional teams. Attendance is strongly encouraged but not mandatory.\n\nSpaces are limited to 20 participants. Please register via the staff portal by May 16 to secure your place. Managers who register after this date will be placed on a waiting list.\n\nLight refreshments will be provided.\n\n[Document 2 – Registration Confirmation]\n\nFrom: Learning & Development Team <ld@stellargroup.com>\nTo: Adrian Moss <a.moss@stellargroup.com>\nDate: May 10\nSubject: Registration Confirmed – Leadership Accelerator Workshop\n\nDear Adrian,\n\nThank you for registering for the Leadership Accelerator Workshop on May 28. Your place has been confirmed.\n\nPlease note that due to high demand, the workshop is now fully booked. If you are unable to attend, we kindly ask that you cancel your registration via the staff portal at least five business days before the event so that a colleague on the waiting list can take your place.\n\nA full pre-reading pack will be sent to you one week before the workshop. We recommend setting aside approximately 90 minutes to review the materials in advance.\n\nWe look forward to seeing you on May 28.\n\nBest regards,\nLearning & Development Team","passageTitle":"Training Invitation + Registration Confirmation","type":"double","questions":[{"id":"g7-d1a","part":7,"question":"What does the confirmation email reveal about the workshop's current status?","options":["It has been postponed to a later date","It has reached maximum capacity","Attendance is now mandatory for all managers","The venue has been changed"],"answer":1,"explanation":"'due to high demand, the workshop is now fully booked' → đã đủ 20 người (maximum)."},{"id":"g7-d1b","part":7,"question":"According to the invitation, what is the registration deadline?","options":["May 6","May 10","May 16","May 28"],"answer":2,"explanation":"'Please register via the staff portal by May 16 to secure your place'."}]},{"passage":"INTERNAL ANNOUNCEMENT\nFrom:  Office of the President\nTo:    All Employees\nDate:  January 18\n\nRE: ORGANISATIONAL RESTRUCTURING – EFFECTIVE MARCH 1\n\nFollowing a comprehensive strategic review conducted over the past quarter, Halcyon Industries will reorganise its operations into three focused business units: Industrial Solutions, Consumer Products, and Digital Services.\n\nThis restructuring is designed to improve accountability, accelerate decision-making, and align our teams more closely with specific market segments.\n\nKey changes include:\n• The current Operations and Manufacturing divisions will merge to form the Industrial Solutions business unit, led by Mr. Victor Russo.\n• The Consumer Products unit will be led by Ms. Angela Tran, who is relocating from our Sydney office to assume this role.\n• The newly established Digital Services unit will be led by Mr. James Okafor, currently Head of Innovation.\n• The Corporate Affairs and Communications teams will continue to operate centrally and report directly to the President's Office.\n\nA town hall meeting will be held on January 25 to give employees an opportunity to ask questions. Managers are asked to cascade this information to their teams by January 20.\n\nDetailed transition plans will be shared with affected departments by February 10.","passageTitle":null,"type":"single","questions":[{"id":"h7-s1a","part":7,"question":"What is the main purpose of this announcement?","options":["To introduce three new executive hires","To inform staff of an upcoming organisational restructuring","To announce the acquisition of three new companies","To present quarterly financial results"],"answer":1,"explanation":"'Halcyon Industries will reorganise its operations into three focused business units' — thông báo tái cơ cấu tổ chức."},{"id":"h7-s1b","part":7,"question":"What will happen to the Operations and Manufacturing divisions?","options":["They will be closed down","They will be led by Ms. Angela Tran","They will merge into the Industrial Solutions unit","They will report directly to the President's Office"],"answer":2,"explanation":"'The current Operations and Manufacturing divisions will merge to form the Industrial Solutions business unit'."},{"id":"h7-s1c","part":7,"question":"What is mentioned about Ms. Angela Tran?","options":["She is a new hire from outside the company","She is currently Head of Innovation","She will be moving from the Sydney office","She was previously in charge of the Digital Services unit"],"answer":2,"explanation":"'Ms. Angela Tran, who is relocating from our Sydney office to assume this role'."},{"id":"h7-s1d","part":7,"question":"By what date must managers share this information with their teams?","options":["January 18","January 20","January 25","February 10"],"answer":1,"explanation":"'Managers are asked to cascade this information to their teams by January 20'."}]},{"passage":"REVIEW: Nexus Coworking Hub – Austin, TX\nPlatform: WorkspaceRater.com  |  Rating: ★★★★☆ (4/5)\nPosted by: T. Okonkwo  |  Verified Member\n\nI have been a hot-desk member at Nexus Coworking Hub for the past four months, and overall I am very satisfied with what it offers.\n\nThe facilities are modern and well-maintained — fast Wi-Fi, a well-equipped kitchen, and plenty of natural light. The staff are always helpful and quick to resolve any issues. On two occasions I needed a private meeting room on short notice, and both times a room was made available within the hour.\n\nMy only area of concern is noise levels in the open workspace during certain hours, particularly between 10 a.m. and noon, when it can get quite loud due to group discussions and phone calls. For deep focus work, I tend to move to the quieter pods near the back.\n\nThe pricing is competitive for the Austin market. At USD 199 per month, the hot-desk plan is reasonable, especially given the round-the-clock access and the excellent location near the city centre.\n\nI would recommend Nexus to freelancers and remote workers who value flexibility. Those who require consistently quiet conditions may want to look at dedicated desk or private office options instead.","passageTitle":null,"type":"single","questions":[{"id":"h7-s2a","part":7,"question":"How long has the reviewer been a member at Nexus?","options":["One month","Two months","Four months","Six months"],"answer":2,"explanation":"'I have been a hot-desk member at Nexus Coworking Hub for the past four months'."},{"id":"h7-s2b","part":7,"question":"What concern does the reviewer mention about the workspace?","options":["The Wi-Fi speed is inconsistent","The kitchen facilities are poorly maintained","The open area becomes noisy during certain hours","Meeting rooms are rarely available on short notice"],"answer":2,"explanation":"'My only area of concern is noise levels in the open workspace during certain hours'."},{"id":"h7-s2c","part":7,"question":"How much does the hot-desk plan cost per month?","options":["USD 99","USD 149","USD 199","USD 249"],"answer":2,"explanation":"'At USD 199 per month, the hot-desk plan is reasonable'."},{"id":"h7-s2d","part":7,"question":"What does the reviewer suggest for those who need a consistently quiet environment?","options":["Work during early morning hours","Use the quiet pods near the back","Consider a dedicated desk or private office","Book a private meeting room for the full day"],"answer":2,"explanation":"'Those who require consistently quiet conditions may want to look at dedicated desk or private office options instead'."}]},{"passage":"[Document 1 – Internship Job Posting]\n\nMARKETING INTERNSHIP – SUMMER PROGRAMME\nLuminary Creative Agency | Melbourne, Australia\n\nDuration:  12 weeks (June 2 – August 22)\nType:      Paid internship (AUD 800/week)\nLocation:  On-site, Melbourne CBD\n\nAbout the Role:\nLuminary Creative Agency is seeking one motivated marketing intern to support our client services and content team during the summer programme.\n\nResponsibilities:\n• Assist in the development of social media content calendars\n• Conduct market research and compile competitor analysis reports\n• Support account managers in preparing client presentations\n• Attend weekly client briefings (observation role)\n\nRequirements:\n• Currently enrolled in a Bachelor's or Master's degree programme in Marketing, Communications, or a related field\n• Strong written English and attention to detail\n• Proficiency in Canva or Adobe Creative Suite (preferred, not required)\n\nApplication Deadline: April 18\nTo apply: Send CV and a 300-word cover letter to intern@luminarycreative.com.au\n\n[Document 2 – Applicant Follow-up Email]\n\nFrom: Sophie Larkin <s.larkin@email.com>\nTo: intern@luminarycreative.com.au\nDate: April 22\nSubject: Follow-up – Marketing Internship Application\n\nDear Hiring Team,\n\nI am writing to follow up on my application for the Summer Marketing Internship, which I submitted on April 15.\n\nI remain very enthusiastic about the opportunity and would welcome any update on the status of my application. I am available for an interview at your convenience and can provide additional references if required.\n\nPlease let me know if there is any further information I can provide to support my candidacy.\n\nThank you for your time and consideration.\n\nBest regards,\nSophie Larkin","passageTitle":"Internship Posting + Applicant Follow-up Email","type":"double","questions":[{"id":"h7-d1a","part":7,"question":"What does Sophie Larkin's follow-up email indicate about her application?","options":["She submitted her application after the deadline","She applied before the stated deadline","She has already been invited to interview","She is requesting to withdraw her application"],"answer":1,"explanation":"Sophie submitted on April 15; the deadline was April 18 → she applied before the deadline."},{"id":"h7-d1b","part":7,"question":"What is described as preferred but not required in the job posting?","options":["A degree in Marketing or Communications","Strong written English skills","Proficiency in Canva or Adobe Creative Suite","Experience with competitor analysis"],"answer":2,"explanation":"'Proficiency in Canva or Adobe Creative Suite (preferred, not required)'."}]},{"passage":"CUSTOMER NOTICE\n\nClearView Opticians — Store Relocation\n\nDear Customers,\n\nWe are pleased to announce that ClearView Opticians will be moving to a new, larger location at 250 Maple Avenue, Suite 3B, effective December 1. Our current location at 88 Oak Street will remain open until November 30.\n\nThe new store will feature an expanded selection of designer frames, a state-of-the-art eye examination room, and a dedicated children's eyewear section. To celebrate the grand opening, we are offering 20% off all frames and lenses purchased during the first two weeks.\n\nOur phone number and email address will remain the same. For appointments, please call (555) 834-2100 or visit clearviewopticians.com.\n\nThank you for your continued patronage.\n\nDr. Maria Santos\nOwner, ClearView Opticians","passageTitle":null,"type":"single","questions":[{"id":"e7-1a","part":7,"question":"What is the purpose of this notice?","options":["To announce a store closing","To advertise a new product line","To inform customers about a relocation","To introduce a new employee"],"answer":2,"explanation":"Thông báo di chuyển cửa hàng đến địa chỉ mới: 250 Maple Avenue."},{"id":"e7-1b","part":7,"question":"What will customers find at the new location?","options":["Lower prices on all items","A children's eyewear section","Extended weekend hours","Free parking"],"answer":1,"explanation":"'a dedicated children's eyewear section' = khu kính trẻ em chuyên biệt."},{"id":"e7-1c","part":7,"question":"What special offer is available?","options":["Free eye exams for new customers","Half-price contact lenses","20% off frames and lenses for two weeks","Buy one get one free"],"answer":2,"explanation":"'20% off all frames and lenses purchased during the first two weeks'."},{"id":"e7-1d","part":7,"question":"What will NOT change after the move?","options":["The store address","The store size","The phone number","The frame selection"],"answer":2,"explanation":"'Our phone number and email address will remain the same'."}]},{"passage":"WORKSHOP ANNOUNCEMENT\n\nEffective Communication Skills for Managers\n\nDate: Saturday, March 22, 9:00 a.m. – 4:00 p.m.\nLocation: Harper Business Center, Room 401\nInstructor: Dr. Angela Torres, Ph.D. in Organizational Psychology\nFee: $175 per participant (includes materials and lunch)\n\nThis one-day workshop is designed for supervisors and managers who want to improve their communication with team members. Topics include active listening, giving constructive feedback, managing difficult conversations, and motivating teams through clear messaging.\n\nClass size is limited to 20 participants to allow for personalized coaching. Early registration is recommended as our previous workshops have filled up quickly.\n\nTo register, visit www.harperbci.com/workshops or call (555) 209-4400.\nRegistration deadline: March 15.","passageTitle":null,"type":"single","questions":[{"id":"e7-2a","part":7,"question":"Who is the workshop primarily intended for?","options":["New employees","Supervisors and managers","IT professionals","Marketing staff"],"answer":1,"explanation":"'designed for supervisors and managers'."},{"id":"e7-2b","part":7,"question":"What is included in the $175 fee?","options":["Transportation to the venue","A certificate of completion","Materials and lunch","Overnight accommodation"],"answer":2,"explanation":"'$175 per participant (includes materials and lunch)'."},{"id":"e7-2c","part":7,"question":"Why is early registration recommended?","options":["There is a discount for early registration","Previous workshops have sold out quickly","The fee increases after March 15","Only online registration is available"],"answer":1,"explanation":"'as our previous workshops have filled up quickly'."},{"id":"e7-2d","part":7,"question":"By when must participants register?","options":["March 1","March 10","March 15","March 22"],"answer":2,"explanation":"'Registration deadline: March 15'."}]},{"passage":"[Document 1 – Internal Memo]\nTo: All Sales Staff\nFrom: Regional Sales Director, Tom Bradley\nDate: August 20\n\nI am pleased to announce that Metro Electronics has been selected as one of three finalists for the National Retailer Excellence Award. This recognition is a direct result of your hard work in achieving record-breaking sales during Q1 and Q2.\n\nThe award ceremony will take place on September 28 at the Grand Pavilion Hotel. Two representatives from our company will attend the event. I plan to select those who have contributed most significantly to our success.\n\nPlease continue your outstanding efforts as we approach Q3 targets.\n\n[Document 2 – Email]\nFrom: Lisa Nguyen <l.nguyen@metroelec.com>\nTo: Tom Bradley <t.bradley@metroelec.com>\nDate: August 22\n\nDear Mr. Bradley,\n\nCongratulations on the nomination! I was thrilled to hear the news.\n\nI wanted to let you know that I will be attending a product training session in Chicago from September 25 to September 30. Unfortunately, this means I will be unable to attend the award ceremony even if selected.\n\nHowever, I would like to recommend my colleague, David Park, who led the Q2 campaign for our Western region and exceeded targets by 40%. I believe he would be an excellent representative for our team.\n\nBest regards,\nLisa Nguyen","passageTitle":"Memo + Email","type":"double","questions":[{"id":"e7-3a","part":7,"question":"What is the main purpose of Tom Bradley's memo?","options":["To announce employee promotions","To share news about an award nomination","To set Q3 sales targets","To introduce new sales policies"],"answer":1,"explanation":"Thông báo Metro Electronics được chọn vào chung kết giải thưởng National Retailer Excellence Award."},{"id":"e7-3b","part":7,"question":"How many people from the company will attend the ceremony?","options":["One","Two","Three","All sales staff"],"answer":1,"explanation":"'Two representatives from our company will attend the event'."},{"id":"e7-3c","part":7,"question":"Why can't Lisa Nguyen attend the award ceremony?","options":["She has a family event","She will be at a training session","She is transferring to another office","She is on vacation"],"answer":1,"explanation":"'I will be attending a product training session in Chicago from September 25 to September 30'."},{"id":"e7-3d","part":7,"question":"What does Lisa Nguyen suggest?","options":["Postponing the ceremony","Sending a video message instead","Nominating David Park as a representative","Canceling her training session"],"answer":2,"explanation":"'I would like to recommend my colleague, David Park' as a representative."}]},{"passage":"PRODUCT REVIEW\n\nAquaPure Water Filter System – Model AP-500\nReviewed by: Karen Mitchell, Home & Kitchen Monthly\n\nThe AquaPure AP-500 is a countertop water filtration system that promises to remove 99% of contaminants from tap water. After testing it for three months, I can confirm that it delivers on that promise.\n\nInstallation was straightforward and took less than 10 minutes. The filter cartridge lasts approximately six months and costs $35 to replace. The system itself retails for $149, making it one of the most affordable options in its category.\n\nThe only downside I noticed was the flow rate, which is slightly slower than competing models. However, the superior filtration quality more than compensates for this minor inconvenience.\n\nOverall rating: 4.5 out of 5 stars. Highly recommended for households looking for an effective and budget-friendly water purification solution.","passageTitle":null,"type":"single","questions":[{"id":"e7-4a","part":7,"question":"What type of text is this?","options":["An advertisement","A product manual","A product review","A scientific study"],"answer":2,"explanation":"Tiêu đề 'PRODUCT REVIEW' và nội dung đánh giá sản phẩm sau khi sử dụng."},{"id":"e7-4b","part":7,"question":"How long was the product tested?","options":["One month","Three months","Six months","One year"],"answer":1,"explanation":"'After testing it for three months'."},{"id":"e7-4c","part":7,"question":"What is mentioned as a disadvantage?","options":["High replacement cost","Difficult installation","Slow flow rate","Limited warranty"],"answer":2,"explanation":"'the flow rate, which is slightly slower than competing models'."},{"id":"e7-4d","part":7,"question":"How much does a replacement filter cost?","options":["$10","$25","$35","$149"],"answer":2,"explanation":"'The filter cartridge costs $35 to replace'."}]},{"passage":"INTERNAL MEMORANDUM\n\nTo:   All Staff\nFrom: Finance Department\nDate: 12 November\nRe:   Updated Expense Reimbursement Procedure\n\nEffective 1 December, all employee expense reimbursements will be processed through the new ExpenseBridge online platform. The current paper-based system will be retired on 30 November.\n\nTo be reimbursed, employees must:\n1. Log in to ExpenseBridge at expenses.strathmore.com using their staff ID and temporary password (sent separately by IT).\n2. Submit all receipts as digital scans or photos within 14 calendar days of the expense being incurred.\n3. Include a brief description and the relevant cost centre code for each item.\n\nExpenses submitted without the required cost centre code will be returned for correction and will not be processed until the information is complete.\n\nA training video on how to use ExpenseBridge is available on the company intranet under \"Finance Resources.\" A live Q&A session will also be held on 20 November at 2:00 P.M. via Teams for staff who would like additional guidance.\n\nPlease direct any questions to finance@strathmore.com.","passageTitle":"Memo – Changes to Expense Reimbursement Process","type":"single","questions":[{"id":"t8-s1-1","part":7,"question":"What is the purpose of the memorandum?","options":["To introduce a new payroll system","To announce changes to how expenses are reimbursed","To remind staff about end-of-year tax submissions","To inform employees about a new finance team member"],"answer":1,"explanation":"Memo thông báo về thay đổi quy trình hoàn tiền chi phí qua nền tảng ExpenseBridge."},{"id":"t8-s1-2","part":7,"question":"By when must employees submit their receipts after incurring an expense?","options":["Within 7 calendar days","Within 10 business days","Within 14 calendar days","Within 30 days"],"answer":2,"explanation":"'Submit all receipts... within 14 calendar days of the expense being incurred' – quy định rõ ràng trong nội dung."},{"id":"t8-s1-3","part":7,"question":"What will happen if an expense is submitted without a cost centre code?","options":["It will be automatically declined.","It will be processed after a 30-day delay.","It will be returned and not processed until corrected.","It will be forwarded to a manager for approval."],"answer":2,"explanation":"'will be returned for correction and will not be processed until the information is complete'."},{"id":"t8-s1-4","part":7,"question":"How can employees get additional help with the new platform?","options":["By visiting the finance department in person","By calling the IT helpdesk","By attending a live online Q&A session","By reading the updated staff handbook"],"answer":2,"explanation":"'A live Q&A session will also be held on 20 November at 2:00 P.M. via Teams' – có thể tham gia phiên hỏi đáp trực tuyến."}]},{"passage":"THORNFIELD EXECUTIVE SUITES\nFully Serviced Office Space in the Heart of the Financial District\n\nWhether you need a private office for one or a collaborative workspace for a growing team, Thornfield Executive Suites offers flexible solutions designed around your business.\n\nWHAT WE OFFER\n• Private offices: 1–20 workstations, available from AUD 850/month\n• Hot-desking memberships: From AUD 250/month (access during business hours)\n• Meeting rooms: Bookable by the hour, fully equipped with video conferencing technology\n• Executive boardroom: Seats up to 24, available for half-day or full-day hire\n\nALL PLANS INCLUDE\n✓ High-speed fibre internet (up to 1 Gbps)\n✓ Reception and mail handling services\n✓ Access to communal kitchen and lounge\n✓ Complimentary tea and coffee\n\nCURRENT PROMOTION\nSign a 12-month lease for a private office before 30 November and receive your first month FREE.\n\nLOCATION\nLevel 18, One Exchange Tower | 100 Market Street, Sydney CBD\n\nTours available Monday to Friday, 9:00 A.M. – 5:00 P.M. Book online at thornfieldsuites.com.au or call 1300 849 200.","passageTitle":"Advertisement – Thornfield Executive Suites","type":"single","questions":[{"id":"t8-s2-1","part":7,"question":"What type of business does Thornfield Executive Suites operate?","options":["A corporate hotel for business travellers","A commercial property management firm","A provider of serviced office space","A technology company offering remote work tools"],"answer":2,"explanation":"'Fully Serviced Office Space' là dịch vụ chính được cung cấp. Không phải khách sạn, công ty quản lý BĐS, hay công ty công nghệ."},{"id":"t8-s2-2","part":7,"question":"What is included in all office plans?","options":["Free parking in the building","A dedicated receptionist for each tenant","Access to a communal kitchen","Complimentary printing services"],"answer":2,"explanation":"'Access to communal kitchen and lounge' được liệt kê trong mục ALL PLANS INCLUDE. Không đề cập đến parking, dedicated receptionist, hay printing."},{"id":"t8-s2-3","part":7,"question":"What condition must be met to receive the promotional offer?","options":["Booking a meeting room for a full day","Signing a 12-month lease before November 30","Paying the first three months in advance","Referring another business to Thornfield"],"answer":1,"explanation":"'Sign a 12-month lease for a private office before 30 November and receive your first month FREE'."},{"id":"t8-s2-4","part":7,"question":"What is suggested about the hot-desking membership?","options":["It includes 24-hour building access.","It is the most expensive plan available.","It does not provide a permanently assigned workspace.","It requires a minimum 6-month commitment."],"answer":2,"explanation":"'Hot-desking' theo định nghĩa là không có chỗ ngồi cố định. Membership mô tả 'access during business hours' chứ không nói về chỗ ngồi cố định."}]},{"passage":"MERIDIAN INFRASTRUCTURE GROUP\nSuite 400, 250 Bay Street\nVancouver, BC  V6C 1L4\n\nNovember 8\n\nMr. Kwame Asante\nManaging Director\nAsante Civil Engineering Ltd.\n1890 Industrial Parkway\nBurnaby, BC  V5A 2C7\n\nDear Mr. Asante,\n\nRe: Contract Award – Westbrook Community Centre Redevelopment\n\nFollowing a competitive tender process, I am pleased to inform you that Asante Civil Engineering Ltd. has been selected as the preferred contractor for the Westbrook Community Centre Redevelopment project. Your submission demonstrated exceptional technical competence and offered the most favourable combination of cost-effectiveness and project timeline.\n\nThe contract is valued at CAD 4.2 million and encompasses the demolition of the existing structure, site preparation, and the construction of the new 2,800-square-metre community centre facility. Work is scheduled to commence on 6 January, with an expected completion date of 30 November of the following year.\n\nA formal contract document will be sent to your office by 20 November for review and execution. Please ensure that all required insurance certificates and subcontractor details are submitted to our project manager, Ms. Ingrid Hoffman, within ten business days of receiving the contract.\n\nWe look forward to working with Asante Civil Engineering on this important community project.\n\nYours sincerely,\n\nDouglas Park\nDirector of Project Development\nMeridian Infrastructure Group","passageTitle":"Business Letter – Contract Award Notice","type":"single","questions":[{"id":"t8-s3-1","part":7,"question":"Why is Mr. Park writing to Mr. Asante?","options":["To request additional information about a tender submission","To inform him that his company has been awarded a contract","To invite him to submit a proposal for a new project","To notify him of a change in project specifications"],"answer":1,"explanation":"'I am pleased to inform you that Asante Civil Engineering Ltd. has been selected as the preferred contractor' – thông báo trúng thầu."},{"id":"t8-s3-2","part":7,"question":"What does the contract involve?","options":["Renovating an existing sports facility","Constructing a new office building","Demolishing a building and constructing a new community centre","Expanding a school campus"],"answer":2,"explanation":"'demolition of the existing structure... and the construction of the new 2,800-square-metre community centre facility'."},{"id":"t8-s3-3","part":7,"question":"When is the project expected to be completed?","options":["By November 20 of the current year","By January 6 of the following year","By November 30 of the following year","By December 31 of the following year"],"answer":2,"explanation":"'expected completion date of 30 November of the following year'."},{"id":"t8-s3-4","part":7,"question":"What is Mr. Asante asked to provide to Ms. Hoffman?","options":["A revised project timeline","Insurance certificates and subcontractor details","A signed copy of the formal contract","Updated cost estimates for the project"],"answer":1,"explanation":"'all required insurance certificates and subcontractor details are submitted to our project manager, Ms. Ingrid Hoffman'."}]},{"passage":"RIVERSTONE CORPORATE LIBRARY\nInformation & Research Services for Riverstone Group Employees\n\nABOUT OUR SERVICES\nThe Riverstone Corporate Library provides employees with access to a comprehensive range of business and industry resources, including databases, journals, market reports, and reference materials.\n\nBORROWING BOOKS\n• Employees may borrow up to 5 books at a time.\n• Loan period: 3 weeks, with one renewal permitted if no reservation exists.\n• Books can be returned to any of the three library locations (City HQ, North Campus, and Eastside Office).\n\nONLINE DATABASES\nAll employees have remote access to our licensed databases, including IBISWorld, Statista, and ProQuest. Access your personal login via the employee portal at intranet.riverstone.com/library.\n\nRESEARCH ASSISTANCE\nOur librarians offer one-on-one research consultations, available Monday to Thursday, 9:00 A.M. to 4:00 P.M. Sessions can be booked up to two weeks in advance through the library portal.\n\nDOCUMENT DELIVERY\nArticles and reports not available through our current subscriptions can be requested through our document delivery service. Requests are typically fulfilled within 3 business days.\n\nFor general enquiries, contact the library team at library@riverstone.com or call extension 1500.","passageTitle":"Web Page – Riverstone Corporate Library Services","type":"single","questions":[{"id":"t8-s4-1","part":7,"question":"How many books may an employee borrow at one time?","options":["Three","Five","Seven","Ten"],"answer":1,"explanation":"'Employees may borrow up to 5 books at a time' – tối đa 5 quyển."},{"id":"t8-s4-2","part":7,"question":"When are research consultations available?","options":["Monday through Friday, 9:00 A.M. to 5:00 P.M.","Monday through Thursday, 9:00 A.M. to 4:00 P.M.","Tuesday through Friday, 10:00 A.M. to 3:00 P.M.","By appointment only, any day of the week"],"answer":1,"explanation":"'Monday to Thursday, 9:00 A.M. to 4:00 P.M.' – chỉ từ thứ Hai đến thứ Năm."},{"id":"t8-s4-3","part":7,"question":"What is suggested about the document delivery service?","options":["It is free for all employees.","It is limited to books only.","It can be used to obtain materials not in the library's current collection.","It requires manager approval."],"answer":2,"explanation":"'Articles and reports not available through our current subscriptions can be requested through our document delivery service' – dùng khi tài liệu không có trong kho hiện tại."},{"id":"t8-s4-4","part":7,"question":"How far in advance can employees book a research consultation?","options":["One week","Two weeks","Three weeks","One month"],"answer":1,"explanation":"'Sessions can be booked up to two weeks in advance through the library portal' – đặt lịch trước tối đa hai tuần."}]},{"passage":"[Document 1 – E-mail]\n\nFrom:    Stefan Volkov <s.volkov@magnoliaevents.com>\nTo:      sales@luminaraudio.com\nDate:    November 6\nSubject: Product Enquiry – Wireless Microphone Systems\n\nDear Lumin Audio Sales Team,\n\nI am the technical coordinator for Magnolia Events, a corporate event production company based in Melbourne. We are currently upgrading our audio equipment and are interested in purchasing wireless microphone systems for use at large-format conferences of up to 800 attendees.\n\nAfter reviewing your website, I have some questions about the ProLink 900 system:\n\n1. What is the maximum number of simultaneous channels the ProLink 900 can support?\n2. Does the system include a rackmount receiver, or is that sold separately?\n3. Can the system be operated in environments with significant radio frequency interference — we often work in venues with multiple Wi-Fi networks?\n\nWe are looking to purchase between 8 and 12 units initially, with potential to expand. Please advise on pricing for this quantity, and whether volume discounts apply.\n\nThank you,\nStefan Volkov\nTechnical Coordinator, Magnolia Events\n\n---\n\n[Document 2 – Product Specification Sheet]\n\nLUMIN AUDIO — ProLink 900 Wireless Microphone System\nProfessional Grade | UHF Band | Ideal for Large Venues\n\nSPECIFICATIONS\nFrequency Range:     620–698 MHz (UHF Band, 78 MHz bandwidth)\nSimultaneous Channels: Up to 20 in standard configuration; expandable to 32 with upgrade module\nOperating Range:     Up to 120 metres (line of sight)\nBattery Life:        Transmitter: up to 10 hours (2 × AA batteries)\n                     Receiver: Powered via included 12V DC adapter\n\nWHAT'S INCLUDED\n• 1 × Handheld transmitter\n• 1 × Bodypack transmitter (clip-on lapel mic included)\n• 1 × Half-rack single-channel receiver (rackmount ears included)\n• 1 × Carrying case\n• User manual and warranty card\n\nINTERFERENCE RESISTANCE\nThe ProLink 900 features advanced frequency scanning technology that automatically identifies and avoids occupied frequencies, making it suitable for RF-dense environments including venues with multiple active Wi-Fi networks and other wireless devices.\n\nPRICING (AUD, ex GST)\nSingle unit:        AUD 1,190\n6–11 units:         AUD 1,090 per unit\n12+ units:          AUD 990 per unit\n\nWarranty: 2 years parts and labour. Extended warranty available.\nFor sales enquiries: sales@luminaraudio.com | 1800 LUM AUDIO","passageTitle":"Enquiry E-mail and Product Specification Sheet","type":"double","questions":[{"id":"t8-d1-1","part":7,"question":"Why is Mr. Volkov contacting Lumin Audio?","options":["To report a fault with an existing product","To enquire about wireless microphone equipment","To request a product demonstration at his office","To negotiate a service maintenance contract"],"answer":1,"explanation":"'interested in purchasing wireless microphone systems' – liên hệ để hỏi về sản phẩm microphone không dây."},{"id":"t8-d1-2","part":7,"question":"According to the specification sheet, what does the ProLink 900 include?","options":["A full-rack receiver","Two handheld transmitters","A bodypack transmitter with a lapel microphone","A wireless charging case"],"answer":2,"explanation":"'1 × Bodypack transmitter (clip-on lapel mic included)' – bộ truyền đeo người kèm micro cài ve áo."},{"id":"t8-d1-3","part":7,"question":"According to the specification sheet, how does the ProLink 900 handle interference from Wi-Fi networks?","options":["It operates on a frequency range that avoids Wi-Fi entirely.","It uses an upgrade module to reduce interference.","It scans for and automatically avoids occupied frequencies.","It requires manual frequency selection by the operator."],"answer":2,"explanation":"'advanced frequency scanning technology that automatically identifies and avoids occupied frequencies'."},{"id":"t8-d1-4","part":7,"question":"If Magnolia Events purchases 10 units, how much will they pay in total?","options":["AUD 9,900","AUD 10,900","AUD 11,900","AUD 12,700"],"answer":1,"explanation":"10 units thuộc nhóm 6–11 units → AUD 1,090 per unit × 10 = AUD 10,900."},{"id":"t8-d1-5","part":7,"question":"Which of Mr. Volkov's questions is directly answered by the specification sheet?","options":["Whether volume discounts are available","Whether the receiver is sold separately","The maximum number of simultaneous channels","Whether training support is provided"],"answer":2,"explanation":"Mr. Volkov hỏi về số kênh đồng thời tối đa → Spec sheet trả lời: 'Up to 20 in standard configuration; expandable to 32 with upgrade module'."}]},{"passage":"[Document 1 – Job Posting]\n\nOPERATIONS MANAGER – VANTAGE DISTRIBUTION SERVICES\nFull-Time | Brisbane, QLD\n\nVantage Distribution Services is seeking a motivated and experienced Operations Manager to oversee its Brisbane warehouse and logistics hub. The successful candidate will be responsible for a team of 35 staff and will report directly to the National Operations Director.\n\nKEY RESPONSIBILITIES\n• Manage daily warehouse operations including receiving, storage, and outbound dispatch\n• Develop and implement process improvements to increase efficiency and reduce costs\n• Ensure compliance with workplace health and safety regulations\n• Prepare weekly performance reports for senior management\n• Liaise with transport carriers and third-party logistics providers\n\nREQUIREMENTS\n• Minimum 5 years of operations management experience in a logistics or distribution environment\n• Proven track record of team leadership and performance management\n• Proficiency in warehouse management systems (WMS); Fishbowl or SAP preferred\n• Certificate IV in Logistics or Supply Chain (desirable)\n• Strong written and verbal communication skills\n\nSALARY: AUD 110,000–125,000 + superannuation\nTO APPLY: Send CV and cover letter to hr@vantagedist.com.au by 5:00 P.M., Friday 22 November.\n\n---\n\n[Document 2 – Application E-mail]\n\nFrom:    Nadia Osei <n.osei@personalmail.com>\nTo:      hr@vantagedist.com.au\nDate:    November 19\nSubject: Application for Operations Manager – Vantage Distribution Services\n\nDear Hiring Team,\n\nPlease find attached my CV and cover letter in application for the Operations Manager position advertised on the Vantage Distribution Services website.\n\nI have seven years of experience managing warehouse and distribution operations, most recently as a Senior Operations Supervisor at Blueshore Freight in Townsville, where I led a team of 28 staff and oversaw a network of three regional depots. During my time at Blueshore Freight, I implemented a new inventory tracking system that reduced picking errors by 31 percent and cut operational costs by approximately AUD 180,000 annually.\n\nI hold a Certificate IV in Logistics and have extensive experience with SAP Warehouse Management. I am confident that my background aligns well with the requirements of this role and the strategic goals of Vantage Distribution Services.\n\nI would welcome the opportunity to discuss my application further and am available for an interview at your earliest convenience.\n\nKind regards,\nNadia Osei\n\n---\n\n[Document 3 – Reference Letter]\n\nBlueshore Freight Solutions\n25 Harbour View Drive, Townsville QLD 4810\n\nNovember 15\n\nTo Whom It May Concern,\n\nI am writing to provide a professional reference for Ms. Nadia Osei, who served as Senior Operations Supervisor at Blueshore Freight Solutions from March 2018 until October 2024.\n\nDuring her six and a half years with our organisation, Ms. Osei consistently demonstrated exceptional leadership and operational expertise. She managed a high-performing team and was directly responsible for several key process improvements that delivered measurable results across our depot network.\n\nMs. Osei's professional approach, sound judgement, and ability to manage complex logistics challenges make her an outstanding candidate for any senior operations role. I recommend her without reservation.\n\nIf you have any further questions, please do not hesitate to contact me at d.mcallister@blueshorefr.com.\n\nYours sincerely,\nDuncan McAllister\nGeneral Manager, Blueshore Freight Solutions","passageTitle":"Job Posting, Application E-mail, and Reference Letter","type":"triple","questions":[{"id":"t8-t1-1","part":7,"question":"What is one requirement listed in the job posting?","options":["A university degree in supply chain management","At least five years of relevant management experience","Fluency in a second language","Experience managing a team of more than 50 staff"],"answer":1,"explanation":"'Minimum 5 years of operations management experience in a logistics or distribution environment' – yêu cầu rõ ràng trong job posting."},{"id":"t8-t1-2","part":7,"question":"What did Ms. Osei accomplish at her previous employer?","options":["She expanded the company's operations to three new cities.","She reduced picking errors and cut operational costs significantly.","She introduced a new transport carrier partnership.","She increased the workforce from 20 to 35 staff."],"answer":1,"explanation":"'implemented a new inventory tracking system that reduced picking errors by 31 percent and cut operational costs by approximately AUD 180,000 annually'."},{"id":"t8-t1-3","part":7,"question":"Based on the application, does Ms. Osei meet the requirement for WMS proficiency?","options":["No, she has no experience with warehouse management systems.","Yes, she has extensive experience with SAP Warehouse Management.","Possibly, but she did not specify which systems she has used.","No, she only has experience with Fishbowl, not SAP."],"answer":1,"explanation":"'extensive experience with SAP Warehouse Management' – SAP được đề cập cụ thể trong job posting là hệ thống ưu tiên."},{"id":"t8-t1-4","part":7,"question":"How long did Ms. Osei work at Blueshore Freight, according to the reference letter?","options":["Four years","Five years","Six and a half years","Seven years"],"answer":2,"explanation":"'from March 2018 until October 2024' – Reference letter ghi 'six and a half years'."},{"id":"t8-t1-5","part":7,"question":"What does Mr. McAllister suggest about Ms. Osei in the reference letter?","options":["She may require additional training in logistics software.","She is well suited for senior operations positions.","She is currently seeking international opportunities.","She prefers working in smaller team environments."],"answer":1,"explanation":"'an outstanding candidate for any senior operations role. I recommend her without reservation' – đánh giá rất tích cực và phù hợp với vai trò quản lý cấp cao."},{"id":"t8-t1-6","part":7,"question":"What information in Ms. Osei's application cannot be verified by the reference letter?","options":["Her previous job title","The duration of her employment at Blueshore Freight","The AUD 180,000 cost reduction she claims to have achieved","Her professional approach and leadership ability"],"answer":2,"explanation":"Reference letter đề cập đến 'measurable results' chung chung nhưng KHÔNG xác nhận con số cụ thể AUD 180,000. Đây là thông tin chỉ có trong email ứng tuyển."}]},{"passage":"CARTIFY — GROW YOUR BUSINESS ONLINE\nEverything you need to sell smarter\n\nABOUT CARTIFY\nCartify is Australia's fastest-growing e-commerce marketplace, connecting over 4 million active shoppers with small and medium-sized businesses nationwide. Whether you sell handmade goods, electronics, or apparel, Cartify provides the tools to reach your customers.\n\nSELLER PLANS\n\nSTARTER (Free)\n• List up to 50 products\n• Standard search visibility\n• Basic sales analytics\n• Cartify-managed fulfillment available at AUD 3.50 per order\n\nPROFESSIONAL (AUD 49/month)\n• Unlimited product listings\n• Priority search placement\n• Advanced analytics including conversion rate tracking\n• Dedicated seller support (Mon–Fri, 9 A.M.–6 P.M.)\n• Fulfillment fee reduced to AUD 2.80 per order\n\nPREMIUM (AUD 120/month)\n• All Professional features\n• Featured placement on homepage and category pages\n• Same-day fulfillment for metro areas (orders placed before 11 A.M.)\n• Quarterly business review with a Cartify growth consultant\n\nHOW TO JOIN\nRegister at cartify.com.au/sellers. Approval typically takes one to two business days. Once approved, you can begin listing products immediately.\n\nCurrent promotion: New sellers who subscribe to a Professional or Premium plan before 30 November receive their first month at no charge.","passageTitle":"Web Page – Cartify Seller Platform","type":"single","questions":[{"id":"t9-s1-1","part":7,"question":"What is Cartify?","options":["A logistics company specialising in same-day delivery","An online marketplace connecting sellers and shoppers","A software provider for retail inventory management","A financial services firm for small businesses"],"answer":1,"explanation":"'Cartify is Australia's fastest-growing e-commerce marketplace, connecting over 4 million active shoppers with small and medium-sized businesses' – sàn thương mại điện tử."},{"id":"t9-s1-2","part":7,"question":"What feature is available ONLY to Premium subscribers?","options":["Unlimited product listings","Advanced analytics with conversion rate tracking","Same-day fulfillment for metro areas","Priority search placement"],"answer":2,"explanation":"'Same-day fulfillment for metro areas' chỉ được liệt kê trong gói Premium. Unlimited listings và analytics có ở Professional; priority placement cũng từ Professional."},{"id":"t9-s1-3","part":7,"question":"How long does seller approval typically take?","options":["A few hours","One to two business days","Up to five business days","One week"],"answer":1,"explanation":"'Approval typically takes one to two business days' – quy trình phê duyệt thường mất 1-2 ngày làm việc."},{"id":"t9-s1-4","part":7,"question":"What must a seller do to receive a free first month?","options":["Sign up for the Starter plan before November 30","Subscribe to the Professional or Premium plan before November 30","Complete a quarterly business review with a consultant","Achieve a minimum sales volume in the first month"],"answer":1,"explanation":"'New sellers who subscribe to a Professional or Premium plan before 30 November receive their first month at no charge' – phải chọn gói Professional hoặc Premium."}]},{"passage":"INTERNAL MEMORANDUM\n\nTo:   Executive Steering Committee\nFrom: Priya Mehta, Project Manager – CRM Implementation\nDate: November 14\nRe:   Halcyon CRM Project – Week 18 Status Update\n\nPROJECT STATUS: AMBER\n\nSUMMARY\nThe Halcyon CRM implementation project reached its third major milestone last week with the successful completion of data migration from the legacy system. However, the project is currently tracking approximately two weeks behind the revised timeline due to delays in third-party API integration.\n\nKEY UPDATES\n• Data migration: Complete ✓\n• User interface customisation: 85% complete, on track\n• API integration with billing system: 40% complete — delayed due to a technical bottleneck identified by the vendor's development team\n• Staff training: Scheduled to commence 2 December (pending API completion)\n\nRISK & CONTINGENCY\nThe project team has identified two risk scenarios. In the first, the API integration is resolved within the next ten days, allowing the overall timeline to be recovered with minimal impact on the go-live date of 15 January. In the second scenario, a contingency plan has been prepared that would allow a partial go-live on 15 January, with full functionality to follow in February.\n\nNEXT STEPS\nThe vendor has committed to providing a resolution update by 21 November. A revised project plan will be circulated to all stakeholders once this update is received.","passageTitle":"Memo – Halcyon CRM Project Status Update","type":"single","questions":[{"id":"t9-s2-1","part":7,"question":"What is the current status of the Halcyon CRM project?","options":["It is ahead of schedule and fully on track.","It is on schedule with no issues reported.","It is behind schedule due to an integration problem.","It has been placed on hold pending executive approval."],"answer":2,"explanation":"'tracking approximately two weeks behind the revised timeline due to delays in third-party API integration' – trễ 2 tuần vì vấn đề tích hợp API."},{"id":"t9-s2-2","part":7,"question":"What caused the delay in the project?","options":["A shortage of trained staff","A technical bottleneck in the API integration","Incomplete data migration from the legacy system","A change in the project scope"],"answer":1,"explanation":"'a technical bottleneck identified by the vendor's development team' làm trễ phần API integration với billing system."},{"id":"t9-s2-3","part":7,"question":"What has been prepared in case the timeline cannot be fully recovered?","options":["A request to postpone the go-live date indefinitely","A proposal to reduce the project scope","A contingency plan for a partial go-live on January 15","A plan to replace the third-party vendor"],"answer":2,"explanation":"'a contingency plan has been prepared that would allow a partial go-live on 15 January' – kế hoạch dự phòng cho phép triển khai một phần vào ngày đã định."}]},{"passage":"NORTHBRIDGE INSURANCE\nBusiness Travel Insurance — Plan Comparison\n\nProtect your team wherever business takes them. Northbridge offers three levels of corporate travel coverage, designed for companies of all sizes.\n\nPLAN OVERVIEW\n\n                    STANDARD        PLUS            EXECUTIVE\nAnnual Premium*     AUD 380/person  AUD 590/person  AUD 890/person\nMedical Cover       AUD 500,000     AUD 2,000,000   Unlimited\nTrip Cancellation   AUD 5,000       AUD 10,000      AUD 20,000\nBaggage Loss        AUD 2,000       AUD 4,000       AUD 6,000\nTravel Delay        AUD 500         AUD 1,000       AUD 2,000\n24/7 Assistance     Yes             Yes             Yes\nDeductible          AUD 250         AUD 150         NIL\n\n*Per person, per year. Minimum 5 employees to qualify for corporate pricing.\n\nMAKING A CLAIM\nAll claims must be submitted within 60 days of the incident. Policyholders can lodge claims online at northbridgeinsurance.com.au/claims or by calling 1800 673 400. Supporting documentation — including receipts, medical reports, or police reports where applicable — must accompany all claims.\n\nIMPORTANT NOTES\n• Pre-existing medical conditions are not covered under any plan unless disclosed and approved at the time of enrolment.\n• Coverage applies to business-related travel only. Personal side trips during a business journey may not be covered.\n• Group discounts of 10% apply to companies enrolling 20 or more employees.\n\nFor a tailored quote, contact our corporate team at corporate@northbridge.com.au.","passageTitle":"Web Page – Northbridge Business Travel Insurance","type":"single","questions":[{"id":"t9-s3-1","part":7,"question":"What is the deductible for the Plus plan?","options":["NIL","AUD 150","AUD 250","AUD 500"],"answer":1,"explanation":"Bảng so sánh: Plus plan — Deductible = AUD 150. Standard = AUD 250, Executive = NIL."},{"id":"t9-s3-2","part":7,"question":"What must policyholders do when submitting a claim?","options":["Visit a Northbridge office in person","Submit the claim within 30 days","Provide supporting documentation with the claim","Obtain approval from their employer first"],"answer":2,"explanation":"'Supporting documentation... must accompany all claims' — tài liệu hỗ trợ phải nộp kèm theo yêu cầu bồi thường."},{"id":"t9-s3-3","part":7,"question":"What condition must be met for a pre-existing medical condition to be covered?","options":["The employee must hold an Executive plan.","The condition must be disclosed and approved at enrolment.","A doctor's certificate must be submitted each year.","The claim must be filed within 30 days of travel."],"answer":1,"explanation":"'Pre-existing medical conditions are not covered unless disclosed and approved at the time of enrolment' — phải khai báo và được chấp thuận khi đăng ký."},{"id":"t9-s3-4","part":7,"question":"What discount is available to a company enrolling 25 employees?","options":["No discount is available.","A 5% group discount applies.","A 10% group discount applies.","A 15% group discount applies."],"answer":2,"explanation":"'Group discounts of 10% apply to companies enrolling 20 or more employees' — 25 nhân viên vượt ngưỡng 20, được giảm 10%."}]},{"passage":"LAKESIDE PROFESSIONAL SUITES\nConference Room Rental Rates\n\nRoom Name | Capacity | Hourly Rate | Full-Day Rate\n----------------------------------------------------\nBoardroom | 12 people| $50         | $350\nTraining B| 30 people| $80         | $550\nAuditorium| 100 people| $150        | $1,000\n\nAll rentals include:\n- High-speed Wi-Fi\n- Digital projector and screen\n- Filtered water and coffee/tea service\n\nOptional Add-ons:\n- Catering (Lunch Buffet): $25 per person\n- On-site IT Support: $40 per hour\n- Video conferencing setup: $75 flat fee\n\nBooking Policy: A 20% non-refundable deposit is required at the time of booking. Cancellations made less than 48 hours before the event will forfeit the full rental fee.\n\nTo book, visit www.lakesidesuites.com/rentals.","passageTitle":null,"type":"single","questions":[{"id":"ex7-1a","part":7,"question":"What is the hourly rate for the largest room?","options":["$50","$80","$150","$350"],"answer":2,"explanation":"Largest room là Auditorium (100 people), hourly rate là $150."},{"id":"ex7-1b","part":7,"question":"What is included in the base rental fee?","options":["Lunch buffet","IT support","Coffee and tea service","Video conferencing"],"answer":2,"explanation":"Trong 'All rentals include' có 'coffee/tea service'."},{"id":"ex7-1c","part":7,"question":"What is the cancellation policy?","options":["Full refund if cancelled anytime","No refund if cancelled less than 48 hours before","Only 20% refund if cancelled","No deposit is required"],"answer":1,"explanation":"Chính sách: hủy dưới 48h mất toàn bộ phí (forfeit the full rental fee)."}]},{"passage":"[Email 1]\nFrom: Marcus Thorne <m.thorne@tech-solutions.com>\nTo: info@lakesidesuites.com\nDate: Oct 5\nSubject: Room Rental for Training Workshop\n\nDear Lakeside Team,\n\nI am interested in booking your 'Training B' room for a full day on Friday, November 12. We expect around 25 participants for our software workshop. \n\nWe will also require on-site IT support for the first two hours of the event to ensure all participants can connect their laptops to our server. Additionally, we would like the lunch buffet for 25 people.\n\nCould you please send me a quote including these add-ons?\n\nBest regards,\nMarcus Thorne\n\n[Email 2]\nFrom: Lakeside Suites Info <info@lakesidesuites.com>\nTo: Marcus Thorne <m.thorne@tech-solutions.com>\nDate: Oct 6\nSubject: Re: Room Rental for Training Workshop\n\nDear Mr. Thorne,\n\nThank you for your interest. I have calculated the quote for November 12 as requested:\n- Training B (Full-Day Rate): $550\n- IT Support (2 hours): $80\n- Catering (25 people): $625\nTOTAL: $1,255\n\nTo confirm this booking, please pay the 20% deposit ($251) by the end of this week. Please note that the IT support technician, Mr. Jenkins, will be available starting at 8:30 a.m. for your setup.\n\nSincerely,\nLakeside Suites Management","passageTitle":"Inquiry Email + Response","type":"double","questions":[{"id":"ex7-2a","part":7,"question":"How many people are expected at the workshop?","options":["12","20","25","30"],"answer":2,"explanation":"Marcus Thorne nói 'around 25 participants'."},{"id":"ex7-2b","part":7,"question":"What is the cost per person for the lunch buffet?","options":["$20","$25","$40","$50"],"answer":1,"explanation":"Từ bảng giá gốc hoặc tính toán: $625 / 25 = $25."},{"id":"ex7-2c","part":7,"question":"How much deposit is required to confirm the booking?","options":["$50","$251","$550","$1,255"],"answer":1,"explanation":"Email 2 ghi rõ '20% deposit ($251)'."},{"id":"ex7-2d","part":7,"question":"Who is Mr. Jenkins?","options":["A training participant","The office manager","A catering staff member","An IT technician"],"answer":3,"explanation":"Email 2 nói 'the IT support technician, Mr. Jenkins'."}]},{"passage":"[Document 1: Job Posting]\nSENIOR GRAPHIC DESIGNER\nStudio Pixel is looking for a creative Senior Graphic Designer with at least 5 years of experience in digital marketing. Candidates must be proficient in Adobe Creative Suite and have a strong portfolio.\nResponsibilities:\n- Design social media campaigns\n- Collaborate with the marketing team\n- Mentor junior designers\nDeadline: August 20\n\n[Document 2: Email Application]\nFrom: Elena Rossi <e.rossi@email.com>\nTo: hr@studiopixel.com\nDate: August 15\nSubject: Application for Senior Graphic Designer\n\nDear HR Manager,\nI am writing to express my interest in the Senior Graphic Designer position advertised. I have 7 years of experience at Creative Lab, where I led several successful digital campaigns. I have attached my portfolio and CV. I am particularly interested in the mentoring aspect of the role.\n\n[Document 3: Interview Invitation]\nFrom: Studio Pixel HR <hr@studiopixel.com>\nTo: Elena Rossi <e.rossi@email.com>\nDate: August 18\nSubject: Interview Invitation\n\nDear Ms. Rossi,\nThank you for your application. We were impressed by your work at Creative Lab. We would like to invite you for an in-person interview on August 25 at 10:00 a.m. at our downtown office. Please let us know if this time works for you.","passageTitle":"Job Posting + Email Application + Interview Invitation","type":"triple","questions":[{"id":"b9-7-1a","part":7,"question":"What is a requirement for the job?","options":["University degree in art","5 years of digital marketing experience","Fluency in three languages","Ability to code websites"],"answer":1,"explanation":"Doc 1 ghi 'at least 5 years of experience'."},{"id":"b9-7-1b","part":7,"question":"Why is Ms. Rossi interested in the position?","options":["The salary is higher","She wants to move downtown","She likes the mentoring responsibility","She uses Adobe Creative Suite"],"answer":2,"explanation":"Doc 2 ghi 'I am particularly interested in the mentoring aspect'."},{"id":"b9-7-1c","part":7,"question":"When will the interview take place?","options":["August 15","August 18","August 20","August 25"],"answer":3,"explanation":"Doc 3 ghi 'on August 25'."},{"id":"b9-7-1d","part":7,"question":"Where did Ms. Rossi previously work?","options":["Studio Pixel","Creative Lab","HR Department","Downtown Office"],"answer":1,"explanation":"Doc 2 ghi 'at Creative Lab'."},{"id":"b9-7-1e","part":7,"question":"Did Ms. Rossi apply before the deadline?","options":["Yes, 5 days early","Yes, on the day of deadline","No, for late application","The deadline was not mentioned"],"answer":0,"explanation":"Deadline 20/8, cô ấy nộp 15/8 -> Sớm 5 ngày."}]},{"passage":"[Review]\n⭐⭐⭐⭐\nProduct: Swift-Charge Power Bank (Model 500)\nReviewer: Alex P.\nDate: Sept 10\n\nI bought this power bank for a business trip. It is compact and charges my phone very quickly. However, the included USB-C cable started fraying after only two uses. The device itself is great, but the accessories are disappointing for the price.\n\n[Response]\nDear Alex,\nThank you for your feedback. We are sorry to hear about the cable issue. We take quality control seriously. Please contact our support team with your order number, and we will ship you a premium replacement cable free of charge. We are currently reviewing our accessory suppliers to ensure this doesn't happen again.\n- Swift-Charge Customer Care","passageTitle":"Product Review + Company Response","type":"double","questions":[{"id":"b9-7-2a","part":7,"question":"What did the reviewer like about the product?","options":["The color","The price","The charging speed","The cable quality"],"answer":2,"explanation":"Reviewer nói 'charges my phone very quickly'."},{"id":"b9-7-2b","part":7,"question":"What was the specific problem mentioned?","options":["The device overheated","The phone wouldn't connect","The cable was damaged quickly","The delivery was late"],"answer":2,"explanation":"Reviewer nói 'USB-C cable started fraying after only two uses'."},{"id":"b9-7-2c","part":7,"question":"What is the company offering the reviewer?","options":["A full refund","A new power bank","A free replacement cable","A discount code"],"answer":2,"explanation":"Công ty nói 'ship you a premium replacement cable free of charge'."},{"id":"b9-7-2d","part":7,"question":"What is the company doing about the issue?","options":["Closing the factory","Changing their phone numbers","Reviewing their suppliers","Discontinuing the product"],"answer":2,"explanation":"Công ty nói 'currently reviewing our accessory suppliers'."}]},{"passage":"PROPERTY LISTING\n\nPineview Business Park — Unit 14B\nAddress: 88 Pineview Drive, Melbourne VIC 3004\nType: Commercial Office Space\nSize: 320 sqm (net lettable area)\nLease Term: 3–5 years preferred; shorter terms considered\nAnnual Rent: AUD 128,000 + outgoings\nParking: 6 allocated spaces included\n\nFEATURES:\n• Fully fitted-out with open-plan workstations for 30 staff\n• Two enclosed meeting rooms (8 and 12 seats)\n• Server room with UPS backup\n• End-of-trip facilities (showers, lockers, bike storage)\n• Direct tram access from Collins Street\n• 24/7 secure access\n\nInspections by appointment only.\nContact: Alex Gould, Pineview Commercial Real Estate\nPhone: 03 9812 4400 | alex.gould@pineviewre.com.au","passageTitle":null,"type":"single","questions":[{"id":"xp7-s01a","part":7,"question":"What type of property is advertised?","options":["A residential apartment","A retail shopfront","A commercial office space","A warehouse facility"],"answer":2,"explanation":"'Commercial Office Space' is stated in the listing type."},{"id":"xp7-s01b","part":7,"question":"How many parking spaces are included?","options":["3","4","6","8"],"answer":2,"explanation":"'6 allocated spaces included'"},{"id":"xp7-s01c","part":7,"question":"How must prospective tenants arrange to view the property?","options":["Submit a formal application","Call during business hours only","Book an appointment in advance","Register on the Pineview website"],"answer":2,"explanation":"'Inspections by appointment only.'"},{"id":"xp7-s01d","part":7,"question":"Which feature caters to staff who cycle to work?","options":["Server room with UPS backup","End-of-trip facilities including bike storage","6 allocated parking spaces","24/7 secure access"],"answer":1,"explanation":"'End-of-trip facilities (showers, lockers, bike storage)' directly caters to cycling commuters."}]},{"passage":"MERIDIAN HEALTH NETWORK\nPatient Information Leaflet\n\nPREPARING FOR YOUR MRI SCAN\n\nThank you for scheduling your MRI scan at Meridian Health Network. Please read the following information carefully before your appointment.\n\nBEFORE YOUR SCAN\n• Do not eat or drink anything for 4 hours prior to your appointment, unless instructed otherwise by your doctor.\n• Leave all metal objects at home or in a locker: jewellery, watches, hairpins, and belt buckles can interfere with the scan.\n• Inform our staff if you have any implanted medical devices (e.g., pacemakers, cochlear implants), as these may be affected by the magnetic field.\n• Wear comfortable, loose-fitting clothing with no metal zippers or buttons.\n\nDURING YOUR SCAN\nThe scan typically takes 30–45 minutes. You will be asked to remain completely still. Some patients find the enclosed environment of the scanner uncomfortable; please notify staff in advance if you experience claustrophobia.\n\nAFTER YOUR SCAN\nYour results will be sent to your referring doctor within 3 business days. Meridian Health does not provide results directly to patients.","passageTitle":null,"type":"single","questions":[{"id":"xp7-s02a","part":7,"question":"What must patients avoid for 4 hours before the appointment?","options":["Wearing metal jewellery","Taking any medication","Eating or drinking","Using electronic devices"],"answer":2,"explanation":"'Do not eat or drink anything for 4 hours prior.'"},{"id":"xp7-s02b","part":7,"question":"Who should patients inform about a pacemaker?","options":["Their referring doctor","The hospital receptionist","The MRI staff","Meridian Health administration"],"answer":2,"explanation":"'Inform our staff if you have any implanted medical devices.'"},{"id":"xp7-s02c","part":7,"question":"How will patients receive their results?","options":["Directly from Meridian Health after the scan","Via email within 24 hours","Through their referring doctor","At a follow-up appointment"],"answer":2,"explanation":"'Your results will be sent to your referring doctor... Meridian Health does not provide results directly to patients.'"},{"id":"xp7-s02d","part":7,"question":"What should claustrophobic patients do?","options":["Request a different scan type","Notify staff in advance","Bring a companion","Ask for medication before the scan"],"answer":1,"explanation":"'Please notify staff in advance if you experience claustrophobia.'"}]},{"passage":"STELLARBANK ONLINE BANKING — SECURITY ALERT\n\nDear Valued Customer,\n\nWe have detected unusual login activity on your StellarBank online account from an unrecognised device in a different location from your usual access point.\n\nAs a precautionary measure, we have temporarily restricted access to your account. No funds have been transferred and your balance remains secure.\n\nTo restore full access, please verify your identity by:\n1. Visiting stellarbank.com/verify\n2. Entering your date of birth and the last 4 digits of your registered mobile number\n3. Resetting your password using a secure, unique combination\n\nIMPORTANT: StellarBank will never ask for your full password, PIN, or one-time passcode by phone or email. If you receive any such request, please report it immediately to 1800 STELLAR.\n\nIf you did not attempt to log in from a new device, this alert may indicate an unauthorised access attempt. In that case, please contact us immediately.\n\nStellarBank Security Team","passageTitle":null,"type":"single","questions":[{"id":"xp7-s03a","part":7,"question":"Why was the customer's account access restricted?","options":["The customer failed to pay a fee","Unusual login activity was detected","The account had not been used for 90 days","A fraud complaint was submitted"],"answer":1,"explanation":"'We have detected unusual login activity... As a precautionary measure, we have temporarily restricted access.'"},{"id":"xp7-s03b","part":7,"question":"What must the customer provide to verify identity?","options":["Their full password and PIN","Date of birth and last 4 digits of mobile number","A copy of government-issued ID","Account number and branch code"],"answer":1,"explanation":"Step 2: 'Entering your date of birth and the last 4 digits of your registered mobile number.'"},{"id":"xp7-s03c","part":7,"question":"What does StellarBank warn customers about?","options":["Using public Wi-Fi for banking","Sharing account details with family","Being asked for passwords or PINs via phone or email","Accessing the account from overseas"],"answer":2,"explanation":"'StellarBank will never ask for your full password, PIN, or one-time passcode by phone or email.'"},{"id":"xp7-s03d","part":7,"question":"What should the customer do if they did NOT attempt to log in from a new device?","options":["Wait for a follow-up email","Change their password without contacting the bank","Contact StellarBank immediately","File a police report"],"answer":2,"explanation":"'If you did not attempt to log in from a new device... please contact us immediately.'"}]},{"passage":"HARBRIDGE UNIVERSITY — CONTINUING EDUCATION\nCertificate in Project Management\n\nCourse Overview\nThis 16-week online programme is designed for working professionals seeking to develop structured project management skills. The curriculum covers the full project lifecycle, from initiation and planning through to execution, monitoring, and closure.\n\nDelivery & Format\n• 100% online; self-paced with weekly live sessions (Tuesdays, 7:00–9:00 p.m.)\n• Each module includes readings, video lectures, and a practical assignment\n• Peer review and instructor feedback provided throughout\n\nAdmission Requirements\n• No formal prerequisites; open to all professionals\n• Applicants must be currently employed or recently employed (within 12 months)\n\nCertification\nUpon successful completion (minimum 70% overall grade), students receive a Harbridge Certificate in Project Management, which carries 3 Continuing Education Units (CEUs) recognised by major professional bodies.\n\nFees: USD 1,850 (payment plans available)\nNext Intake: September 8\nApplication Deadline: August 25\n\nEnrol: ce.harbridge.edu/project-management","passageTitle":null,"type":"single","questions":[{"id":"xp7-s04a","part":7,"question":"How long is the programme?","options":["8 weeks","12 weeks","16 weeks","20 weeks"],"answer":2,"explanation":"'This 16-week online programme.'"},{"id":"xp7-s04b","part":7,"question":"When do live sessions take place?","options":["Mondays 6:00–8:00 p.m.","Tuesdays 7:00–9:00 p.m.","Wednesdays 5:00–7:00 p.m.","Fridays 7:00–9:00 p.m."],"answer":1,"explanation":"'Weekly live sessions (Tuesdays, 7:00–9:00 p.m.)'"},{"id":"xp7-s04c","part":7,"question":"What minimum grade is required to receive the certificate?","options":["60%","65%","70%","75%"],"answer":2,"explanation":"'Minimum 70% overall grade.'"},{"id":"xp7-s04d","part":7,"question":"What is a requirement for admission?","options":["A bachelor's degree in a related field","Completion of a prerequisite course","Current or recent employment","A letter of recommendation from an employer"],"answer":2,"explanation":"'Applicants must be currently employed or recently employed (within 12 months).'"}]},{"passage":"BLOOM & GROVE FLORAL STUDIO\nCustom Event Florals — Service Information\n\nBloom & Grove specialises in bespoke floral design for corporate events, weddings, and private functions. Each arrangement is handcrafted using seasonal and sustainably sourced flowers.\n\nSERVICE PACKAGES\n• Consultation Package (AUD 150): Includes a 60-minute in-person or virtual consultation, mood board creation, and a written quote. The fee is fully credited toward your final booking.\n• Installation Only (from AUD 800): Delivery and installation of pre-agreed floral designs. Suitable for clients who have completed the consultation process.\n• Full Event Package (custom pricing): End-to-end service from initial consultation through to installation and post-event removal.\n\nBOOKING TERMS\nA 30% deposit is required to secure your booking date. Cancellations made more than 30 days before the event will receive a full refund of the deposit. Cancellations within 30 days will forfeit the deposit.\n\nTo enquire, email hello@bloomandgrove.com.au or call 03 9311 7700.","passageTitle":null,"type":"single","questions":[{"id":"xp7-s05a","part":7,"question":"What does the Consultation Package include?","options":["Flower delivery to the venue","A mood board and written quote","Installation of floral arrangements","Post-event removal of flowers"],"answer":1,"explanation":"'Includes a 60-minute consultation, mood board creation, and a written quote.'"},{"id":"xp7-s05b","part":7,"question":"What happens to the consultation fee if the client makes a full booking?","options":["It is refunded after the event","It is non-refundable","It is credited toward the final booking","It is applied as a future discount"],"answer":2,"explanation":"'The fee is fully credited toward your final booking.'"},{"id":"xp7-s05c","part":7,"question":"What percentage deposit is required to secure a booking?","options":["20%","25%","30%","50%"],"answer":2,"explanation":"'A 30% deposit is required to secure your booking date.'"},{"id":"xp7-s05d","part":7,"question":"When will a client NOT receive a refund of their deposit?","options":["If they cancel more than 60 days in advance","If the event is relocated","If the cancellation is within 30 days of the event","If the client requests a design change"],"answer":2,"explanation":"'Cancellations within 30 days will forfeit the deposit.'"}]},{"passage":"CITY TRANSIT AUTHORITY\nAdvisory Notice — Line 7 Service Changes\n\nEffective Monday, April 14, temporary changes will be made to Line 7 (Riverside–Central) services to accommodate track upgrade works between Oakfield and Milford stations.\n\nKEY CHANGES:\n• Trains on Line 7 will not stop at Oakfield or Milford stations from April 14 to May 9.\n• A free replacement bus service (Route 7B) will operate between Oakfield and Milford, connecting with Line 7 services at both terminals.\n• The replacement bus will depart every 12 minutes during peak hours (7:00–9:30 a.m. and 4:30–7:00 p.m.) and every 20 minutes at other times.\n• Passengers holding valid transit cards or printed tickets will be accepted on Route 7B at no additional charge.\n\nPassengers travelling between stations not affected by these works will experience no change to regular services.\n\nWe apologise for any inconvenience and thank passengers for their understanding during this essential upgrade period.\nCity Transit Authority","passageTitle":null,"type":"single","questions":[{"id":"xp7-s06a","part":7,"question":"Why are changes being made to Line 7?","options":["Due to a signal fault","To reduce overcrowding","To allow track upgrade works between two stations","Following a safety audit"],"answer":2,"explanation":"'To accommodate track upgrade works between Oakfield and Milford stations.'"},{"id":"xp7-s06b","part":7,"question":"How often does the replacement bus run during off-peak hours?","options":["Every 8 minutes","Every 12 minutes","Every 15 minutes","Every 20 minutes"],"answer":3,"explanation":"'Every 20 minutes at other times' (outside peak hours)."},{"id":"xp7-s06c","part":7,"question":"What do passengers need to board Route 7B at no extra cost?","options":["A Route 7B-specific ticket","A valid transit card or printed ticket","Proof of regular Line 7 usage","A free pass from the transit authority"],"answer":1,"explanation":"'Passengers holding valid transit cards or printed tickets will be accepted on Route 7B at no additional charge.'"},{"id":"xp7-s06d","part":7,"question":"Who will NOT be affected by these service changes?","options":["Commuters who use Oakfield station daily","Passengers travelling between other Line 7 stations","Passengers connecting to Route 7B","Passengers travelling to Milford station"],"answer":1,"explanation":"'Passengers travelling between stations not affected by these works will experience no change to regular services.'"}]},{"passage":"GLOBALREACH COMMUNICATIONS\nService Agreement — Summary of Key Terms\n\nThis summary outlines the key terms of your GlobalReach Business Communications contract (Ref: GR-881123).\n\nSERVICES INCLUDED:\n• Unlimited domestic calls and texts\n• 50GB data per month (rollover of unused data not permitted)\n• International calling credit: USD 30 per month (applicable to 45 countries)\n\nCONTRACT TERM: 24 months from activation date\n\nBILLING: Monthly invoices will be issued on the 1st of each month and are payable within 14 days.\n\nEARLY TERMINATION: If you cancel the service before the end of the 24-month term, an early termination fee of USD 15 per remaining month will apply.\n\nAUTO-RENEWAL: This contract will automatically renew on a month-to-month basis at the prevailing rate unless written notice of cancellation is provided at least 30 days before the contract end date.\n\nFor service queries, contact business@globalreach.com or call 1800 555 0100.","passageTitle":null,"type":"single","questions":[{"id":"xp7-s07a","part":7,"question":"What happens to unused monthly data?","options":["It rolls over to the following month","It is added to international credit","It cannot be carried over","It converts to additional call minutes"],"answer":2,"explanation":"'Rollover of unused data not permitted.'"},{"id":"xp7-s07b","part":7,"question":"What is the early termination fee per month?","options":["USD 10","USD 15","USD 20","USD 30"],"answer":1,"explanation":"'An early termination fee of USD 15 per remaining month.'"},{"id":"xp7-s07c","part":7,"question":"What must a customer do to prevent automatic renewal?","options":["Contact the provider 14 days before end date","Submit written cancellation at least 30 days before end date","Call 1800 555 0100 on the final day","Email a cancellation request any time before renewal"],"answer":1,"explanation":"'Written notice of cancellation... at least 30 days before the contract end date.'"},{"id":"xp7-s07d","part":7,"question":"Within how many days must monthly invoices be paid?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"'Payable within 14 days.'"}]},{"passage":"MERIDIAN EXECUTIVE SEARCH\nPlacement Report — October\n\nMeridian Executive Search is pleased to present the following highlights from our October placement activity.\n\nDuring October, Meridian successfully placed 14 senior professionals across the Finance, Technology, and Operations sectors. This represents a 22% increase from September's total of 11 placements.\n\nNotable placements this month included a Chief Information Officer for a mid-sized logistics company, a Regional Finance Director for a multinational consumer goods firm, and three Senior Software Engineers for a fast-growing fintech startup.\n\nOur average time-to-placement for the month was 31 days, compared to an industry benchmark of 45 days. Client satisfaction surveys indicated that 92% of hiring managers rated the quality of candidates presented as 'excellent' or 'very good'.\n\nLooking ahead, we anticipate continued demand in the Technology and ESG-focused leadership roles as companies accelerate their digital and sustainability agendas.\n\nFor enquiries, contact your Meridian relationship manager or email partners@meridianexec.com.","passageTitle":null,"type":"single","questions":[{"id":"xp7-s08a","part":7,"question":"By how much did placements increase from September to October?","options":["11%","18%","22%","25%"],"answer":2,"explanation":"'22% increase from September's total of 11 placements.'"},{"id":"xp7-s08b","part":7,"question":"What was Meridian's average time-to-placement in October?","options":["22 days","31 days","38 days","45 days"],"answer":1,"explanation":"'Our average time-to-placement for the month was 31 days.'"},{"id":"xp7-s08c","part":7,"question":"What did 92% of hiring managers say about candidates?","options":["They were placed faster than expected","They met technical requirements","They were rated excellent or very good","They exceeded salary expectations"],"answer":2,"explanation":"'92% of hiring managers rated the quality of candidates as excellent or very good.'"},{"id":"xp7-s08d","part":7,"question":"What future trend does the report anticipate?","options":["Increased demand in retail leadership","Growth in Technology and ESG leadership roles","A slowdown in Finance sector hiring","Consolidation in executive search"],"answer":1,"explanation":"'We anticipate continued demand in the Technology and ESG-focused leadership roles.'"}]},{"passage":"LAKEWOOD BUSINESS IMPROVEMENT DISTRICT\nGrant Programme — Call for Applications\n\nThe Lakewood Business Improvement District (BID) is inviting applications for its 2024–25 Small Business Sustainability Grant.\n\nPURPOSE\nThe grant supports small businesses in the Lakewood precinct to implement environmentally sustainable practices, reduce operating costs, and improve community engagement.\n\nELIGIBILITY\n• Business must be located within the Lakewood BID boundary\n• Annual turnover not exceeding AUD 2 million\n• Business must have been operating for at least 12 months at the time of application\n\nGRANT DETAILS\n• Grants of AUD 3,000–10,000 are available\n• Funds must be used within 12 months of approval\n• A progress report must be submitted 6 months after grant approval\n• Final acquittal documentation required within 30 days of project completion\n\nAPPLICATION PROCESS\nApplications open: September 1\nApplications close: September 30\nOutcomes notified: November 1\n\nApply online: www.lakewoodbid.org/grants","passageTitle":null,"type":"single","questions":[{"id":"xp7-s09a","part":7,"question":"What is the maximum annual turnover allowed for applicants?","options":["AUD 500,000","AUD 1 million","AUD 2 million","AUD 5 million"],"answer":2,"explanation":"'Annual turnover not exceeding AUD 2 million.'"},{"id":"xp7-s09b","part":7,"question":"How long must a business have been operating to be eligible?","options":["6 months","12 months","18 months","24 months"],"answer":1,"explanation":"'Business must have been operating for at least 12 months at the time of application.'"},{"id":"xp7-s09c","part":7,"question":"When will successful applicants be notified of outcomes?","options":["September 1","September 30","November 1","December 1"],"answer":2,"explanation":"'Outcomes notified: November 1.'"},{"id":"xp7-s09d","part":7,"question":"What must applicants submit within 30 days of project completion?","options":["A progress report","A second application","Final acquittal documentation","A community impact assessment"],"answer":2,"explanation":"'Final acquittal documentation required within 30 days of project completion.'"}]},{"passage":"WEST END COMMUNITY CENTRE\nSummer Programme — Activity Guide\n\nThe West End Community Centre is offering its annual Summer Activity Programme for residents of all ages. Registrations open June 1.\n\nHIGHLIGHT PROGRAMMES:\n• Junior Robotics (Ages 8–12): A hands-on 4-week course teaching basic coding and robot assembly. Monday/Wednesday, 10:00 a.m. – 12:00 p.m.\n• Seniors Yoga (Ages 60+): Gentle yoga sessions designed for flexibility and relaxation. Tuesday/Thursday, 9:00–10:00 a.m. Free of charge.\n• Community Garden Workshops (All ages): Learn sustainable gardening practices. Saturday mornings, 8:30–10:30 a.m. Materials fee: AUD 10 per session.\n• Youth Photography (Ages 15–19): 8-week course in digital photography and editing. Fridays, 2:00–4:30 p.m.\n\nREGISTRATION: Visit www.westendcc.org.au or call the centre at 02 9514 2200.\nPlaces are limited; early registration is recommended.\n\nThe Community Centre is committed to ensuring programmes are accessible to all. Concession pricing and subsidies are available for eligible residents.","passageTitle":null,"type":"single","questions":[{"id":"xp7-s10a","part":7,"question":"Which programme is available at no cost?","options":["Junior Robotics","Seniors Yoga","Community Garden Workshops","Youth Photography"],"answer":1,"explanation":"'Seniors Yoga... Free of charge.'"},{"id":"xp7-s10b","part":7,"question":"How long is the Youth Photography course?","options":["4 weeks","6 weeks","8 weeks","10 weeks"],"answer":2,"explanation":"'8-week course in digital photography and editing.'"},{"id":"xp7-s10c","part":7,"question":"What fee is charged for each Community Garden Workshop?","options":["AUD 5","AUD 10","AUD 15","AUD 20"],"answer":1,"explanation":"'Materials fee: AUD 10 per session.'"},{"id":"xp7-s10d","part":7,"question":"What does the centre offer to lower-income residents?","options":["Free registration for all programmes","Concession pricing and subsidies","Online participation options","Flexible payment plans"],"answer":1,"explanation":"'Concession pricing and subsidies are available for eligible residents.'"}]},{"passage":"[Document 1 – Newsletter Excerpt]\n\nSOUTHBAY CHAMBER OF COMMERCE\nMember Spotlight — Spring Edition\n\nThis quarter, we shine the spotlight on DataBridge Analytics, a Southbay-based data consultancy that has grown from a two-person startup to a team of 45 in just four years.\n\nFounded in 2020 by former university colleagues Priya Mehta and Oliver Fung, DataBridge specialises in helping mid-sized businesses interpret complex datasets to improve operational decision-making. Their flagship product, ClearView, is now used by over 200 clients across healthcare, logistics, and retail sectors.\n\nPriya Mehta credits the company's rapid growth to its focus on accessibility: \"We built ClearView for the business manager who doesn't have a data science background. We translate numbers into plain language that drives action.\"\n\nDataBridge was recently named a finalist in the National Technology Innovation Awards in the SME category.\n\n[Document 2 – Event Invitation]\n\nSouthbay Chamber of Commerce — Networking Breakfast\nFeaturing: Priya Mehta, Co-Founder, DataBridge Analytics\n\nDate: Thursday, June 12\nTime: 7:30 – 9:30 a.m.\nVenue: The Harbour Club, Level 2, 40 Bay Street, Southbay\n\nPriya Mehta will share her experience building a fast-growing data consultancy, including lessons learned about hiring, scaling technology, and winning enterprise clients.\n\nTickets: AUD 45 per person (Chamber members); AUD 65 (non-members)\nIncludes: Breakfast, networking, and Q&A session\n\nRSVP by June 5: events@southbaychamber.org","passageTitle":"Newsletter + Event Invitation","type":"double","questions":[{"id":"xp7-d01a","part":7,"question":"How many staff does DataBridge Analytics currently employ?","options":["2","20","45","200"],"answer":2,"explanation":"'Grown from a two-person startup to a team of 45 in just four years.'"},{"id":"xp7-d01b","part":7,"question":"What is ClearView designed for?","options":["Data scientists seeking advanced tools","Business managers without a data science background","University researchers analysing large datasets","IT departments managing enterprise software"],"answer":1,"explanation":"'We built ClearView for the business manager who doesn't have a data science background.'"},{"id":"xp7-d01c","part":7,"question":"How much does a Chamber member pay to attend the breakfast?","options":["AUD 25","AUD 45","AUD 55","AUD 65"],"answer":1,"explanation":"'AUD 45 per person (Chamber members)'"},{"id":"xp7-d01d","part":7,"question":"What does the breakfast ticket include?","options":["A copy of ClearView software","A post-event summary report","Breakfast, networking, and a Q&A session","Access to the Chamber's member portal"],"answer":2,"explanation":"'Includes: Breakfast, networking, and Q&A session'"},{"id":"xp7-d01e","part":7,"question":"What can be inferred about DataBridge Analytics?","options":["It is seeking venture capital investment","It was recently established in healthcare","It has achieved significant growth since founding","It plans to expand overseas next year"],"answer":2,"explanation":"Growing from 2 to 45 staff in 4 years, 200+ clients, and a national award finalist demonstrates significant growth."}]},{"passage":"[Document 1 – Internal Announcement]\n\nFrom: CEO Office\nTo: All Staff\nDate: March 10\nSubject: Welcoming Our New Chief Financial Officer\n\nI am delighted to announce that Ms. Vanessa Osei will join Hartwell Group as Chief Financial Officer, effective April 1.\n\nVanessa brings 18 years of financial leadership experience, most recently as Deputy CFO at Crestline Capital Partners, where she led a team of 40 finance professionals and oversaw a portfolio of over USD 3 billion in managed assets.\n\nVanessa holds an MBA from INSEAD and is a Fellow of the Chartered Institute of Management Accountants (FCMA). She is known for her disciplined approach to capital allocation and her track record of driving operational efficiency.\n\nVanessa will present at our All-Staff Townhall on April 8, where she will share her priorities for the finance function and answer questions from the team.\n\nPlease join me in welcoming Vanessa to Hartwell Group.\n\nJonathan Webb, CEO\n\n[Document 2 – Email from Vanessa Osei]\n\nFrom: Vanessa Osei <v.osei@hartwellgroup.com>\nTo: Finance Team <finance@hartwellgroup.com>\nDate: April 1\nSubject: Hello from Your New CFO\n\nDear Finance Team,\n\nI am thrilled to have joined Hartwell Group today. I have been looking forward to this opportunity and cannot wait to meet each of you in person.\n\nIn my first few weeks, I plan to spend time understanding the current structure and workflows of our finance function. I will be scheduling one-on-one meetings with each team member during April to hear your perspectives and identify opportunities for improvement.\n\nI also want to share that my initial focus will be on three areas: strengthening our financial reporting framework, improving forecasting accuracy, and reviewing our vendor payment processes.\n\nI look forward to working alongside you all.\nVanessa Osei","passageTitle":"CEO Announcement + New Employee Email","type":"double","questions":[{"id":"xp7-d02a","part":7,"question":"How many years of financial leadership experience does Ms. Osei have?","options":["8 years","12 years","15 years","18 years"],"answer":3,"explanation":"'18 years of financial leadership experience.'"},{"id":"xp7-d02b","part":7,"question":"Where will Ms. Osei introduce herself to all staff?","options":["In a one-on-one with the CEO","At the All-Staff Townhall on April 8","In a welcome lunch with the finance team","Via a company-wide video call on April 1"],"answer":1,"explanation":"'Vanessa will present at our All-Staff Townhall on April 8.'"},{"id":"xp7-d02c","part":7,"question":"What does Ms. Osei plan to do during her first few weeks?","options":["Launch a new financial reporting system","Schedule team-building workshops","Hold one-on-one meetings with each finance team member","Review the company's five-year strategic plan"],"answer":2,"explanation":"'I will be scheduling one-on-one meetings with each team member during April.'"},{"id":"xp7-d02d","part":7,"question":"Which area is NOT one of Ms. Osei's initial priorities?","options":["Strengthening the financial reporting framework","Improving forecasting accuracy","Reviewing vendor payment processes","Reducing the size of the finance team"],"answer":3,"explanation":"Her three stated priorities are: financial reporting, forecasting accuracy, and vendor payment processes. Team reduction is not mentioned."},{"id":"xp7-d02e","part":7,"question":"What can be inferred about Hartwell Group's finance function?","options":["It is currently overstaffed","It may have areas in need of improvement","It recently underwent major restructuring","It has no existing financial reporting framework"],"answer":1,"explanation":"Ms. Osei mentions 'identifying opportunities for improvement' and reviewing multiple processes."}]},{"passage":"[Document 1 – Gym Membership Contract]\n\nIRONFIELD FITNESS — MEMBERSHIP AGREEMENT\nMember: Lucas Hartmann | Plan: Premium Annual | Start: January 1\n\nMONTHLY FEE: AUD 79 (billed annually as AUD 948)\nINCLUDES: Unlimited access to all equipment, group classes, sauna, and guest passes (2 per month).\n\nCONTRACT TERM: 12 months. Early cancellation fee: AUD 150.\nAUTO-RENEWAL: Membership renews automatically unless cancelled in writing 30 days before expiry.\n\n[Document 2 – Member Complaint Email]\n\nFrom: Lucas Hartmann <l.hartmann@email.com>\nTo: info@ironfield.com.au\nDate: November 10\nSubject: Membership Concern — Account Ref LH-1122\n\nHello,\n\nI joined Ironfield on January 1 on an annual Premium plan. I am now concerned that my membership is set to auto-renew in January, and I have recently moved to a suburb with no nearby Ironfield location.\n\nI would like to cancel my membership before the renewal date without being charged the AUD 150 early termination fee, given that the nearest branch is now over 40 km from my home.\n\nCould you please advise on whether an exception to the cancellation fee can be made in this circumstance? I am happy to provide proof of my change of address.\n\nThank you,\nLucas Hartmann","passageTitle":"Gym Contract + Member Complaint Email","type":"double","questions":[{"id":"xp7-d03a","part":7,"question":"How many guest passes per month does Lucas receive?","options":["1","2","3","4"],"answer":1,"explanation":"'Guest passes (2 per month)'"},{"id":"xp7-d03b","part":7,"question":"What is the early cancellation fee?","options":["AUD 79","AUD 100","AUD 150","AUD 200"],"answer":2,"explanation":"'Early cancellation fee: AUD 150.'"},{"id":"xp7-d03c","part":7,"question":"Why does Lucas Hartmann want to cancel?","options":["He is unhappy with service quality","He is relocating overseas","He has moved far from the nearest branch","His financial situation has changed"],"answer":2,"explanation":"'I have recently moved to a suburb with no nearby Ironfield location' — nearest branch is 40 km away."},{"id":"xp7-d03d","part":7,"question":"What does Lucas offer to provide?","options":["A doctor's certificate","Proof of his change of address","A referral for a new member","His original signed contract"],"answer":1,"explanation":"'I am happy to provide proof of my change of address.'"},{"id":"xp7-d03e","part":7,"question":"Based on the contract, when must Lucas cancel to avoid auto-renewal?","options":["By November 30","By December 1","By December 15","By January 1"],"answer":1,"explanation":"Auto-renewal requires written cancellation '30 days before expiry.' Membership ends January 1, so he must cancel by December 1."}]},{"passage":"[Document 1 – Conference Programme]\n\nASIA-PACIFIC SUPPLY CHAIN FORUM — DAY 2 PROGRAMME\nVenue: Marina Bay Exhibition Hall, Singapore\n\n09:00 – 09:45  Keynote: The Future of Last-Mile Delivery in Urban Centres\n                Speaker: Dr. Soo-Lin Chen, Director, APAC Logistics Institute\n\n10:00 – 11:00  Panel: Resilience Strategies After Global Disruption\n                Panellists: Riku Tanaka (VP, NovaTrade); Maria Ferreiro (COO, SwiftFreight); James Park (Director, PortLogix)\n\n11:00 – 11:30  Morning Break & Exhibition Networking\n\n11:30 – 12:30  Workshop A: Implementing AI in Warehouse Operations\n                Workshop B: Green Logistics — Decarbonising the Supply Chain\n\n12:30 – 14:00  Lunch\n\n14:00 – 14:30  How GreenHarbour Reduced Picking Errors by 40% Using Robotics\n14:30 – 15:00  Cross-Border Trade Compliance: Lessons from a Failed Expansion\n\n15:15 – 16:30  Closing Keynote & Awards Ceremony\n\n[Document 2 – Delegate Message]\n\nFrom: Patricia Nguyen <p.nguyen@supplychainpro.vn>\nTo: Conference Team <info@apsupplychain.org>\nDate: Day 2, 10:52 a.m.\nSubject: Workshop Registration\n\nHello,\n\nI attended the morning keynote and am now at the networking break. I would like to attend one of the 11:30 workshops but am uncertain which to choose.\n\nCould you tell me whether Workshop A is suitable for someone who has no technical background in AI, and whether it is still possible to register on the day?\n\nAlso, is the Case Study at 14:30 focused on import compliance, or does it cover export regulations as well?\n\nThank you,\nPatricia Nguyen","passageTitle":"Conference Programme + Delegate Email","type":"double","questions":[{"id":"xp7-d04a","part":7,"question":"How many panellists are listed for the 10:00 session?","options":["2","3","4","5"],"answer":1,"explanation":"Three panellists: Riku Tanaka, Maria Ferreiro, and James Park."},{"id":"xp7-d04b","part":7,"question":"At what time does Patricia Nguyen send her email?","options":["9:00 a.m.","10:52 a.m.","11:30 a.m.","12:30 p.m."],"answer":1,"explanation":"The email timestamp is 'Day 2, 10:52 a.m.'"},{"id":"xp7-d04c","part":7,"question":"Which session immediately precedes the workshops?","options":["The morning keynote","The panel discussion","The morning break and networking","The case study presentations"],"answer":2,"explanation":"'11:00 – 11:30 Morning Break & Exhibition Networking' precedes '11:30 workshops.'"},{"id":"xp7-d04d","part":7,"question":"What topic does the 14:30 case study address?","options":["Robotics in warehouse operations","AI applications in logistics","Cross-border trade compliance","Green energy in freight"],"answer":2,"explanation":"'14:30 – 15:00 Cross-Border Trade Compliance: Lessons from a Failed Expansion.'"},{"id":"xp7-d04e","part":7,"question":"What can be inferred about Patricia Nguyen?","options":["She has expertise in AI applications","She works in the robotics industry","She has some interest in international trade regulations","She is presenting at the conference"],"answer":2,"explanation":"Her question about the 14:30 case study — whether it covers both import and export compliance — indicates interest in cross-border trade."}]},{"passage":"[Document 1 – Online Listing]\n\nLISTING: Sublet Office Space — 3 Months\nLocation: 45 King Street, Level 8, Sydney CBD\nSize: 6 workstations (approx. 45 sqm)\nAvailable: September 1 – November 30\nRent: AUD 3,800/month (all-inclusive: utilities, internet, meeting room access)\n\nDESCRIPTION:\nPrime CBD location, 2 minutes walk from Wynyard Station. Shared reception and kitchen. Building amenities include end-of-trip facilities and a rooftop terrace. Flexible access hours: 7:00 a.m. – 10:00 p.m.\n\nIdeal for: small teams on short-term projects, pop-up operations, or companies awaiting a permanent lease.\n\nContact: Michelle Croft at m.croft@stratosgroup.com.au\n\n[Document 2 – Enquiry Email]\n\nFrom: Nathan Briggs <n.briggs@lumino.io>\nTo: m.croft@stratosgroup.com.au\nDate: August 14\nSubject: Enquiry — King Street Sublet\n\nDear Ms. Croft,\n\nI am writing regarding the sublet listing at 45 King Street. We are a team of 4 currently working out of a shared coworking space, and we are looking for a dedicated, private office for a 2–3 month period while our permanent premises are being refurbished.\n\nWe would be interested in the space if it is exclusively accessible to our team — i.e., not shared with other companies during our tenancy.\n\nCould you also confirm whether the AUD 3,800/month rate includes parking for 2 vehicles?\n\nWe are hoping to take occupancy from September 1 and would appreciate an early response.\n\nKind regards,\nNathan Briggs, Director, Lumino","passageTitle":"Office Sublet Listing + Enquiry Email","type":"double","questions":[{"id":"xp7-d05a","part":7,"question":"How long is the sublet available?","options":["1 month","2 months","3 months","6 months"],"answer":2,"explanation":"'Available: September 1 – November 30' = 3 months."},{"id":"xp7-d05b","part":7,"question":"What does the rent include?","options":["Parking, utilities, and internet","Utilities, internet, and meeting room access","Meeting room access and catering","Rooftop terrace hire and reception services"],"answer":1,"explanation":"'AUD 3,800/month (all-inclusive: utilities, internet, meeting room access).'"},{"id":"xp7-d05c","part":7,"question":"What is Lumino's reason for needing the office space?","options":["They are expanding their team","Their office is being refurbished","They have no permanent address","They are testing a new market"],"answer":1,"explanation":"'Our permanent premises are being refurbished.'"},{"id":"xp7-d05d","part":7,"question":"What specific concern does Nathan Briggs raise?","options":["Whether the building has 24-hour access","Whether parking is included","Whether the space will be shared with other tenants","Whether the internet speed is adequate"],"answer":2,"explanation":"'We would be interested in the space if it is exclusively accessible to our team — not shared with other companies.'"},{"id":"xp7-d05e","part":7,"question":"How does Lumino's team size compare to the office capacity?","options":["The team is too large for the space","The team is exactly the right size","The space has more workstations than Lumino needs","The space needs to be expanded"],"answer":2,"explanation":"The listing offers 6 workstations; Lumino has a team of 4 — 2 extra workstations."}]},{"passage":"[Document 1 – Job Posting]\n\nHEAD OF MARKETING — NOVA CONSUMER GOODS\nLocation: Sydney, NSW | Permanent, Full-Time\n\nNova Consumer Goods is seeking an experienced Head of Marketing to lead our brand strategy and marketing team of 12.\n\nKey Responsibilities:\n• Develop and execute the company's brand and digital marketing strategy\n• Oversee all marketing channels including social media, email, paid advertising, and events\n• Manage a marketing budget of AUD 4.5 million\n• Lead and develop a team of 12 marketing professionals\n• Report directly to the CEO and present quarterly performance updates to the board\n\nRequirements:\n• Minimum 8 years of marketing experience, including at least 3 at a senior leadership level\n• Experience managing large marketing budgets (AUD 3M+)\n• Proven track record in B2C consumer brands\n• Bachelor's degree; MBA preferred\n\nSalary: AUD 180,000–210,000 + bonus\nDeadline: February 28. Apply to: careers@novacg.com.au\n\n[Document 2 – Cover Letter]\n\nFrom: Dominic Leung <d.leung@email.com>\nTo: careers@novacg.com.au\nDate: February 22\n\nDear Hiring Team,\n\nI am applying for the Head of Marketing position at Nova Consumer Goods. With 11 years of marketing experience, including 4 years as Marketing Director at Brightfield Brands, I believe I am a strong fit for this role.\n\nAt Brightfield, I oversaw a marketing budget of AUD 5.2 million and led a team of 9. I spearheaded the company's digital transformation, achieving a 38% increase in online revenue over two years.\n\nI hold a Bachelor of Commerce and an MBA from the University of Melbourne. I am particularly drawn to Nova's commitment to sustainable product development, which aligns with my own values.\n\nPlease find my CV and portfolio attached.\n\nDominic Leung\n\n[Document 3 – Interview Outcome Email]\n\nFrom: Talent Team <talent@novacg.com.au>\nTo: Dominic Leung <d.leung@email.com>\nDate: March 18\nSubject: Head of Marketing — Interview Outcome\n\nDear Mr. Leung,\n\nThank you for your time and the excellent presentation you delivered during your final-round interview last week.\n\nAfter careful consideration, we are pleased to offer you the position of Head of Marketing at Nova Consumer Goods. We were particularly impressed by your track record in digital transformation and your strategic approach to brand building.\n\nYour proposed start date is April 7. Please confirm your acceptance by March 25 by signing and returning the enclosed offer letter.\n\nWe look forward to welcoming you to the team.\n\nNova Talent Team","passageTitle":"Job Posting + Cover Letter + Interview Outcome","type":"triple","questions":[{"id":"xp7-t01a","part":7,"question":"What is the size of the team the successful candidate will lead?","options":["9","10","12","15"],"answer":2,"explanation":"'Lead and develop a team of 12 marketing professionals.'"},{"id":"xp7-t01b","part":7,"question":"Does Dominic Leung meet the minimum experience requirement?","options":["No, he has only 8 years","Yes, he has exactly the minimum","Yes, he exceeds the minimum","No, he lacks senior leadership experience"],"answer":2,"explanation":"Job requires 8 years + 3 senior; Dominic has 11 years + 4 as Marketing Director — exceeds both."},{"id":"xp7-t01c","part":7,"question":"What notable achievement does Dominic highlight?","options":["Winning a national marketing award","Reducing marketing costs by 38%","Increasing online revenue by 38%","Growing his team from 5 to 9"],"answer":2,"explanation":"'Achieving a 38% increase in online revenue over two years.'"},{"id":"xp7-t01d","part":7,"question":"By what date must Dominic confirm his acceptance?","options":["March 18","March 22","March 25","April 7"],"answer":2,"explanation":"'Please confirm your acceptance by March 25.'"},{"id":"xp7-t01e","part":7,"question":"What particularly impressed Nova Consumer Goods?","options":["His MBA qualification","His experience managing a large team","His digital transformation track record and strategic approach","His connection to sustainable product development"],"answer":2,"explanation":"'We were particularly impressed by your track record in digital transformation and your strategic approach to brand building.'"},{"id":"xp7-t01f","part":7,"question":"How does the budget Dominic managed at Brightfield compare to Nova's?","options":["It was smaller","It was equal","It was larger","Cannot be compared from the information given"],"answer":2,"explanation":"Dominic managed AUD 5.2M at Brightfield vs Nova's AUD 4.5M — his previous budget was larger."}]},{"passage":"[Document 1 – Company Policy Extract]\n\nSUNRISE FINANCIAL SERVICES\nEmployee Travel & Entertainment Policy — Section 4\n\n4.1 CLIENT ENTERTAINMENT\nEmployees may claim expenses for client entertainment up to AUD 200 per client per occasion. Expenses above this limit require prior written approval from a senior manager.\n\n4.2 MEALS DURING BUSINESS TRAVEL\nThe daily meal allowance for domestic travel is AUD 75. For international travel, AUD 120 applies. Receipts are required for all claims above AUD 30.\n\n4.3 TRANSPORT\nTaxi and rideshare fares are reimbursable for business travel where public transport is impractical. Airport transfers are fully reimbursable. Car rental requires pre-approval.\n\n4.4 SUBMISSION DEADLINE\nAll expense claims must be submitted within 15 business days of the expense being incurred. Late submissions will require written justification to the Finance Director.\n\n[Document 2 – Expense Claim Email]\n\nFrom: Fiona Marsh <f.marsh@sunrisefs.com>\nTo: finance@sunrisefs.com\nDate: June 6\nSubject: Expense Claim — Client Visit, Perth, June 2–4\n\nHi Finance Team,\n\nPlease find attached my expense claim for my Perth trip. Summary below:\n\n- Return flights: AUD 680 (pre-approved)\n- Hotel (3 nights): AUD 895\n- Meals (3 days @ AUD 75): AUD 225\n- Client dinner, June 3: AUD 310 (4 guests)\n- Airport transfers (x2): AUD 95\n- Car rental (June 3): AUD 140 (pre-approved)\n\nTotal claimed: AUD 2,345\n\nI note the client dinner exceeded the per-person AUD 200 limit. With 4 guests, the limit would be AUD 800. I obtained verbal approval from my manager before the event — could you confirm whether that is sufficient, or whether I need a written record?\n\nThanks,\nFiona\n\n[Document 3 – Finance Team Response]\n\nFrom: Finance Team <finance@sunrisefs.com>\nTo: Fiona Marsh <f.marsh@sunrisefs.com>\nDate: June 7\n\nHi Fiona,\n\nThank you for your submission. Your claim is within the 15-business-day window and all documentation appears to be in order.\n\nRegarding the client dinner: the policy requires prior written approval for client entertainment exceeding the per-occasion limit. Verbal approval is not sufficient. Please obtain a written confirmation from your manager (an email is acceptable) and resubmit the client dinner claim.\n\nAll other items will be processed in the next payment cycle.\n\nFinance Team","passageTitle":"Company Policy + Expense Email + Finance Response","type":"triple","questions":[{"id":"xp7-t02a","part":7,"question":"What is the daily domestic meal allowance?","options":["AUD 30","AUD 50","AUD 75","AUD 120"],"answer":2,"explanation":"'The daily meal allowance for domestic travel is AUD 75.'"},{"id":"xp7-t02b","part":7,"question":"What is the client entertainment limit per occasion without prior approval?","options":["AUD 100 per person","AUD 200 per client per occasion","AUD 800 for groups of 4","AUD 200 total per event"],"answer":1,"explanation":"'Up to AUD 200 per client per occasion.'"},{"id":"xp7-t02c","part":7,"question":"Did Fiona submit her claim on time?","options":["No, she submitted more than 15 days after the trip","Yes, her claim is within the 15-business-day window","Her claim was submitted before receipts were attached","She needs manager approval for the hotel cost"],"answer":1,"explanation":"Finance confirms 'Your claim is within the 15-business-day window.'"},{"id":"xp7-t02d","part":7,"question":"Why is Fiona's client dinner claim not fully processed?","options":["The amount exceeds the absolute maximum","She failed to include receipts","Verbal manager approval is not sufficient per policy","She has not listed all 4 guests"],"answer":2,"explanation":"'The policy requires prior written approval... Verbal approval is not sufficient.'"},{"id":"xp7-t02e","part":7,"question":"What does the finance team accept as written approval?","options":["A signed memo from the Finance Director","A formal letter on company letterhead","An email from the manager","A completed pre-approval form"],"answer":2,"explanation":"'Please obtain a written confirmation from your manager (an email is acceptable).'"}]},{"passage":"[Document 1 – Product Recall Notice]\n\nOFFICIAL RECALL NOTICE\nProduct: BrewMaster Pro Coffee Machine — Model BM-400\nManufacturer: TasteLine Appliances Ltd.\n\nTasteLine Appliances Ltd. is voluntarily recalling the BrewMaster Pro BM-400 due to a manufacturing defect in the heating element, which may cause the unit to overheat under extended use. This could pose a fire risk.\n\nAffected units: Serial numbers BM400-001000 to BM400-075000\nDate range manufactured: March–July 2023\n\nCustomers are advised to IMMEDIATELY stop using the product and unplug it. Do not continue to use the machine even if it appears to be functioning normally.\n\nFor a full refund or replacement, contact TasteLine at 1800 TASTELINE or register at tasteline.com/recall.\n\n[Document 2 – Customer Forum Post]\n\nPosted by: HomeKitchenFan | Product Review Forum\nDate: October 22\n\nHas anyone else received a recall notice for the BrewMaster Pro? I bought mine in May 2023 and just got an email about it. The serial number on mine is BM400-041222, so it's within the affected range.\n\nHonestly, the machine has been working perfectly for me. I'm a bit frustrated because it's my daily driver and I use it at least twice a day. However, I understand the safety risk.\n\nI registered for a replacement rather than a refund since I'm happy with the product otherwise. Has anyone gone through the replacement process? How long does it take?\n\n[Document 3 – TasteLine Customer Service Email]\n\nFrom: TasteLine Customer Service <recall@tasteline.com>\nTo: HomeKitchenFan (registered email)\nDate: October 24\nSubject: BrewMaster Pro Recall — Your Replacement Request\n\nDear Customer,\n\nThank you for registering your recall request. We have confirmed that your unit (BM400-041222) is within the affected serial number range.\n\nYour replacement BrewMaster Pro BM-450 (the updated model with the corrected heating element) will be dispatched within 10 business days. A prepaid return label for your BM-400 will be included in the delivery box.\n\nPlease do not return the unit until you have received the replacement — this ensures you are not without a coffee machine during the exchange.\n\nWe apologise for the inconvenience and thank you for your cooperation.\nTasteLine Customer Service","passageTitle":"Recall Notice + Forum Post + Customer Service Email","type":"triple","questions":[{"id":"xp7-t03a","part":7,"question":"What is the safety risk with the BM-400?","options":["Electrical shock from a faulty power cord","Water leakage from the brewing chamber","Overheating of the heating element, creating a fire risk","Excessive noise during operation"],"answer":2,"explanation":"'A manufacturing defect in the heating element, which may cause the unit to overheat... This could pose a fire risk.'"},{"id":"xp7-t03b","part":7,"question":"Is HomeKitchenFan's machine included in the recall?","options":["No, it was purchased after the affected date range","Yes, the serial number falls within the affected range","It cannot be determined","No, only units made before March 2023 are affected"],"answer":1,"explanation":"Serial BM400-041222 falls within BM400-001000 to BM400-075000. TasteLine confirms this in Document 3."},{"id":"xp7-t03c","part":7,"question":"Why did HomeKitchenFan choose a replacement rather than a refund?","options":["The refund process takes too long","The replacement comes with an extended warranty","They are satisfied with the product overall","The refund amount was too low"],"answer":2,"explanation":"'I registered for a replacement rather than a refund since I'm happy with the product otherwise.'"},{"id":"xp7-t03d","part":7,"question":"What is included with the replacement unit delivery?","options":["A full refund cheque","A prepaid return label for the BM-400","A coupon for a future purchase","An extended warranty certificate"],"answer":1,"explanation":"'A prepaid return label for your BM-400 will be included in the delivery box.'"},{"id":"xp7-t03e","part":7,"question":"What does TasteLine instruct about returning the old machine?","options":["Return it immediately before the replacement is dispatched","Drop it off at an authorised service centre","Do not return it until the replacement has arrived","Send it back within 5 business days of the new unit"],"answer":2,"explanation":"'Please do not return the unit until you have received the replacement.'"}]},{"passage":"[Document 1 – Programme Flyer]\n\nSPRINGFIELD ARTS COUNCIL — GRANT INFORMATION SESSION\n\nDate: Wednesday, July 9\nTime: 5:30 – 7:30 p.m.\nVenue: Springfield Arts Council, Studio Gallery, 14 Park Lane\n\nAre you an artist, performer, or arts organisation looking for funding? Come and learn about available grants, eligibility criteria, and how to write a compelling application.\n\nPresenters:\n- Grant Advisory Team, Springfield Arts Council\n- Kira Moss, successful grant recipient (mural installation, 2023)\n\nLight refreshments will be served. Free entry; no registration required.\n\n[Document 2 – Post-Session Email]\n\nFrom: Springfield Arts Council <grants@springfieldarts.org>\nTo: Session Attendees\nDate: July 10\nSubject: Resources from Last Night's Session\n\nDear Attendees,\n\nThank you for joining us last night. We were delighted to see over 60 people in attendance.\n\nAs promised, we have attached the following resources:\n1. Grant Programme Overview (PDF)\n2. Application checklist and common mistakes guide\n3. Recording of Kira Moss's presentation\n\nThe next grant application deadline is August 31. Applications must be submitted via the online portal at springfieldarts.org/grants.\n\nIf you have questions about your specific project or application, please book a one-on-one advisory session with our grants team via the portal.\n\nGood luck with your applications!\nSpringfield Arts Council Grants Team","passageTitle":"Grants Session Flyer + Follow-up Email","type":"double","questions":[{"id":"xp7-d06a","part":7,"question":"Who is Kira Moss?","options":["A member of the grant team","An artist who previously received a council grant","The director of the Arts Council","A guest lecturer from a university"],"answer":1,"explanation":"'Kira Moss, successful grant recipient (mural installation, 2023)'"},{"id":"xp7-d06b","part":7,"question":"How many people attended the information session?","options":["Over 30","Over 45","Over 60","Over 75"],"answer":2,"explanation":"'We were delighted to see over 60 people in attendance.'"},{"id":"xp7-d06c","part":7,"question":"What is the next grant application deadline?","options":["July 9","July 10","July 31","August 31"],"answer":3,"explanation":"'The next grant application deadline is August 31.'"},{"id":"xp7-d06d","part":7,"question":"How can attendees get personalised advice?","options":["By emailing grants@springfieldarts.org","By attending the next information session","By booking a one-on-one advisory session via the portal","By submitting a draft application for review"],"answer":2,"explanation":"'Please book a one-on-one advisory session with our grants team via the portal.'"},{"id":"xp7-d06e","part":7,"question":"What was NOT required to attend the information session?","options":["Refreshments","A presentation by a grant recipient","Registration","Information on eligibility"],"answer":2,"explanation":"'Free entry; no registration required.'"}]}]};
